window.AP_QUESTIONS = [{"id":"Units_1-2-q47","source":"Units_1-2","sourceNumber":"47","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A bowling ball rolls over a smooth horizontal floor with constant velocity. Four students (Antonio, Bela, Charles, and Dominique) are presented with the measured position-versus-time data shown on the graph above, and are asked to calculate the velocity of the ball. Each of the students takes a different approach, drawing the lines shown in red below, and calculating the slope of these lines. Which student's analysis will result in the most accurate calculation of the ball's velocity during the six-second time interval shown?","choices":[{"label":"A","text":"Charles"},{"label":"B","text":"Dominique"},{"label":"C","text":"Antonio"},{"label":"D","text":"Bela"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"307","height":"285"},{"src":"data:image/jpeg;base64,","alt":"","width":"586","height":"146"}],"answer":"B"},{"id":"Units_1-2-q49","source":"Units_1-2","sourceNumber":"49","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"At which instant(s) in time do the cars have the same velocity?","choices":[{"label":"A","text":"1 s, 2 s, 3 s, and 5 s"},{"label":"B","text":"1 s"},{"label":"C","text":"1 s, 3 s, and 5 s"},{"label":"D","text":"1 s, 2 s, and 3 s"},{"label":"E","text":"never"}],"images":[],"answer":"E"},{"id":"Units_1-2-q50","source":"Units_1-2","sourceNumber":"50","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Which of the following is true about the average acceleration of Car 1 and the acceleration of Car 2 during the time interval shown?","choices":[{"label":"A","text":"Car 1's average acceleration is nonzero and equal to that of Car 2."},{"label":"B","text":"Car 1's average acceleration is nonzero and twice that of Car 2."},{"label":"C","text":"Car 2's average acceleration is nonzero and twice that of Car 1."},{"label":"D","text":"Both cars have an average acceleration of zero."}],"images":[],"answer":"D"},{"id":"Units_1-2-q51","source":"Units_1-2","sourceNumber":"51","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The figure above shows a motion diagram for an object. The number near each dot indicates the clock reading in seconds when the object passes that location. The positive direction is defined as to the right of the page. Which of the following is true about the object?","choices":[{"label":"A","text":"The object has negative acceleration for the entire time interval."},{"label":"B","text":"The object has negative acceleration before t = 3 and positive acceleration after t = 3 s."},{"label":"C","text":"The object has positive acceleration for the entire time interval."},{"label":"D","text":"The object has the greatest magnitude acceleration at t = 3 s."},{"label":"E","text":"The object has positive acceleration before t = 3 s and negative acceleration after t = 3 s."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"576","height":"133"}],"answer":"B"},{"id":"Units_1-2-q52","source":"Units_1-2","sourceNumber":"52","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Which of the following must be true of an object that is slowing down?","choices":[{"label":"A","text":"Its velocity must be negative."},{"label":"B","text":"Its velocity must be larger than its acceleration."},{"label":"C","text":"Its velocity must be smaller than its acceleration."},{"label":"D","text":"Its velocity and its acceleration must be in opposite directions."},{"label":"E","text":"Its acceleration must be negative."}],"images":[],"answer":"D"},{"id":"Units_1-2-q53","source":"Units_1-2","sourceNumber":"53","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An object is shot vertically upward on the surface of the Earth with a positive initial velocity. Which of the following correctly describes the velocity and acceleration of the object at its maximum elevation, taking the positive direction as upward? Velocity Acceleration","choices":[{"label":"A","text":"Zero Negative"},{"label":"B","text":"Positive Positive"},{"label":"C","text":"Zero Zero"},{"label":"D","text":"Positive Negative"},{"label":"E","text":"Negative Negative"}],"images":[],"answer":"A"},{"id":"Units_1-2-q54","source":"Units_1-2","sourceNumber":"54","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"You throw a small ball upward and notice the time it takes to come back. If you then throw the same ball so that it takes twice as much time to come back, what is true about the motion of the ball the second time?","choices":[{"label":"A","text":"Its initial speed was more than four times the speed in the first experiment."},{"label":"B","text":"Its initial speed was more than twice, but less than four times the speed in the first experiment."},{"label":"C","text":"Its initial speed was less than twice the speed in the first experiment."},{"label":"D","text":"Its initial speed was twice the speed in the first experiment."}],"images":[],"answer":"D"},{"id":"Units_1-2-q55","source":"Units_1-2","sourceNumber":"55","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"You throw a small ball upward and measure the upward distance that it travels to its peak. If you then throw the same ball so that it travels twice the upward distance to its peak, what is true about the motion of the ball the second time?","choices":[{"label":"A","text":"Its initial speed was four times the speed in the first experiment."},{"label":"B","text":"Its initial speed was more than four times the speed in the first experiment."},{"label":"C","text":"Its initial speed was twice the speed in the first experiment."},{"label":"D","text":"Its initial speed was more than twice, but less than four times the speed in the first experiment."},{"label":"E","text":"Its initial speed was less than twice the speed in the first experiment."}],"images":[],"answer":"E"},{"id":"Units_1-2-q56","source":"Units_1-2","sourceNumber":"56","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"You throw a small ball upward and notice the time it takes to come back. If you then throw the same ball so that it takes twice as much time to come back, what is true about the motion of the ball the second time?","choices":[{"label":"A","text":"It had more than twice as much acceleration on the way up as it did the first time."},{"label":"B","text":"It had the same acceleration on the way up as it did the first time."},{"label":"C","text":"It had twice as much acceleration on the way up as it did the first time."},{"label":"D","text":"It had half as much acceleration on the way up as it did the first time."}],"images":[],"answer":"B"},{"id":"Units_1-2-q57","source":"Units_1-2","sourceNumber":"57","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"In the absence of air resistance, an object dropped near the surface of the Earth moves with a constant acceleration of 9.8 m/s 2 downwards. This means that","choices":[{"label":"A","text":"the speed of the object increases by 9.8 m/s during the first second only."},{"label":"B","text":"the speed of the object increases by 9.8 m/s during each second."},{"label":"C","text":"the speed of the object as it falls is 9.8 m/s."},{"label":"D","text":"the object falls 9.8 meters during each second."},{"label":"E","text":"the object falls 9.8 meters during the first second only."}],"images":[],"answer":"B"},{"id":"Units_1-2-q58","source":"Units_1-2","sourceNumber":"58","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"When a ball is thrown straight up with no air resistance, the acceleration of the ball at its highest point","choices":[{"label":"A","text":"reverses from upward to downward"},{"label":"B","text":"is upward"},{"label":"C","text":"is downward"},{"label":"D","text":"reverses from downward to upward"},{"label":"E","text":"is zero"}],"images":[],"answer":"C"},{"id":"Units_1-2-q59","source":"Units_1-2","sourceNumber":"59","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A girl is standing on top of a building, initially holding a baseball and a softball. She simultaneously does something to each ball, causing each to undergo the motion represented by the velocity-versus-time graph above. What does the girl do? Select two answers.","choices":[{"label":"A","text":"Throws the softball upward."},{"label":"B","text":"Throws the baseball upward."},{"label":"C","text":"Throws the baseball downward."},{"label":"D","text":"Throws the softball downward."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"336","height":"251"}],"answer":"C, A"},{"id":"Units_1-2-q61","source":"Units_1-2","sourceNumber":"61","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Which of the dot diagrams above represents the motion of an object that has a negative velocity and a negative acceleration?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"},{"label":"E","text":"E"}],"images":[],"answer":"E"},{"id":"Units_1-2-q62","source":"Units_1-2","sourceNumber":"62","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Which of the motion diagrams above represents an object whose position as a function of time is shown on the graph below?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"},{"label":"E","text":"E"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"165","height":"143"}],"answer":"B"},{"id":"Units_1-2-q64","source":"Units_1-2","sourceNumber":"64","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A position-versus-time graph for a point-like object is shown above. In which of the lettered graphs below does the object have the same average speed as in the above graph for the time interval t = 0 to t = 5s?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"307","height":"192"},{"src":"data:image/jpeg;base64,","alt":"","width":"255","height":"165"},{"src":"data:image/jpeg;base64,","alt":"","width":"252","height":"163"},{"src":"data:image/jpeg;base64,","alt":"","width":"259","height":"167"},{"src":"data:image/jpeg;base64,","alt":"","width":"258","height":"166"},{"src":"data:image/jpeg;base64,","alt":"","width":"252","height":"163"}],"answer":"C"},{"id":"Units_1-2-q68","source":"Units_1-2","sourceNumber":"68","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"When is the object represented by the graph above moving in the positive direction?","choices":[{"label":"A","text":"from t = 8 s to t = 10 s only"},{"label":"B","text":"at t = 4 s and t = 10 s"},{"label":"C","text":"from t = 0 s to t = 4 s only"},{"label":"D","text":"from t = 0 s to t = 3 s and from t = 6 s to t = 8 s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"298","height":"272"}],"answer":"C"},{"id":"Units_1-2-q70","source":"Units_1-2","sourceNumber":"70","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"You have two small metal spheres. You drop the first sphere and throw the second one in the upward direction. Which of the following statements are correct about their motion? Select two answers.","choices":[{"label":"A","text":"The second sphere will have larger acceleration."},{"label":"B","text":"The second sphere will spend less time in flight."},{"label":"C","text":"Both spheres will have the same acceleration."},{"label":"D","text":"The first sphere will have a slower final speed when it reaches the ground."}],"images":[],"answer":"D, C"},{"id":"Units_1-2-q71","source":"Units_1-2","sourceNumber":"71","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The graph above represents the velocity as a function of time for an object moving along a straight line. Which of the following is true at t = 4 s? Select two answers.","choices":[{"label":"A","text":"The object is changing direction."},{"label":"B","text":"The object is instantaneously at rest."},{"label":"C","text":"The object is moving in the positive direction."},{"label":"D","text":"The object is moving in the negative direction."},{"label":"E","text":"The object is changing acceleration."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"250","height":"225"}],"answer":"C, E"},{"id":"Units_1-2-q72","source":"Units_1-2","sourceNumber":"72","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Above is a position-versus-time graph for an object. Which is a correct description of the object's motion?","choices":[{"label":"A","text":"The object does not move at first. Then it rolls down a hill, and keeps going."},{"label":"B","text":"The object does not move at first. Then it moves at a constant velocity, and stops."},{"label":"C","text":"The object rolls along a flat surface. It then rolls down a hill, and finally stops."},{"label":"D","text":"The object moves along a flat surface. Then it rolls down a hill, and keeps going."},{"label":"E","text":"The object is moving at a constant velocity. Then it slows down and stops."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"477","height":"197"}],"answer":"B"},{"id":"Units_1-2-q73","source":"Units_1-2","sourceNumber":"73","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"The graph shown above represents an object that is doing which of the following?","choices":[{"label":"A","text":"speeding up in the negative direction"},{"label":"B","text":"moving at a constant velocity in the negative direction"},{"label":"C","text":"moving in the negative direction and slowing down"},{"label":"D","text":"moving down a hill at a constant speed"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"213","height":"191"}],"answer":"A"},{"id":"Units_1-2-q74","source":"Units_1-2","sourceNumber":"74","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A cart is released from rest on a uniform ramp, shown above. It takes the Car 2 seconds to roll all the way to the bottom of the ramp. Where is the Car located at t = 1 second?","choices":[{"label":"A","text":"to the right of the halfway point"},{"label":"B","text":"at the halfway point"},{"label":"C","text":"to the left of the halfway point"},{"label":"D","text":"Cannot be determined"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"326","height":"175"}],"answer":"C"},{"id":"Units_1-2-q75","source":"Units_1-2","sourceNumber":"75","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An object that is thrown straight upward in free fall on Earth will have an acceleration of magnitude","choices":[{"label":"A","text":"More than 9.8 m/s 2 on the way up and 9.8 m/s 2 on the way down"},{"label":"B","text":"9.8 m/s 2 on the way up and less than 9.8 m/s 2 on the way down"},{"label":"C","text":"Less than 9.8 m/s 2 on the way up and 9.8 m/s 2 on the way down"},{"label":"D","text":"9.8 m/s 2 on the way up and more than 9.8 m/s 2 on the way down"},{"label":"E","text":"9.8 m/s 2 on the way up and 9.8 m/s 2 on the way down"}],"images":[],"answer":"E"},{"id":"Units_1-2-q78","source":"Units_1-2","sourceNumber":"78","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"The velocity-versus-time graph for an object is shown above. At which clock reading is the object changing its direction of motion?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"},{"label":"E","text":"E"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"219","height":"218"}],"answer":"C"},{"id":"Units_1-2-q79","source":"Units_1-2","sourceNumber":"79","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"The graph shown above represents an object that is doing which of the following?","choices":[{"label":"A","text":"Speeding up in the negative direction, then speeding up in the positive direction"},{"label":"B","text":"Speeding up in the positive direction"},{"label":"C","text":"Slowing down, then speeding up"},{"label":"D","text":"Moving in the positive direction and slowing down"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"201","height":"181"}],"answer":"D"},{"id":"Units_1-2-q80","source":"Units_1-2","sourceNumber":"80","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A cheetah is initially moving in the positive direction, but slowing down with a constant acceleration. Which of the following is true about the distance traveled by the cheetah?","choices":[{"label":"A","text":"The cheetah travels less distance between the times 0 and 1 s than between the times 1 and 2 s."},{"label":"B","text":"The cheetah travels a greater distance between the times 0 and 1 s than between the times 1 and 2 s."},{"label":"C","text":"The cheetah travels the same distance between the instants 0 and 1 s as it does between the times 1 and 2 s."},{"label":"D","text":"Not enough information."}],"images":[],"answer":"B"},{"id":"Units_1-2-q81","source":"Units_1-2","sourceNumber":"81","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An object has a negative acceleration. Which is true about the motion of the object?","choices":[{"label":"A","text":"It is speeding up."},{"label":"B","text":"It is moving at a constant speed."},{"label":"C","text":"It is turning around."},{"label":"D","text":"It is slowing down."},{"label":"E","text":"Not enough information."}],"images":[],"answer":"E"},{"id":"Units_1-2-q83","source":"Units_1-2","sourceNumber":"83","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"At which time after t = 0 s will the object be found back at its starting position?","choices":[{"label":"A","text":"At t = 3 s"},{"label":"B","text":"At t = 6 s"},{"label":"C","text":"At t = 5 s"},{"label":"D","text":"Never during the time interval shown on the graph"}],"images":[],"answer":"D"},{"id":"Units_1-2-q84","source":"Units_1-2","sourceNumber":"84","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"During which time interval(s) is the object moving in negative direction?","choices":[{"label":"A","text":"From t = 3 s to t = 8 s"},{"label":"B","text":"From t = 3 s to t = 5 s"},{"label":"C","text":"From t = 3 s to t = 6 s"},{"label":"D","text":"From t = 5 s to t = 8 s"},{"label":"E","text":"From t = 5 s to t = 6 s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q86","source":"Units_1-2","sourceNumber":"86","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"At which instant in time after t = 0 s will the object be found back at its starting position?","choices":[{"label":"A","text":"Never during the time interval graphed"},{"label":"B","text":"At t = 6 s"},{"label":"C","text":"At t = 2 s"},{"label":"D","text":"At t = 4 s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q87","source":"Units_1-2","sourceNumber":"87","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"At which time interval(s) is the object slowing down?","choices":[{"label":"A","text":"From t = 4 s to t = 6 s"},{"label":"B","text":"From t = 0 s to t = 2 s"},{"label":"C","text":"From t = 0 s to t = 4 s"},{"label":"D","text":"From t = 0 s to t = 2 s and from t = 4 s to t = 6 s"},{"label":"E","text":"From t = 2 s to t = 6 s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q89","source":"Units_1-2","sourceNumber":"89","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Which of the following velocity-versus-time graphs represents an object that is speeding up at a uniform rate of acceleration?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"128","height":"108"},{"src":"data:image/jpeg;base64,","alt":"","width":"130","height":"109"},{"src":"data:image/jpeg;base64,","alt":"","width":"132","height":"108"},{"src":"data:image/jpeg;base64,","alt":"","width":"128","height":"108"},{"src":"data:image/jpeg;base64,","alt":"","width":"131","height":"109"}],"answer":"C"},{"id":"Units_1-2-q91","source":"Units_1-2","sourceNumber":"91","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The displacement x of an object moving along the x -axis is shown as a function of time t . The acceleration must be","choices":[{"label":"A","text":"zero"},{"label":"B","text":"decreasing"},{"label":"C","text":"increasing"},{"label":"D","text":"constant but not zero"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"188","height":"187"}],"answer":"A"},{"id":"Units_1-2-q92","source":"Units_1-2","sourceNumber":"92","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Two cars are initially 400 m apart, moving toward each other on a straight road. The graphs to the right represent the cars' velocities as a function of time. When will the cars be located at the same position?","choices":[{"label":"A","text":"At t = 50 s"},{"label":"B","text":"At t = 20 s"},{"label":"C","text":"At t = 10 s"},{"label":"D","text":"At t = 40 s"},{"label":"E","text":"At t = 30 s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"269","height":"239"}],"answer":"C"},{"id":"Units_1-2-q93","source":"Units_1-2","sourceNumber":"93","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"The velocity-versus-time graph above could represent the motion of which of the following objects?","choices":[{"label":"A","text":"A ball is thrown straight upward. It reaches the peak of its flight, and comes back down."},{"label":"B","text":"A ball is rolling horizontally while slowing down. It bounces from a wall, and continues to slow down while moving in the opposite direction."},{"label":"C","text":"A ball is rolling horizontally at a constant rate. It bounces from a wall, and continues to move at a constant rate in the opposite direction."},{"label":"D","text":"A ball is released from rest. It bounces off from the ground, and reaches its peak again after bouncing."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"448","height":"318"}],"answer":"D"},{"id":"Units_1-2-q94","source":"Units_1-2","sourceNumber":"94","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"Consider a deer that runs from point A to point B. The path length traveled by the deer can be greater than the magnitude of the deer's displacement, but the magnitude of the deer's displacement can never be greater than the path length traveled.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"A"},{"id":"Units_1-2-q95","source":"Units_1-2","sourceNumber":"95","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Which of the following quantities has units of a displacement? (There could be more than one correct choice.)","choices":[{"label":"A","text":"- 120 m/s"},{"label":"B","text":"32 ft/s 2 vertically downward"},{"label":"C","text":"40 km southwest"},{"label":"D","text":"186,000 mi"},{"label":"E","text":"9.8 m/s 2"}],"images":[],"answer":"D, C"},{"id":"Units_1-2-q96","source":"Units_1-2","sourceNumber":"96","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"Suppose that an object travels from one point in space to another. Make a comparison between the magnitude of the object's displacement and the path length traveled by the object.","choices":[{"label":"A","text":"The displacement can be either greater than, smaller than, or equal to the path length traveled."},{"label":"B","text":"The displacement is either greater than or equal to the path length traveled."},{"label":"C","text":"The displacement is always equal to the path length traveled."},{"label":"D","text":"The displacement is either less than or equal to the path length traveled."}],"images":[],"answer":"D"},{"id":"Units_1-2-q97","source":"Units_1-2","sourceNumber":"97","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"Consider a car that travels between points A and B. The car's average speed can be greater than the magnitude of its average velocity, but the magnitude of its average velocity can never be greater than its average speed.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"A"},{"id":"Units_1-2-q98","source":"Units_1-2","sourceNumber":"98","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Which of the following quantities has units of a velocity? (There could be more than one correct choice.)","choices":[{"label":"A","text":"9.8 m/s downward"},{"label":"B","text":"40 km southwest"},{"label":"C","text":"186,000 mi"},{"label":"D","text":"- 120 m/s"},{"label":"E","text":"9.8 m/s 2 downward"}],"images":[],"answer":"A, D"},{"id":"Units_1-2-q99","source":"Units_1-2","sourceNumber":"99","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"When is the average velocity of an object equal to the instantaneous velocity throughout a particular time interval?","choices":[{"label":"A","text":"when the velocity is increasing at a constant rate throughout the time interval"},{"label":"B","text":"when the velocity is constant throughout the time interval"},{"label":"C","text":"when the velocity is decreasing at a constant rate throughout the time interval"},{"label":"D","text":"always"},{"label":"E","text":"never"}],"images":[],"answer":"B"},{"id":"Units_1-2-q100","source":"Units_1-2","sourceNumber":"100","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"You drive 6.0 km at 50 km/h and then another 6.0 km at 90 km/h. Your average speed over the 12 km drive will be","choices":[{"label":"A","text":"less than 70 km/h"},{"label":"B","text":"equal to 70 km/h"},{"label":"C","text":"greater than 70 km/h"},{"label":"D","text":"exactly 38 km/h"},{"label":"E","text":"It cannot be determined from the information given because we must also know directions traveled."}],"images":[],"answer":"A"},{"id":"Units_1-2-q101","source":"Units_1-2","sourceNumber":"101","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"If the instantaneous velocity of an object is zero at some instant in time, then its acceleration must also be zero at that instant.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_1-2-q102","source":"Units_1-2","sourceNumber":"102","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Which of the following situations is impossible ?","choices":[{"label":"A","text":"An object's instantaneous velocity is directed east and its acceleration is also directed east."},{"label":"B","text":"An object's instantaneous velocity is directed east and its acceleration is directed west."},{"label":"C","text":"An object's instantaneous velocity is zero and it acceleration is directed east."},{"label":"D","text":"An object's instantaneous velocity is directed east and its acceleration is zero."},{"label":"E","text":"All of the above are possible."}],"images":[],"answer":"E"},{"id":"Units_1-2-q103","source":"Units_1-2","sourceNumber":"103","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"If an object has an acceleration of zero, then that object must also have an instantaneous velocity of zero.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_1-2-q104","source":"Units_1-2","sourceNumber":"104","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"If the instantaneous velocity of an object is zero, then that object must also have zero acceleration.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_1-2-q105","source":"Units_1-2","sourceNumber":"105","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Suppose that a car traveling to the west slows down as it approaches a traffic light. Which of the following statements about its acceleration is correct?","choices":[{"label":"A","text":"The acceleration is toward the east."},{"label":"B","text":"The acceleration is zero."},{"label":"C","text":"The acceleration is toward the west."},{"label":"D","text":"The direction of the acceleration cannot be determined."}],"images":[],"answer":"A"},{"id":"Units_1-2-q106","source":"Units_1-2","sourceNumber":"106","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An auto manufacturer advertises that their car can go \"from zero to sixty miles per hour in eight seconds.\" This specifies what characteristic of the car's motion?","choices":[{"label":"A","text":"instantaneous speed"},{"label":"B","text":"instantaneous acceleration"},{"label":"C","text":"average acceleration"},{"label":"D","text":"average speed"},{"label":"E","text":"displacement"}],"images":[],"answer":"C"},{"id":"Units_1-2-q107","source":"Units_1-2","sourceNumber":"107","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An object moving positive direction along the x -axis has an acceleration of +2.0 m/s 2 . This means the object","choices":[{"label":"A","text":"is increasing its velocity by 2.0 m/s every second."},{"label":"B","text":"travels 2.0 m in every second."},{"label":"C","text":"is traveling at 2.0 m/s."},{"label":"D","text":"is decreasing its velocity by 2.0 m/s every second."}],"images":[],"answer":"A"},{"id":"Units_1-2-q108","source":"Units_1-2","sourceNumber":"108","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Suppose that a car traveling in the + x direction begins to slow down as it approaches a traffic light. Which statement concerning its acceleration must be correct?","choices":[{"label":"A","text":"Its acceleration is in the + x direction."},{"label":"B","text":"Its acceleration is increasing in magnitude."},{"label":"C","text":"Its acceleration is zero."},{"label":"D","text":"Its acceleration is in the - x direction."},{"label":"E","text":"Its acceleration is decreasing in magnitude."}],"images":[],"answer":"A"},{"id":"Units_1-2-q109","source":"Units_1-2","sourceNumber":"109","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Suppose that a car traveling in the - x direction begins to slow down as it approaches a traffic light. Which statement concerning its acceleration must be correct?","choices":[{"label":"A","text":"Its acceleration is in the - x direction."},{"label":"B","text":"Its acceleration is in the + x direction."},{"label":"C","text":"Its acceleration is decreasing in magnitude."},{"label":"D","text":"Its acceleration is increasing in magnitude."},{"label":"E","text":"Its acceleration is zero."}],"images":[],"answer":"A"},{"id":"Units_1-2-q110","source":"Units_1-2","sourceNumber":"110","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Suppose that an object is moving with a constant velocity. Which statement concerning its acceleration must be correct?","choices":[{"label":"A","text":"The acceleration is constantly increasing."},{"label":"B","text":"The acceleration is a constant nonzero value."},{"label":"C","text":"The acceleration is constant and equal to zero."},{"label":"D","text":"The acceleration is constantly decreasing."}],"images":[],"answer":"C"},{"id":"Units_1-2-q111","source":"Units_1-2","sourceNumber":"111","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"If the velocity of an object is zero at one instant, what is true about the acceleration of that object at that same instant? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The acceleration must be zero."},{"label":"B","text":"The acceleration could be zero."},{"label":"C","text":"The acceleration could be negative."},{"label":"D","text":"The acceleration could be positive."}],"images":[],"answer":"D, A, C"},{"id":"Units_1-2-q112","source":"Units_1-2","sourceNumber":"112","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A racing car speeds up from rest with a constant acceleration along a straight track. This track has markers spaced at equal distances along it from the start, as shown in the figure. The car reaches a speed of 140 km/h as it passes marker 2. Where on the track was the car when it was traveling at an instantaneous speed of 70 km/h?","choices":[{"label":"A","text":"Between marker 1 and marker 2"},{"label":"B","text":"At marker 1"},{"label":"C","text":"To the left of marker 1"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"576","height":"77"}],"answer":"C"},{"id":"Units_1-2-q113","source":"Units_1-2","sourceNumber":"113","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"When a ball is thrown straight up with no air resistance, the acceleration of the ball at its highest point","choices":[{"label":"A","text":"is zero"},{"label":"B","text":"reverses from downward to upward"},{"label":"C","text":"reverses from upward to downward"},{"label":"D","text":"is upward"},{"label":"E","text":"is downward"}],"images":[],"answer":"E"},{"id":"Units_1-2-q114","source":"Units_1-2","sourceNumber":"114","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A rock from a volcanic eruption is launched straight upward with negligible air resistance. Which of the following statements about this rock while it is in flight is correct?","choices":[{"label":"A","text":"Throughout its flight, the rock's acceleration is downward, and its velocity is always in the same direction as the acceleration."},{"label":"B","text":"The acceleration is downward throughout its flight."},{"label":"C","text":"On the way down, both its velocity and acceleration are downward, and at the highest point both its velocity and acceleration are zero."},{"label":"D","text":"The acceleration is downward throughout its flight except that is zero at the highest point."},{"label":"E","text":"On the way up, its acceleration is downward and its velocity is upward, and at the highest point both its velocity and acceleration are zero."}],"images":[],"answer":"B"},{"id":"Units_1-2-q115","source":"Units_1-2","sourceNumber":"115","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Suppose a ball is thrown straight upward in the absence of air resistance. What is its acceleration just before it reaches its highest point?","choices":[{"label":"A","text":"downward, with magnitude slightly greater than 9.80 m/s 2 g"},{"label":"B","text":"precisely 9.80 m/s 2 downward"},{"label":"C","text":"downward, with magnitude slightly less than 9.80 m/s 2"},{"label":"D","text":"zero"}],"images":[],"answer":"B"},{"id":"Units_1-2-q116","source":"Units_1-2","sourceNumber":"116","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A ball is thrown straight upward in the absence of air resistance, reaches its maximum height, then falls back to its initial position. Which of the following statements about the direction of the velocity and acceleration of the ball as it is moving upward is correct?","choices":[{"label":"A","text":"Its velocity points upward and its acceleration points downward."},{"label":"B","text":"Its velocity points downward and its acceleration points upward."},{"label":"C","text":"Both its velocity and its acceleration point upward."},{"label":"D","text":"Both its velocity and its acceleration point downward."}],"images":[],"answer":"A"},{"id":"Units_1-2-q117","source":"Units_1-2","sourceNumber":"117","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A ball is thrown downward in the absence of air resistance. After it has been released, which statement(s) concerning its acceleration is correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Its acceleration is zero."},{"label":"B","text":"Its acceleration increases at first, and then remains constant."},{"label":"C","text":"Its acceleration is constant."},{"label":"D","text":"Its acceleration is constantly decreasing."},{"label":"E","text":"Its acceleration is constantly increasing."}],"images":[],"answer":"C"},{"id":"Units_1-2-q118","source":"Units_1-2","sourceNumber":"118","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Two objects are dropped from a bridge, an interval of 1.0 s apart. Air resistance is negligible. During the time that both objects are falling, their separation","choices":[{"label":"A","text":"stays constant."},{"label":"B","text":"increases."},{"label":"C","text":"decreases."},{"label":"D","text":"decreases at first, but then stays constant."},{"label":"E","text":"increases at first, but then stays constant."}],"images":[],"answer":"B"},{"id":"Units_1-2-q119","source":"Units_1-2","sourceNumber":"119","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"Ball A is dropped from the top of a building. One second later, ball B is dropped from the same building. Neglect air resistance. As time progresses, the difference in their speeds","choices":[{"label":"A","text":"remains constant."},{"label":"B","text":"increases."},{"label":"C","text":"decreases."},{"label":"D","text":"cannot be determined from the information given."}],"images":[],"answer":"A"},{"id":"Units_1-2-q120","source":"Units_1-2","sourceNumber":"120","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"Two objects are thrown from the top of a tall building in the absence of air resistance. One is thrown upward, and the other is thrown downward, both with the same initial speed. What are their speeds at the instant before they hit the ground below?","choices":[{"label":"A","text":"The one thrown downward is traveling faster."},{"label":"B","text":"They are traveling at the same speed."},{"label":"C","text":"The one thrown upward is traveling faster."},{"label":"D","text":"It is impossible to determine because the height of the building is not given."}],"images":[],"answer":"B"},{"id":"Units_1-2-q121","source":"Units_1-2","sourceNumber":"121","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Brick A is dropped from the top of a building. Brick B is thrown straight down from the same building, and neither one experiences significant air resistance. Which statement about their accelerations is correct while they are in flight?","choices":[{"label":"A","text":"Both bricks have an acceleration of zero."},{"label":"B","text":"The acceleration of A is greater than the acceleration of B."},{"label":"C","text":"The two bricks have the same, nonzero acceleration."},{"label":"D","text":"The acceleration of B is greater than the acceleration of A."}],"images":[],"answer":"C"},{"id":"Units_1-2-q122","source":"Units_1-2","sourceNumber":"122","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"An object is moving with constant nonzero velocity in the + x direction. The position-versus-time graph of this object is","choices":[{"label":"A","text":"a vertical straight line."},{"label":"B","text":"a non-vertical straight line with a constant, nonzero slope."},{"label":"C","text":"a horizontal straight line."},{"label":"D","text":"a parabolic curve."}],"images":[],"answer":"B"},{"id":"Units_1-2-q123","source":"Units_1-2","sourceNumber":"123","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"An object is moving with constant nonzero acceleration in the + x direction. The position-versus-time graph of this object is","choices":[{"label":"A","text":"a horizontal straight line."},{"label":"B","text":"a vertical straight line."},{"label":"C","text":"a non-vertical straight line with a constant, nonzero slope."},{"label":"D","text":"a parabolic curve."}],"images":[],"answer":"D"},{"id":"Units_1-2-q124","source":"Units_1-2","sourceNumber":"124","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"An object is moving with constant nonzero velocity in the + x direction. The velocity-versus-time graph of this object is","choices":[{"label":"A","text":"a horizontal straight line."},{"label":"B","text":"a vertical straight line."},{"label":"C","text":"a non-vertical straight line with a constant, nonzero slope."},{"label":"D","text":"a parabolic curve."}],"images":[],"answer":"A"},{"id":"Units_1-2-q125","source":"Units_1-2","sourceNumber":"125","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"An object is moving with constant nonzero acceleration in the + x direction. The velocity-versus-time graph of this object is","choices":[{"label":"A","text":"a horizontal straight line."},{"label":"B","text":"a vertical straight line."},{"label":"C","text":"a non-vertical straight line with a constant, nonzero slope."},{"label":"D","text":"a parabolic curve."}],"images":[],"answer":"C"},{"id":"Units_1-2-q126","source":"Units_1-2","sourceNumber":"126","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The slope of a position-versus-time graph represents","choices":[{"label":"A","text":"velocity."},{"label":"B","text":"acceleration."},{"label":"C","text":"distance traveled."},{"label":"D","text":"displacement."}],"images":[],"answer":"A"},{"id":"Units_1-2-q127","source":"Units_1-2","sourceNumber":"127","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The slope of a velocity-versus-time graph represents","choices":[{"label":"A","text":"displacement."},{"label":"B","text":"distance traveled."},{"label":"C","text":"velocity."},{"label":"D","text":"acceleration."}],"images":[],"answer":"D"},{"id":"Units_1-2-q128","source":"Units_1-2","sourceNumber":"128","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"If the position-versus-time graph of an object is a horizontal line, the object is","choices":[{"label":"A","text":"moving with constant nonzero acceleration."},{"label":"B","text":"moving with constant nonzero speed."},{"label":"C","text":"moving with decreasing speed."},{"label":"D","text":"at rest."},{"label":"E","text":"moving with increasing speed."}],"images":[],"answer":"D"},{"id":"Units_1-2-q129","source":"Units_1-2","sourceNumber":"129","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"If the velocity-versus-time graph of an object is a horizontal line, the object is","choices":[{"label":"A","text":"at rest."},{"label":"B","text":"moving with constant nonzero acceleration."},{"label":"C","text":"moving with zero acceleration."},{"label":"D","text":"moving with decreasing speed."}],"images":[],"answer":"C"},{"id":"Units_1-2-q130","source":"Units_1-2","sourceNumber":"130","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"If the velocity-versus-time graph of an object is a non-vertical straight line with a constant, nonzero slope, the object is","choices":[{"label":"A","text":"at rest."},{"label":"B","text":"moving with decreasing acceleration."},{"label":"C","text":"moving with constant nonzero acceleration."},{"label":"D","text":"moving with increasing acceleration."},{"label":"E","text":"moving with constant nonzero speed."}],"images":[],"answer":"C"},{"id":"Units_1-2-q131","source":"Units_1-2","sourceNumber":"131","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The velocities of a car and a truck along a straight road are represented by the velocity-time graphs in the figure. The two vehicles are initially alongside each other at time t = 0. At time T , what is true of the displacements of the vehicles since time t = 0?","choices":[{"label":"A","text":"The truck has a greater displacement than the car."},{"label":"B","text":"The truck has a displacement of zero."},{"label":"C","text":"They will have the same displacement."},{"label":"D","text":"The car has a greater displacement than the truck."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"467","height":"242"}],"answer":"A"},{"id":"Units_1-2-q133","source":"Units_1-2","sourceNumber":"133","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Which of the following graphs represent an object with zero acceleration?","choices":[{"label":"A","text":"Graphs (a) and (b)"},{"label":"B","text":"Graphs (c) and (d)"},{"label":"C","text":"Only Graph (b)"},{"label":"D","text":"Graphs (b) and (c)"},{"label":"E","text":"Only Graph (a)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"586","height":"414"}],"answer":"A"},{"id":"Units_1-2-q134","source":"Units_1-2","sourceNumber":"134","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The figure shows a graph of the position x of two cars, C and D, as a function of time t . According to this graph, which statements about these cars must be true? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Both cars have the same acceleration."},{"label":"B","text":"The magnitude of the acceleration of car C is less than the magnitude of the acceleration of car D."},{"label":"C","text":"At time t = 10 s, both cars have the same velocity."},{"label":"D","text":"The magnitude of the acceleration of car C is greater than the magnitude of the acceleration of car D."},{"label":"E","text":"At time t = 10 s, both cars are at the same position."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"225","height":"186"}],"answer":"E, A"},{"id":"Units_1-2-q136","source":"Units_1-2","sourceNumber":"136","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A child standing on a bridge throws a rock straight downward. The rock leaves the child's hand at time t = 0 s. If we take upward as the positive direction, which of the graphs best represents the velocity v of the stone as a function of time t ?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"119","height":"131"},{"src":"data:image/jpeg;base64,","alt":"","width":"121","height":"133"},{"src":"data:image/jpeg;base64,","alt":"","width":"121","height":"140"},{"src":"data:image/jpeg;base64,","alt":"","width":"119","height":"133"},{"src":"data:image/jpeg;base64,","alt":"","width":"122","height":"129"}],"answer":"C"},{"id":"Units_1-2-q138","source":"Units_1-2","sourceNumber":"138","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"The motion of a point-like object is described in the velocity-versus-time graph shown in the figure. Throughout the time interval shown, which of the following is true about the speed of the object?","choices":[{"label":"A","text":"It increases and then decreases."},{"label":"B","text":"It only increases."},{"label":"C","text":"It decreases and then increases."},{"label":"D","text":"It remains constant."},{"label":"E","text":"It only decreases."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"340","height":"306"}],"answer":"C"},{"id":"Units_1-2-q139","source":"Units_1-2","sourceNumber":"139","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The graph in the figure shows the position of a point-like object as it travels along the x -axis. At what value of t is the speed of the object closest to 0 m/s?","choices":[{"label":"A","text":"0 s"},{"label":"B","text":"1 s"},{"label":"C","text":"2 s"},{"label":"D","text":"3 s"},{"label":"E","text":"4 s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"328","height":"289"}],"answer":"D"},{"id":"Units_1-2-q140","source":"Units_1-2","sourceNumber":"140","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"On a velocity-versus-time graph, the area between the curve and the time axis represents","choices":[{"label":"A","text":"acceleration."},{"label":"B","text":"displacement."},{"label":"C","text":"position."},{"label":"D","text":"velocity."}],"images":[],"answer":"B"},{"id":"Units_1-2-q141","source":"Units_1-2","sourceNumber":"141","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A ball dropped from a height h will hit the ground with a speed v . How fast will a ball hit the ground when dropped from a height 4 h ?","choices":[{"label":"A","text":"16 v"},{"label":"B","text":"4 v"},{"label":"C","text":"4 v"},{"label":"D","text":"2 v"},{"label":"E","text":"8 v"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"D"},{"id":"Units_1-2-q142","source":"Units_1-2","sourceNumber":"142","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A driver, traveling in a car at 12.0 m/s, notices a deer in the middle of the road. The driver takes 0.26 s to react before stepping on the brake pedal. If the car then slows down at a constant rate of 3.90 m/s 2 as it comes to a stop, how far does it travel from when the driver first notices the deer?","choices":[{"label":"A","text":"3.30 m"},{"label":"B","text":"3.00 m"},{"label":"C","text":"18.5 m"},{"label":"D","text":"21.6 m"},{"label":"E","text":"13.0 m"}],"images":[],"answer":"D"},{"id":"Units_1-2-q143","source":"Units_1-2","sourceNumber":"143","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A firework is shot straight upward with an initial speed v , and reaches a maximum height h . If the firework were fired with an initial speed 2 v , what would be the maximum height it would reach? Ignore air resistance.","choices":[{"label":"A","text":"h"},{"label":"B","text":"2 h"},{"label":"C","text":"2 h"},{"label":"D","text":"4 h"},{"label":"E","text":"3 h /2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"D"},{"id":"Units_1-2-q144","source":"Units_1-2","sourceNumber":"144","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car traveling at 20 mi/h can come to a stop after traveling 30 m. If the car is traveling at 40 mi/h, how far must it travel to stop, moving with the same acceleration?","choices":[{"label":"A","text":"40 m"},{"label":"B","text":"90 m"},{"label":"C","text":"30 m"},{"label":"D","text":"60 m"},{"label":"E","text":"120 m"}],"images":[],"answer":"E"},{"id":"Units_1-2-q145","source":"Units_1-2","sourceNumber":"145","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car goes from rest to 30 m/s in 12 s with constant acceleration. How long does it take the car to go from rest to 15 m/s with the same acceleration?","choices":[{"label":"A","text":"6.0 s"},{"label":"B","text":"3.0 s"},{"label":"C","text":"12 s"},{"label":"D","text":"12/ s"},{"label":"E","text":"24 s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_1-2-q146","source":"Units_1-2","sourceNumber":"146","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball is dropped off a cliff of height h . Its velocity upon hitting the ground is v . At what height from the base of the cliff is the ball's velocity equal to v /2?","choices":[{"label":"A","text":"15 h /16"},{"label":"B","text":"h /2"},{"label":"C","text":"h /16"},{"label":"D","text":"3 h /4"},{"label":"E","text":"h /4"}],"images":[],"answer":"E"},{"id":"Units_1-2-q147","source":"Units_1-2","sourceNumber":"147","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The tortoise and the hare are having a race. Both start at rest and have the same constant acceleration, but the hare maintains this acceleration for a time interval twice as great as the tortoise before reaching her top speed. If the tortoise reaches a top speed of v , what is the hare's top speed, in terms of v ?","choices":[{"label":"A","text":"2 v"},{"label":"B","text":"8 v"},{"label":"C","text":"v"},{"label":"D","text":"4 v"},{"label":"E","text":"v"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"C"},{"id":"Units_1-2-q148","source":"Units_1-2","sourceNumber":"148","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Starting from rest, a ball rolls down a long incline with a constant acceleration. After 2 s, it has traveled 2 m. In the next second it will travel","choices":[{"label":"A","text":"1 m"},{"label":"B","text":"3 m"},{"label":"C","text":"2.5 m"},{"label":"D","text":"1.25 m"},{"label":"E","text":"2 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q149","source":"Units_1-2","sourceNumber":"149","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An airplane touches down on a runway with a velocity of 150 m/s forward. How far will it travel as it stops if its acceleration is constant at -3.00 m/s 2 ?","choices":[{"label":"A","text":"9813 m"},{"label":"B","text":"6235 m"},{"label":"C","text":"10,435 m"},{"label":"D","text":"3750 m"},{"label":"E","text":"525 m"}],"images":[],"answer":"D"},{"id":"Units_1-2-q150","source":"Units_1-2","sourceNumber":"150","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Take the positive direction as upward. A ball is thrown downward from the top of a roof with a speed of 25.0 m/s. After 2.00 s, its velocity will be","choices":[{"label":"A","text":"19.6 m/s"},{"label":"B","text":"44.6 m/s"},{"label":"C","text":"- 25 m/s"},{"label":"D","text":"- 44.6 m/s"},{"label":"E","text":"- 5.4 m/s"}],"images":[],"answer":"B"},{"id":"Units_1-2-q152","source":"Units_1-2","sourceNumber":"152","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"An object moves 15.0 m north and then 11.0 m south. Find both the path length it has traveled and the magnitude of its displacement.","choices":[{"label":"A","text":"26.0 m, 4.0 m"},{"label":"B","text":"26.0 m, 26.0 m"},{"label":"C","text":"4.0 m, 26.0 m"},{"label":"D","text":"4.0 m, 4.0 m"}],"images":[],"answer":"A"},{"id":"Units_1-2-q153","source":"Units_1-2","sourceNumber":"153","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"What must be your average speed in order to travel 350 km in 5.15 h?","choices":[{"label":"A","text":"67.0 km/h"},{"label":"B","text":"69.0 km/h"},{"label":"C","text":"68.0 km/h"},{"label":"D","text":"66.0 km/h"}],"images":[],"answer":"C"},{"id":"Units_1-2-q154","source":"Units_1-2","sourceNumber":"154","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A runner ran the marathon (approximately 42.0 km) in 2 hours and 57 min. What was the average speed of the runner in m/s?","choices":[{"label":"A","text":"124 m/s"},{"label":"B","text":"14,200 m/s"},{"label":"C","text":"3.95 m/s"},{"label":"D","text":"14.2 m/s"}],"images":[],"answer":"C"},{"id":"Units_1-2-q155","source":"Units_1-2","sourceNumber":"155","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A light-year is the distance that light travels in vacuum in 1 year. The speed of light is 3.00 × 10 8 m/s. How many miles are equal to one light-year? (1 mi = 1609 m, 1 yr = 365 d)","choices":[{"label":"A","text":"9.46 × 10 12 mi"},{"label":"B","text":"9.46 × 10 15 mi"},{"label":"C","text":"5.88 × 10 12 mi"},{"label":"D","text":"5.88 × 10 15 mi"}],"images":[],"answer":"D"},{"id":"Units_1-2-q156","source":"Units_1-2","sourceNumber":"156","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"If you are driving 72 km/h along a straight road and you look to the side for 4.0 s, how far do you travel during this time interval?","choices":[{"label":"A","text":"80 m"},{"label":"B","text":"20 m"},{"label":"C","text":"18 m"},{"label":"D","text":"40 m"}],"images":[],"answer":"A"},{"id":"Units_1-2-q158","source":"Units_1-2","sourceNumber":"158","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A polar bear starts at the North Pole. It travels 1.0 km south, then 1.0 km east, and then 1.0 km north to return to its starting point. This trip takes 45 min. What was the bear's average speed during this time interval?","choices":[{"label":"A","text":"0.067 km/h"},{"label":"B","text":"0.00 km/h"},{"label":"C","text":"4.0 km/h"},{"label":"D","text":"5.3 km/h"}],"images":[],"answer":"C"},{"id":"Units_1-2-q159","source":"Units_1-2","sourceNumber":"159","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A polar bear starts at the North Pole. It travels 1.0 km south, then 1.0 km east, and then 1.0 km north to return to its starting point. This trip takes 45 min. What was the bear's average velocity during this time interval?","choices":[{"label":"A","text":"0.067 km/h"},{"label":"B","text":"4.0 km/h"},{"label":"C","text":"5.3 km/h"},{"label":"D","text":"0.00 km/h"}],"images":[],"answer":"D"},{"id":"Units_1-2-q160","source":"Units_1-2","sourceNumber":"160","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"You are driving home on a weekend from school at 55 mi/h for 110 miles. It then starts to snow, and you slow to 35 mi/h. You arrive home after driving for a total of 4 hours and 15 minutes. How far is your hometown from school?","choices":[{"label":"A","text":"210 mi"},{"label":"B","text":"200 mi"},{"label":"C","text":"180 mi"},{"label":"D","text":"190 mi"}],"images":[],"answer":"D"},{"id":"Units_1-2-q161","source":"Units_1-2","sourceNumber":"161","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A motorist travels 160 km at 80 km/h and then another 160 km at 100 km/h. What is the average speed of the motorist for this trip?","choices":[{"label":"A","text":"84 km/h"},{"label":"B","text":"89 km/h"},{"label":"C","text":"91 km/h"},{"label":"D","text":"90 km/h"}],"images":[],"answer":"B"},{"id":"Units_1-2-q162","source":"Units_1-2","sourceNumber":"162","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A motorist travels for 3.0 h at 80 km/h and then for 2.0 h at 100 km/h. What is her average speed for the trip?","choices":[{"label":"A","text":"88 km/h"},{"label":"B","text":"90 km/h"},{"label":"C","text":"85 km/h"},{"label":"D","text":"92 km/h"}],"images":[],"answer":"A"},{"id":"Units_1-2-q163","source":"Units_1-2","sourceNumber":"163","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"An airplane travels at 300 mi/h south for 2.00 h and then at 250 mi/h north for 750 miles. What is the average speed for the trip?","choices":[{"label":"A","text":"260 mi/h"},{"label":"B","text":"275 mi/h"},{"label":"C","text":"270 mi/h"},{"label":"D","text":"280 mi/h"}],"images":[],"answer":"C"},{"id":"Units_1-2-q166","source":"Units_1-2","sourceNumber":"166","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A runner runs around a track consisting of two parallel straight lanes 96 m long connected at the ends by two semicircles with a radius of 49 m. She completes one lap in 100 seconds. What is her average velocity?","choices":[{"label":"A","text":"2.5 m/s"},{"label":"B","text":"5.0 m/s"},{"label":"C","text":"1.3 m/s"},{"label":"D","text":"10 m/s"},{"label":"E","text":"0 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q167","source":"Units_1-2","sourceNumber":"167","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A runner runs around a track consisting of two parallel straight lanes 96 m long connected at the ends by two semicircles with a radius of 49 m. She completes one lap in 100 seconds. What is her average speed?","choices":[{"label":"A","text":"10 m/s"},{"label":"B","text":"2.5 m/s"},{"label":"C","text":"0 m/s"},{"label":"D","text":"1.3 m/s"},{"label":"E","text":"5.0 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q168","source":"Units_1-2","sourceNumber":"168","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"You leave on a 549-mi trip in order to attend a meeting that will start 10.8 h after you begin your trip. Along the way you plan to stop for dinner. If the fastest you can safely drive is 65 mi/h, what is the longest time interval you can spend at dinner and still arrive just in time for the meeting?","choices":[{"label":"A","text":"1.9 h"},{"label":"B","text":"2.6 h"},{"label":"C","text":"2.4 h"},{"label":"D","text":"You can't stop at all."}],"images":[],"answer":"C"},{"id":"Units_1-2-q169","source":"Units_1-2","sourceNumber":"169","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A motorist makes a trip of 180 miles. For the first 90 miles she drives at a constant speed of 30 mi/h. At what constant speed must she drive the remaining distance if her average speed for the total trip is to be 40 mi/h?","choices":[{"label":"A","text":"60 mi/h"},{"label":"B","text":"45 mi/h"},{"label":"C","text":"55 mi/h"},{"label":"D","text":"52.5 mi/h"},{"label":"E","text":"50 mi/h"}],"images":[],"answer":"A"},{"id":"Units_1-2-q174","source":"Units_1-2","sourceNumber":"174","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"An airplane increases its speed at the constant rate 15 m/s 2 . In what time interval does it increase its speed from 100 m/s to 160 m/s?","choices":[{"label":"A","text":"4.0 s"},{"label":"B","text":"17 s"},{"label":"C","text":"0.25 s"},{"label":"D","text":"0.058 s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q175","source":"Units_1-2","sourceNumber":"175","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car is traveling north at 17.7 m/s. After 12 s, its velocity is 14.1 m/s in the same direction. Find the magnitude and direction of the car's average acceleration during this time interval.","choices":[{"label":"A","text":"2.7 m/s 2 , north"},{"label":"B","text":"2.7 m/s 2 , south"},{"label":"C","text":"0.30 m/s 2 , north"},{"label":"D","text":"0.30 m/s 2 , south"}],"images":[],"answer":"D"},{"id":"Units_1-2-q176","source":"Units_1-2","sourceNumber":"176","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A racketball strikes a wall with a speed of 30 m/s and rebounds in the opposite direction with a speed of 26 m/s. The collision takes 20 milliseconds. What is the magnitude of the average acceleration of the ball during its collision with the wall?","choices":[{"label":"A","text":"0 m/s 2"},{"label":"B","text":"200 m/s 2"},{"label":"C","text":"1300 m/s 2"},{"label":"D","text":"2800 m/s 2"},{"label":"E","text":"1500 m/s 2"}],"images":[],"answer":"B"},{"id":"Units_1-2-q181","source":"Units_1-2","sourceNumber":"181","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A car initially traveling at 60 km/h to the east accelerates at a constant rate of 2.0 m/s 2 to the east . What time interval is required for the car to reach a speed of 90 km/h?","choices":[{"label":"A","text":"4.2 s"},{"label":"B","text":"15 s"},{"label":"C","text":"30 s"},{"label":"D","text":"45 s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q182","source":"Units_1-2","sourceNumber":"182","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A cart starts from rest and accelerates at a constant rate of 4.0 m/s 2 for 5.0 s. It then maintains the velocity it has reached for another 10 s. It then slows down with a constant acceleration of magnitude 2.0 m/s 2 for 4.0 s. What is the final speed of the car?","choices":[{"label":"A","text":"16 m/s"},{"label":"B","text":"12 m/s"},{"label":"C","text":"10 m/s"},{"label":"D","text":"20 m/s"}],"images":[],"answer":"B"},{"id":"Units_1-2-q183","source":"Units_1-2","sourceNumber":"183","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car travels at a constant speed 15 m/s for 10 s. It then speeds up with a constant acceleration of 2.0 m/s 2 for 15 s. At the end of this time, what is its velocity?","choices":[{"label":"A","text":"30 m/s"},{"label":"B","text":"375 m/s"},{"label":"C","text":"15 m/s"},{"label":"D","text":"45 m/s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q184","source":"Units_1-2","sourceNumber":"184","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A cart with an initial velocity of 5.0 m/s to the right experiences a constant acceleration of 2.0 m/s 2 to the right. What is the cart's displacement during 6.0 s?","choices":[{"label":"A","text":"10 m to the right"},{"label":"B","text":"55 m to the right"},{"label":"C","text":"80 m to the right"},{"label":"D","text":"66 m to the right"}],"images":[],"answer":"D"},{"id":"Units_1-2-q185","source":"Units_1-2","sourceNumber":"185","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A jet plane is launched from rest on an aircraft carrier. It reaches a speed of 42 m/s in a time interval of 2.0 s. Assuming the acceleration of the jet plane is constant, determine how far it travel during those 2.0 s.","choices":[{"label":"A","text":"16 m"},{"label":"B","text":"84 m"},{"label":"C","text":"24 m"},{"label":"D","text":"42 m"}],"images":[],"answer":"D"},{"id":"Units_1-2-q186","source":"Units_1-2","sourceNumber":"186","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car starting from rest accelerates at a constant rate of 2.0 m/s 2 for 10 s. It then travels with constant speed for another 10 s. Then it finally slows to a stop with constant acceleration of magnitude 2.0 m/s 2 . How far does it travel in this entire process, from beginning to end?","choices":[{"label":"A","text":"300 m"},{"label":"B","text":"500 m"},{"label":"C","text":"200 m"},{"label":"D","text":"400 m"}],"images":[],"answer":"D"},{"id":"Units_1-2-q187","source":"Units_1-2","sourceNumber":"187","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car increases its velocity uniformly from 40 m/s to 80 m/s while traveling a distance of 200 m. What is its acceleration during this time?","choices":[{"label":"A","text":"24 m/s 2"},{"label":"B","text":"12 m/s 2"},{"label":"C","text":"8.0 m/s 2"},{"label":"D","text":"9.6 m/s 2"}],"images":[],"answer":"D"},{"id":"Units_1-2-q188","source":"Units_1-2","sourceNumber":"188","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An object starts from rest and undergoes constant acceleration. During the time interval from 0 to 1 seconds, it travels 5.0 m. How far will it travel during the time interval from 2 to 3 seconds?","choices":[{"label":"A","text":"15 m"},{"label":"B","text":"45 m"},{"label":"C","text":"25 m"},{"label":"D","text":"5.0 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q189","source":"Units_1-2","sourceNumber":"189","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"An object is accelerating at a constant rate along a straight line. Initially it is traveling at 16 m/s. Three seconds later it is traveling at 10 m/s in the same direction. How far does it travel during this time interval?","choices":[{"label":"A","text":"39 m"},{"label":"B","text":"57 m"},{"label":"C","text":"30 m"},{"label":"D","text":"48 m"}],"images":[],"answer":"A"},{"id":"Units_1-2-q190","source":"Units_1-2","sourceNumber":"190","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A car starts from rest and accelerates at a constant rate of 3.0 m/s 2 toward the north. A second car starts from rest 6.0 s later at the same position, and accelerates at a constant rate of 5.0 m/s 2 toward the north. For what time interval is the second car in motion until it passes the first car?","choices":[{"label":"A","text":"21 s"},{"label":"B","text":"24 s"},{"label":"C","text":"19 s"},{"label":"D","text":"12 s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q193","source":"Units_1-2","sourceNumber":"193","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Starting from rest, a dragster travels a straight 0.25 mi racetracks in 6.70 s with constant acceleration. What is its speed when it crosses the finish line?","choices":[{"label":"A","text":"135 mi/h"},{"label":"B","text":"296 mi/h"},{"label":"C","text":"269 mi/h"},{"label":"D","text":"188 mi/h"}],"images":[],"answer":"C"},{"id":"Units_1-2-q194","source":"Units_1-2","sourceNumber":"194","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A bicyclist starts a timed race at 6.0 mi/h. In order to win, she must average 21 mi/h. Assuming constant acceleration from the start, determine how fast she must be traveling at the end of the race in order to win.","choices":[{"label":"A","text":"30 mi/h"},{"label":"B","text":"24 mi/h"},{"label":"C","text":"36 mi/h"},{"label":"D","text":"42 mi/h"}],"images":[],"answer":"C"},{"id":"Units_1-2-q195","source":"Units_1-2","sourceNumber":"195","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A car accelerates from 5.0 m/s to 21 m/s at a constant rate of 3.0 m/s 2 . How far does it travel while accelerating?","choices":[{"label":"A","text":"41 m"},{"label":"B","text":"117 m"},{"label":"C","text":"207 m"},{"label":"D","text":"69 m"}],"images":[],"answer":"D"},{"id":"Units_1-2-q196","source":"Units_1-2","sourceNumber":"196","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An airplane needs to reach a speed of 203.0 km/h to take off. If it starts from rest on a 2000-m runway, what is the minimum constant acceleration necessary for the plane to take off before reaching the end of the runway?","choices":[{"label":"A","text":"0.9559 m/s 2"},{"label":"B","text":"1.258 m/s 2"},{"label":"C","text":"0.8754 m/s 2"},{"label":"D","text":"0.7949 m/s 2"}],"images":[],"answer":"C"},{"id":"Units_1-2-q197","source":"Units_1-2","sourceNumber":"197","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Assuming equal rates of constant acceleration in both cases, how many times farther would you travel if braking from 56 mi/h to rest than from 28 mi/h?","choices":[{"label":"A","text":"4 times farther"},{"label":"B","text":"5.2 times farther"},{"label":"C","text":"4.8 times farther"},{"label":"D","text":"3.2 times farther"}],"images":[],"answer":"A"},{"id":"Units_1-2-q198","source":"Units_1-2","sourceNumber":"198","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Acceleration is sometimes expressed in multiples of g , where g = 9.8 m/s 2 is the acceleration of an object in freefall near Earth's surface. In a car crash, the car's velocity may go from 29 m/s to 0 m/s in 0.15 s. What is the average acceleration of a passenger in this car, in terms of g ?","choices":[{"label":"A","text":"20 g"},{"label":"B","text":"26 g"},{"label":"C","text":"14 g"},{"label":"D","text":"24 g"}],"images":[],"answer":"A"},{"id":"Units_1-2-q199","source":"Units_1-2","sourceNumber":"199","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A train starts from rest, and accelerates at a constant rate until it has traveled 5.6 km and has an instantaneous speed of 42 m/s. The acceleration of the train during this time interval is closest to which of the following?","choices":[{"label":"A","text":"0.14 m/ s 2"},{"label":"B","text":"0.17 m/ s 2"},{"label":"C","text":"0.20 m/ s 2"},{"label":"D","text":"0.16 m/ s 2"},{"label":"E","text":"0.19 m/ s 2"}],"images":[],"answer":"E"},{"id":"Units_1-2-q200","source":"Units_1-2","sourceNumber":"200","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A train is moving at a speed of 24 m/s. The train then slows down uniformly at 0.065 m/s 2 , until it comes to rest. The distance traveled by the train while slowing down is closest to","choices":[{"label":"A","text":"4.2 km"},{"label":"B","text":"4.4 km"},{"label":"C","text":"3.6 km"},{"label":"D","text":"4.0 km"},{"label":"E","text":"3.8 km"}],"images":[],"answer":"B"},{"id":"Units_1-2-q202","source":"Units_1-2","sourceNumber":"202","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A car starts from rest and accelerates at a constant rate of 6.00 m/s 2 . How far does it travel in the first 3.00 s?","choices":[{"label":"A","text":"54.0 m"},{"label":"B","text":"27.0 m"},{"label":"C","text":"18.0 m"},{"label":"D","text":"36.0 m"},{"label":"E","text":"9.00 m"}],"images":[],"answer":"B"},{"id":"Units_1-2-q203","source":"Units_1-2","sourceNumber":"203","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car is moving with a constant acceleration. At the instant t = 5.0 s, its velocity is 8.0 m/s in the positive direction, and at the instant t = 8.0 s its velocity is 12.0 m/s in the positive direction. What is the distance traveled during that time interval?","choices":[{"label":"A","text":"40 m"},{"label":"B","text":"10 m"},{"label":"C","text":"20 m"},{"label":"D","text":"30 m"},{"label":"E","text":"50 m"}],"images":[],"answer":"D"},{"id":"Units_1-2-q204","source":"Units_1-2","sourceNumber":"204","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"An airplane starts from rest and accelerates at a constant rate of 10.8 m/s 2 . What is its speed at the end of a 400 m-long runway?","choices":[{"label":"A","text":"4320 m/s"},{"label":"B","text":"93.0 m/s"},{"label":"C","text":"186 m/s"},{"label":"D","text":"65.7 m/s"},{"label":"E","text":"37.0 m/s"}],"images":[],"answer":"B"},{"id":"Units_1-2-q205","source":"Units_1-2","sourceNumber":"205","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car is moving with a speed of 32.0 m/s. The driver sees an accident ahead and slams on the brakes, causing the car to slow down with a constant acceleration of magnitude 3.50 m/s 2 . How far does the car travel as it comes to rest?","choices":[{"label":"A","text":"9.14 m"},{"label":"B","text":"4.57 m"},{"label":"C","text":"292 m"},{"label":"D","text":"146 m"},{"label":"E","text":"112 m"}],"images":[],"answer":"D"},{"id":"Units_1-2-q206","source":"Units_1-2","sourceNumber":"206","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car is traveling with a constant speed when the driver suddenly presses on the brake pedal, causing the car to slow down with a constant acceleration of magnitude 3.50 m/s 2 . If the car comes to rest in a distance of 30.0 m, what was the car's original speed?","choices":[{"label":"A","text":"210 m/s"},{"label":"B","text":"14.5 m/s"},{"label":"C","text":"105 m/s"},{"label":"D","text":"315 m/s"},{"label":"E","text":"10.2 m/s"}],"images":[],"answer":"B"},{"id":"Units_1-2-q207","source":"Units_1-2","sourceNumber":"207","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car is traveling with a constant speed of 30.0 m/s when the driver suddenly presses on the brake pedal, causing the car to slow down with a constant acceleration. The car comes to a stop in a distance of 120 m. What was the magnitude of the acceleration of the car as it slowed down?","choices":[{"label":"A","text":"4.75 m/s 2"},{"label":"B","text":"3.75 m/s 2"},{"label":"C","text":"4.25 m/s 2"},{"label":"D","text":"4.50 m/s 2"},{"label":"E","text":"4.00 m/s 2"}],"images":[],"answer":"D"},{"id":"Units_1-2-q208","source":"Units_1-2","sourceNumber":"208","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A car is traveling at 26.0 m/s when the driver suddenly presses on the brake pedal, causing the car to slow down with constant acceleration. The car comes to a stop in a distance of 120 m. How fast was the car moving when it was 60.0 m past the position where it started slowing down?","choices":[{"label":"A","text":"15.0 m/s"},{"label":"B","text":"12.1 m/s"},{"label":"C","text":"22.5 m/s"},{"label":"D","text":"9.20 m/s"},{"label":"E","text":"18.4 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q209","source":"Units_1-2","sourceNumber":"209","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Car A is traveling at 22.0 m/s and car B is traveling at 29.0 m/s. Car A is 300 m behind car B, when car A begins to speed up with a constant acceleration of 2.40 m/s 2 . For what time interval does car A accelerate does until it reaches the same position as car B?","choices":[{"label":"A","text":"316 s"},{"label":"B","text":"5.50 s"},{"label":"C","text":"19.0 s"},{"label":"D","text":"12.6 s"},{"label":"E","text":"Car A never reaches the same position as car B."}],"images":[],"answer":"C"},{"id":"Units_1-2-q210","source":"Units_1-2","sourceNumber":"210","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A stone is thrown with an initial upward velocity of 7.0 m/s, in the absence of air resistance. If we take upward as the positive direction, what is the velocity of the stone after 0.50 s?","choices":[{"label":"A","text":"0.00 m/s"},{"label":"B","text":"2.1 m/s"},{"label":"C","text":"- 2.1 m/s"},{"label":"D","text":"4.9 m/s"},{"label":"E","text":"- 4.9 m/s"}],"images":[],"answer":"B"},{"id":"Units_1-2-q212","source":"Units_1-2","sourceNumber":"212","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"An object is thrown upward with a speed of 12 m/s on the surface of planet X, where the freefall acceleration is 1.5 m/s 2 downward and atmospheric resistance is negligible. What is the maximum height reached by the object?","choices":[{"label":"A","text":"8.0 m"},{"label":"B","text":"144 m"},{"label":"C","text":"48 m"},{"label":"D","text":"18 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q213","source":"Units_1-2","sourceNumber":"213","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"An object is thrown upward with a speed of 12 m/s on the surface of planet X, where the freefall acceleration is 1.5 m/s 2 downward and atmospheric resistance is negligible. After what time interval does the object reach its maximum height?","choices":[{"label":"A","text":"11 s"},{"label":"B","text":"14 s"},{"label":"C","text":"8.0 s"},{"label":"D","text":"16 s"}],"images":[],"answer":"C"},{"id":"Units_1-2-q214","source":"Units_1-2","sourceNumber":"214","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"An object is thrown upward with a speed of 15 m/s on the surface of planet X where the freefall acceleration is 2.5 m/s 2 downward and atmospheric resistance is negligible. After what time interval does the object return to the same position from which it was thrown?","choices":[{"label":"A","text":"6.0 s"},{"label":"B","text":"8.0 s"},{"label":"C","text":"12 s"},{"label":"D","text":"10 s"}],"images":[],"answer":"C"},{"id":"Units_1-2-q215","source":"Units_1-2","sourceNumber":"215","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A geologist's hammer is thrown upward with a speed of 14 m/s on the surface of planet X where the freefall acceleration is 3.5 m/s 2 downward and atmospheric resistance is negligible. What is the speed of the hammer after 8.0 s?","choices":[{"label":"A","text":"14 m/s"},{"label":"B","text":"64 m/s"},{"label":"C","text":"21 m/s"},{"label":"D","text":"7.0 m/s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q216","source":"Units_1-2","sourceNumber":"216","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Human reaction time is usually greater than 0.10 s. If your friend holds a ruler between your fingers and releases it without warning, how far can you expect the ruler to fall before you catch it, assuming negligible air resistance?","choices":[{"label":"A","text":"At least 4.9 cm"},{"label":"B","text":"At least 9.8 cm"},{"label":"C","text":"At least 3.0 cm"},{"label":"D","text":"At least 6.8 cm"}],"images":[],"answer":"A"},{"id":"Units_1-2-q217","source":"Units_1-2","sourceNumber":"217","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball is thrown upward at a speed of 19.6 m/s. Calculate its velocity after 3.0 s, assuming negligible air resistance?","choices":[{"label":"A","text":"19.6 m/s downward"},{"label":"B","text":"0 m/s"},{"label":"C","text":"9.8 m/s downward"},{"label":"D","text":"9.8 m/s upward"}],"images":[],"answer":"C"},{"id":"Units_1-2-q218","source":"Units_1-2","sourceNumber":"218","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A bullet shot straight upward returns to its initial position after 10 s. Calculate the initial speed of the bullet, assuming negligible air resistance.","choices":[{"label":"A","text":"49 m/s"},{"label":"B","text":"9.8 m/s"},{"label":"C","text":"25 m/s"},{"label":"D","text":"98 m/s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q219","source":"Units_1-2","sourceNumber":"219","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball is thrown straight upward with a speed of 36 m/s. After what time interval does it return to its initial position, if there is negligible air resistance?","choices":[{"label":"A","text":"3.7 s"},{"label":"B","text":"15 s"},{"label":"C","text":"7.3 s"},{"label":"D","text":"11 s"}],"images":[],"answer":"C"},{"id":"Units_1-2-q220","source":"Units_1-2","sourceNumber":"220","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball is thrown downward from the top of a building with an initial speed of 25 m/s, in the absence of air resistance. It strikes the ground after 2.0 s. How tall is the building?","choices":[{"label":"A","text":"30 m"},{"label":"B","text":"50 m"},{"label":"C","text":"70 m"},{"label":"D","text":"20 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q223","source":"Units_1-2","sourceNumber":"223","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball is launched upward at time t = 0 s, from a location on a flat roof 10 m above the ground. The ball rises and then falls with negligible air resistance, missing the roof, and strikes the ground. The initial velocity of the ball is 58.5 m/s. Consider all quantities as positive in the upward direction. At time t = 5.97 s, the vertical velocity of the ball is closest to","choices":[{"label":"A","text":"- 175 m/s"},{"label":"B","text":"- 12 m/s"},{"label":"C","text":"+ 175 m/s"},{"label":"D","text":"+ 12 m/s"},{"label":"E","text":"0 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q224","source":"Units_1-2","sourceNumber":"224","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball is launched upward at time t = 0 s, from a point on a flat roof 90 m above the ground. The ball rises and then falls with negligible air resistance, missing the roof, and strikes the ground below. The initial velocity of the ball is 80.5 m/s. Consider all quantities in the upward direction as positive. The vertical velocity of the ball when it is 89 m above the ground is closest to","choices":[{"label":"A","text":"- 32 m/s"},{"label":"B","text":"- 81 m/s"},{"label":"C","text":"- 64 m/s"},{"label":"D","text":"- 97 m/s"},{"label":"E","text":"- 48 m/s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q225","source":"Units_1-2","sourceNumber":"225","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A rocket at ground level is fired straight up from rest with a constant upward acceleration of 20 m/s 2 . After 4.0 s, the motor turns off but the rocket continues to move upward with negligible air resistance. What maximum height does the rocket reach by the time it momentarily comes to rest?","choices":[{"label":"A","text":"410 m"},{"label":"B","text":"320 m"},{"label":"C","text":"490 m"},{"label":"D","text":"160 m"},{"label":"E","text":"330 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q226","source":"Units_1-2","sourceNumber":"226","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A rock is projected upward from the surface of the Moon, at time t = 0 s, with an upward velocity of 30.0 m/s. The freefall acceleration near the surface of the Moon is 1.62 m/s 2 downward, and the Moon has no atmosphere. The height of the rock when it is traveling downward with a speed of 20.0 m/s is closest to","choices":[{"label":"A","text":"154 m"},{"label":"B","text":"115 m"},{"label":"C","text":"145 m"},{"label":"D","text":"135 m"},{"label":"E","text":"125 m"}],"images":[],"answer":"A"},{"id":"Units_1-2-q227","source":"Units_1-2","sourceNumber":"227","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball is thrown straight upward from ground level with a speed of 18 m/s. Air resistance is negligible. How much time elapses before the ball strikes the ground?","choices":[{"label":"A","text":"1.8 s"},{"label":"B","text":"0.6 s"},{"label":"C","text":"1.1 s"},{"label":"D","text":"3.7 s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q231","source":"Units_1-2","sourceNumber":"231","topic":"Unit 8: Fluids","difficulty":"Medium","question":"An object is dropped from a bridge. A second object is thrown downwards 1.0 s later. They both reach the water 20 m below at the same instant. What was the initial speed of the second object? Neglect air resistance.","choices":[{"label":"A","text":"21 m/s"},{"label":"B","text":"20 m/s"},{"label":"C","text":"4.9 m/s"},{"label":"D","text":"9.9 m/s"},{"label":"E","text":"15 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q232","source":"Units_1-2","sourceNumber":"232","topic":"Unit 8: Fluids","difficulty":"Medium","question":"To determine the height of a bridge above the water, a person drops a stone and measures the time interval it takes for it to hit the water. If the time is 2.3 s, what is the height of the bridge? Neglect air resistance.","choices":[{"label":"A","text":"32 m"},{"label":"B","text":"10 m"},{"label":"C","text":"52 m"},{"label":"D","text":"14 m"},{"label":"E","text":"26 m"}],"images":[],"answer":"E"},{"id":"Units_1-2-q233","source":"Units_1-2","sourceNumber":"233","topic":"Unit 8: Fluids","difficulty":"Medium","question":"To determine the height of a bridge above the water, a person drops a stone and measures the time interval it takes for it to hit the water. If the height of the bridge is 41 m, after what time interval will the stone hit the water? Neglect air resistance.","choices":[{"label":"A","text":"2.9 s"},{"label":"B","text":"3.2 s"},{"label":"C","text":"2.6 s"},{"label":"D","text":"2.3 s"},{"label":"E","text":"3.6 s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q234","source":"Units_1-2","sourceNumber":"234","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"An astronaut stands by the rim of a crater on the Moon, where the freefall acceleration is 1.62 m/s 2, and there is no air resistance. The crater has vertical walls and a flat floor. To determine the depth of the crater, she drops a rock and measures that it takes 6.3 s for it to hit the bottom. What is the depth of the crater?","choices":[{"label":"A","text":"10 m"},{"label":"B","text":"14 m"},{"label":"C","text":"32 m"},{"label":"D","text":"26 m"},{"label":"E","text":"38 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q235","source":"Units_1-2","sourceNumber":"235","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"An astronaut stands by the rim of a crater on the Moon, where the freefall acceleration is 1.62 m/s 2 and there is no air resistance. The crater has vertical walls. To determine the depth of the crater, she drops a rock and measures the time it takes for it to hit the bottom. If the depth of the crater is 120 m, after what time interval will the rock hit the floor of the crater?","choices":[{"label":"A","text":"37.5 s"},{"label":"B","text":"3.04 s"},{"label":"C","text":"12.2 s"},{"label":"D","text":"29.3 s"},{"label":"E","text":"32.1 s"}],"images":[],"answer":"C"},{"id":"Units_1-2-q236","source":"Units_1-2","sourceNumber":"236","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"To determine the height of a flagpole, Abby throws a ball straight upward. She sees that the ball passes the top of the pole after 0.50 s and then passes the top of the pole again after a total elapsed time of 4.1 s. How high is the pole above the point where the ball was launched? Neglect air resistance.","choices":[{"label":"A","text":"16 m"},{"label":"B","text":"13 m"},{"label":"C","text":"26 m"},{"label":"D","text":"18 m"},{"label":"E","text":"10 m"}],"images":[],"answer":"E"},{"id":"Units_1-2-q237","source":"Units_1-2","sourceNumber":"237","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Abby throws a ball straight upward and times it. She sees that the ball passes the top of a flagpole after 0.50 s on the way up, and again on the way down after a total elapsed time of 4.1 s. What was the speed of the ball at launch? Neglect air resistance.","choices":[{"label":"A","text":"11 m/s"},{"label":"B","text":"45 m/s"},{"label":"C","text":"48 m/s"},{"label":"D","text":"34 m/s"},{"label":"E","text":"23 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q238","source":"Units_1-2","sourceNumber":"238","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Abby throws a ball straight upward. She sees that the ball passes the top of a flagpole after 0.50 s, and again after a total elapsed time of 4.1 s. What was the speed of the ball as it passed the top of the flagpole? Neglect air resistance.","choices":[{"label":"A","text":"6.4 m/s"},{"label":"B","text":"29 m/s"},{"label":"C","text":"33 m/s"},{"label":"D","text":"16 m/s"},{"label":"E","text":"18 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q242","source":"Units_1-2","sourceNumber":"242","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The graph shows the velocity of a point-like object as it travels along the x -axis. What is the magnitude of the average acceleration of the object between t = 1.0 s and t = 4.0 s?","choices":[{"label":"A","text":"3.0 m/s 2"},{"label":"B","text":"0.33 m/s 2"},{"label":"C","text":"1.7 m/s 2"},{"label":"D","text":"2.5 m/s 2"},{"label":"E","text":"2.0 m/s 2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"363","height":"295"}],"answer":"D"},{"id":"Units_1-2-q249","source":"Units_1-2","sourceNumber":"249","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The figure shows a graph of the velocity of an object as a function of time. What is the displacement of the object from 0 s to 6.0 s?","choices":[{"label":"A","text":"20 m"},{"label":"B","text":"80 m"},{"label":"C","text":"40 m"},{"label":"D","text":"100 m"},{"label":"E","text":"60 m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"342","height":"195"}],"answer":"B"},{"id":"Units_1-2-q250","source":"Units_1-2","sourceNumber":"250","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The figure shows a graph of the velocity of an object as a function of time. What is the displacement of the object from 0 s to 8.0 s?","choices":[{"label":"A","text":"40 m"},{"label":"B","text":"80 m"},{"label":"C","text":"100 m"},{"label":"D","text":"60 m"},{"label":"E","text":"20 m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"342","height":"195"}],"answer":"D"},{"id":"Units_1-2-q254","source":"Units_1-2","sourceNumber":"254","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"In deep space a rocket ship starts from rest. When it fires its engines, a constant force is exerted on it by the ejected fuel. The mass of the ship decreases significantly as it fires exhaust gas backwards. Which line on the graph above would best represent the velocity of the rocket ship as time goes on?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"327","height":"265"}],"answer":"D"},{"id":"Units_1-2-q256","source":"Units_1-2","sourceNumber":"256","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A ball is launched from the ground at an angle, and follows the trajectory shown above. The ball experiences negligible air resistance, and passes through positions P , Q , and R , in order. Which of the following correctly represents the force(s) exerted on the ball at the three labeled positions?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"437","height":"160"},{"src":"data:image/jpeg;base64,","alt":"","width":"174","height":"99"},{"src":"data:image/jpeg;base64,","alt":"","width":"172","height":"101"},{"src":"data:image/jpeg;base64,","alt":"","width":"172","height":"101"},{"src":"data:image/jpeg;base64,","alt":"","width":"172","height":"101"},{"src":"data:image/jpeg;base64,","alt":"","width":"172","height":"102"}],"answer":"C"},{"id":"Units_1-2-q257","source":"Units_1-2","sourceNumber":"257","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"As a person is sliding down a vertical rope, her grip steadily tightens. This action causes the upward frictional force that the rope exerts on her to increase also. What happens when the upward frictional force is exactly equal in magnitude the force exerted on her by Earth?","choices":[{"label":"A","text":"She will begin slowing down."},{"label":"B","text":"She will move at constant velocity."},{"label":"C","text":"She will accelerate downward."},{"label":"D","text":"She will stop."},{"label":"E","text":"She will start moving upward."}],"images":[],"answer":"B"},{"id":"Units_1-2-q258","source":"Units_1-2","sourceNumber":"258","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A child standing on a scale in an elevator notices that the scale reading is steady, but larger than its value when the elevator was standing at rest. Which velocity-versus-time graph shown above could best represent the child's motion?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"338","height":"274"}],"answer":"C"},{"id":"Units_1-2-q259","source":"Units_1-2","sourceNumber":"259","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A coffee filter is released from rest, and its velocity is plotted as a function of time above. The downward direction is considered positive. Which of the following correctly shows the forces exerted on the coffee filter at t = 3 s?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"497","height":"269"},{"src":"data:image/jpeg;base64,","alt":"","width":"99","height":"125"},{"src":"data:image/jpeg;base64,","alt":"","width":"85","height":"105"},{"src":"data:image/jpeg;base64,","alt":"","width":"97","height":"132"},{"src":"data:image/jpeg;base64,","alt":"","width":"39","height":"49"},{"src":"data:image/jpeg;base64,","alt":"","width":"96","height":"159"}],"answer":"C"},{"id":"Units_1-2-q260","source":"Units_1-2","sourceNumber":"260","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A large block of ice is on the floor of the refrigerator car of a train that is initially moving at a constant velocity to the right, as shown above. Assume that friction between the ice and the floor of the train car is negligible. Suddenly, the train slams on its brakes, and the car begins to slow down. Which of the diagrams below accurately represents the forces exerted on the block of ice while the car is slowing down?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"344","height":"130"},{"src":"data:image/jpeg;base64,","alt":"","width":"76","height":"119"},{"src":"data:image/jpeg;base64,","alt":"","width":"41","height":"122"},{"src":"data:image/jpeg;base64,","alt":"","width":"64","height":"118"},{"src":"data:image/jpeg;base64,","alt":"","width":"62","height":"118"},{"src":"data:image/jpeg;base64,","alt":"","width":"81","height":"119"}],"answer":"C"},{"id":"Units_1-2-q263","source":"Units_1-2","sourceNumber":"263","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Which of the force diagrams above would correspond with an object that is sliding to the right across a horizontal frictionless surface at constant velocity?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"},{"label":"E","text":"E"}],"images":[],"answer":"D"},{"id":"Units_1-2-q264","source":"Units_1-2","sourceNumber":"264","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Which of the force diagrams above would correspond to an object that is being pushed to the right across a rough horizontal surface at a constant, nonzero acceleration?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"},{"label":"E","text":"E"}],"images":[],"answer":"B"},{"id":"Units_1-2-q265","source":"Units_1-2","sourceNumber":"265","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"The force diagram below corresponds with an object that is doing which of the following?","choices":[{"label":"A","text":"speeding up"},{"label":"B","text":"slowing down"},{"label":"C","text":"moving at constant velocity"},{"label":"D","text":"A or B"},{"label":"E","text":"A, B, or C"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"134","height":"153"}],"answer":"D"},{"id":"Units_1-2-q266","source":"Units_1-2","sourceNumber":"266","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A hammer strikes a nail, driving it farther into a block of wood. Which of the following is the Newton's Third Law pair to the force that the hammer exerts on the nail?","choices":[{"label":"A","text":"The force that the nail exerts on the wood."},{"label":"B","text":"The force that the wood exerts on the hammer."},{"label":"C","text":"The force that the hammer exerts on the wood."},{"label":"D","text":"The force that the wood exerts on the nail."},{"label":"E","text":"The force that the nail exerts on the hammer."}],"images":[],"answer":"E"},{"id":"Units_1-2-q267","source":"Units_1-2","sourceNumber":"267","topic":"Unit 8: Fluids","difficulty":"Easy","question":"With no tether, an astronaut is in space, floating away from her spaceship toward certain death. If she is holding a large wrench, how can she save herself?","choices":[{"label":"A","text":"Hit herself with the wrench, toward the spaceship"},{"label":"B","text":"Hit herself with the wrench, away from the spaceship."},{"label":"C","text":"Throw the wrench away from the spaceship."},{"label":"D","text":"Throw the wrench toward the spaceship."},{"label":"E","text":"None of the above would work."}],"images":[],"answer":"C"},{"id":"Units_1-2-q268","source":"Units_1-2","sourceNumber":"268","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A driver is driving in a car, and the car stops suddenly. Why is it important that the driver is wearing a seatbelt?","choices":[{"label":"A","text":"To prevent the driver from feeling an unbalanced force."},{"label":"B","text":"To prevent the driver from continuing forward at constant velocity."},{"label":"C","text":"To prevent the driver from accelerating backward."},{"label":"D","text":"To prevent the driver from accelerating forward."},{"label":"E","text":"More than one of the above."}],"images":[],"answer":"B"},{"id":"Units_1-2-q269","source":"Units_1-2","sourceNumber":"269","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A tennis ball is thrown straight upward, reaches its peak, and comes back down. Which of the following sets of force diagrams correctly represents the force(s) exerted on the ball during its trip? Ignore air resistance.","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"117","height":"123"},{"src":"data:image/jpeg;base64,","alt":"","width":"116","height":"121"},{"src":"data:image/jpeg;base64,","alt":"","width":"118","height":"122"},{"src":"data:image/jpeg;base64,","alt":"","width":"117","height":"121"}],"answer":"A"},{"id":"Units_1-2-q272","source":"Units_1-2","sourceNumber":"272","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A book remains at rest on a table. Which of the following is the force paired, according to Newton's Third Law, to the force that Earth exerts on the book?","choices":[{"label":"A","text":"The force that the book exerts on the table."},{"label":"B","text":"The force that the table exerts on the book."},{"label":"C","text":"The force that the Earth exerts on the table."},{"label":"D","text":"The force that the table exerts on the Earth."},{"label":"E","text":"The force that the book exerts on Earth."}],"images":[],"answer":"E"},{"id":"Units_1-2-q273","source":"Units_1-2","sourceNumber":"273","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 5-kg cart is being pushed by a constant horizontal force on a frictionless surface. What would happen to the cart if the pushing force exerted on it were doubled in magnitude?","choices":[{"label":"A","text":"Its speed would double."},{"label":"B","text":"Its acceleration would double."},{"label":"C","text":"Its speed would be cut in half."},{"label":"D","text":"Its acceleration would be cut in half."}],"images":[],"answer":"B"},{"id":"Units_1-2-q274","source":"Units_1-2","sourceNumber":"274","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A student in a laboratory exerts a constant horizontal force to the right on a 1-kg cart by using a force probe, as shown above. The magnitude of the force that the probe exerts on the cart, and the horizontal velocity of the cart as functions of time are shown on the graphs displayed. Observe that the value of the force does not agree with the value of mass times acceleration. Which of the following could explain this observation? Select two possible answer choices.","choices":[{"label":"A","text":"The laboratory itself is accelerating to the right."},{"label":"B","text":"The force probe is unable to measure forces of greater magnitude than 2 N."},{"label":"C","text":"The mass of the cart is actually less than 1 kg."},{"label":"D","text":"Friction between the cart and the surface is not negligible."},{"label":"E","text":"The laboratory itself is accelerating to the left."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"576","height":"295"}],"answer":"D, A"},{"id":"Units_1-2-q275","source":"Units_1-2","sourceNumber":"275","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Two cars of equal mass have a head-on collision during a safety test. Car A has an initial velocity of 40 m/s, and car B has an initial velocity of -20 m/s. Which of the following choices describes the forces exerted by the cars on one another during the collision?","choices":[{"label":"A","text":"B exerts twice as much force on A as A exerts on B."},{"label":"B","text":"A exerts a force on B, but B does not exert force on A."},{"label":"C","text":"A exerts twice as much force on B as B exerts on A."},{"label":"D","text":"A exerts equal magnitude force on B as B exerts on A."}],"images":[],"answer":"D"},{"id":"Units_1-2-q276","source":"Units_1-2","sourceNumber":"276","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"In a collision between a huge SUV and a small hybrid car, the SUV exerts a larger force on the hybrid than the hybrid exerts on the SUV.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"},{"label":"C","text":"It depends on the relative masses of the two vehicles."},{"label":"D","text":"It depends on whether the collision is a head-on collision or a rear-end collision."},{"label":"E","text":"It depends on the speeds of the two vehicles before the collision."}],"images":[],"answer":"B"},{"id":"Units_1-2-q277","source":"Units_1-2","sourceNumber":"277","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A box is placed on a table, which rests on the floor. The box exerts a force on the table; the Newton's Third Law force pair to this force is the force that the table exerts on the floor.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_1-2-q278","source":"Units_1-2","sourceNumber":"278","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"In order to get a stationary object to start moving on a frictionless horizontal surface, you must exert a greater magnitude horizontal force on the object than the horizontal force that it exerts on you.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_1-2-q279","source":"Units_1-2","sourceNumber":"279","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A girl attaches a rock to a string, which she then swings counter-clockwise in a horizontal circle. The string breaks when the rock is at point P in the figure, which shows a bird's-eye view (as seen from above). Which path (A-E) will the rock follow?","choices":[{"label":"A","text":"Path A"},{"label":"B","text":"Path B"},{"label":"C","text":"Path C"},{"label":"D","text":"Path D"},{"label":"E","text":"Path E"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"215","height":"215"}],"answer":"B"},{"id":"Units_1-2-q280","source":"Units_1-2","sourceNumber":"280","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"A satellite is in orbit around Earth. Which one feels the greater-magnitude force during this interaction?","choices":[{"label":"A","text":"The satellite feels a greater force, because Earth is so much more massive."},{"label":"B","text":"It depends on the distance of the satellite from Earth."},{"label":"C","text":"Earth feels a greater force, because the satellite has so little mass."},{"label":"D","text":"Earth and the satellite feel exactly the same magnitude force."}],"images":[],"answer":"D"},{"id":"Units_1-2-q281","source":"Units_1-2","sourceNumber":"281","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"You pull on a crate with a rope. If the crate moves, the force that the rope exerts on the crate must have been larger than force that the crate exerts on the rope, but if the crate does not move, both of these forces must have been equal.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_1-2-q282","source":"Units_1-2","sourceNumber":"282","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"In order to lift a bucket of concrete, you must exert more force on the bucket than the bucket exerts on you.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_1-2-q283","source":"Units_1-2","sourceNumber":"283","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"If the rockets of a spaceship in deep space (far from all other objects, and in the absence of air resistance) suddenly lose power and turn off, the spaceship will gradually slow to a stop.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_1-2-q284","source":"Units_1-2","sourceNumber":"284","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"You are in a train traveling on a horizontal track and notice that a piece of luggage on the floor starts to accelerate directly toward the front of the train. From this observation, you can conclude that this train is","choices":[{"label":"A","text":"changing direction."},{"label":"B","text":"slowing down."},{"label":"C","text":"slowing down and changing direction."},{"label":"D","text":"speeding up."},{"label":"E","text":"speeding up and changing direction."}],"images":[],"answer":"B"},{"id":"Units_1-2-q285","source":"Units_1-2","sourceNumber":"285","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"While flying horizontally in an airplane, you notice that a string dangling from the overhead luggage compartment hangs at rest at 15° away from the vertical toward the front of the plane. Using this observation, you can conclude that the airplane is","choices":[{"label":"A","text":"accelerating backward."},{"label":"B","text":"moving backward."},{"label":"C","text":"not accelerating because the string is at rest."},{"label":"D","text":"accelerating forward."},{"label":"E","text":"moving forward."}],"images":[],"answer":"A"},{"id":"Units_1-2-q286","source":"Units_1-2","sourceNumber":"286","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"An elevator car suspended by a vertical cable is moving downward but slowing down. The tension in the cable must be","choices":[{"label":"A","text":"greater than the force that Earth exerts on the elevator car."},{"label":"B","text":"equal to the force that Earth exerts on the elevator car."},{"label":"C","text":"less than the force that Earth exerts on the elevator car."}],"images":[],"answer":"A"},{"id":"Units_1-2-q287","source":"Units_1-2","sourceNumber":"287","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A crate is sliding down an inclined ramp at a constant speed of 0.55 m/s. The vector sum of all the forces exerted on this crate must be directed","choices":[{"label":"A","text":"vertically downward."},{"label":"B","text":"down the ramp."},{"label":"C","text":"perpendicular to the ramp."},{"label":"D","text":"up the ramp."},{"label":"E","text":"None of the above choices is correct."}],"images":[],"answer":"E"},{"id":"Units_1-2-q288","source":"Units_1-2","sourceNumber":"288","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A bucket is being lowered by a very light rope with a constant downward velocity. The tension in the rope must be","choices":[{"label":"A","text":"less than the force that Earth exerts on the bucket."},{"label":"B","text":"greater than the force that Earth exerts on the bucket."},{"label":"C","text":"equal to the force that Earth exerts on the bucket."}],"images":[],"answer":"C"},{"id":"Units_1-2-q289","source":"Units_1-2","sourceNumber":"289","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"Bill and his daughter Susan are both standing on identical skateboards (with frictionless axles), initially at rest. Bill's mass is three times that of Susan. Bill pushes horizontally on Susan's back, causing Susan to accelerate away from Bill. Just after Bill stops pushing,","choices":[{"label":"A","text":"Susan and Bill are moving away from each other, with equal speeds."},{"label":"B","text":"Susan and Bill are moving away from each other, and Susan's speed is one-third that of Bill."},{"label":"C","text":"Susan and Bill are moving away from each other, and Susan's speed is three times that of Bill."},{"label":"D","text":"Susan is moving away from Bill, and Bill is stationary."}],"images":[],"answer":"C"},{"id":"Units_1-2-q290","source":"Units_1-2","sourceNumber":"290","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"You push on box G that is next to box H, causing both boxes to slide along the floor, as shown in the figure. The force paired by Newton's Third Law to the force to your push is","choices":[{"label":"A","text":"the force that box H exerts on you."},{"label":"B","text":"the force that box G exerts on you."},{"label":"C","text":"the acceleration of box G."},{"label":"D","text":"the force that box G exerts on box H."},{"label":"E","text":"the force that box H exerts on box G."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"210","height":"87"}],"answer":"B"},{"id":"Units_1-2-q291","source":"Units_1-2","sourceNumber":"291","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"An object is moving with constant nonzero velocity. Which of the following statements about it must be true?","choices":[{"label":"A","text":"Its acceleration is in the same direction as it velocity."},{"label":"B","text":"A constant force is being exerted on it in the direction opposite of motion."},{"label":"C","text":"A constant force is being exerted on it in the direction of motion."},{"label":"D","text":"The net force on the object is zero."},{"label":"E","text":"A constant force is being exerted on it perpendicular to the direction of motion."}],"images":[],"answer":"D"},{"id":"Units_1-2-q292","source":"Units_1-2","sourceNumber":"292","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A truck is using a hook to tow a car whose mass is one quarter that of the truck. If the force exerted by the truck on the car is 6000 N, then the force exerted by the car on the truck is","choices":[{"label":"A","text":"6000 N"},{"label":"B","text":"1500 N"},{"label":"C","text":"24,000 N"},{"label":"D","text":"12,000 N"},{"label":"E","text":"We need to know if the car is accelerating to answer this question."}],"images":[],"answer":"A"},{"id":"Units_1-2-q293","source":"Units_1-2","sourceNumber":"293","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"The figure shows two boxes, with m 1 > m 2 , that are on a level frictionless surface. We can exert a horizontal force , always of magnitude 20.0 N, either toward the right on m 1 or toward the left on m 2 . The magnitude of the forces that the boxes exert on each other is","choices":[{"label":"A","text":"larger if the force is exerted toward the right."},{"label":"B","text":"zero newtons in either case."},{"label":"C","text":"the same in either case."},{"label":"D","text":"larger if the force is exerted toward the left."}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(F)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"","width":"403","height":"271"},{"src":"data:image/jpeg;base64,","alt":"right ray(F)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(F)","width":null,"height":null}],"answer":"D"},{"id":"Units_1-2-q294","source":"Units_1-2","sourceNumber":"294","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A horse pulls a cart by exerting a force . As a result, the cart accelerates with constant acceleration. The magnitude of the force that the cart exerts on the horse","choices":[{"label":"A","text":"is zero newtons."},{"label":"B","text":"is equal to the magnitude of ."},{"label":"C","text":"is greater than the magnitude of ."},{"label":"D","text":"is less than the magnitude of ."},{"label":"E","text":"cannot be determined without knowing the mass of the horse."}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(F)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(F)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(F)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(F)","width":null,"height":null}],"answer":"B"},{"id":"Units_1-2-q295","source":"Units_1-2","sourceNumber":"295","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"An object of mass m is in freefall close to the surface of Earth. The magnitude of the force that the object exerts on Earth is","choices":[{"label":"A","text":"less than mg."},{"label":"B","text":"greater than mg."},{"label":"C","text":"equal to mg."},{"label":"D","text":"zero."},{"label":"E","text":"cannot be determined without knowing the relative masses of the object and Earth."}],"images":[],"answer":"C"},{"id":"Units_1-2-q296","source":"Units_1-2","sourceNumber":"296","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"An object of mass m rests on a flat table. Earth exerts a force on this object of magnitude mg . What is the Newton's Third Law force pair to this force?","choices":[{"label":"A","text":"The table pushing down on the floor with force mg ."},{"label":"B","text":"The table pushing up on the object with force mg ."},{"label":"C","text":"The object pulling upward on Earth with force mg ."},{"label":"D","text":"The object pushing down on the table with force mg ."},{"label":"E","text":"The table pulling upward on Earth with force mg ."}],"images":[],"answer":"C"},{"id":"Units_1-2-q297","source":"Units_1-2","sourceNumber":"297","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"You are standing in a moving bus, facing forward, when you suddenly slide forward as the bus slows down to a stop. What force caused you to slide forward?","choices":[{"label":"A","text":"the force exerted by the floor of the bus, perpendicular to the floor."},{"label":"B","text":"the friction force exerted by the floor of the bus, in direction parallel to the floor."},{"label":"C","text":"the gravitational force exerted by Earth."},{"label":"D","text":"There is no force causing you to slide forward."}],"images":[],"answer":"D"},{"id":"Units_1-2-q298","source":"Units_1-2","sourceNumber":"298","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A person is using a rope to lower a 0.51-kg bucket into a well with a constant speed of 2.0 m/s. What is the magnitude of the force exerted by the rope on the bucket?","choices":[{"label":"A","text":"10 N"},{"label":"B","text":"2.0 N"},{"label":"C","text":"0.00 N"},{"label":"D","text":"5.0 N"},{"label":"E","text":"49 N"}],"images":[],"answer":"D"},{"id":"Units_1-2-q299","source":"Units_1-2","sourceNumber":"299","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A person stands on a bathroom scale, which has a reading of 700 N when the person remains at rest. If the person stands on the scale in an elevator that is moving vertically at a constant speed of 9.8 m/s, what would the scale read?","choices":[{"label":"A","text":"700 N"},{"label":"B","text":"less than 700 N"},{"label":"C","text":"more than 700 N"},{"label":"D","text":"It could be more or less than 700 N, depending on whether the elevator is going up or down."}],"images":[],"answer":"A"},{"id":"Units_1-2-q300","source":"Units_1-2","sourceNumber":"300","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A person stands on a bathroom scale, which has a reading of 700 N when the person remains at rest. If the person stands on the scale in an elevator that is moving upward and slowing down, what would the scale read?","choices":[{"label":"A","text":"more than 700 N"},{"label":"B","text":"700 N"},{"label":"C","text":"less than 700 N"},{"label":"D","text":"It could be more or less than 700 N, depending on whether the magnitude of the acceleration is greater than or less than 9.8 m/s 2 ."}],"images":[],"answer":"C"},{"id":"Units_1-2-q301","source":"Units_1-2","sourceNumber":"301","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 75-kg box rests on a perfectly smooth horizontal surface. The minimum force need to start the box moving is","choices":[{"label":"A","text":"7.5 N"},{"label":"B","text":"75 N"},{"label":"C","text":"750 N"},{"label":"D","text":"any nonzero horizontal force will start the box moving."}],"images":[],"answer":"D"},{"id":"Units_1-2-q302","source":"Units_1-2","sourceNumber":"302","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"When a 45-kg person steps on a scale in an elevator, the scale reads a steady 480 N. Which of the following statements must be true? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The elevator is moving downward at a constant rate."},{"label":"B","text":"The elevator is accelerating downward at a constant rate."},{"label":"C","text":"The elevator is accelerating upward at a constant rate."},{"label":"D","text":"The elevator is moving upward at a constant rate."},{"label":"E","text":"From the given information, we cannot tell if the elevator is moving up or down."}],"images":[],"answer":"C, E"},{"id":"Units_1-2-q303","source":"Units_1-2","sourceNumber":"303","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"When a 45-kg person steps on a scale in an elevator, the scale reads a steady 410 N. Which of the following statements must be true? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The elevator is accelerating upward at a constant rate."},{"label":"B","text":"The elevator is moving downward at a constant rate."},{"label":"C","text":"The elevator is moving upward at a constant rate."},{"label":"D","text":"The elevator is accelerating downward at a constant rate."},{"label":"E","text":"From the given information, we cannot tell if the elevator is moving up or down."}],"images":[],"answer":"D, E"},{"id":"Units_1-2-q304","source":"Units_1-2","sourceNumber":"304","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"In the following figure, a 10-lb object (that is, an object on which Earth exerts gravitational force of 10 lb down) is suspended from two spring scales, each of which has negligible mass. Which one of the following statements about the readings in the scales is true?","choices":[{"label":"A","text":"Each scale will read 5 lb."},{"label":"B","text":"The lower scale will read zero, the top scale will read 10 lb."},{"label":"C","text":"The top scale will read zero, the lower scale will read 10 lb."},{"label":"D","text":"Each scale will show a reading between one and 10 lb, such that the sum of the two is 10 lb. However, exact readings cannot be determined without more information."},{"label":"E","text":"None of these is true."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"122","height":"345"}],"answer":"E"},{"id":"Units_1-2-q305","source":"Units_1-2","sourceNumber":"305","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"As shown in the figure, a woman is straining to lift a large crate, but without success. We denote the forces on the crate as follows: P is the magnitude of the upward force being exerted on the crate by the person, C is the magnitude of the vertical contact force on the crate by the floor, and W is the force that Earth exerts on the crate. How are the magnitudes of these forces related while the person is trying unsuccessfully to lift the crate?","choices":[{"label":"A","text":"P = C"},{"label":"B","text":"P + C > W"},{"label":"C","text":"P + C < W"},{"label":"D","text":"P + C = W"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"237","height":"166"}],"answer":"D"},{"id":"Units_1-2-q306","source":"Units_1-2","sourceNumber":"306","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A cart is initially at rest on a frictionless surface, and has exerted on it a net force of constant magnitude F . Measurements are taken of its acceleration a . Then the process is repeated with a force of different magnitude. The data are summarized in the graph above. What is the best estimate for the mass of the cart?","choices":[{"label":"A","text":"0.5 kg"},{"label":"B","text":"0.7 kg"},{"label":"C","text":"0.2 kg"},{"label":"D","text":"1.0 kg"},{"label":"E","text":"1.5 kg"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"323","height":"222"}],"answer":"E"},{"id":"Units_1-2-q307","source":"Units_1-2","sourceNumber":"307","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"What is the mass of an object that has a 685 N gravitational force exerted on it near Earth's surface, where g = 9.80 m/s 2 ?","choices":[{"label":"A","text":"71.3 kg"},{"label":"B","text":"69.9 kg"},{"label":"C","text":"72.7 kg"},{"label":"D","text":"68.5 kg"}],"images":[],"answer":"B"},{"id":"Units_1-2-q308","source":"Units_1-2","sourceNumber":"308","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A net force of 125 N is exerted on a certain object. As a result, the object accelerates with an acceleration of 24.0 m/s 2 . The mass of the object is","choices":[{"label":"A","text":"2880 kg."},{"label":"B","text":"144 kg."},{"label":"C","text":"5.21 kg."},{"label":"D","text":"3000 kg."},{"label":"E","text":"0.200 kg."}],"images":[],"answer":"C"},{"id":"Units_1-2-q309","source":"Units_1-2","sourceNumber":"309","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A net force accelerates a 4.5-kg tool at 40 m/s 2 . What acceleration would that same net force cause if it were exerted on an 18-kg tool?","choices":[{"label":"A","text":"180 m/s 2"},{"label":"B","text":"9.8 m/s 2"},{"label":"C","text":"10 m/s 2"},{"label":"D","text":"160 m/s 2"},{"label":"E","text":"32 m/s 2"}],"images":[],"answer":"D"},{"id":"Units_1-2-q310","source":"Units_1-2","sourceNumber":"310","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A block is on a frictionless table, on Earth. The block accelerates at 3.0 m/s 2 when a 20 N horizontal force is exerted on it. The block and table are set up on the Moon where the freefall acceleration is 1.62 m/s 2 . The gravitational force exerted on the block by the Moon is closest to","choices":[{"label":"A","text":"11 N"},{"label":"B","text":"8.1 N"},{"label":"C","text":"5.5 N"},{"label":"D","text":"9.5 N"},{"label":"E","text":"6.8 N"}],"images":[],"answer":"A"},{"id":"Units_1-2-q311","source":"Units_1-2","sourceNumber":"311","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A block is on a frictionless table, on Earth. The block accelerates at 5.3 m/s 2 when a 10 N horizontal force is exerted on it. The block and table are set up on the Moon where the freefall acceleration is 1.62 m/s 2 . A horizontal force of 5 N is now exerted on the block when it is on the Moon. The acceleration caused by this force is closest to","choices":[{"label":"A","text":"2.9 m/s 2"},{"label":"B","text":"2.7 m/s 2"},{"label":"C","text":"2.4 m/s 2"},{"label":"D","text":"3.2 m/s 2"},{"label":"E","text":"3.4 m/s 2"}],"images":[],"answer":"C"},{"id":"Units_1-2-q313","source":"Units_1-2","sourceNumber":"313","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 450-kg sports car accelerates from rest to 100 km/h in 4.80 s. What is the magnitude of the net force exerted on a 68.0-kg passenger during the acceleration?","choices":[{"label":"A","text":"342 N"},{"label":"B","text":"311 N"},{"label":"C","text":"82.0 N"},{"label":"D","text":"394 N"}],"images":[],"answer":"D"},{"id":"Units_1-2-q314","source":"Units_1-2","sourceNumber":"314","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A tow truck can accelerate at 3.0 m/s 2 on its own. What will be its acceleration when the truck is using a horizontal chain of negligible mass to tow a bus of twice the mass of the tow truck?","choices":[{"label":"A","text":"2.5 m/s 2"},{"label":"B","text":"2.0 m/s 2"},{"label":"C","text":"1.0 m/s 2"},{"label":"D","text":"1.5 m/s 2"}],"images":[],"answer":"B"},{"id":"Units_1-2-q315","source":"Units_1-2","sourceNumber":"315","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"An object experiences a gravitational force of 75 N on Earth. The object is then pulled on a horizontal surface by a horizontal pull of 50 N to the right. The friction force on this object is 30 N horizontally to the left. What is the acceleration of the object?","choices":[{"label":"A","text":"0.27 m/s 2 to the right"},{"label":"B","text":"2.6 m/s 2 to the right"},{"label":"C","text":"11 m/s 2 to the right"},{"label":"D","text":"1.1 m/s 2 to the right"}],"images":[],"answer":"B"},{"id":"Units_1-2-q316","source":"Units_1-2","sourceNumber":"316","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 1200-kg car is pulling a 500-kg trailer along level ground. Friction of the road on the trailer is negligible. The car accelerates at 1.3 m/s 2 . What is the force exerted by the car on the trailer?","choices":[{"label":"A","text":"650 N forward"},{"label":"B","text":"700 N backward"},{"label":"C","text":"550 N forward"},{"label":"D","text":"600 N backward"},{"label":"E","text":"750 N forward"}],"images":[],"answer":"A"},{"id":"Units_1-2-q321","source":"Units_1-2","sourceNumber":"321","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 45.0-kg person steps on a scale in an elevator. The scale reads 460 N. What is the magnitude of the acceleration of the elevator?","choices":[{"label":"A","text":"46.9 m/s 2"},{"label":"B","text":"0.206 m/s 2"},{"label":"C","text":"0.422 m/s 2"},{"label":"D","text":"4.91 m/s 2"},{"label":"E","text":"9.81 m/s 2"}],"images":[],"answer":"B"},{"id":"Units_1-2-q322","source":"Units_1-2","sourceNumber":"322","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"The figure shows an acceleration-versus-force graph for a 125-g object. What should be the value of the first tick-mark on the vertical scale, as indicated by the arrow in the figure?","choices":[{"label":"A","text":"0.00400"},{"label":"B","text":"8"},{"label":"C","text":"0.00800"},{"label":"D","text":"4"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"467","height":"331"}],"answer":"D"},{"id":"Units_1-2-q323","source":"Units_1-2","sourceNumber":"323","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"The figure shows an object's acceleration-versus-force graph. What is the mass of this object?","choices":[{"label":"A","text":"400,000 g"},{"label":"B","text":"630 g"},{"label":"C","text":"2.5 g"},{"label":"D","text":"1.6 g"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"354","height":"281"}],"answer":"C"},{"id":"Units_1-2-q324","source":"Units_1-2","sourceNumber":"324","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"The following figure shows an acceleration-versus-net-force graph for three objects pulled by wires. If the mass of object 2 is 36 kg, what are the masses of objects 1 and 3?","choices":[{"label":"A","text":"12 kg and 90 kg"},{"label":"B","text":"90 kg and 12 kg"},{"label":"C","text":"72 kg and 18 kg"},{"label":"D","text":"12 kg and 7 kg"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"377","height":"332"}],"answer":"A"},{"id":"Units_1-2-q327","source":"Units_1-2","sourceNumber":"327","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"The magnitude of a vector can never be less than the magnitude of any of its components.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"A"},{"id":"Units_1-2-q328","source":"Units_1-2","sourceNumber":"328","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"The magnitude of a vector can only be zero if all of its components are zero.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"A"},{"id":"Units_1-2-q329","source":"Units_1-2","sourceNumber":"329","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The eastward component of vector is equal to the magnitude of the westward component of vector and their northward components are equal. Which one of the following statements must be correct for these two vectors?","choices":[{"label":"A","text":"Vector is parallel to vector ."},{"label":"B","text":"Vector is antiparallel (in the opposite direction) to vector ."},{"label":"C","text":"The magnitude of vector must be equal to the magnitude of vector ."},{"label":"D","text":"Vector must be perpendicular to vector ."},{"label":"E","text":"The angle between vector and vector must be 90°."}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null}],"answer":"C"},{"id":"Units_1-2-q330","source":"Units_1-2","sourceNumber":"330","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"The direction of vector is along the + x -axis and vector is along the + y -axis. Which one of the following statements is correct with respect to these vectors?","choices":[{"label":"A","text":"The x component of vector is equal to the y component of vector ."},{"label":"B","text":"The y component of vector is equal to the y component of vector ."},{"label":"C","text":"The y component of vector is equal to the x component of vector ."},{"label":"D","text":"The x component of vector is equal to the x component of vector ."}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null}],"answer":"A"},{"id":"Units_1-2-q331","source":"Units_1-2","sourceNumber":"331","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A block hangs from two ropes at unequal angles, as shown above. The block remains at rest. Which of the following makes correct comparisons of the horizontal and vertical components of the tension in each rope? Horizontal Component Vertical Component","choices":[{"label":"A","text":"equal in both ropes greater in rope A"},{"label":"B","text":"greater in rope A greater in rope A"},{"label":"C","text":"equal in both ropes equal in both ropes"},{"label":"D","text":"greater in rope B greater in rope A"},{"label":"E","text":"greater in rope B equal in both ropes"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"346","height":"90"}],"answer":"A"},{"id":"Units_1-2-q332","source":"Units_1-2","sourceNumber":"332","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"In the scenario shown above, neither of the blocks moves. F 1 has equal magnitude to F 2 . What can be said about the static friction force exerted on each of the blocks?","choices":[{"label":"A","text":"A comparison cannot be made without knowing the material the blocks are made of and the material that the surface is made of."},{"label":"B","text":"The block on the left has a stronger friction force exerted on it."},{"label":"C","text":"The blocks have equal friction forces exerted on them."},{"label":"D","text":"A comparison cannot be made without knowing the material that the blocks are made of."},{"label":"E","text":"The block on the right has a stronger friction force exerted on it."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"472","height":"99"}],"answer":"C"},{"id":"Units_1-2-q333","source":"Units_1-2","sourceNumber":"333","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A box sits on an inclined plane without sliding. As the angle of the plane (measured from the horizontal) increases, the normal force","choices":[{"label":"A","text":"does not change"},{"label":"B","text":"increases linearly"},{"label":"C","text":"decreases linearly"},{"label":"D","text":"increases nonlinearly"},{"label":"E","text":"decreases nonlinearly"}],"images":[],"answer":"E"},{"id":"Units_1-2-q334","source":"Units_1-2","sourceNumber":"334","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"An ice cube slides down a frictionless ramp. How does N , the magnitude of the normal force exerted by the ramp on the ice cube, compare to F E on C , the magnitude of the gravitational force exerted by the Earth on the ice cube?","choices":[{"label":"A","text":"N = F E on C"},{"label":"B","text":"N = 0 < F E on C"},{"label":"C","text":"N > F E on C"},{"label":"D","text":"0 < N < F E on C"},{"label":"E","text":"Not enough information"}],"images":[],"answer":"B"},{"id":"Units_1-2-q335","source":"Units_1-2","sourceNumber":"335","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"In the situations diagrammed above, two blocks of masses m 1 and m 2 , with m 2 > m 1 , are connected by a massless string over a light, frictionless pulley. In scenario I a hand is holding block 1 so that it stays at rest, in scenario II a hand is holding block 2 so that it stays at rest, and in scenario III the blocks are released from rest. What comparison can you make about the scale readings in each of the three scenarios?","choices":[{"label":"A","text":"The scale readings in scenarios I and II are equal, and each is greater than scenario III."},{"label":"B","text":"The scale reading in scenario I is the greatest, followed by scenario II, and then scenario III."},{"label":"C","text":"The scale readings in scenarios I and II are equal, and each is less than scenario III."},{"label":"D","text":"The scale reading in scenario I is the greatest, followed by scenario III, and then scenario II."},{"label":"E","text":"The scale readings in all three are equal."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"478","height":"242"}],"answer":"D"},{"id":"Units_1-2-q336","source":"Units_1-2","sourceNumber":"336","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Two scenarios are diagrammed above. In scenario 1, two blocks of equal mass m 1 are connected by a massless string over frictionless pulleys and released from rest. The tension in the string is T 1 . In scenario 2, a block of mass m 1 is connected to a block of mass m 2 by a massless string over a frictionless pulley. The coefficient of static friction μ s between block 2 and the tabletop is sufficiently high that both blocks remain at rest when released. The tension in the string is T 2 . Which of the following correctly compares T 1 and T 2 ?","choices":[{"label":"A","text":"T 1 > T 2"},{"label":"B","text":"T 1 < T 2"},{"label":"C","text":"T 1 = T 2"},{"label":"D","text":"T 1 may be greater than, less than, or equal to T 2 depending on the values of m 2 and μ s ."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"586","height":"201"}],"answer":"A"},{"id":"Units_1-2-q337","source":"Units_1-2","sourceNumber":"337","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Three balls are projected with the same speed from the edge of a cliff. Ball 1 is fired horizontally and hits the ground after time t 1 , ball 2 is fired at an angle of 30˚ above the horizontal and hits the ground after time t 2 , and ball 3 is fired at an angle of 60˚ above the horizontal and hits the ground after time t 3 . Which of the following correctly ranks the time that it takes the balls to reach the ground, from least to greatest?","choices":[{"label":"A","text":"t 1 < t 2 = t 3"},{"label":"B","text":"t 1 < t 3 < t 2"},{"label":"C","text":"t 1 < t 2 < t 3"},{"label":"D","text":"t 3 < t 2 < t 1"},{"label":"E","text":"t 1 = t 2 = t 3"}],"images":[],"answer":"C"},{"id":"Units_1-2-q339","source":"Units_1-2","sourceNumber":"339","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"Which statement is true about the impact speed of each cannonball?","choices":[{"label":"A","text":"The impact speed is greater for the cannonball that hits ship B than the one that hits ship A"},{"label":"B","text":"The impact speeds of both cannonballs will be equal."},{"label":"C","text":"The impact speed is greater for the cannonball that hits ship A than the one that hits ship B"},{"label":"D","text":"More information is needed."}],"images":[],"answer":"B"},{"id":"Units_1-2-q340","source":"Units_1-2","sourceNumber":"340","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A projectile is fired at speed v on a flat surface at an angle 30 above the horizontal. Air resistance is negligible. Which of the following pairs of velocity-time graphs represents the horizontal and vertical components of velocity, v x and v y , of the projectile, as functions of time?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"472","height":"237"},{"src":"data:image/jpeg;base64,","alt":"","width":"470","height":"237"},{"src":"data:image/jpeg;base64,","alt":"","width":"478","height":"233"},{"src":"data:image/jpeg;base64,","alt":"","width":"480","height":"235"}],"answer":"C"},{"id":"Units_1-2-q344","source":"Units_1-2","sourceNumber":"344","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"A boulder rolls off a very high cliff and experiences no significant air resistance. While it is falling, its trajectory is never truly vertical.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"A"},{"id":"Units_1-2-q345","source":"Units_1-2","sourceNumber":"345","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"For projectile motion with no air resistance, the horizontal component of a projectile's velocity","choices":[{"label":"A","text":"remains a non-zero constant, generally not zero."},{"label":"B","text":"continuously decreases."},{"label":"C","text":"continuously increases."},{"label":"D","text":"remains zero"},{"label":"E","text":"first decreases and then increases."}],"images":[],"answer":"A"},{"id":"Units_1-2-q346","source":"Units_1-2","sourceNumber":"346","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"For projectile motion with no air resistance, the horizontal component of a projectile's acceleration","choices":[{"label":"A","text":"continuously decreases."},{"label":"B","text":"remains a non-zero constant."},{"label":"C","text":"is always zero."},{"label":"D","text":"first decreases and then increases."},{"label":"E","text":"continuously increases."}],"images":[],"answer":"C"},{"id":"Units_1-2-q347","source":"Units_1-2","sourceNumber":"347","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"For projectile motion with no air resistance, the vertical component of a projectile's acceleration","choices":[{"label":"A","text":"remains a non-zero constant."},{"label":"B","text":"continuously decreases."},{"label":"C","text":"continuously increases."},{"label":"D","text":"first decreases and then increases."},{"label":"E","text":"is always zero."}],"images":[],"answer":"A"},{"id":"Units_1-2-q348","source":"Units_1-2","sourceNumber":"348","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Which of the following statements is/are true about an object in two-dimensional projectile motion with no air resistance? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The horizontal acceleration is always zero and the vertical acceleration is always a non-zero constant downward."},{"label":"B","text":"The acceleration of the object is + g when the object is rising and - g when it is falling."},{"label":"C","text":"The acceleration of the object is zero at its highest point."},{"label":"D","text":"The speed of the object is constant but its velocity is not constant."},{"label":"E","text":"The speed of the object is zero at its highest point."}],"images":[],"answer":"A"},{"id":"Units_1-2-q349","source":"Units_1-2","sourceNumber":"349","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"A ball is thrown horizontally from the top of a tower at the same instant that a stone is dropped vertically. Which object is traveling faster when it hits the level ground below if neither of them experiences any air resistance?","choices":[{"label":"A","text":"the ball"},{"label":"B","text":"It is impossible to tell because we do not know their masses."},{"label":"C","text":"the stone"},{"label":"D","text":"Both are traveling at the same speed."}],"images":[],"answer":"A"},{"id":"Units_1-2-q350","source":"Units_1-2","sourceNumber":"350","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"In an air-free chamber, a pebble is thrown horizontally, and at the same instant a second pebble is dropped from the same height. Compare the times of fall of the two pebbles.","choices":[{"label":"A","text":"The thrown pebble hits first."},{"label":"B","text":"They hit at the same time."},{"label":"C","text":"The dropped pebble hits first."},{"label":"D","text":"We cannot tell without knowing which pebble is heavier."}],"images":[],"answer":"B"},{"id":"Units_1-2-q351","source":"Units_1-2","sourceNumber":"351","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"A pilot drops a package from a plane flying horizontally at a constant speed. Air resistance is absent. When the package hits the ground the horizontal location of the plane will","choices":[{"label":"A","text":"be directly over the package."},{"label":"B","text":"be in front of the package."},{"label":"C","text":"depend on the speed of the plane when the package was released."},{"label":"D","text":"be behind the package."}],"images":[],"answer":"A"},{"id":"Units_1-2-q352","source":"Units_1-2","sourceNumber":"352","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"James and John dive from an overhang into the lake below. James simply drops straight down from the edge. John takes a running start and jumps with an initial horizontal velocity of 12 m/s. If there is no air resistance, when they reach the lake below","choices":[{"label":"A","text":"the speed of James is larger than that of John."},{"label":"B","text":"they will both have the same speed."},{"label":"C","text":"the speed of James must be 9.8 m/s larger than that of John."},{"label":"D","text":"the speed of John must be 12 m/s larger than that of James."},{"label":"E","text":"the speed of John is larger than that of James."}],"images":[],"answer":"E"},{"id":"Units_1-2-q353","source":"Units_1-2","sourceNumber":"353","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"James and John dive from an overhang into the lake below. James simply drops from rest. John takes a running start with an initial horizontal velocity of 12 m/s. Compare the time interval for each to reach the lake below if there is no air resistance.","choices":[{"label":"A","text":"James and John will reach the surface of the lake at the same time."},{"label":"B","text":"James reaches the surface of the lake first."},{"label":"C","text":"John reaches the surface of the lake first."},{"label":"D","text":"Cannot be determined without knowing the masses of both James and John."},{"label":"E","text":"Cannot be determined without knowing the weights of both James and John."}],"images":[],"answer":"A"},{"id":"Units_1-2-q354","source":"Units_1-2","sourceNumber":"354","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A player kicks a soccer ball in a high arc toward the opponent's goal. At the highest point in its trajectory","choices":[{"label":"A","text":"the ball's velocity points downward."},{"label":"B","text":"the ball's acceleration is zero but its velocity is not zero."},{"label":"C","text":"both the velocity and the acceleration of the soccer ball are zero."},{"label":"D","text":"the ball's acceleration points upward."},{"label":"E","text":"neither the ball's velocity nor its acceleration is zero."}],"images":[],"answer":"E"},{"id":"Units_1-2-q355","source":"Units_1-2","sourceNumber":"355","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Mary and Debra stand on a snow-covered roof. They both throw snowballs with the same initial speed, but in different directions. Mary throws her snowball downward, at 30° below the horizontal; Debra throws her snowball upward, at 30° above the horizontal. Which of the following statements are true about the moment just before the snowballs reach the ground below? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Both snowballs hit the ground at the same time."},{"label":"B","text":"Debra's snowball will have a greater speed than Mary's snowball."},{"label":"C","text":"Mary's snowball will have a greater speed than Debra's snowball."},{"label":"D","text":"Both snowballs will hit the ground with the same speed."},{"label":"E","text":"Mary's snowball reaches the ground before Debra's snowball."}],"images":[],"answer":"E, D"},{"id":"Units_1-2-q356","source":"Units_1-2","sourceNumber":"356","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Mary and Debra stand on a snow-covered roof. They both throw snowballs with the same initial speed, but in different directions. Mary throws her snowball downward, at 30° below the horizontal; Debra throws her snowball upward, at 30° above the horizontal. Which of the following statements are true about the flight of the snowballs to the ground below? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Debra's snowball will be in flight longer than Mary's snowball."},{"label":"B","text":"Debra's snowball has precisely the same acceleration as Mary's snowball."},{"label":"C","text":"Both snowballs will take the same time interval to reach the ground."},{"label":"D","text":"Mary's snowball has a greater downward acceleration than Debra's snowball."},{"label":"E","text":"Mary's snowball will be in flight longer than Debra's snowball."}],"images":[],"answer":"A, B"},{"id":"Units_1-2-q357","source":"Units_1-2","sourceNumber":"357","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"A rock is thrown from the edge at the top of a tall cliff at some angle above the horizontal. It reaches its highest point and starts falling down. Which of the following statements about the rock's motion are true just before it hits the ground? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Its velocity is vertical."},{"label":"B","text":"Its vertical velocity component is the same as it was just as it was launched."},{"label":"C","text":"Its horizontal velocity component is the same as it was just as it was launched."},{"label":"D","text":"Its speed is the same as it was just as it was launched."},{"label":"E","text":"Its horizontal velocity component is zero."}],"images":[],"answer":"C"},{"id":"Units_1-2-q358","source":"Units_1-2","sourceNumber":"358","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Inside a train a ball of mass m is hanging by a light wire from the ceiling, at rest relative to the train. The wire makes an angle θ with the horizontal ceiling, as shown in the figure. Which one of the following conditions must be true about the tension T in the wire?","choices":[{"label":"A","text":"T tan θ = mg"},{"label":"B","text":"T = ma"},{"label":"C","text":"T = mg"},{"label":"D","text":"T cos θ = mg"},{"label":"E","text":"T sin θ = mg"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"88","height":"112"}],"answer":"E"},{"id":"Units_1-2-q359","source":"Units_1-2","sourceNumber":"359","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Two blocks, A and B, are being pulled to the right along a horizontal surface by a horizontal 100-N pull, as shown in the figure. Both of them are moving together at a constant velocity of 2.0 m/s to the right, and both have the same mass. Which of the figures below shows a correct free-body diagram of the horizontal forces exerted on the upper block, A?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"233","height":"99"},{"src":"data:image/jpeg;base64,","alt":"","width":"110","height":"35"},{"src":"data:image/jpeg;base64,","alt":"","width":"120","height":"33"},{"src":"data:image/jpeg;base64,","alt":"","width":"146","height":"36"},{"src":"data:image/jpeg;base64,","alt":"","width":"204","height":"31"},{"src":"data:image/jpeg;base64,","alt":"","width":"254","height":"34"}],"answer":"C"},{"id":"Units_1-2-q361","source":"Units_1-2","sourceNumber":"361","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A force of magnitude P is exerted on a box of mass m, as shown in the figure. The force is directed at an angle θ below the horizontal, and the box remains a rest. The box rests on a horizontal surface, with which the box has a nonzero coefficient of friction. The normal force on the box due to the floor is equal to","choices":[{"label":"A","text":"mg"},{"label":"B","text":"mg + P cos θ."},{"label":"C","text":"mg + P sin θ ."},{"label":"D","text":"mg - P sin θ."},{"label":"E","text":"mg + P"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"272","height":"120"}],"answer":"E"},{"id":"Units_1-2-q362","source":"Units_1-2","sourceNumber":"362","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A push of magnitude P acts on a box of mass m as shown in the figure. The push is directed at an angle θ below the horizontal, and the box remains a rest. The box rests on a horizontal surface, with which the box has some nonzero coefficient of friction. The friction force on the box due to the floor is equal to","choices":[{"label":"A","text":"0"},{"label":"B","text":"P + mg"},{"label":"C","text":"P cos θ"},{"label":"D","text":"P sin θ"},{"label":"E","text":"P cos θ + mg"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"272","height":"120"}],"answer":"C"},{"id":"Units_1-2-q363","source":"Units_1-2","sourceNumber":"363","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"In the situation shown above, Earth exerts gravitational force 1.0 N on each block, which remains stationary. What does the spring scale read? The pulleys are massless and have frictionless axles and the strings and scale are also massless.","choices":[{"label":"A","text":"precisely 1.0 N"},{"label":"B","text":"more than 19.6 N"},{"label":"C","text":"0.50 N"},{"label":"D","text":"precisely 2.0 N."},{"label":"E","text":"0.00 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"338","height":"157"}],"answer":"A"},{"id":"Units_1-2-q364","source":"Units_1-2","sourceNumber":"364","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Two boxes P and Q on a perfectly smooth horizontal surface are connected by a light horizontal cord. The mass of P is greater than that of Q. A horizontal force is exerted on the box Q, as shown in the figure, accelerating the bodies to the right. The magnitude of the force exerted by the connecting cord on body P is","choices":[{"label":"A","text":"less than F but not zero."},{"label":"B","text":"zero."},{"label":"C","text":"greater than F ."},{"label":"D","text":"equal to F ."}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(F)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"","width":"320","height":"67"}],"answer":"A"},{"id":"Units_1-2-q365","source":"Units_1-2","sourceNumber":"365","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Earth exerts gravitational forces as shown in the figure on three boxes, which are pulled along a horizontal frictionless floor by a constant horizontal force P . The boxes are connected by light horizontal strings, having tensions T 1 and T 2 . Which of the following statements about the tensions is correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"T 1 > T 2"},{"label":"B","text":"T 1 + T 2 = P"},{"label":"C","text":"T 1 = P"},{"label":"D","text":"T 2 = P"},{"label":"E","text":"T 2 > T 1"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"379","height":"65"}],"answer":"A"},{"id":"Units_1-2-q366","source":"Units_1-2","sourceNumber":"366","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Two boxes are connected to each other by a string as shown in the figure. The box which has a gravitational force of 10 N exerted on it slides without friction on the horizontal table surface. The pulley is massless and frictionless and the string has negligible mass. What is true about the tension T in the string? (More than one answer might be true.)","choices":[{"label":"A","text":"T = 10 N"},{"label":"B","text":"T < 30 N"},{"label":"C","text":"T > 30 N"},{"label":"D","text":"T = 30 N"},{"label":"E","text":"T = 20 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"272","height":"228"}],"answer":"B"},{"id":"Units_1-2-q367","source":"Units_1-2","sourceNumber":"367","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Two objects of unequal masses, M and m (with M > m ), are connected by a very light cord passing over a frictionless pulley of negligible mass. When released, the system accelerates, and friction is negligible. Which one of the following free-body diagrams most realistically represents the forces acting on the two objects in the moving system?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"103","height":"308"},{"src":"data:image/jpeg;base64,","alt":"","width":"102","height":"232"},{"src":"data:image/jpeg;base64,","alt":"","width":"113","height":"243"},{"src":"data:image/jpeg;base64,","alt":"","width":"102","height":"197"},{"src":"data:image/jpeg;base64,","alt":"","width":"100","height":"234"}],"answer":"C"},{"id":"Units_1-2-q368","source":"Units_1-2","sourceNumber":"368","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Two objects have masses m and 5 m . They both are placed side by side on a frictionless inclined ramp and allowed to slide down from rest without any air resistance. Which one of the following statements about these objects is correct?","choices":[{"label":"A","text":"It takes the heavier object 5 times longer to reach the bottom of the ramp than the lighter."},{"label":"B","text":"It takes the lighter object 10 times longer to reach the bottom of the ramp than the heavier."},{"label":"C","text":"It takes the heavier object 10 times longer to reach the bottom of the ramp than the lighter."},{"label":"D","text":"It takes the lighter object 5 times longer to reach the bottom of the ramp than the heavier."},{"label":"E","text":"The two objects reach the bottom of the ramp at precisely the same time."}],"images":[],"answer":"E"},{"id":"Units_1-2-q369","source":"Units_1-2","sourceNumber":"369","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A block of mass m remains at rest on a rough inclined ramp that makes an angle θ with the horizontal. What must be true about force of static friction f on the block?","choices":[{"label":"A","text":"f = mg sin θ"},{"label":"B","text":"f > mg"},{"label":"C","text":"f > mg cos θ"},{"label":"D","text":"f > mg sin θ"},{"label":"E","text":"f = mg cos θ"}],"images":[],"answer":"A"},{"id":"Units_1-2-q370","source":"Units_1-2","sourceNumber":"370","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A block of mass m sits at rest on a rough inclined ramp that makes an angle θ with the horizontal. What must be true about normal force N on the block due to the ramp?","choices":[{"label":"A","text":"N = mg cos θ"},{"label":"B","text":"N > mg cos θ"},{"label":"C","text":"N > mg sin θ"},{"label":"D","text":"N = mg sin θ"},{"label":"E","text":"N > mg"}],"images":[],"answer":"A"},{"id":"Units_1-2-q372","source":"Units_1-2","sourceNumber":"372","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"The x component of vector is 8.7 units, and its y component is -6.5 units. The magnitude of is closest to","choices":[{"label":"A","text":"8.9 units"},{"label":"B","text":"12 units"},{"label":"C","text":"9.9 units"},{"label":"D","text":"7.9 units"},{"label":"E","text":"11 units"}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null}],"answer":"E"},{"id":"Units_1-2-q373","source":"Units_1-2","sourceNumber":"373","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Without using a starting block, a runner accelerates forward on a horizontal track at the start of a race, with an acceleration of magnitude 4.9 m/s 2 . Which of the following can be determined about the coefficient of static friction μ s for the surface of the runner's shoes and the surface of the track?","choices":[{"label":"A","text":"μ s ≥ 0.50"},{"label":"B","text":"μ s > 0.50"},{"label":"C","text":"μ s = 0.50"},{"label":"D","text":"μ s < 0.50"},{"label":"E","text":"μ s ≤ 0.50"}],"images":[],"answer":"E"},{"id":"Units_1-2-q374","source":"Units_1-2","sourceNumber":"374","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A block of mass 2.0 kg sits on a horizontal tabletop. A horizontal force of 12 N and a vertical force of 15 N are exerted on the block, as shown above. The block does not move. If the coefficient of static friction between the block and the table is 0.50, the frictional force exerted on the block has a magnitude of","choices":[{"label":"A","text":"12 N"},{"label":"B","text":"17.5 N"},{"label":"C","text":"28 N"},{"label":"D","text":"7.5 N"},{"label":"E","text":"10 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"128","height":"137"}],"answer":"A"},{"id":"Units_1-2-q375","source":"Units_1-2","sourceNumber":"375","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A horizontal force F pushes a block of mass m against a vertical wall. The coefficient of static friction between the block and the wall is µ s . What minimum value of F is necessary to keep the block from slipping down the wall?","choices":[{"label":"A","text":"mg / µ s"},{"label":"B","text":"µ s mg"},{"label":"C","text":"Mg"},{"label":"D","text":"mg (1 + µ s )"},{"label":"E","text":"mg (1 - µ s )"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"154","height":"107"}],"answer":"C"},{"id":"Units_1-2-q376","source":"Units_1-2","sourceNumber":"376","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 4-kg block is pulled straight toward the right along a horizontal surface (Friction cannot be ignored). When the pulling force is 8 N, the block accelerates to the right at 1 m/s 2 . If the pulling force is doubled to 16 N, the acceleration of the block will be","choices":[{"label":"A","text":"1 m/s 2"},{"label":"B","text":"0.5 m/s 2"},{"label":"C","text":"4 m/s 2"},{"label":"D","text":"3 m/s 2"},{"label":"E","text":"2 m/s 2"}],"images":[],"answer":"D"},{"id":"Units_1-2-q377","source":"Units_1-2","sourceNumber":"377","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A metal truck accelerates forward with a wooden crate against its vertical front panel. If the coefficient of static friction for wood and metal is 0.800, what is the minimum acceleration that the truck can have without the crate slipping down the front?","choices":[{"label":"A","text":"7.84 m/s 2"},{"label":"B","text":"9.80 m/s 2"},{"label":"C","text":"12.3 m/s 2"},{"label":"D","text":"2.00 m/s 2"},{"label":"E","text":"The mass of the crate must be known."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"263","height":"165"}],"answer":"C"},{"id":"Units_1-2-q379","source":"Units_1-2","sourceNumber":"379","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"From the given information, what can be determined about the coefficient of static friction between the two blocks?","choices":[{"label":"A","text":"µ s = 2/3"},{"label":"B","text":"The coefficient of static friction between the two objects is less than the coefficient of kinetic friction."},{"label":"C","text":"µ s ≤ 2/3"},{"label":"D","text":"No information can be determined."},{"label":"E","text":"µ s ≥ 2/3"}],"images":[],"answer":"C"},{"id":"Units_1-2-q380","source":"Units_1-2","sourceNumber":"380","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A block of mass M has a force of magnitude F exerted on it at angle as shown above. The coefficient of static friction between the block and the floor is µ s . If F is increased until the block slides on the surface, what is the frictional force exerted on the block at the moment before it starts to slip?","choices":[{"label":"A","text":"µ s ( Mg - F sin )"},{"label":"B","text":"µ s Mg"},{"label":"C","text":"µ s ( Mg - F cos )"},{"label":"D","text":"µ s ( Mg + F sin )"},{"label":"E","text":"µ s ( Mg + F cos )"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"298","height":"134"}],"answer":"D"},{"id":"Units_1-2-q381","source":"Units_1-2","sourceNumber":"381","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A block of mass m remains at rest on a ramp with an angle of elevation . The coefficient of static friction between the block and the ramp is s . In the picture shown above, a force F is exerted on the block, pointing down the surface of the ramp. The magnitude of this force is steadily increased until the block starts to slide down the ramp. What is the magnitude of F at the point where the block just starts to slip?","choices":[{"label":"A","text":"s mg cos - mg sin"},{"label":"B","text":"mg sin + s mg cos"},{"label":"C","text":"mg sin"},{"label":"D","text":"s mg cos"},{"label":"E","text":"mg sin - s mg cos"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"296","height":"168"}],"answer":"E"},{"id":"Units_1-2-q382","source":"Units_1-2","sourceNumber":"382","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A block of mass m remains at rest on a ramp with an angle of elevation . The coefficient of static friction between the block and the ramp is s . In the picture shown above, a force F is exerted on the block, pointing up the surface of the ramp. The magnitude of this force is steadily increased until the block starts to slide up the ramp. What is the magnitude of F at the point where the block just starts to slip?","choices":[{"label":"A","text":"mg sin - s mg cos"},{"label":"B","text":"s mg cos"},{"label":"C","text":"s mg cos - mg sin"},{"label":"D","text":"mg sin"},{"label":"E","text":"mg sin + s mg cos"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"321","height":"148"}],"answer":"D"},{"id":"Units_1-2-q383","source":"Units_1-2","sourceNumber":"383","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Blocks A and B are attached by light string over a light, frictionless pulley, as shown. The blocks have masses m A and m B , respectively. When released, the blocks remain at rest. Which of the following expressions represents the coefficient of static friction for Block B and the tabletop?","choices":[{"label":"A","text":"m B /( m A + m B )"},{"label":"B","text":"m A / m B"},{"label":"C","text":"m A /( m A + m B )"},{"label":"D","text":"m B / m A"},{"label":"E","text":"Not enough information."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"254","height":"156"}],"answer":"E"},{"id":"Units_1-2-q384","source":"Units_1-2","sourceNumber":"384","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A set of fuzzy dice hang from the ceiling of a taxi, as shown above. If the taxi maintains a constant horizontal acceleration of 6.0 m/s 2 , what will be the angle at which the dice hang, relative to the vertical axis?","choices":[{"label":"A","text":"81"},{"label":"B","text":"31"},{"label":"C","text":"59"},{"label":"D","text":"The mass of the dice must be known."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"404","height":"160"}],"answer":"B"},{"id":"Units_1-2-q385","source":"Units_1-2","sourceNumber":"385","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Two divers run horizontally at the same time from diving platforms of equal height, but Diver 2 runs at twice the speed of Diver 1. If Diver 1 lands a horizontal distance D from the base of the platform, what will be the horizontal distance between Diver 2's landing point and the base of the platform?","choices":[{"label":"A","text":"D"},{"label":"B","text":"D"},{"label":"C","text":"2 D"},{"label":"D","text":"D"},{"label":"E","text":"2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"(square root of (2)/2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_1-2-q386","source":"Units_1-2","sourceNumber":"386","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Two divers run horizontally from diving platforms at the same speed, and at the same time. However, Diver 2's platform is twice as high above the water, and directly above Diver 1's platform. If Diver 1 lands a horizontal distance D from the base of the platform, what will be the horizontal distance between Diver 2's landing point and the platform?","choices":[{"label":"A","text":"2D"},{"label":"B","text":"2 D"},{"label":"C","text":"D"},{"label":"D","text":"D"},{"label":"E","text":"D"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"(square root of (2)/2)","width":null,"height":null}],"answer":"A"},{"id":"Units_1-2-q387","source":"Units_1-2","sourceNumber":"387","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"When a rock rolled down a mountainside at 7.0 m/s, the horizontal component of its velocity vector was 1.8 m/s. What was the angle of the mountain surface with the horizontal?","choices":[{"label":"A","text":"75°"},{"label":"B","text":"33°"},{"label":"C","text":"15°"},{"label":"D","text":"57°"}],"images":[],"answer":"A"},{"id":"Units_1-2-q388","source":"Units_1-2","sourceNumber":"388","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Earth exerts a 200-N gravitational force on a sled, which slides down a frictionless hillside that slopes at 37° below the horizontal. What is the magnitude of the force that the surface of the hill exerts on the sled?","choices":[{"label":"A","text":"160 N"},{"label":"B","text":"200 N"},{"label":"C","text":"150 N"},{"label":"D","text":"120 N"},{"label":"E","text":"0 N"}],"images":[],"answer":"A"},{"id":"Units_1-2-q389","source":"Units_1-2","sourceNumber":"389","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Earth exerts a 200-N gravitational force on a sled, which slides down a frictionless hillside that slopes at 37° below the horizontal. What is the magnitude of the force that the hill exerts on the sled parallel to the surface of the hill?","choices":[{"label":"A","text":"160 N"},{"label":"B","text":"0 N"},{"label":"C","text":"200 N"},{"label":"D","text":"120 N"},{"label":"E","text":"150 N"}],"images":[],"answer":"B"},{"id":"Units_1-2-q390","source":"Units_1-2","sourceNumber":"390","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"When Jeff ran up a hill at 7.0 m/s, the horizontal component of his velocity vector was 5.1 m/s. What was the vertical component of Jeff's velocity?","choices":[{"label":"A","text":"3.4 m/s"},{"label":"B","text":"4.3 m/s"},{"label":"C","text":"3.8 m/s"},{"label":"D","text":"4.8 m/s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q391","source":"Units_1-2","sourceNumber":"391","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The x component of vector is 5.3 units, and its y component is -2.3 units. The angle that vector makes, measured counterclockwise from the + x- axis is closest to","choices":[{"label":"A","text":"23°"},{"label":"B","text":"340°"},{"label":"C","text":"160°"},{"label":"D","text":"250°"},{"label":"E","text":"110°"}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null}],"answer":"B"},{"id":"Units_1-2-q393","source":"Units_1-2","sourceNumber":"393","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A displacement vector is 34.0 m in length and is directed 60.0° east of north. Selected from the choices in the table below, what are the components of this vector? Northward Eastward choice component component 1 29.4 m 17.0 m 2 18.2 m 28.1 m 3 22.4 m 11.5 m 4 17.0 m 29.4 m 5 25.2 m 18.2 m","choices":[{"label":"A","text":"choice 1"},{"label":"B","text":"choice 2"},{"label":"C","text":"choice 3"},{"label":"D","text":"choice 4"},{"label":"E","text":"choice 5"}],"images":[],"answer":"D"},{"id":"Units_1-2-q394","source":"Units_1-2","sourceNumber":"394","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A player throws a football 50.0 m at 61.0° north of west. What is the westward component of the displacement of the football?","choices":[{"label":"A","text":"74.0 m"},{"label":"B","text":"0.00 m"},{"label":"C","text":"55.0 m"},{"label":"D","text":"64.7 m"},{"label":"E","text":"24.2 m"}],"images":[],"answer":"E"},{"id":"Units_1-2-q397","source":"Units_1-2","sourceNumber":"397","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A boy jumps with a velocity of magnitude 20.0 m/s at an angle of 25.0° above the horizontal. What is the horizontal component of the boy's velocity?","choices":[{"label":"A","text":"18.1 m/s"},{"label":"B","text":"8.45 m/s"},{"label":"C","text":"9.33 m/s"},{"label":"D","text":"12.6 m/s"},{"label":"E","text":"15.6 m/s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q398","source":"Units_1-2","sourceNumber":"398","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The magnitude of is 5.5 m, and this vector lies in the second quadrant and makes an angle of 34° with the + y -axis. The components of are closest to:","choices":[{"label":"A","text":"A x = -4.6 m, A y = -3.1 m."},{"label":"B","text":"A x = -3.1 m, A y = 4.6 m."},{"label":"C","text":"A x = -4.6 m, A y = 3.1 m."},{"label":"D","text":"A x = 3.1 m, A y = -4.6 m."},{"label":"E","text":"A x = 4.6 m, A y = -3.1 m."}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(A)","width":null,"height":null}],"answer":"B"},{"id":"Units_1-2-q399","source":"Units_1-2","sourceNumber":"399","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The components of vectors and are given as follows: B x = -9.2 C x = -4.5 B y = -6.1 C y = 4.3 The angle (less than 180°) between vectors and is closest to","choices":[{"label":"A","text":"77°"},{"label":"B","text":"170°"},{"label":"C","text":"10°"},{"label":"D","text":"84°"},{"label":"E","text":"103°"}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(C)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(B)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"right ray(C)","width":null,"height":null}],"answer":"A"},{"id":"Units_1-2-q401","source":"Units_1-2","sourceNumber":"401","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball is thrown with an initial velocity of 20 m/s at an angle of 60° above the horizontal. If we can neglect air resistance, what is the horizontal component of its instantaneous velocity at the top of its trajectory?","choices":[{"label":"A","text":"20 m/s"},{"label":"B","text":"17 m/s"},{"label":"C","text":"10 m/s"},{"label":"D","text":"zero"}],"images":[],"answer":"C"},{"id":"Units_1-2-q402","source":"Units_1-2","sourceNumber":"402","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball is thrown at an original speed of 8.0 m/s at an angle of 35° above the horizontal. If there is no air resistance, what is the speed of the ball when it returns to the same horizontal level?","choices":[{"label":"A","text":"9.8 m/s"},{"label":"B","text":"16 m/s"},{"label":"C","text":"8.0 m/s"},{"label":"D","text":"4.0 m/s"}],"images":[],"answer":"C"},{"id":"Units_1-2-q403","source":"Units_1-2","sourceNumber":"403","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A stone is thrown horizontally with an initial speed of 10 m/s from the edge of a cliff. A stopwatch is used to measure the time interval for the stone to travel from the top of the cliff to the level of the bottom to be 4.3 s. What is the height of the cliff if air resistance is negligible?","choices":[{"label":"A","text":"77 m"},{"label":"B","text":"22 m"},{"label":"C","text":"91 m"},{"label":"D","text":"43 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q404","source":"Units_1-2","sourceNumber":"404","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A girl throws a rock horizontally, with a velocity of 10 m/s, from a bridge. It falls 20 m vertically to the water below. How far does the rock travel horizontally before striking the water, if there is negligible air resistance?","choices":[{"label":"A","text":"14 m"},{"label":"B","text":"24 m"},{"label":"C","text":"20 m"},{"label":"D","text":"16 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q405","source":"Units_1-2","sourceNumber":"405","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball thrown horizontally, from a point 24 m above the ground, strikes the ground after traveling horizontally a distance of 18 m. With what speed was it thrown, if there is negligible air resistance?","choices":[{"label":"A","text":"7.4 m/s"},{"label":"B","text":"6.1 m/s"},{"label":"C","text":"8.9 m/s"},{"label":"D","text":"8.1 m/s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q406","source":"Units_1-2","sourceNumber":"406","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"The freefall acceleration on the Moon is only one-sixth of that on Earth, and the Moon has no atmosphere. If you hit a baseball on the Moon with the same speed and angle as on Earth, how far the ball would travel on the Moon compared to on Earth? Neglect air resistance on Earth.","choices":[{"label":"A","text":"times as far as on Earth"},{"label":"B","text":"1/6 as far as on Earth"},{"label":"C","text":"36 times as far as on Earth"},{"label":"D","text":"6 times as far as on Earth"},{"label":"E","text":"the same distance as on Earth"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (6)","width":null,"height":null}],"answer":"D"},{"id":"Units_1-2-q407","source":"Units_1-2","sourceNumber":"407","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A boy throws a rock with an initial velocity of 3.13 m/s at 30.0° above the horizontal. In what time interval will the rock reach the maximum height in its trajectory if air resistance is negligibly small and g = 9.80 m/s 2 ?","choices":[{"label":"A","text":"0.160 s"},{"label":"B","text":"0.313 s"},{"label":"C","text":"0.282 s"},{"label":"D","text":"0.441 s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q408","source":"Units_1-2","sourceNumber":"408","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A cat leaps to try to catch a bird. If the cat's jump was at 60° above the horizontal and its initial speed was 2.74 m/s, what is the maximum height of its trajectory, neglecting air resistance?","choices":[{"label":"A","text":"0.29 m"},{"label":"B","text":"0.58 m"},{"label":"C","text":"0.19 m"},{"label":"D","text":"10.96 m"}],"images":[],"answer":"A"},{"id":"Units_1-2-q409","source":"Units_1-2","sourceNumber":"409","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A fisherman casts his bait toward the river at an angle of 25° above the horizontal. As the line pays out, he notices that the bait and hook reach a maximum height of 2.9 m. What was the initial velocity with which he launched the bait? Assume that the line exerts no appreciable drag force on the bait and hook and that air resistance is negligible.","choices":[{"label":"A","text":"7.6 m/s"},{"label":"B","text":"7.9 m/s"},{"label":"C","text":"6.3 m/s"},{"label":"D","text":"18 m/s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q410","source":"Units_1-2","sourceNumber":"410","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A football kicker is attempting a field goal from 44 m away. The ball is kicked and passes just below the crossbar of the goalpost after a time interval of 2.9 s. If there is no air resistance and the angle of the kick was 45.0°, what was the initial speed of the ball?","choices":[{"label":"A","text":"2.20 m/s"},{"label":"B","text":"39.2 m/s"},{"label":"C","text":"19.7 m/s"},{"label":"D","text":"21.5 m/s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q411","source":"Units_1-2","sourceNumber":"411","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"You throw a rock horizontally off a cliff with a speed of 20 m/s. There is no significant air resistance. After 2.0 s, the magnitude of the velocity of the rock is closest to","choices":[{"label":"A","text":"28 m/s"},{"label":"B","text":"40 m/s"},{"label":"C","text":"20 m/s"},{"label":"D","text":"37 m/s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q421","source":"Units_1-2","sourceNumber":"421","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A hockey puck slides off the edge of a platform with an initial velocity of 20 m/s horizontally. The height of the platform above the ground is 2.0 m. What is the magnitude of the velocity of the puck just before it strikes the ground? You can neglect air resistance.","choices":[{"label":"A","text":"22 m/s"},{"label":"B","text":"24 m/s"},{"label":"C","text":"25 m/s"},{"label":"D","text":"21 m/s"},{"label":"E","text":"6.3 m/s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q422","source":"Units_1-2","sourceNumber":"422","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A hockey puck slides off the edge of a platform with an initial velocity of 28.0 m/s horizontally. The height of the platform above the ground is 2.00 m. What is the speed of the puck just before it hits the ground? Air resistance is negligible.","choices":[{"label":"A","text":"48.2 m/s"},{"label":"B","text":"26.3 m/s"},{"label":"C","text":"6.26 m/s"},{"label":"D","text":"28.0 m/s"},{"label":"E","text":"28.7 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q423","source":"Units_1-2","sourceNumber":"423","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A ball rolls over the edge of a platform, moving horizontally. The height of the platform is 1.6 m and the horizontal range of the ball from the base of the platform is 20 m. What is the horizontal velocity component of the ball just before it touches the ground? Neglect air resistance.","choices":[{"label":"A","text":"70 m/s"},{"label":"B","text":"9.8 m/s"},{"label":"C","text":"4.9 m/s"},{"label":"D","text":"20 m/s"},{"label":"E","text":"35 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q425","source":"Units_1-2","sourceNumber":"425","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A wind farm generator uses a two-bladed turbine or propeller mounted on a pylon at a height of 20 m, as shown in the figure. The width of the pylon is very narrow, and the length of each propeller blade is 12 m. A tip of the propeller breaks off just when the propeller is vertical. The fragment flies off horizontally, falls with negligible air resistance, and strikes the ground at point P . Just before the fragment broke off, the propeller was turning uniformly, taking 1.2 s for each rotation. How far is point P from the base of the pylon?","choices":[{"label":"A","text":"130 m"},{"label":"B","text":"160 m"},{"label":"C","text":"150 m"},{"label":"D","text":"140 m"},{"label":"E","text":"120 m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"240","height":"170"}],"answer":"B"},{"id":"Units_1-2-q426","source":"Units_1-2","sourceNumber":"426","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A child is trying to throw a ball over a fence. She gives the ball an initial speed of 8.0 m/s at an angle of 40° above the horizontal. The ball leaves her hand 1.0 m above the ground and the fence is 2.0 m high. The ball just clears the fence while still traveling upward and experiences no significant air resistance. How far is the child from the fence?","choices":[{"label":"A","text":"3.8 m"},{"label":"B","text":"2.7 m"},{"label":"C","text":"1.6 m"},{"label":"D","text":"7.5 m"},{"label":"E","text":"0.73 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q427","source":"Units_1-2","sourceNumber":"427","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"An athlete competing in the long jump leaves the ground with a speed of 9.14 m/s at an angle of 35° above the horizontal. For what time interval is the athlete in flight, assuming no significant air resistance?","choices":[{"label":"A","text":"0.88 s"},{"label":"B","text":"2.5 s"},{"label":"C","text":"0.54 s"},{"label":"D","text":"0.50 s"},{"label":"E","text":"1.1 s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q428","source":"Units_1-2","sourceNumber":"428","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"An athlete participates in an interplanetary discus throw competition during an Olympiad that takes place on a planet where the freefall acceleration is 9.7 m/s 2 . He throws the discus with an initial velocity of 20 m/s at an angle of 60° from the vertical. Neglecting air resistance and the height of the discus at the point of release, what is the range of the discus?","choices":[{"label":"A","text":"40 m"},{"label":"B","text":"21 m"},{"label":"C","text":"36 m"},{"label":"D","text":"60 m"},{"label":"E","text":"32 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q430","source":"Units_1-2","sourceNumber":"430","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A projectile is fired at an angle above the horizontal at a location where g = 9.8 m/s 2 . The initial x and y components of its velocity are 86.6 m/s and 50 m/s, respectively. At what angle was the projectile fired above the horizontal?","choices":[{"label":"A","text":"30°"},{"label":"B","text":"60°"},{"label":"C","text":"45°"},{"label":"D","text":"90°"},{"label":"E","text":"75°"}],"images":[],"answer":"A"},{"id":"Units_1-2-q431","source":"Units_1-2","sourceNumber":"431","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A projectile is fired from ground level at an angle above the horizontal on a planet where g = 10.0 m/s 2 and air resistance is negligible. The initial x and y components of its velocity are 86.6 m/s and 50.0 m/s, respectively. After what time interval does the projectile hit the level ground?","choices":[{"label":"A","text":"20.0 seconds"},{"label":"B","text":"5.00 seconds"},{"label":"C","text":"10.0 seconds"},{"label":"D","text":"15.0 seconds"}],"images":[],"answer":"C"},{"id":"Units_1-2-q434","source":"Units_1-2","sourceNumber":"434","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A projectile is fired from the edge of a cliff as shown in the figure. The initial velocity components are 940 m/s (horizontal) and 96 m/s (vertical). The projectile reaches maximum height at point P and then falls and strikes the ground at point Q. How high is point P above point Q, assuming no air resistance?","choices":[{"label":"A","text":"490 m"},{"label":"B","text":"470 m"},{"label":"C","text":"45,000 m"},{"label":"D","text":"90,000 m"},{"label":"E","text":"940 m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"326","height":"125"}],"answer":"A"},{"id":"Units_1-2-q435","source":"Units_1-2","sourceNumber":"435","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A projectile is launched with an initial velocity of 80 m/s at 30° above the horizontal. Neglect air resistance. What is horizontal component of the projectile's acceleration?","choices":[{"label":"A","text":"80 m/s 2"},{"label":"B","text":"9.8 m/s 2"},{"label":"C","text":"40 m/s 2"},{"label":"D","text":"0 m/s 2"},{"label":"E","text":"69 m/s 2"}],"images":[],"answer":"A"},{"id":"Units_1-2-q436","source":"Units_1-2","sourceNumber":"436","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A boy kicks a football with an initial velocity of 20 m/s at an angle of 25° above the horizontal. If we neglect air resistance, the magnitude of the acceleration of the ball while it is in flight is","choices":[{"label":"A","text":"25 m/s 2"},{"label":"B","text":"9.8 m/s 2"},{"label":"C","text":"18 m/s 2"},{"label":"D","text":"0 m/s 2"},{"label":"E","text":"8.5 m/s 2"}],"images":[],"answer":"B"},{"id":"Units_1-2-q437","source":"Units_1-2","sourceNumber":"437","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A projectile is fired from ground level on a horizontal surface. If the initial speed of the projectile is now doubled, and we neglect air resistance,","choices":[{"label":"A","text":"its range will decrease by a factor of four."},{"label":"B","text":"its range will quadruple."},{"label":"C","text":"its range will double."},{"label":"D","text":"its range will be increased by ."},{"label":"E","text":"its range will be decreased by a factor of two."}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"B"},{"id":"Units_1-2-q438","source":"Units_1-2","sourceNumber":"438","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A hobbyist launches a projectile from ground level on a horizontal surface. It reaches a maximum height of 72.3 m and lands 111 m from the launch point, with no appreciable air resistance. What was the angle of launch if g = 9.80 m/s 2 ?","choices":[{"label":"A","text":"44.8°"},{"label":"B","text":"67.4°"},{"label":"C","text":"22.6°"},{"label":"D","text":"69.0°"}],"images":[],"answer":"D"},{"id":"Units_1-2-q439","source":"Units_1-2","sourceNumber":"439","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 1000-kg barge is being towed by means of two horizontal cables. One cable is pulling with a force of 80.0 N in a direction 30.0° west of north. In what direction should the second cable pull so that the barge will accelerate due northward, if the force exerted by the cable is 120 N? Assume that the water exerts no appreciable frictional drag on the barge.","choices":[{"label":"A","text":"39.0° east of north"},{"label":"B","text":"54.7° east of north"},{"label":"C","text":"19.5° east of north"},{"label":"D","text":"21.1° east of north"},{"label":"E","text":"47.5° east of north"}],"images":[],"answer":"C"},{"id":"Units_1-2-q440","source":"Units_1-2","sourceNumber":"440","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Two forces act on a 55-kg object. One force has magnitude 65 N directed 59° clockwise from the positive x -axis, and the other has a magnitude 35 N at 32° clockwise from the positive y -axis. What is the magnitude of this object's acceleration?","choices":[{"label":"A","text":"1.1 m/s 2"},{"label":"B","text":"1.7 m/s 2"},{"label":"C","text":"1.5 m/s 2"},{"label":"D","text":"1.3 m/s 2"}],"images":[],"answer":"D"},{"id":"Units_1-2-q441","source":"Units_1-2","sourceNumber":"441","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A tightrope walker walks across a 30-m long wire tied between two poles. When he is halfway across and pauses for dramatic effect, the center of the wire is displaced vertically downward by 1.0 m, relative to a straight horizontal line between the two ends of the wire. If the tension in both halves of the wire at this point is 6294 N, what is the mass of the tightrope walker? Neglect the mass of the wire.","choices":[{"label":"A","text":"74 kg"},{"label":"B","text":"86 kg"},{"label":"C","text":"91 kg"},{"label":"D","text":"43 kg"}],"images":[],"answer":"B"},{"id":"Units_1-2-q442","source":"Units_1-2","sourceNumber":"442","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"An object has three forces exerted on it and as a result moves with a constant velocity. One force is 60.0 N along the + x -axis, and the second is 75.0 N along the + y -axis. What is the magnitude of the third force?","choices":[{"label":"A","text":"15.0 N"},{"label":"B","text":"135 N"},{"label":"C","text":"48.0 N"},{"label":"D","text":"67.5 N"},{"label":"E","text":"96.0 N"}],"images":[],"answer":"E"},{"id":"Units_1-2-q444","source":"Units_1-2","sourceNumber":"444","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 6.00-kg ornament is held at rest by two light wires that form 30.0° angles with the vertical, as shown in the figure. An external force of magnitude F acts vertically downward on the ornament. The tension exerted by each of the two wires is denoted by T . A free-body diagram, showing the four forces that act on the box, is shown in the figure. If the magnitude of force F is 410 N, what is the magnitude of the tension T ?","choices":[{"label":"A","text":"188 N"},{"label":"B","text":"470 N"},{"label":"C","text":"376 N"},{"label":"D","text":"235 N"},{"label":"E","text":"271 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"138","height":"183"}],"answer":"E"},{"id":"Units_1-2-q445","source":"Units_1-2","sourceNumber":"445","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"The figure shows a block of mass M hanging at rest. The light wire fastened to the wall is horizontal and has a tension of 38 N. The wire fastened to the ceiling is also very light, has a tension of 59N, and makes an angle θ with the ceiling. Find the angle θ .","choices":[{"label":"A","text":"40°"},{"label":"B","text":"45°"},{"label":"C","text":"33°"},{"label":"D","text":"65°"},{"label":"E","text":"50°"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"213","height":"198"}],"answer":"E"},{"id":"Units_1-2-q447","source":"Units_1-2","sourceNumber":"447","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 400-kg box is lifted vertically upward with constant velocity by means of two cables pulling at 40.0° on either side of the vertical direction. What is the tension in each cable?","choices":[{"label":"A","text":"231 N"},{"label":"B","text":"2560 N"},{"label":"C","text":"800 N"},{"label":"D","text":"400 N"},{"label":"E","text":"3920 N"}],"images":[],"answer":"B"},{"id":"Units_1-2-q448","source":"Units_1-2","sourceNumber":"448","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 10.0-kg picture is held in place by two wires, the first one hanging at 50.0° to the left of the vertical and the second one at 45.0° to the right of the vertical. What is the tension in the first wire?","choices":[{"label":"A","text":"50.8 N"},{"label":"B","text":"69.4 N"},{"label":"C","text":"69.6 N"},{"label":"D","text":"23.8 N"},{"label":"E","text":"98.1 N"}],"images":[],"answer":"C"},{"id":"Units_1-2-q450","source":"Units_1-2","sourceNumber":"450","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A load is being lifted vertically upward by means of two cables attached to it. The first cable exerts a force of 600 N at an angle of 35.0° to the left of the vertical. The second cable exerts a force of 1300 N. At what angle to the right of the vertical is the second cable pulling?","choices":[{"label":"A","text":"15.4°"},{"label":"B","text":"30.8°"},{"label":"C","text":"75.8°"},{"label":"D","text":"67.8°"},{"label":"E","text":"16.2°"}],"images":[],"answer":"A"},{"id":"Units_1-2-q451","source":"Units_1-2","sourceNumber":"451","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 10-kg sign is held by two ropes as shown in the figure. What is the tension in rope A?","choices":[{"label":"A","text":"98 N"},{"label":"B","text":"44 N"},{"label":"C","text":"88 N"},{"label":"D","text":"72 N"},{"label":"E","text":"69 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"274","height":"134"}],"answer":"C"},{"id":"Units_1-2-q452","source":"Units_1-2","sourceNumber":"452","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 3.0-kg and a 5.0-kg box rest side-by-side on a perfectly smooth, level floor. A horizontal force of 32 N is applied to the 3.0-kg box pushing it against the 5.0-kg box, and, as a result, both boxes slide along the floor. How hard do the two boxes push against each other?","choices":[{"label":"A","text":"32 N"},{"label":"B","text":"0 N"},{"label":"C","text":"12 N"},{"label":"D","text":"24 N"},{"label":"E","text":"20 N"}],"images":[],"answer":"E"},{"id":"Units_1-2-q453","source":"Units_1-2","sourceNumber":"453","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 3.0-kg and a 5.0-kg box rest side-by-side on a smooth, level floor. A horizontal force of 32 N is applied to the 5.0-kg box pushing it against the 3.0-kg box, and, as a result, both boxes slide along the floor. How hard do the two boxes push against each other?","choices":[{"label":"A","text":"24 N"},{"label":"B","text":"0 N"},{"label":"C","text":"12 N"},{"label":"D","text":"32 N"},{"label":"E","text":"20 N"}],"images":[],"answer":"C"},{"id":"Units_1-2-q454","source":"Units_1-2","sourceNumber":"454","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Three boxes rest side-by-side on a smooth, horizontal floor. Their masses are 5.0 kg, 3.0 kg, and 2.0 kg, with the 3.0-kg mass in the center. A force of 50 N pushes on the 5.0-kg box, which pushes against the other two boxes. What magnitude force does the 5.0-kg box exert on the 3.0-kg box?","choices":[{"label":"A","text":"25 N"},{"label":"B","text":"40 N"},{"label":"C","text":"10 N"},{"label":"D","text":"0 N"},{"label":"E","text":"50 N"}],"images":[],"answer":"A"},{"id":"Units_1-2-q459","source":"Units_1-2","sourceNumber":"459","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 3.0-kg object and a 5.0-kg object hang vertically at the opposite ends of a very light rope that goes over a massless, frictionless pulley. If the objects are released from rest, what is the resulting acceleration of the objects?","choices":[{"label":"A","text":"4.9 m/s 2"},{"label":"B","text":"2.5 m/s 2"},{"label":"C","text":"0.00 m/s 2"},{"label":"D","text":"6.1 m/s 2"},{"label":"E","text":"3.7 m/s 2"}],"images":[],"answer":"A"},{"id":"Units_1-2-q460","source":"Units_1-2","sourceNumber":"460","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 3.0-kg object and a 5.0-kg object hang vertically at the opposite ends of a rope that goes over a massless, frictionless pulley. If the objects are released from rest, in what time interval will the 3.0-kg object rise by 1.0 m?","choices":[{"label":"A","text":"0.74 s"},{"label":"B","text":"0.41 s"},{"label":"C","text":"1.8 s"},{"label":"D","text":"0.90 s"},{"label":"E","text":"0.82 s"}],"images":[],"answer":"D"},{"id":"Units_1-2-q461","source":"Units_1-2","sourceNumber":"461","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"As shown in the figure, a 10-kg block on a perfectly smooth horizontal table is connected by a horizontal string to a 63-kg block that is hanging over the edge of the table. What is the magnitude of the acceleration of the 10-kg block when the other block is released?","choices":[{"label":"A","text":"7.5 m/s 2"},{"label":"B","text":"8.5 m/s 2"},{"label":"C","text":"9.0 m/s 2"},{"label":"D","text":"8.1 m/s 2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"137","height":"126"}],"answer":"D"},{"id":"Units_1-2-q463","source":"Units_1-2","sourceNumber":"463","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"The figure shows a 100-kg block being released from rest from a height of 1.0 m. It then takes 0.53 s for it to reach the floor. What is the mass m of the block on the left? There is no friction or mass in the pulley, and the connecting rope is very light.","choices":[{"label":"A","text":"13 kg"},{"label":"B","text":"14 kg"},{"label":"C","text":"16 kg"},{"label":"D","text":"11 kg"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"188","height":"257"}],"answer":"C"},{"id":"Units_1-2-q465","source":"Units_1-2","sourceNumber":"465","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"In the figure, block A has a mass of 3.00 kg. It rests on a smooth horizontal table and is connected by a very light horizontal string over a massless, frictionless pulley to block B, which has a mass of 2.00 kg. When block B is released from rest, in what time interval will block B travel 80.0 cm?","choices":[{"label":"A","text":"0.639 s"},{"label":"B","text":"0.785 s"},{"label":"C","text":"0.404 s"},{"label":"D","text":"0.935 s"},{"label":"E","text":"0.494 s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"213","height":"138"}],"answer":"A"},{"id":"Units_1-2-q467","source":"Units_1-2","sourceNumber":"467","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"The coefficients of static and kinetic friction between a 3.0-kg box and a horizontal desktop are 0.40 and 0.30, respectively. What is the friction force on the box when a 15-N horizontal force is being exerted on the box?","choices":[{"label":"A","text":"12 N"},{"label":"B","text":"4.5 N"},{"label":"C","text":"15 N"},{"label":"D","text":"8.8 N"},{"label":"E","text":"6.0 N"}],"images":[],"answer":"D"},{"id":"Units_1-2-q468","source":"Units_1-2","sourceNumber":"468","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"An object slides on a level floor. It slows and comes to a stop with a constant acceleration of magnitude 2.4 m/s 2 . What is the coefficient of kinetic friction between the object and the floor?","choices":[{"label":"A","text":"0.24"},{"label":"B","text":"0.48"},{"label":"C","text":"0.12"},{"label":"D","text":"It is impossible to determine without knowing the mass of the object."}],"images":[],"answer":"A"},{"id":"Units_1-2-q470","source":"Units_1-2","sourceNumber":"470","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A policeman investigating an accident measures the skid marks left by a classic car on the horizontal road. He determines that the distance between the point that the driver slammed on the brakes (thereby locking the wheels) and the point where the car came to a stop was 28.0 m. From a reference manual he determines that the coefficient of kinetic friction between the tires and the road under the prevailing conditions was 0.300. How fast was the car going when the driver began slowing down?","choices":[{"label":"A","text":"32.9 m/s"},{"label":"B","text":"21.4 m/s"},{"label":"C","text":"10.7 m/s"},{"label":"D","text":"45.7 m/s"},{"label":"E","text":"12.8 m/s"}],"images":[],"answer":"E"},{"id":"Units_1-2-q471","source":"Units_1-2","sourceNumber":"471","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A 50-kg box is being pushed along a horizontal surface. The coefficient of static friction between the box and the ground is 0.65, and the coefficient of kinetic friction is 0.35. What horizontal force must be exerted on the box for its acceleration to be measured as 1.2 m/s 2 ?","choices":[{"label":"A","text":"60 N"},{"label":"B","text":"120 N"},{"label":"C","text":"490 N"},{"label":"D","text":"230 N"},{"label":"E","text":"170 N"}],"images":[],"answer":"D"},{"id":"Units_1-2-q472","source":"Units_1-2","sourceNumber":"472","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 50-kg box is resting on a horizontal floor. A force of 250 N directed at an angle of 30.0° below the horizontal is exerted on the box. The coefficient of static friction between the box and the surface is 0.40, and the coefficient of kinetic friction is 0.30. What is the force of friction on the box?","choices":[{"label":"A","text":"32 N"},{"label":"B","text":"250 N"},{"label":"C","text":"200 N"},{"label":"D","text":"220 N"},{"label":"E","text":"620 N"}],"images":[],"answer":"D"},{"id":"Units_1-2-q473","source":"Units_1-2","sourceNumber":"473","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A baseball player is running to second base at 5.03 m/s. When he is 4.80 m from the plate, he starts to slide. The coefficient of kinetic friction between the player and the ground is 0.180, and the coefficient of static friction is 3.14. What is his speed when he reaches the plate?","choices":[{"label":"A","text":"2.56 m/s"},{"label":"B","text":"1.96 m/s"},{"label":"C","text":"4.47 m/s"},{"label":"D","text":"2.89 m/s"},{"label":"E","text":"He stops before reaching the plate."}],"images":[],"answer":"D"},{"id":"Units_1-2-q474","source":"Units_1-2","sourceNumber":"474","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 55-kg box rests on a horizontal surface. The coefficient of static friction between the box and the surface is 0.30. A horizontal 140-N force is applied to the box. What is the friction force exerted on the box?","choices":[{"label":"A","text":"0.00 N"},{"label":"B","text":"160 N"},{"label":"C","text":"16.5 N"},{"label":"D","text":"140 N"},{"label":"E","text":"42 N"}],"images":[],"answer":"D"},{"id":"Units_1-2-q475","source":"Units_1-2","sourceNumber":"475","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A horizontal 52-N force is needed to slide a 50-kg box across a flat surface at a constant velocity of 3.5 m/s. What is the coefficient of kinetic friction between the box and the floor?","choices":[{"label":"A","text":"0.13"},{"label":"B","text":"0.10"},{"label":"C","text":"0.09"},{"label":"D","text":"0.11"}],"images":[],"answer":"D"},{"id":"Units_1-2-q476","source":"Units_1-2","sourceNumber":"476","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"In a shuffleboard game, the puck slides a total of 12 m on a horizontal surface before coming to rest. If the coefficient of kinetic friction between the puck and board is 0.10, what was the initial speed of the puck?","choices":[{"label":"A","text":"4.8 m/s"},{"label":"B","text":"4.3 m/s"},{"label":"C","text":"3.8 m/s"},{"label":"D","text":"48.5 m/s"}],"images":[],"answer":"A"},{"id":"Units_1-2-q477","source":"Units_1-2","sourceNumber":"477","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"During a hockey game, a puck is given an initial speed of 10 m/s. It slides 50 m on the horizontal ice before it stops due to friction. What is the coefficient of kinetic friction between the puck and the ice?","choices":[{"label":"A","text":"0.090"},{"label":"B","text":"0.11"},{"label":"C","text":"0.10"},{"label":"D","text":"0.12"}],"images":[],"answer":"C"},{"id":"Units_1-2-q478","source":"Units_1-2","sourceNumber":"478","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A driver in a 1000- kg classic car traveling at 24 m/s slams on the brakes and skids to a stop. If the coefficient of friction between the tires and the level road is 0.80, how long will the skid marks be?","choices":[{"label":"A","text":"34 m"},{"label":"B","text":"30 m"},{"label":"C","text":"37 m"},{"label":"D","text":"46 m"}],"images":[],"answer":"C"},{"id":"Units_1-2-q479","source":"Units_1-2","sourceNumber":"479","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A flatbed truck is carrying a 20.0-kg crate along a level road. The coefficient of static friction between the crate and the truck bed is 0.400, and the coefficient of kinetic friction is 0.300. What is the maximum acceleration that the truck can have if the crate does not slide relative to the truck?","choices":[{"label":"A","text":"7.84 m/s 2"},{"label":"B","text":"196 m/s 2"},{"label":"C","text":"78.5 m/s 2"},{"label":"D","text":"8.00 m/s 2"},{"label":"E","text":"3.92 m/s 2"}],"images":[],"answer":"A"},{"id":"Units_1-2-q480","source":"Units_1-2","sourceNumber":"480","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"You push downward on a trunk at an angle 25° below the horizontal with a force of 750 N. If the trunk is on a flat surface and the coefficient of static friction between the surface and the trunk is 0.61, what is the most massive trunk you will be able to move?","choices":[{"label":"A","text":"112 kg"},{"label":"B","text":"81 kg"},{"label":"C","text":"93 kg"},{"label":"D","text":"73 kg"}],"images":[],"answer":"B"},{"id":"Units_1-2-q484","source":"Units_1-2","sourceNumber":"484","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A flatbed truck is carrying a 20-kg crate up a sloping road. The coefficient of static friction between the crate and the truck bed is 0.40, and the coefficient of kinetic friction is 0.30. What is the maximum angle of slope that the truck can climb at constant speed if the crate is to stay in place relative to the truck?","choices":[{"label":"A","text":"17°"},{"label":"B","text":"0.38°"},{"label":"C","text":"22°"},{"label":"D","text":"68°"},{"label":"E","text":"13°"}],"images":[],"answer":"C"},{"id":"Units_1-2-q487","source":"Units_1-2","sourceNumber":"487","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 15-kg block is on a frictionless ramp that is inclined at 20° above the horizontal. It is connected by a very light string over a light frictionless pulley at the top end of the ramp to a hanging 19-kg block, as shown in the figure. The string pulls on the 15-kg block parallel to the surface of the ramp. Find the magnitude of the acceleration of the 19-kg block after the system is released.","choices":[{"label":"A","text":"4.0 m/s 2"},{"label":"B","text":"3.8 m/s 2"},{"label":"C","text":"4.2 m/s 2"},{"label":"D","text":"3.6 m/s 2"},{"label":"E","text":"4.5 m/s 2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"227","height":"105"}],"answer":"E"},{"id":"Units_1-2-q491","source":"Units_1-2","sourceNumber":"491","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 6.0-kg box slides down an inclined plane that makes an angle of 39° with the horizontal. If the coefficient of kinetic friction is 0.40, at what rate does the box accelerate down the slope?","choices":[{"label":"A","text":"3.4 m/s 2"},{"label":"B","text":"3.1 m/s 2"},{"label":"C","text":"3.7 m/s 2"},{"label":"D","text":"4.1 m/s 2"}],"images":[],"answer":"A"},{"id":"Units_1-2-q492","source":"Units_1-2","sourceNumber":"492","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 200-g hockey puck is launched at an initial speed of 16 m/s up a metal ramp that is inclined at a 30° angle. The coefficients of static and kinetic friction between the hockey puck and the metal ramp are µ s = 0.40 and µ k = 0.30, respectively. What vertical height does the puck reach above its starting point?","choices":[{"label":"A","text":"17 m"},{"label":"B","text":"13 m"},{"label":"C","text":"4.2 m"},{"label":"D","text":"8.6 m"}],"images":[],"answer":"D"},{"id":"Units_1-2-q493","source":"Units_1-2","sourceNumber":"493","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"The figure shows a block of mass m resting on a 20° slope. The block has coefficients of friction μ s = 0.64 and μ k = 0.54 with the surface of the slope. It is connected using a very light string over a massless frictionless pulley to a hanging block of mass 2.0 kg. The string above the slope pulls parallel to the surface. What is the maximum mass m so the system will remain at rest when it is released from rest?","choices":[{"label":"A","text":"2.1 kg"},{"label":"B","text":"1.3 kg"},{"label":"C","text":"3.3 kg"},{"label":"D","text":"3.6 kg"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"293","height":"160"}],"answer":"A"},{"id":"Units_1-2-q496","source":"Units_1-2","sourceNumber":"496","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A 50.0-kg block is being pulled up a 16.0° slope by a force of 250 N that is parallel to the slope. The coefficient of kinetic friction between the block and the slope is 0.200. What is the acceleration of the block?","choices":[{"label":"A","text":"0.415 m/s 2"},{"label":"B","text":"0.528 m/s 2"},{"label":"C","text":"0.158 m/s 2"},{"label":"D","text":"0.983 m/s 2"},{"label":"E","text":"0.260 m/s 2"}],"images":[],"answer":"C"},{"id":"Units_3-4-q1","source":"Units_3-4","sourceNumber":"1","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A cart of mass m is at rest on a horizontal, frictionless track in a laboratory. A student uses a force sensor to exert horizontal force on the cart, and collects the data shown in the graph above. Which of the following is true about the cart during the time interval from 0 to 8s?","choices":[{"label":"A","text":"Its initial momentum is equal to its final momentum."},{"label":"B","text":"Its momentum is zero at t = 4 s."},{"label":"C","text":"Its initial momentum is positive, and its final momentum is negative."},{"label":"D","text":"Its initial momentum is in the opposite direction as its final momentum."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"379","height":"248"}],"answer":"A"},{"id":"Units_3-4-q2","source":"Units_3-4","sourceNumber":"2","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Two identical balls with equal speed hit a wall. Ball 1 hits the wall and stops. Ball 2 bounces off with half of its initial speed, moving in the opposite direction. Which of the following is true?","choices":[{"label":"A","text":"Ball 2 has 2/3 as much impulse imparted to it as Ball 1."},{"label":"B","text":"Ball 2 has 3/2 as much impulse imparted to it as Ball 1."},{"label":"C","text":"Ball 2 has half as much impulse imparted to it as Ball 1."},{"label":"D","text":"Ball 2 has twice as much impulse imparted to it as Ball 1."},{"label":"E","text":"Ball 2 has the same impulse imparted to it as Ball 1."}],"images":[],"answer":"B"},{"id":"Units_3-4-q3","source":"Units_3-4","sourceNumber":"3","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"During a head-on collision, how does an air bag protect a passenger in the car?","choices":[{"label":"A","text":"It decreases the impulse exerted the passenger."},{"label":"B","text":"It shortens the stopping time interval for the passenger, and increases the force exerted on them during the collision."},{"label":"C","text":"It decreases the initial momentum of the passenger."},{"label":"D","text":"It lengthens the stopping time interval for the passenger, and decreases the force exerted on them during the collision."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"300","height":"215"}],"answer":"D"},{"id":"Units_3-4-q4","source":"Units_3-4","sourceNumber":"4","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Two separate boxes, of masses m and 2 m , are initially at rest on a frictionless sheet of ice. A constant force is exerted horizontally on the smaller box, for a horizontal distance d . After this, the smaller box has a final momentum p . Now the application of the force is repeated for the larger box, until it has traveled the same horizontal distance d . What will be true about the larger box's final momentum?","choices":[{"label":"A","text":"The larger box will have a final momentum that is equal to p ."},{"label":"B","text":"The larger box will have a final momentum that is less than p ."},{"label":"C","text":"The larger box will have a final momentum that is greater than p ."},{"label":"D","text":"There is not enough information to compare their final momenta."}],"images":[],"answer":"C"},{"id":"Units_3-4-q5","source":"Units_3-4","sourceNumber":"5","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"Objects A and B are moving toward one another on a frictionless surface. Object B has twice the mass and twice the speed as object A . The two objects collide and stick together. Which of the following is true about the magnitude of the final momentum of the two-object system?","choices":[{"label":"A","text":"It is equal in magnitude to the initial momentum of Object A ."},{"label":"B","text":"It is four times the magnitude of the initial momentum of Object A ."},{"label":"C","text":"It is twice the magnitude of the initial momentum of Object A ."},{"label":"D","text":"It is three times the magnitude of the initial momentum of Object A ."}],"images":[],"answer":"D"},{"id":"Units_3-4-q6","source":"Units_3-4","sourceNumber":"6","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A block of mass m 1 moving with speed v 1 collides with an originally stationary block of mass m 2 . These two blocks latch together. The blocks then move, stuck together, at a new common speed, as diagrammed. Both blocks then collide and latch together with a third block, of mass m 3 , which is also originally stationary. Which of the following is true?","choices":[{"label":"A","text":"v 3 = v 2 < v 1"},{"label":"B","text":"v 3 = v 2 = v 1"},{"label":"C","text":"v 3 < v 2 < v 1"},{"label":"D","text":"v 3 < v 2 = v 1"},{"label":"E","text":"v 3 > v 2 > v 1"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"403","height":"318"}],"answer":"D"},{"id":"Units_3-4-q8","source":"Units_3-4","sourceNumber":"8","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"Moving vertically, two objects of the same mass strike a flat tabletop at the same speed, as shown above. However, in Scenario 2 the object stops when it hits the table, and in Scenario 1, the object bounces off the table with an equal speed in the opposite direction. Which of the following statements is true about the change in momentum of the two objects?","choices":[{"label":"A","text":"The object's change in momentum is larger in Scenario 2."},{"label":"B","text":"The object's change in momentum is the same in both scenarios."},{"label":"C","text":"The object's change in momentum is larger in Scenario 1."},{"label":"D","text":"It depends on the time interval for which each object is in contact with the table."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"428","height":"209"}],"answer":"C"},{"id":"Units_3-4-q10","source":"Units_3-4","sourceNumber":"10","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"You have two objects: a ball that is covered with the hook side of Velcro and an incline covered with the loop side of Velcro that is fixed onto a low-friction cart. The ball is dropped vertically onto the incline, which is at rest. When the ball collides with the incline, it sticks where it first touches, without moving relative to the surface. Which of the following will be true about the cart-ball system after the ball sticks to the cart?","choices":[{"label":"A","text":"It will be at rest."},{"label":"B","text":"It will be rolling to the right."},{"label":"C","text":"The final velocity of the system depends on the angle of the incline."},{"label":"D","text":"It will be rolling to the left."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"248","height":"295"}],"answer":"A"},{"id":"Units_3-4-q15","source":"Units_3-4","sourceNumber":"15","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A ball of mass m with speed v strikes the floor at an angle with the normal (perpendicular) to the floor, as shown above. It then rebounds with the same speed and at the same angle. The magnitude of the ball's change in momentum is","choices":[{"label":"A","text":"Zero"},{"label":"B","text":"mv cos"},{"label":"C","text":"mv sin"},{"label":"D","text":"2 mv sin"},{"label":"E","text":"2 mv cos"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"274","height":"118"}],"answer":"E"},{"id":"Units_3-4-q16","source":"Units_3-4","sourceNumber":"16","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A cart of mass m is at rest on a horizontal, frictionless track in a laboratory. A student uses a force sensor to exert horizontal force on the cart, and collects the data shown in the graph above. Which of the following is true about the cart during the time interval from 0 to 8s?","choices":[{"label":"A","text":"Its momentum is positive and decreasing."},{"label":"B","text":"Its momentum is negative and becoming increasingly negative."},{"label":"C","text":"Its momentum is positive and constant."},{"label":"D","text":"Its momentum is negative and constant."},{"label":"E","text":"Its momentum is positive and increasing."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"328","height":"216"}],"answer":"E"},{"id":"Units_3-4-q17","source":"Units_3-4","sourceNumber":"17","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"A rubber ball and a lump of clay have equal mass. They are thrown with equal speed against a wall. The ball bounces back with nearly the same speed with which it hits. The clay sticks to the wall. Which one of these objects undergoes the greater momentum change?","choices":[{"label":"A","text":"The ball"},{"label":"B","text":"The clay"},{"label":"C","text":"Both of them undergo the same non-zero momentum change."},{"label":"D","text":"Both of them undergo zero momentum change."}],"images":[],"answer":"A"},{"id":"Units_3-4-q18","source":"Units_3-4","sourceNumber":"18","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Which of the following quantities are units of momentum? (There may be more than one correct choice.)","choices":[{"label":"A","text":"kg ∙ m/s"},{"label":"B","text":"N ∙ s"},{"label":"C","text":"kg ∙ s/m"},{"label":"D","text":"kg ∙ m 2 /s 2"},{"label":"E","text":"N ∙ m"}],"images":[],"answer":"A, B"},{"id":"Units_3-4-q19","source":"Units_3-4","sourceNumber":"19","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A tiger is running in a straight line. If we double both the mass and speed of the tiger, by what factor will the magnitude of its momentum increase?","choices":[{"label":"A","text":"B) 2"},{"label":"C","text":"4"},{"label":"D","text":"16"},{"label":"E","text":"8"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"C"},{"id":"Units_3-4-q20","source":"Units_3-4","sourceNumber":"20","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"A very bouncy rubber ball is dropped from a certain height and hits the floor with a downward speed v. Since it is so elastic, the ball bounces back with the same speed v going upward. Which of the following statements about the bounce are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The magnitude of the ball's momentum was the same just before and just after the bounce."},{"label":"B","text":"The ball's momentum was constant during the bounce."},{"label":"C","text":"The ball had the same momentum just before and just after the bounce."},{"label":"D","text":"None of the above statements is correct."}],"images":[],"answer":"A"},{"id":"Units_3-4-q21","source":"Units_3-4","sourceNumber":"21","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"Two friends are standing on opposite ends of a canoe that is initially at rest with respect to a frictionless lake. The person in the front throws a very massive ball toward the back, and the person in the back catches it. After the ball is caught, the canoe is","choices":[{"label":"A","text":"moving forward."},{"label":"B","text":"stationary."},{"label":"C","text":"moving backward."}],"images":[],"answer":"B"},{"id":"Units_3-4-q22","source":"Units_3-4","sourceNumber":"22","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"You are standing on a skateboard, initially at rest. A friend throws a very heavy ball toward you. You have two choices about what to do with the ball: either catch the ball or push it back toward your friend with the same speed as it was originally thrown. Which choice should you make in order to maximize your speed on the skateboard?","choices":[{"label":"A","text":"Deflect the ball back."},{"label":"B","text":"Catch the ball."},{"label":"C","text":"Your final speed on the skateboard will be the same regardless whether you catch the ball or push the ball back."}],"images":[],"answer":"A"},{"id":"Units_3-4-q23","source":"Units_3-4","sourceNumber":"23","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"A small car collides head-on with a large truck and the two vehicles become permanently entangled. Which of the following statements concerning the magnitude of the momentum change during the collision is correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The truck experiences the greater magnitude momentum change."},{"label":"B","text":"The magnitude of the momentum change experienced by each one is directly proportional to its mass."},{"label":"C","text":"The small car and the truck experience the same magnitude momentum change."},{"label":"D","text":"The small car experiences the greater magnitude momentum change."},{"label":"E","text":"The magnitude of the momentum change experienced by each one is inversely proportional to its mass."}],"images":[],"answer":"C"},{"id":"Units_3-4-q24","source":"Units_3-4","sourceNumber":"24","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"A small car collides head-on with a large truck in and the two vehicles become permanently entangled. Which of the following statements concerning the momentum during the collision are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The car and the truck must undergo the same change in speed."},{"label":"B","text":"The momentum of the truck is constant."},{"label":"C","text":"The momentum of the car is constant."},{"label":"D","text":"The momentum of the car and the momentum of the truck are each constant."},{"label":"E","text":"The momentum of the car-truck system is constant, but the momentum of each one separately is not constant."}],"images":[],"answer":"E"},{"id":"Units_3-4-q25","source":"Units_3-4","sourceNumber":"25","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Consider two less-than-desirable options. In the first you are driving 30 mi/h and crash head-on into an identical car also going 30 mi/h. In the second option you are driving 30 mi/h and crash head-on into a stationary brick wall which your car does not even dent. In neither case does your car bounce back from the thing it hits, and the collision time interval is the same in both cases. Which of these two situations would result in the greater force on your car?","choices":[{"label":"A","text":"hitting the other car"},{"label":"B","text":"hitting the brick wall"},{"label":"C","text":"The force would be the same in both cases."},{"label":"D","text":"None of the above choices are correct."}],"images":[],"answer":"C"},{"id":"Units_3-4-q26","source":"Units_3-4","sourceNumber":"26","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A rocket explodes into two fragments, one with 25 times more mass than the other. The magnitude of the momentum change of the less massive fragment is","choices":[{"label":"A","text":"The same as the momentum change of the more massive fragment."},{"label":"B","text":"5 times as great as the momentum change of the more massive fragment."},{"label":"C","text":"1/4 as great as the momentum change of the more massive fragment."},{"label":"D","text":"25 times as great as the momentum change of the more massive fragment."},{"label":"E","text":"1/25 as great as the momentum change of the more massive fragment."}],"images":[],"answer":"A"},{"id":"Units_3-4-q27","source":"Units_3-4","sourceNumber":"27","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Which of the following quantities are units of impulse? (There could be more than one correct choice.)","choices":[{"label":"A","text":"kg ∙ m 2 /s 2"},{"label":"B","text":"N ∙ m"},{"label":"C","text":"kg ∙ m/s"},{"label":"D","text":"kg ∙ s/m"},{"label":"E","text":"N ∙ s"}],"images":[],"answer":"C, E"},{"id":"Units_3-4-q28","source":"Units_3-4","sourceNumber":"28","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Three cars, car X, car Y, and car Z, begin accelerating from rest at the same time. Car X is more massive than car Y, which is more massive than car Z. The net = force exerted on each car is identical. After 10 seconds, which car has the greatest magnitude of momentum?","choices":[{"label":"A","text":"They all have the same magnitude of momentum."},{"label":"B","text":"Car Z"},{"label":"C","text":"Car Y"},{"label":"D","text":"Car X"}],"images":[],"answer":"A"},{"id":"Units_3-4-q29","source":"Units_3-4","sourceNumber":"29","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"During World War I, Germany used a \"Big Bertha\" cannon to hurl shells into Paris 30 miles away. This gun had a very long barrel. What was the reason for using a long barrel in these guns?","choices":[{"label":"A","text":"to allow the force of the expanding gases from the gunpowder to act for a longer time interval"},{"label":"B","text":"to reduce frictional losses"},{"label":"C","text":"to increase the force exerted on the bullet due to the expanding gases from the gunpowder"},{"label":"D","text":"to exert a larger force on the shells"},{"label":"E","text":"to reduce the force exerted on the bullet due to the expanding gases from the gunpowder"}],"images":[],"answer":"A"},{"id":"Units_3-4-q30","source":"Units_3-4","sourceNumber":"30","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"In a collision between two unequal masses, which mass has a greater magnitude impulse exerted on it?","choices":[{"label":"A","text":"the larger mass"},{"label":"B","text":"the smaller mass"},{"label":"C","text":"They receive equal impulses."}],"images":[],"answer":"C"},{"id":"Units_3-4-q31","source":"Units_3-4","sourceNumber":"31","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"Identical net forces are exerted for the same time interval on two different objects. The magnitude of the change in momentum of the less-massive object is","choices":[{"label":"A","text":"smaller than the magnitude of the change in momentum of the more-massive object, but not zero."},{"label":"B","text":"precisely equal to the magnitude of the change in momentum of the more-massive object."},{"label":"C","text":"larger than the magnitude of the change in momentum of the more-massive object."},{"label":"D","text":"zero."},{"label":"E","text":"There is not enough information to answer the question."}],"images":[],"answer":"B"},{"id":"Units_3-4-q32","source":"Units_3-4","sourceNumber":"32","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"In a friction-free environment, a very light ping-pong ball moving east at a speed of 4 m/s collides with a very heavy stationary bowling ball. The ping-pong ball bounces back to the west, and the bowling ball moves very slowly to the east. Which object has a greater magnitude impulse imparted to it during the collision?","choices":[{"label":"A","text":"Neither; both experienced the same magnitude impulse."},{"label":"B","text":"The ping-pong ball"},{"label":"C","text":"It is impossible to tell since the velocities after the collision are unknown."},{"label":"D","text":"The bowling ball"},{"label":"E","text":"It is impossible to tell since the actual mass values are not given."}],"images":[],"answer":"A"},{"id":"Units_3-4-q33","source":"Units_3-4","sourceNumber":"33","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"A small car collides head-on with a large truck. The two vehicles become permanently entangled. Which of the following statements concerning the magnitude of the average force during the collision is correct?","choices":[{"label":"A","text":"The force experienced by each one is directly proportional to its mass."},{"label":"B","text":"The truck experiences the greater average force."},{"label":"C","text":"The force experienced by each one is inversely proportional to its mass."},{"label":"D","text":"The small car and the truck experience average forces of the same magnitude."},{"label":"E","text":"The small car experiences the greater average force."}],"images":[],"answer":"D"},{"id":"Units_3-4-q34","source":"Units_3-4","sourceNumber":"34","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 2.0-kg ball moving eastward at 3.0 m/s suddenly collides with and sticks to a 4.0-kg ball moving northward at 2.0 m/s. What is the magnitude of the momentum of this system just after the collision?","choices":[{"label":"A","text":"14 kg ∙ m/s"},{"label":"B","text":"10 kg ∙ m/s"},{"label":"C","text":"6.0 kg ∙ m/s"},{"label":"D","text":"2.0 kg ∙ m/s"},{"label":"E","text":"8.0 kg ∙ m/s"}],"images":[],"answer":"B"},{"id":"Units_3-4-q36","source":"Units_3-4","sourceNumber":"36","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 0.14-kg baseball is dropped from rest from a height of 2.0 m above the ground. What is the magnitude of its momentum just before it hits the ground if there is no air resistance?","choices":[{"label":"A","text":"0.28 kg ∙ m/s"},{"label":"B","text":"0.44 kg ∙ m/s"},{"label":"C","text":"1.4 kg ∙ m/s"},{"label":"D","text":"0.88 kg ∙ m/s"},{"label":"E","text":"0.62 kg ∙ m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q37","source":"Units_3-4","sourceNumber":"37","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"Three objects are moving along a straight line as shown in the figure. Taking the positive direction to be to the right, what is the total momentum of this system?","choices":[{"label":"A","text":"+ 106 kg ∙ m/s"},{"label":"B","text":"- 14.0 kg ∙ m/s"},{"label":"C","text":"0.00 kg ∙ m/s"},{"label":"D","text":"- 106 kg ∙ m/s"},{"label":"E","text":"+ 14.0 kg ∙ m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"253","height":"64"}],"answer":"A"},{"id":"Units_3-4-q38","source":"Units_3-4","sourceNumber":"38","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"The two blocks of masses m and 2 m shown above travel along a frictionless surface at speeds v and 2 v , but in opposite directions. If the blocks collide and stick together, what is their final speed?","choices":[{"label":"A","text":"v"},{"label":"B","text":"3 v /2"},{"label":"C","text":"4 v /3"},{"label":"D","text":"v /2"},{"label":"E","text":"5 v /3"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"261","height":"43"}],"answer":"A"},{"id":"Units_3-4-q39","source":"Units_3-4","sourceNumber":"39","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A 1500-kg car traveling at 12.5 m/s collides with a 2500-kg van stopped at a traffic light. As a result of the collision, the two vehicles become attached to each other. If the duration of the collision is 0.2 seconds, which choice is closest to the magnitude of the average force exerted on the car during this time interval?","choices":[{"label":"A","text":"45 kN"},{"label":"B","text":"95 kN"},{"label":"C","text":"5 kN"},{"label":"D","text":"35 kN"},{"label":"E","text":"60 kN"}],"images":[],"answer":"E"},{"id":"Units_3-4-q40","source":"Units_3-4","sourceNumber":"40","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A 10-kg block is sliding across a horizontal, frictionless surface with an initial velocity component of -2 m/s. Referred to the same axis, the horizontal force component exerted on the block as a function of time is graphed as shown. What is the change in the momentum of the block between t = 0 s and t = 4 s?","choices":[{"label":"A","text":"60 Ns"},{"label":"B","text":"40 Ns"},{"label":"C","text":"50 Ns"},{"label":"D","text":"100 Ns"},{"label":"E","text":"80 Ns"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"259","height":"190"}],"answer":"A"},{"id":"Units_3-4-q41","source":"Units_3-4","sourceNumber":"41","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A bobsled of mass M moves across a surface with negligible friction at speed v . Two objects are dropped vertically into the bobsled one after the other: first an object of mass 2 m , and then an object of mass m . Afterward the sled moves with speed v/ 2. What would be the final speed of the sled if the objects were dropped into it at the same moment?","choices":[{"label":"A","text":"v/ 3"},{"label":"B","text":"3 v /5"},{"label":"C","text":"2 v /3"},{"label":"D","text":"v/ 2"},{"label":"E","text":"v /4"}],"images":[],"answer":"C"},{"id":"Units_3-4-q42","source":"Units_3-4","sourceNumber":"42","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"The graph above shows the velocity-versus-time graph for two carts on a horizontal track before and after a collision during which the carts stick together. The green and blue lines show the velocities of the carts before they collide, and the black lines show the velocity of the carts joined together after the collision. What is the ratio of the masses of the carts, m 1 / m 2 ?","choices":[{"label":"A","text":"3/4"},{"label":"B","text":"1/4"},{"label":"C","text":"1/3"},{"label":"D","text":"1/2"},{"label":"E","text":"2/3"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"484","height":"227"}],"answer":"C"},{"id":"Units_3-4-q43","source":"Units_3-4","sourceNumber":"43","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A 0.050-kg tennis ball is moving to the left at 10 m/s when it is hit by a tennis racket that is moving to the right. The magnitude of the force exerted on the ball by the racket as a function of time is shown in the figure above. What is the speed of the ball after the collision with the racket?","choices":[{"label":"A","text":"50 m/s"},{"label":"B","text":"30 m/s"},{"label":"C","text":"70 m/s"},{"label":"D","text":"90 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"286","height":"173"}],"answer":"B"},{"id":"Units_3-4-q44","source":"Units_3-4","sourceNumber":"44","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A 1500—kg car is initially travelling 10 m/s north on a straight road toward an intersection, as shown on the figure above on the left. At the same moment, a 2000-kg pickup truck is traveling 10 m/s east toward the same intersection. The two vehicles collide and stick together. At what angle north of east do the two vehicles move after the collision?","choices":[{"label":"A","text":"53°"},{"label":"B","text":"22°"},{"label":"C","text":"68°"},{"label":"D","text":"37°"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"535","height":"268"}],"answer":"D"},{"id":"Units_3-4-q45","source":"Units_3-4","sourceNumber":"45","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 0.330-kg volleyball is thrown vertically downward with a speed of 0.150 m/s in a place where g = 9.81 m/s 2 . It takes it 0.0655 s to reach the ground. What is the magnitude of its momentum just before it hits the ground?","choices":[{"label":"A","text":"0.0216 kg ∙ m/s"},{"label":"B","text":"0.262 kg ∙ m/s"},{"label":"C","text":"0.212 kg ∙ m/s"},{"label":"D","text":"0.0418 kg ∙ m/s"},{"label":"E","text":"0.163 kg ∙ m/s"}],"images":[],"answer":"B"},{"id":"Units_3-4-q46","source":"Units_3-4","sourceNumber":"46","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Two air track carts move along an air track toward each other. Cart A has a mass of 450 g and moves toward the right with a speed of 0.850 m/s. Cart B has a mass of 300 g and moves toward the left with a speed of 1.12 m/s. What is the total momentum of the two-cart system?","choices":[{"label":"A","text":"0.719 kg ∙ m/s toward the right"},{"label":"B","text":"0.750 kg ∙ m/s toward the right"},{"label":"C","text":"0.750 kg ∙ m/s toward the left"},{"label":"D","text":"0.719 kg ∙ m/s toward the left"},{"label":"E","text":"0.047 kg ∙ m/s toward the right"}],"images":[],"answer":"E"},{"id":"Units_3-4-q47","source":"Units_3-4","sourceNumber":"47","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 100-g ball falls from a window that is 12 m above ground level and experiences no significant air resistance as it falls. What is its momentum just before it strikes the ground?","choices":[{"label":"A","text":"3.3 kg ∙ m/s down"},{"label":"B","text":"1.8 kg ∙ m/s horizontally along the ground"},{"label":"C","text":"4.8 kg ∙ m/s up"},{"label":"D","text":"1.5 kg ∙ m/s down"},{"label":"E","text":"2.4 kg ∙ m/s down"}],"images":[],"answer":"D"},{"id":"Units_3-4-q48","source":"Units_3-4","sourceNumber":"48","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 0.140-kg baseball is dropped and reaches a speed of 1.20 m/s just before it hits the ground and bounces. It rebounds with an upward velocity of 1.00 m/s. What is the change of the ball's momentum during the bounce?","choices":[{"label":"A","text":"0.000 kg ∙ m/s"},{"label":"B","text":"0.308 kg ∙ m/s downward"},{"label":"C","text":"0.0280 kg ∙ m/s downward"},{"label":"D","text":"0.308 kg ∙ m/s upward"},{"label":"E","text":"0.0280 kg ∙ m/s upward"}],"images":[],"answer":"D"},{"id":"Units_3-4-q49","source":"Units_3-4","sourceNumber":"49","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A firecracker breaks up into two pieces, one of which has a mass of 200 g and flies off along the + x -axis with a speed of 82.0 m/s. The second piece has a mass of 300 g and flies off along the + y -axis with a speed of 45.0 m/s. What is the total momentum of the two pieces?","choices":[{"label":"A","text":"93.5 kg ∙ m/s at 28.8° counterclockwise from the + x -axis"},{"label":"B","text":"361 kg ∙ m/s at 0.983° counterclockwise from the + x -axis"},{"label":"C","text":"21.2 kg ∙ m/s at 56.3° counterclockwise from the + x -axis"},{"label":"D","text":"21.2 kg ∙ m/s at 39.5° counterclockwise from the + x -axis"},{"label":"E","text":"361 kg ∙ m/s at 56.3° counterclockwise from the + x -axis"}],"images":[],"answer":"D"},{"id":"Units_3-4-q50","source":"Units_3-4","sourceNumber":"50","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 600-kg car makes a 90.0° turn. Its speed before the turn is 21.0 m/s and after the turn it is 24.0 m/s. What is the magnitude of the change in the car's momentum during the turn?","choices":[{"label":"A","text":"10.2 × 10 3 kg ∙ m/s"},{"label":"B","text":"12.0 × 10 3 kg ∙ m/s"},{"label":"C","text":"19.1 × 10 3 kg ∙ m/s"},{"label":"D","text":"9.55 × 10 3 kg ∙ m/s"},{"label":"E","text":"22.2 × 10 3 kg ∙ m/s"}],"images":[],"answer":"C"},{"id":"Units_3-4-q51","source":"Units_3-4","sourceNumber":"51","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 0.10-kg ball, traveling horizontally at 25 m/s, strikes a wall and rebounds straight back at 19 m/s. What is the magnitude of the change in the momentum of the ball during the rebound?","choices":[{"label":"A","text":"1.2 kg ∙ m/s"},{"label":"B","text":"1.8 kg ∙ m/s"},{"label":"C","text":"5.4 kg ∙ m/s"},{"label":"D","text":"4.4 kg ∙ m/s"},{"label":"E","text":"72 kg ∙ m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q55","source":"Units_3-4","sourceNumber":"55","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 328-kg subcompact car moving at 19.1 m/s in the + x direction hits from behind a second car moving at 13.0 m/s in the same direction. If the second car has a mass of 790 kg and is moving straight ahead with a speed of 15.1 m/s immediately after the collision, what is the velocity of the first car after this sudden collision?","choices":[{"label":"A","text":"14.0 m/s forward"},{"label":"B","text":"18.2 m/s forward"},{"label":"C","text":"14.0 m/s backward"},{"label":"D","text":"24.2 m/s forward"}],"images":[],"answer":"A"},{"id":"Units_3-4-q56","source":"Units_3-4","sourceNumber":"56","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A 1200-kg ore cart is rolling at 10.8 m/s across a flat friction-free surface. A crane suddenly drops 858 kg of ore vertically into the cart. How fast does the cart move just after being loaded with the ore?","choices":[{"label":"A","text":"6.30 m/s"},{"label":"B","text":"3.80 m/s"},{"label":"C","text":"5.70 m/s"},{"label":"D","text":"4.20 m/s"}],"images":[],"answer":"A"},{"id":"Units_3-4-q58","source":"Units_3-4","sourceNumber":"58","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Two ice skaters suddenly push off against each other starting from a stationary position. The 45-kg skater acquires a speed of 0.375 m/s relative to the ice. What speed does the 60-kg skater acquire relative to the ice?","choices":[{"label":"A","text":"0.28 m/s"},{"label":"B","text":"0.50 m/s"},{"label":"C","text":"0.00 m/s"},{"label":"D","text":"0.38 m/s"},{"label":"E","text":"0.75 m/s"}],"images":[],"answer":"A"},{"id":"Units_3-4-q59","source":"Units_3-4","sourceNumber":"59","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A stationary 1200-kg cannon fires a 100-kg cannonball at 35 m/s. What is the recoil speed of the cannon? Assume that frictional forces are negligible and the cannon is fired horizontally.","choices":[{"label":"A","text":"3.2 m/s"},{"label":"B","text":"35 m/s"},{"label":"C","text":"2.9 m/s"},{"label":"D","text":"3.5 m/s"}],"images":[],"answer":"C"},{"id":"Units_3-4-q60","source":"Units_3-4","sourceNumber":"60","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A dinner plate falls vertically to the floor and breaks up into three pieces, which slide horizontally along the floor. Immediately after the impact, a 200-g piece moves along the + x -axis with a speed of 2.00 m/s, a 235-g piece moves along the + y -axis with a speed of 1.50 m/s. The third piece has a mass of 100 g. What is the speed of the third piece?","choices":[{"label":"A","text":"2.51 m/s"},{"label":"B","text":"2.57 m/s"},{"label":"C","text":"3.50 m/s"},{"label":"D","text":"6.83 m/s"},{"label":"E","text":"5.33 m/s"}],"images":[],"answer":"E"},{"id":"Units_3-4-q61","source":"Units_3-4","sourceNumber":"61","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"In a police ballistics test, a 10.0-g bullet moving at 300 m/s is fired into a 1.00-kg block at rest. The bullet goes through the block almost instantaneously and emerges with 50.0% of its original speed. What is the speed of the block just after the bullet emerges?","choices":[{"label":"A","text":"273 m/s"},{"label":"B","text":"1.50 m/s"},{"label":"C","text":"2.97 m/s"},{"label":"D","text":"3.00 m/s"}],"images":[],"answer":"B"},{"id":"Units_3-4-q62","source":"Units_3-4","sourceNumber":"62","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"Two astronauts, of masses 60 kg and 80 kg, are initially right next to each other and at rest in outer space. They suddenly push each other apart. What is their separation after the more massive astronaut has moved 12 m?","choices":[{"label":"A","text":"16 m"},{"label":"B","text":"28 m"},{"label":"C","text":"21 m"},{"label":"D","text":"24 m"},{"label":"E","text":"9.0 m"}],"images":[],"answer":"B"},{"id":"Units_3-4-q63","source":"Units_3-4","sourceNumber":"63","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Two astronauts, of masses 60 kg and 80 kg, are initially right next to each other and at rest in outer space. They suddenly push each other apart. How far has the more massive astronaut moved when the less massive astronaut has moved 12 m?","choices":[{"label":"A","text":"21 m"},{"label":"B","text":"7.0 m"},{"label":"C","text":"9.0 m"},{"label":"D","text":"12 m"},{"label":"E","text":"16 m"}],"images":[],"answer":"C"},{"id":"Units_3-4-q64","source":"Units_3-4","sourceNumber":"64","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Astronaut Jennifer's lifeline to her spaceship comes loose and she finds herself stranded, \"floating\" 100 m from the mothership and at rest with respect to it. She throws her 2.00-kg wrench at 20 m/s in a direction away from the ship. If she and her spacesuit have a combined mass of 200 kg, during what time interval will she coast back to her spaceship?","choices":[{"label":"A","text":"500 s"},{"label":"B","text":"1000 s"},{"label":"C","text":"750 s"},{"label":"D","text":"250 s"},{"label":"E","text":"2.50 min"}],"images":[],"answer":"A"},{"id":"Units_3-4-q65","source":"Units_3-4","sourceNumber":"65","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 14-cm diameter champagne bottle rests on its side on top of a frictionless horizontal table. Suddenly, the cork pops and the bottle slides backward, traveling a distance of 220 cm in 0.44 s. If the mass of the bottle is 500 times the mass of the cork, find the distance from the original position that the cork will land on the table. Neglect air resistance and assume that the cork is very small compared to the bottle. Also assume that no champagne enters or leaves the bottle.","choices":[{"label":"A","text":"30 m"},{"label":"B","text":"85 m"},{"label":"C","text":"8.5 cm"},{"label":"D","text":"60 m"}],"images":[],"answer":"A"},{"id":"Units_3-4-q66","source":"Units_3-4","sourceNumber":"66","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"The graph in the figure shows the x component F of the net force that acts for 10 s on a 100-kg crate. What is the change in the momentum of the crate during the 10 s that this force acts?","choices":[{"label":"A","text":"- 25 kg ∙ m/s"},{"label":"B","text":"25 kg ∙ m/s"},{"label":"C","text":"75 kg ∙ m/s"},{"label":"D","text":"- 75 kg ∙ m/s"},{"label":"E","text":"- 100 kg ∙ m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"188","height":"161"}],"answer":"C"},{"id":"Units_3-4-q67","source":"Units_3-4","sourceNumber":"67","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A forklift pushes a 100-kg crate, starting from rest, with a horizontal force of magnitude F . The graph in the figure shows the x component of the net force on the crate as a function of time. What is the instantaneous velocity of the crate at time t = 10 s?","choices":[{"label":"A","text":"- 75 cm/s"},{"label":"B","text":"25 cm/s"},{"label":"C","text":"75 cm/s"},{"label":"D","text":"- 25 cm/s"},{"label":"E","text":"0.00 cm/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"188","height":"161"}],"answer":"C"},{"id":"Units_3-4-q72","source":"Units_3-4","sourceNumber":"72","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A super dart of mass 20 g, traveling at 350 m/s, strikes a steel plate at an angle of 30° with the plane of the plate, as shown in the figure. It bounces off the plate at the same angle but at a speed of 320 m/s. What is the magnitude of the impulse that the plate exerts on the dart?","choices":[{"label":"A","text":"300 N ∙ s"},{"label":"B","text":"6.7 N ∙ s"},{"label":"C","text":"4.3 N ∙ s"},{"label":"D","text":"0.52 N ∙ s"},{"label":"E","text":"0.30 N ∙ s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"71","height":"199"}],"answer":"B"},{"id":"Units_3-4-q73","source":"Units_3-4","sourceNumber":"73","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A golf club exerts an average horizontal force of 1000 N on a 0.045-kg golf ball that is initially at rest on the tee. The club is in contact with the ball for 1.8 ms. What is the speed of the golf ball just as it leaves the clubface?","choices":[{"label":"A","text":"40 m/s"},{"label":"B","text":"50 m/s"},{"label":"C","text":"35 m/s"},{"label":"D","text":"45 m/s"},{"label":"E","text":"30 m/s"}],"images":[],"answer":"A"},{"id":"Units_3-4-q74","source":"Units_3-4","sourceNumber":"74","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 0.140-kg baseball is thrown with a velocity of 27.1 m/s. It is struck by the bat with an average force of 5000 N, which results in a velocity of 37.0 m/s in the opposite direction from the original velocity. For what time interval were the bat and ball in contact?","choices":[{"label":"A","text":"1.79 × 10 -3 s"},{"label":"B","text":"3.07 × 10 -2 s"},{"label":"C","text":"4.30 × 10 -3 s"},{"label":"D","text":"1.28 × 10 -2 s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q75","source":"Units_3-4","sourceNumber":"75","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Calculate the impulse due to a force of 4.5 N that lasts for 1.4 s.","choices":[{"label":"A","text":"5.7 kg∙ m/s"},{"label":"B","text":"6.9 kg∙ m/s"},{"label":"C","text":"5.0 kg∙ m/s"},{"label":"D","text":"6.3 kg∙ m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q76","source":"Units_3-4","sourceNumber":"76","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A girl of mass 55 kg throws a ball of mass 0.80 kg against a wall. The ball strikes the wall horizontally with a speed of 25 m/s, and it bounces straight back with this same speed. The ball is in contact with the wall 0.050 s. What is the magnitude of the average force exerted on the wall by the ball?","choices":[{"label":"A","text":"27,500 N"},{"label":"B","text":"800 N"},{"label":"C","text":"400 N"},{"label":"D","text":"13,750 N"},{"label":"E","text":"55,000 N"}],"images":[],"answer":"B"},{"id":"Units_3-4-q78","source":"Units_3-4","sourceNumber":"78","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 0.140-kg baseball is thrown horizontally with a velocity of 28.9 m/s. It is struck with a constant horizontal force that lasts for 1.85 ms, which results in a velocity of 37.0 m/s in the opposite direction. What was the magnitude of the horizontal force?","choices":[{"label":"A","text":"2.80 kN"},{"label":"B","text":"2.19 kN"},{"label":"C","text":"4.99 kN"},{"label":"D","text":"0.613 kN"}],"images":[],"answer":"C"},{"id":"Units_3-4-q79","source":"Units_3-4","sourceNumber":"79","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A golf ball of mass 0.050 kg is at rest on the tee. Just after being struck, it has a velocity of 102 m/s. If the club and ball were in contact for 0.81 ms, what is the magnitude of the average force exerted on the ball by the club?","choices":[{"label":"A","text":"5.5 kN"},{"label":"B","text":"4.9 kN"},{"label":"C","text":"6.3 kN"},{"label":"D","text":"7.1 kN"}],"images":[],"answer":"C"},{"id":"Units_3-4-q80","source":"Units_3-4","sourceNumber":"80","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 0.24-kg blob of clay is thrown at a wall with an initial horizontal velocity of 16 m/s. If the clay comes to a stop in 91 ms, what is the average horizontal force exerted on the clay by the wall?","choices":[{"label":"A","text":"42 N"},{"label":"B","text":"51 N"},{"label":"C","text":"26 N"},{"label":"D","text":"35 N"}],"images":[],"answer":"A"},{"id":"Units_3-4-q81","source":"Units_3-4","sourceNumber":"81","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A steady horizontal force lasting for 2.1 s gives a 1.25-kg object an acceleration of 3.2 m/s 2 on a frictionless table. What impulse does this force exert on the object?","choices":[{"label":"A","text":"2.6 kg ∙ m/s"},{"label":"B","text":"8.4 kg ∙ m/s"},{"label":"C","text":"11 kg ∙ m/s"},{"label":"D","text":"26 kg ∙ m/s"}],"images":[],"answer":"B"},{"id":"Units_3-4-q82","source":"Units_3-4","sourceNumber":"82","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A block of mass m = 34 kg and speed V is behind a block of mass M = 81 kg and speed of 0.50 m/s, as shown in the figure. The surface is frictionless and the blocks collide and couple together. After the collision, the blocks have a common speed of 0.90 m/s. What is the magnitude of the impulse exerted on the 34-kg block due to the collision?","choices":[{"label":"A","text":"32 N ∙ s"},{"label":"B","text":"73 N ∙ s"},{"label":"C","text":"41 N ∙ s"},{"label":"D","text":"57 N ∙ s"},{"label":"E","text":"14 N ∙ s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"339","height":"79"}],"answer":"A"},{"id":"Units_3-4-q83","source":"Units_3-4","sourceNumber":"83","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 51-g steel ball is released from rest and falls vertically onto a steel plate. The ball strikes the plate and is in contact with it for 0.50 ms. The ball bounces and returns to its original height. The total time interval for a round trip is 3.00 s. What is the magnitude of the average force exerted on the ball by the plate during contact with the plate?","choices":[{"label":"A","text":"1500 N"},{"label":"B","text":"2000 N"},{"label":"C","text":"2490 N"},{"label":"D","text":"3500 N"},{"label":"E","text":"3000 N"}],"images":[],"answer":"E"},{"id":"Units_3-4-q84","source":"Units_3-4","sourceNumber":"84","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 0.140-kg baseball is dropped from rest. It has a speed of 1.20 m/s just before it hits the ground, and it rebounds with an upward speed of 1.00 m/s. The ball is in contact with the ground for 0.0140 s. What is the average force exerted by the ground on the ball during the time interval of contact?","choices":[{"label":"A","text":"22.0 N downward"},{"label":"B","text":"22.0 N upward"},{"label":"C","text":"2.00 N upward"},{"label":"D","text":"0.00 N"},{"label":"E","text":"2.00 N downward"}],"images":[],"answer":"B"},{"id":"Units_3-4-q85","source":"Units_3-4","sourceNumber":"85","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A batter hits a foul ball. The 0.14-kg baseball that was approaching him at 40 m/s leaves the bat at 30 m/s in a direction perpendicular to the line between the batter and the pitcher. What is the magnitude of the impulse imparted to the baseball?","choices":[{"label":"A","text":"3.5 N ∙ s"},{"label":"B","text":"7.0 N ∙ s"},{"label":"C","text":"9.8 N ∙ s"},{"label":"D","text":"5.6 N ∙ s"},{"label":"E","text":"1.4 N ∙ s"}],"images":[],"answer":"B"},{"id":"Units_3-4-q86","source":"Units_3-4","sourceNumber":"86","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A block of mass m = 5.60 kg, moving on a frictionless surface with a velocity of v i = 6.50 m/s to the right, collides with a block of mass M at rest, as shown in the figure. After the collision, the 5.60-kg block recoils with a velocity of v f = 0.700 m/s to the left. If the blocks are in contact for 0.200 s, what is the magnitude of the average force on the 5.60-kg block, while the two blocks are in contact?","choices":[{"label":"A","text":"102 N"},{"label":"B","text":"192 N"},{"label":"C","text":"182 N"},{"label":"D","text":"0 N"},{"label":"E","text":"202 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"403","height":"98"}],"answer":"E"},{"id":"Units_3-4-q88","source":"Units_3-4","sourceNumber":"88","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A fire hose is pointed toward the door of a burning building in order to knock the door down. This requires a force of 1000 N. If the hose delivers 40 kg of water per second, what is the minimum speed of the stream needed to knock down the door, assuming the water stops upon striking the door?","choices":[{"label":"A","text":"20 m/s"},{"label":"B","text":"30 m/s"},{"label":"C","text":"25 m/s"},{"label":"D","text":"15 m/s"}],"images":[],"answer":"C"},{"id":"Units_3-4-q90","source":"Units_3-4","sourceNumber":"90","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 1200-kg car moving at 15.6 m/s collides with a stationary car of mass 1500 kg. If the two vehicles lock together, what is their common velocity immediately after the collision?","choices":[{"label":"A","text":"12.1 m/s"},{"label":"B","text":"5.5 m/s"},{"label":"C","text":"8.6 m/s"},{"label":"D","text":"6.9 m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q91","source":"Units_3-4","sourceNumber":"91","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 1000-kg whale swims horizontally to the right at a speed of 6.0 m/s. It suddenly collides directly with a stationary seal of mass 200 kg. The seal grabs onto the whale and holds fast. What is the momentum of these two sea creatures just after their collision? You can neglect any drag effects of the water during the brief collision.","choices":[{"label":"A","text":"7200 kg ∙ m/s to the right"},{"label":"B","text":"1200 kg ∙ m/s to the right"},{"label":"C","text":"6000 kg ∙ m/s to the right"},{"label":"D","text":"2000 kg ∙ m/s to the right"},{"label":"E","text":"0.00 kg ∙ m/s to the right"}],"images":[],"answer":"C"},{"id":"Units_3-4-q92","source":"Units_3-4","sourceNumber":"92","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 1000-kg whale swims horizontally to the right at a speed of 6.0 m/s. It suddenly collides directly with a stationary squid of mass 200 kg. The squid grabs onto the whale and holds fast. What is the speed of these two sea creatures just after their collision? You can neglect any drag effects of the water during the brief collision.","choices":[{"label":"A","text":"4.0 m/s"},{"label":"B","text":"5.0 m/s"},{"label":"C","text":"6.0 m/s"},{"label":"D","text":"0.00 m/s"},{"label":"E","text":"3.0 m/s"}],"images":[],"answer":"B"},{"id":"Units_3-4-q95","source":"Units_3-4","sourceNumber":"95","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A car heading north collides at an intersection with a van of the same mass heading east. If they lock together and travel at 28 m/s at 15° north of east just after the collision, how fast was the car initially traveling?","choices":[{"label":"A","text":"11 m/s"},{"label":"B","text":"29 m/s"},{"label":"C","text":"7.2 m/s"},{"label":"D","text":"14 m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q96","source":"Units_3-4","sourceNumber":"96","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 900-kg car is traveling east at 15.0 m/s, and collides with a 750-kg car traveling north at 20.0 m/s. The cars stick together during the collision. In what direction do the interlocked cars move just after the collision?","choices":[{"label":"A","text":"42.0° N of E"},{"label":"B","text":"36.9° N of E"},{"label":"C","text":"45.0° N of E"},{"label":"D","text":"48.0° N of E"},{"label":"E","text":"53.1° N of E"}],"images":[],"answer":"D"},{"id":"Units_3-4-q97","source":"Units_3-4","sourceNumber":"97","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 900-kg car traveling 30.0° south of east at 12.0 m/s collides with a 750-kg car traveling north at 17.0 m/s. The cars stick together when they collide. What is the speed of the interlocked cars just after the collision?","choices":[{"label":"A","text":"20.4 m/s"},{"label":"B","text":"25.0 m/s"},{"label":"C","text":"7.21 m/s"},{"label":"D","text":"12.2 m/s"},{"label":"E","text":"17.3 m/s"}],"images":[],"answer":"C"},{"id":"Units_3-4-q98","source":"Units_3-4","sourceNumber":"98","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 1500-kg car traveling at 90 km/h toward the east collides with a 3000-kg car traveling at 60 km/h toward the south. The two cars stick together during the collision. What is the speed of the interlocked cars after the collision?","choices":[{"label":"A","text":"14 m/s"},{"label":"B","text":"22 m/s"},{"label":"C","text":"17 m/s"},{"label":"D","text":"8.3 m/s"}],"images":[],"answer":"A"},{"id":"Units_3-4-q99","source":"Units_3-4","sourceNumber":"99","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 1500-kg car traveling at 90.0 km/h toward the east collides with a 3000-kg car traveling at 60.0 km/h toward the south. The two cars stick together during the collision. What is the direction of motion of the interlocked cars after the collision?","choices":[{"label":"A","text":"53.1° E of S"},{"label":"B","text":"36.9° E of S"},{"label":"C","text":"53.1° S of E"},{"label":"D","text":"36.9° S of E"}],"images":[],"answer":"C"},{"id":"Units_3-4-q100","source":"Units_3-4","sourceNumber":"100","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Two fun-loving farm dogs, Rover and Bowser, run through the fields and then jump from different directions onto the frictionless ice of a pond Rover there slides eastward with a momentum of 24 kg ∙ m/s, and Bowser slides northward with momentum 10 kg ∙ m/s. When they collide, each grabs the other's collar and does not let go. What is the magnitude of their combined momentum after the collision?","choices":[{"label":"A","text":"34 kg ∙ m/s"},{"label":"B","text":"14 kg ∙ m/s"},{"label":"C","text":"26 kg ∙ m/s"},{"label":"D","text":"It cannot be determined without knowing the masses and velocities of the dogs."}],"images":[],"answer":"C"},{"id":"Units_3-4-q103","source":"Units_3-4","sourceNumber":"103","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Three objects are thrown off the roof of a building at the same speed. Object I is thrown horizontally, Object II is thrown at an angle 30º above the horizontal, and Object III is thrown at an angle 30º below the horizontal. Air resistance is negligible for each of the three objects. Which of the following correctly ranks the speeds of the three objects, v If , v IIf , and v IIIf , at the instant before they hit the ground?","choices":[{"label":"A","text":"v IIf = v IIIf < v If"},{"label":"B","text":"v If < v IIf = v IIIf"},{"label":"C","text":"v If = v IIf = v IIIf"},{"label":"D","text":"v IIIf < v IIf < v If"},{"label":"E","text":"v If < v IIf < v IIIf"}],"images":[],"answer":"C"},{"id":"Units_3-4-q104","source":"Units_3-4","sourceNumber":"104","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"A person carries a book horizontally at a constant speed. Which of the following accurately describes the total mechanical energy of the Earth-book system during this time? Select two answers.","choices":[{"label":"A","text":"The total mechanical energy is unchanged, because there is no change in the book's kinetic energy or the system's gravitational potential energy as the book is carried."},{"label":"B","text":"The total mechanical energy increases, because the person does positive work on the book by exerting a force in the same direction as its displacement."},{"label":"C","text":"The total mechanical energy increases, because the person does positive work while carrying the book, and the Earth does a lesser magnitude of negative work."},{"label":"D","text":"The total mechanical energy is unchanged, because the person does positive work while carrying the book, and the Earth does the same amount of negative work."},{"label":"E","text":"The total mechanical energy increases, because the kinetic energy of the book is increasing."}],"images":[],"answer":"A, D"},{"id":"Units_3-4-q107","source":"Units_3-4","sourceNumber":"107","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"Three processes are described below. We choose the Earth and the box to be the system we consider. Choose two processes in which there is work done on the system.","choices":[{"label":"A","text":"A box is resting on the ground. A person picks up the box, and then drops it. The box falls, and comes to rest in its original location."},{"label":"B","text":"A box is being held at rest a few meters above the ground by a person."},{"label":"C","text":"A box is sliding down a smooth incline. As it slides down, its speed increases (ignore friction)."},{"label":"D","text":"After being thrown upward, a box slows down as it approaches the peak of its flight (ignore air resistance)."},{"label":"E","text":"A box is sliding down a rough incline at a constant speed."}],"images":[],"answer":"A, E"},{"id":"Units_3-4-q108","source":"Units_3-4","sourceNumber":"108","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"Person X pushes twice as hard against a stationary brick wall as person Y. Which one of the following statements is correct?","choices":[{"label":"A","text":"Both do positive work on the wall, but person X does one-half the work of person Y."},{"label":"B","text":"Both do the same amount of positive work on the wall."},{"label":"C","text":"Both do positive work on the wall, but person X does four times the work of person Y."},{"label":"D","text":"Both do zero work on the wall."},{"label":"E","text":"Both do positive work on the wall, but person X does twice the work of person Y."}],"images":[],"answer":"D"},{"id":"Units_3-4-q109","source":"Units_3-4","sourceNumber":"109","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Two men, Joel and Jerry, push against a car that has stalled, trying unsuccessfully to get it moving. Jerry stops after 10 min, while Joel is able to push for 5 min longer. Compare the work they do on the car.","choices":[{"label":"A","text":"Joel does 50% more work on the car than Jerry."},{"label":"B","text":"Jerry does 50% more work on the car than Joel."},{"label":"C","text":"Joel does 25% more work on the car than Jerry."},{"label":"D","text":"Joel does 75% more work on the car than Jerry."},{"label":"E","text":"Neither of them does any work on the car."}],"images":[],"answer":"E"},{"id":"Units_3-4-q110","source":"Units_3-4","sourceNumber":"110","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"If the force on an object is in the negative direction, the work it does on the object must be","choices":[{"label":"A","text":"positive."},{"label":"B","text":"negative."},{"label":"C","text":"The work could be either positive, negative, or zero, depending on the direction of the object's displacement."}],"images":[],"answer":"C"},{"id":"Units_3-4-q111","source":"Units_3-4","sourceNumber":"111","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"You throw a baseball straight up. Analyzing the system consisting of just the baseball, compare the sign of the work done by Earth on the ball while the ball goes up with the sign of the work done by Earth while the ball goes down.","choices":[{"label":"A","text":"The work is negative on the way up and on the way down because the gravitational force is always downward."},{"label":"B","text":"The work is zero in both portions of the motion."},{"label":"C","text":"The work is positive on the way up and positive on the way down."},{"label":"D","text":"The work is positive on the way up and negative on the way down."},{"label":"E","text":"The work is negative on the way up and positive on the way down."}],"images":[],"answer":"E"},{"id":"Units_3-4-q112","source":"Units_3-4","sourceNumber":"112","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Which one has larger kinetic energy: a 500-kg object moving at 40 m/s or a 1000-kg object moving at 20 m/s?","choices":[{"label":"A","text":"The 500-kg object"},{"label":"B","text":"The 1000-kg object"},{"label":"C","text":"Both have the same kinetic energy."}],"images":[],"answer":"A"},{"id":"Units_3-4-q113","source":"Units_3-4","sourceNumber":"113","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A truck has four times the mass of a car and is moving with twice the speed of the car. If K t and K c refer to the kinetic energies of truck and car respectively, it is correct to say that","choices":[{"label":"A","text":"K t = 16 K c ."},{"label":"B","text":"K t = 2 K c ."},{"label":"C","text":"K t = K c."},{"label":"D","text":"K t = K c ."},{"label":"E","text":"K t = 4 K c ."}],"images":[{"src":"data:image/jpeg;base64,","alt":"(1/2)","width":null,"height":null}],"answer":"E"},{"id":"Units_3-4-q114","source":"Units_3-4","sourceNumber":"114","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"The graph in the figure above shows the time dependence of the vertical height of a ball from the floor with marked initial and final states. Choose all the work-energy bar charts (a) to (d) that can represent this process (multiple answers may be correct).","choices":[{"label":"A","text":"K i + U gi + W = K f + U gf"},{"label":"B","text":"K i + U gi + W = K f + U gf"},{"label":"C","text":"K i + U gi + W = K f + U gf"},{"label":"D","text":"K i + U gi + W = K f + U gf"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"375","height":"206"},{"src":"data:image/jpeg;base64,","alt":"","width":"318","height":"255"},{"src":"data:image/jpeg;base64,","alt":"","width":"316","height":"255"},{"src":"data:image/jpeg;base64,","alt":"","width":"318","height":"255"},{"src":"data:image/jpeg;base64,","alt":"","width":"316","height":"252"}],"answer":"B, C"},{"id":"Units_3-4-q115","source":"Units_3-4","sourceNumber":"115","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Two boxes of masses m and 2 m are initially at rest on a frictionless sheet of ice. A constant force is exerted horizontally on the smaller box, for a time interval t . After this, the smaller box has a final kinetic energy K . If this is repeated for the larger box, for the same time interval t , what will be true about the larger box's final kinetic energy?","choices":[{"label":"A","text":"The larger box will have a final kinetic energy that is less then K ."},{"label":"B","text":"The larger box will have a final kinetic energy that is greater than K ."},{"label":"C","text":"The larger box will have a final kinetic energy that is equal to K ."},{"label":"D","text":"There is not enough information to compare their final kinetic energies."}],"images":[],"answer":"A"},{"id":"Units_3-4-q116","source":"Units_3-4","sourceNumber":"116","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"You want to load a box into the back of a truck. One way is to lift it straight upward at constant speed, as shown in the image above on the left. Alternatively, you can slide the box up a frictionless loading ramp at a constant speed, as shown in the image above on the right. Which of the following correctly compares the work that you would do on the box-Earth system in each case?","choices":[{"label":"A","text":"You would do the same amount of work in each case, since you would need to exert the same amount of force on each."},{"label":"B","text":"You would do the same amount of work in each case, since the energy change of the system is the same in both scenarios."},{"label":"C","text":"You would do more work by lifting the box straight upward, since the final gravitational potential energy of the system is greater."},{"label":"D","text":"You would do more work by pushing the box up the ramp, since the displacement of the system is greater."},{"label":"E","text":"You would do more work by lifting the box straight upward, since you must exert a greater force on the system."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"806","height":"222"}],"answer":"B"},{"id":"Units_3-4-q117","source":"Units_3-4","sourceNumber":"117","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Your antique car does not have antilock brakes. You slam on the brakes in an emergency, and skid a certain distance on a straight level road. If you had been traveling twice as fast, what distance would the car have skidded, under the same conditions?","choices":[{"label":"A","text":"It would have skidded one half as far."},{"label":"B","text":"It would have skidded 4 times farther."},{"label":"C","text":"It would have skidded 1.4 times farther."},{"label":"D","text":"It would have skidded twice as far."},{"label":"E","text":"It is impossible to tell from the information given."}],"images":[],"answer":"B"},{"id":"Units_3-4-q118","source":"Units_3-4","sourceNumber":"118","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Which requires more work, increasing a car's speed from 0 m/s to 10 m/s or from 10 m/s to 20 m/s?","choices":[{"label":"A","text":"0 m/s to 10 m/s"},{"label":"B","text":"10 m/s to 20 m/s"},{"label":"C","text":"It is the same in both cases."}],"images":[],"answer":"B"},{"id":"Units_3-4-q119","source":"Units_3-4","sourceNumber":"119","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Lisa makes the claim that human exertion is related to the work that a person does on an object. Which of the following scenarios would be most likely to challenge Lisa's idea?","choices":[{"label":"A","text":"Running up a flight of stairs at constant speed."},{"label":"B","text":"Holding a bowling ball at rest above the floor."},{"label":"C","text":"Pushing very lightly on a low-friction cart and noticing that it moves."},{"label":"D","text":"Pushing an initially floating tennis ball downward into a tank of water."}],"images":[],"answer":"B"},{"id":"Units_3-4-q121","source":"Units_3-4","sourceNumber":"121","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"Which of the following experiments would most likely provide the students with additional insights about the relative amounts of elastic energy during the bounce of the ball?","choices":[{"label":"A","text":"They could do an experiment to show that the same ball will not bounce as high off the gym floor if it has been put in the freezer."},{"label":"B","text":"They could do an experiment to see if a ball bounces higher on a soft carpet surface or a hard concrete floor."},{"label":"C","text":"They could compare the elastic energies of two non-identical springs when they are compressed with the same force."},{"label":"D","text":"They could measure the spring constants and the displacements of both the floor and the ball, and use those to compare the elastic energies."}],"images":[],"answer":"D"},{"id":"Units_3-4-q123","source":"Units_3-4","sourceNumber":"123","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"Another student's written explanation states, \"The two blocks have equal final kinetic energies when they cross the finish line because the blower pushed each block equally hard\". If this student were to use similar reasoning to compare the final kinetic energies for the two blocks in each of the experiment below, for which experiment will the student's comparison of the final kinetic energies of the blocks be incorrect?","choices":[{"label":"A","text":"The original experiment is repeated on a table that has significant friction"},{"label":"B","text":"Instead of a blower, each block is pushed by the same compressed spring as the spring is released. The experiment takes place on the original very, very smooth table."},{"label":"C","text":"The experiment is repeated on the same very, very smooth table. The blower pushes both blocks with the same constant forces for the same time interval."},{"label":"D","text":"The smooth table is slanted upward; the blower exerts the same constant force on each block uphill parallel to the table surface over the same distance."}],"images":[],"answer":"C"},{"id":"Units_3-4-q125","source":"Units_3-4","sourceNumber":"125","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"The students find that the thermal energy generated in a given distance is proportional to the square of the speed. Assuming this model, which of the following graphs of terminal velocity vs. number of filters best represents the data that might result from careful experiments?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"315","height":"262"},{"src":"data:image/jpeg;base64,","alt":"","width":"289","height":"241"},{"src":"data:image/jpeg;base64,","alt":"","width":"316","height":"263"},{"src":"data:image/jpeg;base64,","alt":"","width":"293","height":"242"}],"answer":"A"},{"id":"Units_3-4-q126","source":"Units_3-4","sourceNumber":"126","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"You and your friend, who has the same mass as you, want to go to the top of the Eiffel Tower. Your friend takes the elevator straight up. You decide to walk up the spiral stairway, taking longer to do so. System A consists of you and Earth. System B consists of your friend and Earth. Compare the gravitational potential energy of the two systems, after you both reach the top.","choices":[{"label":"A","text":"Both systems have the same amount of gravitational potential energy."},{"label":"B","text":"It is impossible to tell, since the distances you both traveled are unknown."},{"label":"C","text":"System A has more gravitational potential energy than system B, because you traveled a greater distance in getting to the top."},{"label":"D","text":"System B has more gravitational potential energy than system A, because your friend got to the top faster."},{"label":"E","text":"It is impossible to tell, since the travel time intervals are unknown."}],"images":[],"answer":"A"},{"id":"Units_3-4-q127","source":"Units_3-4","sourceNumber":"127","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"The graphs shown represent the magnitude F of the force exerted by a spring as a function of the distance x the spring has been stretched. For which one of the graphs is the spring described by Hooke's law?","choices":[{"label":"A","text":"Graph a"},{"label":"B","text":"Graph b"},{"label":"C","text":"Graph c"},{"label":"D","text":"Graph d"},{"label":"E","text":"Graph e"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"576","height":"589"}],"answer":"B"},{"id":"Units_3-4-q128","source":"Units_3-4","sourceNumber":"128","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A dart of mass m and a dart of mass 2 m are launched horizontally on a frictionless table by identical massless springs. Both springs were initially compressed by the same amount. Which of the following statements about these darts are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The dart of mass 2 m leaves the spring with more kinetic energy than the dart of mass m ."},{"label":"B","text":"The dart of mass 2 m leaves the spring moving faster than the dart of mass m ."},{"label":"C","text":"Both darts leave the spring with the same speed."},{"label":"D","text":"The dart of mass m leaves the spring with more kinetic energy than the dart of mass 2 m ."},{"label":"E","text":"The dart of mass m leaves the spring moving faster than the dart of mass 2 m ."}],"images":[],"answer":"C, B"},{"id":"Units_3-4-q129","source":"Units_3-4","sourceNumber":"129","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"When you throw a pebble straight up with initial speed v , it reaches a maximum height H with no air resistance. At what speed should you throw it up vertically so it will go twice as high?","choices":[{"label":"A","text":"4 v"},{"label":"B","text":"v"},{"label":"C","text":"8 v"},{"label":"D","text":"16 v"},{"label":"E","text":"2 v"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"B"},{"id":"Units_3-4-q130","source":"Units_3-4","sourceNumber":"130","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"When you drop a pebble from height H , it reaches the ground with speed v if there is no air resistance. From what height should you drop it so it will reach the ground with twice the speed?","choices":[{"label":"A","text":"H"},{"label":"B","text":"16 H"},{"label":"C","text":"8 H"},{"label":"D","text":"4 H"},{"label":"E","text":"2 H"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_3-4-q131","source":"Units_3-4","sourceNumber":"131","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"When you drop a pebble from height H , it reaches the ground with kinetic energy K if there is no air resistance. From what height should you drop it so it will reach the ground with twice as much kinetic energy?","choices":[{"label":"A","text":"8 H"},{"label":"B","text":"4 H"},{"label":"C","text":"2 H"},{"label":"D","text":"H"},{"label":"E","text":"16 H"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"D"},{"id":"Units_3-4-q132","source":"Units_3-4","sourceNumber":"132","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Two objects, one of mass m and the other of mass 2 m , are dropped from the top of a building. If there is no air resistance, when they hit the ground","choices":[{"label":"A","text":"the more massive one will have one-fourth the kinetic energy of the less massive one."},{"label":"B","text":"both will have the same kinetic energy."},{"label":"C","text":"the more massive one will have twice the kinetic energy of the less massive one."},{"label":"D","text":"the more massive one will have half the kinetic energy of the less massive one."},{"label":"E","text":"the more massive one will have four times the kinetic energy of the less massive one."}],"images":[],"answer":"C"},{"id":"Units_3-4-q133","source":"Units_3-4","sourceNumber":"133","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Swimmers at a water park have a choice of two frictionless water slides, as shown in the figure. Although both slides drop over the same height h , slide 1 is straight while slide 2 is curved, dropping quickly at first and then leveling out. How does the speed v 1 of a swimmer reaching the bottom of slide 1 compare with v 2 , the speed of a swimmer reaching the end of slide 2?","choices":[{"label":"A","text":"v 1 < v 2"},{"label":"B","text":"v 1 > v 2"},{"label":"C","text":"v 1 = v 2"},{"label":"D","text":"The heavier swimmer will have a greater speed than the lighter swimmer, no matter which slide he uses."},{"label":"E","text":"More information is needed about the precise shape of slide 2."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"541","height":"181"}],"answer":"C"},{"id":"Units_3-4-q134","source":"Units_3-4","sourceNumber":"134","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Two frisky otters slide down frictionless mudbanks of the same height but different slopes. The slope of the hill of otter 1 is 30°, while the slope of the hill of otter 2 is 60°. If both start from rest, which otter is moving faster when she reaches the bottom of her hill?","choices":[{"label":"A","text":"Otter 1 is moving faster."},{"label":"B","text":"The otter with more mass is moving faster, no matter which hill she used."},{"label":"C","text":"Otter 2 is moving faster."},{"label":"D","text":"Both otters have the same speed at the bottom."}],"images":[],"answer":"D"},{"id":"Units_3-4-q135","source":"Units_3-4","sourceNumber":"135","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"An object of mass m and an object of mass 2 m are sliding with equal speeds along a level frictionless surface. Then they both slide up the same frictionless hill with no air resistance. Which object rises to a greater height?","choices":[{"label":"A","text":"The object of mass m, because the gravitational force exerted on it is less."},{"label":"B","text":"The object of mass 2 m , because it has more inertia to carry it up the hill."},{"label":"C","text":"The object of mass 2 m , because it has greater initial kinetic energy."},{"label":"D","text":"They both slide up to the same height."}],"images":[],"answer":"D"},{"id":"Units_3-4-q136","source":"Units_3-4","sourceNumber":"136","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"A person stands on the edge of a cliff. She throws three identical rocks with the same speed. Rock X is thrown vertically upward, rock Y is thrown horizontally, and rock Z is thrown vertically downward. If the ground at the base of the cliff is level, which rock hits the ground traveling at the greatest speed if there is no air resistance?","choices":[{"label":"A","text":"Rock Y"},{"label":"B","text":"Rock Z"},{"label":"C","text":"Rock X"},{"label":"D","text":"They all hit the ground traveling at the same speed."}],"images":[],"answer":"D"},{"id":"Units_3-4-q137","source":"Units_3-4","sourceNumber":"137","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Joe and Bill throw identical balls vertically upward. Joe throws his ball with an initial speed twice as high as Bill. If there is no air resistance, the maximum height of Joe's ball will be","choices":[{"label":"A","text":"roughly 1.4 times that of Bill's ball."},{"label":"B","text":"two times that of Bill's ball."},{"label":"C","text":"eight times that of Bill's ball."},{"label":"D","text":"equal to that of Bill's ball."},{"label":"E","text":"four times that of Bill's ball."}],"images":[],"answer":"E"},{"id":"Units_3-4-q138","source":"Units_3-4","sourceNumber":"138","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A stone can slide down one of four different frictionless ramps, as shown in the figure. For which ramp will the speed of the ball be the greatest at the bottom?","choices":[{"label":"A","text":"Ramp X"},{"label":"B","text":"Ramp Z"},{"label":"C","text":"Ramp Y"},{"label":"D","text":"The speed of the ball will be the same for all ramps."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"534","height":"142"}],"answer":"D"},{"id":"Units_3-4-q139","source":"Units_3-4","sourceNumber":"139","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A girl throws a stone from a bridge. Consider the following ways she might throw the stone. The speed of the stone as it leaves her hand is the same in each case. Case A: Thrown straight up. Case B: Thrown straight down. Case C: Thrown out at an angle of 45° above horizontal. Case D: Thrown straight out horizontally. In which case will the speed of the stone be greatest when it hits the water below if there is no air resistance?","choices":[{"label":"A","text":"Case A"},{"label":"B","text":"Case B"},{"label":"C","text":"Case C"},{"label":"D","text":"Case D"},{"label":"E","text":"The speed will be the same in all cases."}],"images":[],"answer":"E"},{"id":"Units_3-4-q140","source":"Units_3-4","sourceNumber":"140","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"A frog of mass m and a lighter frog jump straight up into the air. They push off in such a way that they both have the same kinetic energy just as they leave the ground. Air resistance is negligible. Which of the following statements about these frogs are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Both frogs reach the same maximum height."},{"label":"B","text":"Just as they leave the ground, the lighter frog is moving faster than the heavier frog."},{"label":"C","text":"The heavier frog goes higher than the lighter frog."},{"label":"D","text":"Just as they leave the ground, the heavier frog is moving faster than the lighter frog."},{"label":"E","text":"The lighter frog goes higher than the heavier frog."}],"images":[],"answer":"B, E"},{"id":"Units_3-4-q141","source":"Units_3-4","sourceNumber":"141","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Two identical grasshoppers jump into the air with the same initial speed and experience no air resistance. Grasshopper A goes straight up, but grasshopper B takes off at a 66° angle above the horizontal. Which of the following statements about these grasshoppers are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"At their highest point, both of them have the same amount of gravitational potential energy."},{"label":"B","text":"At their highest point, both of them have the same amount of kinetic energy."},{"label":"C","text":"At their highest point, grasshopper B is moving faster than grasshopper A."},{"label":"D","text":"At their highest point, grasshopper A has more gravitational potential energy than grasshopper B."},{"label":"E","text":"At their highest point, both of them have the same amount of mechanical energy."}],"images":[],"answer":"A, E, C"},{"id":"Units_3-4-q142","source":"Units_3-4","sourceNumber":"142","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A rock of mass m and a rock of mass 2 m are dropped from the same height and experience no significant air resistance as they fall. Which of the following statements about these rocks are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Both rocks have the same speed when they reach the ground."},{"label":"B","text":"Both rocks have the same kinetic energy when they reach the ground."},{"label":"C","text":"The rock of mass 2 m reaches the ground before the rock of mass m ."},{"label":"D","text":"When they reach the ground, the rock of mass 2 m has more kinetic energy than the rock of mass m ."}],"images":[],"answer":"D, A"},{"id":"Units_3-4-q143","source":"Units_3-4","sourceNumber":"143","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 1-kg ball is released from a height of 6 m, and a 2-kg ball is released from a height of 3 m. Air resistance is negligible as they fall. Which of the following statements about these balls are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Both balls will reach the ground with the same kinetic energy."},{"label":"B","text":"Both balls will reach the ground with the same speed."},{"label":"C","text":"Both balls will take the same time interval to reach the ground."},{"label":"D","text":"As they reach the ground, the 1-kg ball will have more kinetic energy than the 2-kg ball because it was dropped from a greater height."},{"label":"E","text":"As they reach the ground, the 1-kg ball will be moving faster than the 2-kg ball."}],"images":[],"answer":"E, A"},{"id":"Units_3-4-q144","source":"Units_3-4","sourceNumber":"144","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A dart of mass m and a dart of mass 2 m are launched vertically by identical massless springs. Both springs were initially compressed by the same amount. There is no significant air resistance. Which of the following statements about these darts are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The dart of mass m goes higher than the dart of mass 2 m ."},{"label":"B","text":"Both darts began moving upward with the same initial speed."},{"label":"C","text":"The dart of mass 2 m goes higher than the dart of mass m ."},{"label":"D","text":"When each dart reaches its peak, both Earth-dart systems have the same gravitational potential energy."},{"label":"E","text":"Both darts reach the same maximum height."}],"images":[],"answer":"D, A"},{"id":"Units_3-4-q145","source":"Units_3-4","sourceNumber":"145","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A sled of mass m and a sled of mass 2 m , both moving horizontally with the same speed, suddenly slide onto a rough patch of snow and eventually come to a stop. The coefficient of kinetic friction between the sleds and the rough snow is the same for both of them. Which of the following statements about these sleds are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The friction force exerted by the snow will do more negative mechanical work on the sled of mass 2 m than on the sled of mass m ."},{"label":"B","text":"Both sleds will slide the same distance on the rough snow before stopping."},{"label":"C","text":"The friction force exerted by the snow will do the same amount of mechanical work on both sleds."},{"label":"D","text":"The sled of mass 2 m will slide farther on the rough snow than the sled of mass m ."},{"label":"E","text":"The sled of mass m will slide farther on the rough snow than the sled of mass 2 m ."}],"images":[],"answer":"A, B"},{"id":"Units_3-4-q146","source":"Units_3-4","sourceNumber":"146","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A sled of mass 2 m and a sled of mass m , both moving horizontally with the same kinetic energy, suddenly slide onto a rough patch of snow and eventually come to a stop. The coefficient of kinetic friction between the sleds and the rough snow is the same for both of them. Which of the following statements about these sleds are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The friction force exerted by the snow will do the same amount of mechanical work on both sleds."},{"label":"B","text":"Both sleds will slide the same distance on the rough snow before stopping."},{"label":"C","text":"The sled of mass 2 m will slide farther on the rough snow than the sled of mass m ."},{"label":"D","text":"The sled of mass m will slide farther on the rough snow than the sled of mass 2 m ."},{"label":"E","text":"On the rough snow, the change in kinetic energy will be the same for both sleds."}],"images":[],"answer":"E, C, B"},{"id":"Units_3-4-q147","source":"Units_3-4","sourceNumber":"147","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A small stone is dropped from a high bridge over a body of water. Initially, the stone-Earth system has a gravitational potential energy of 100 J, but the stone reaches the water with a kinetic energy of only 95 J. Which of the following is true? Select the best answer.","choices":[{"label":"A","text":"The \"missing\" energy is still present as internal energy in the air and the rock."},{"label":"B","text":"The \"missing\" energy is still present as Earth's kinetic energy."},{"label":"C","text":"The \"missing\" energy is still present as potential energy in the water below."},{"label":"D","text":"This is a violation of the principle of conservation of energy."}],"images":[],"answer":"A"},{"id":"Units_3-4-q148","source":"Units_3-4","sourceNumber":"148","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"If the units of your answer are kg ∙ m 2 /s 3 , which of the following types of quantities could your answer be? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Force"},{"label":"B","text":"Work"},{"label":"C","text":"Power"},{"label":"D","text":"Kinetic energy"},{"label":"E","text":"Potential energy"}],"images":[],"answer":"C"},{"id":"Units_3-4-q149","source":"Units_3-4","sourceNumber":"149","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"Two cyclists who have equal mass and have identical bicycles ride up the same mountain, both starting at the same time. Joe rides up a shorter road that has a steeper incline, and Bob rides up a longer road that has a less-steep incline. Joe gets to the top before Bob. If we can ignore road friction and air resistance, which one of the following statements is true?","choices":[{"label":"A","text":"The amount of work done by Joe is equal to the amount of work done by Bob, but the average power put out by Joe is greater than that of Bob."},{"label":"B","text":"Bob and Joe did the same amount of work, and the average power of each cyclist was also the same."},{"label":"C","text":"The amount of work done by Joe is greater than the amount of work done by Bob, and the average power put out by Joe is greater than that of Bob."},{"label":"D","text":"The average power put out by Bob and Joe was the same, but Joe did more work in getting there."}],"images":[],"answer":"A"},{"id":"Units_3-4-q150","source":"Units_3-4","sourceNumber":"150","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"Carrying buckets up a hill, Jill does twice as much work as Jack does and in half the time interval. Jill's power output is","choices":[{"label":"A","text":"the same as Jack's power output."},{"label":"B","text":"one-fourth as much as Jack's power output."},{"label":"C","text":"twice Jack's power output."},{"label":"D","text":"one-half as much as Jack's power output."},{"label":"E","text":"four times Jack's power output."}],"images":[],"answer":"E"},{"id":"Units_3-4-q151","source":"Units_3-4","sourceNumber":"151","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"A force produces power P by doing work W in a time interval T. What power will be produced by a force that does six times as much work in half the time interval?","choices":[{"label":"A","text":"P"},{"label":"B","text":"12 P"},{"label":"C","text":"6 P"},{"label":"D","text":"P"},{"label":"E","text":"P"}],"images":[{"src":"data:image/jpeg;base64,","alt":"(1/6)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"(1/12)","width":null,"height":null}],"answer":"A"},{"id":"Units_3-4-q152","source":"Units_3-4","sourceNumber":"152","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"The momentum of an isolated system is constant","choices":[{"label":"A","text":"only in inelastic collisions."},{"label":"B","text":"only in elastic collisions."},{"label":"C","text":"in both elastic and inelastic collisions."}],"images":[],"answer":"C"},{"id":"Units_3-4-q153","source":"Units_3-4","sourceNumber":"153","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"In an inelastic collision involving an isolated system, the final total momentum is","choices":[{"label":"A","text":"less than the initial momentum."},{"label":"B","text":"precisely the same as the initial momentum."},{"label":"C","text":"more than the initial momentum."}],"images":[],"answer":"B"},{"id":"Units_3-4-q154","source":"Units_3-4","sourceNumber":"154","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 5-kg ball collides inelastically head-on with a 10-kg ball, which is initially stationary. The collision is over so quickly that outside forces exert negligible impulse. Which of the following statements is true? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The magnitude of the change of velocity the 5-kg ball experiences is greater than that of the 10-kg ball."},{"label":"B","text":"The magnitude of the change of velocity the 5-kg ball experiences is equal to that of the 10-kg ball."},{"label":"C","text":"The magnitude of the change of the momentum of the 5-kg ball is equal to the magnitude of the change of momentum of the 10-kg ball."},{"label":"D","text":"The magnitude of the change of velocity the 5-kg ball experiences is less than that of the 10-kg ball."},{"label":"E","text":"Both balls lose all their momentum since the collision is inelastic."}],"images":[],"answer":"C, A"},{"id":"Units_3-4-q155","source":"Units_3-4","sourceNumber":"155","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"In a game of pool, the white cue ball hits the #5 ball and stops, while the #5 ball moves away with the same velocity as the cue ball had originally. Both balls have the same mass. This type of collision is","choices":[{"label":"A","text":"totally inelastic."},{"label":"B","text":"elastic."},{"label":"C","text":"somewhat inelastic."}],"images":[],"answer":"B"},{"id":"Units_3-4-q156","source":"Units_3-4","sourceNumber":"156","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"In the figure, determine the character of the collision. The masses of the blocks, and the velocities before and after, are shown. The collision is","choices":[{"label":"A","text":"elastic."},{"label":"B","text":"partially inelastic."},{"label":"C","text":"totally inelastic."},{"label":"D","text":"characterized by an increase in kinetic energy."},{"label":"E","text":"not possible because momentum is not constant."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"361","height":"96"}],"answer":"A"},{"id":"Units_3-4-q157","source":"Units_3-4","sourceNumber":"157","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"In the figure showing an isolated system, determine the character of the collision. The masses of the blocks, and the velocities before and after, are shown. The collision is","choices":[{"label":"A","text":"elastic."},{"label":"B","text":"partially inelastic."},{"label":"C","text":"totally inelastic."},{"label":"D","text":"characterized by an increase in kinetic energy."},{"label":"E","text":"not possible because momentum is not constant."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"371","height":"96"}],"answer":"E"},{"id":"Units_3-4-q158","source":"Units_3-4","sourceNumber":"158","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"In the diagram, determine the character of the collision. The masses of the blocks, and the velocities before and after, are shown. The collision is","choices":[{"label":"A","text":"elastic."},{"label":"B","text":"partially inelastic."},{"label":"C","text":"totally inelastic."},{"label":"D","text":"characterized by an increase in kinetic energy."},{"label":"E","text":"not possible because momentum is not constant."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"358","height":"94"}],"answer":"C"},{"id":"Units_3-4-q159","source":"Units_3-4","sourceNumber":"159","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"An egg falls from a bird's nest in a tree and feels no effects due to the air. As it falls,","choices":[{"label":"A","text":"only its momentum is constant."},{"label":"B","text":"only its kinetic energy is constant."},{"label":"C","text":"both its kinetic energy and its momentum are constant."},{"label":"D","text":"both its mechanical energy and its momentum are constant."},{"label":"E","text":"only its mechanical energy is constant."}],"images":[],"answer":"E"},{"id":"Units_3-4-q160","source":"Units_3-4","sourceNumber":"160","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"If a quantity you calculated had units of kg ∙ m/s, what type of quantity could it be? (There could be more than one correct choice.)","choices":[{"label":"A","text":"work"},{"label":"B","text":"kinetic energy"},{"label":"C","text":"momentum"},{"label":"D","text":"force"},{"label":"E","text":"impulse"}],"images":[],"answer":"E, C"},{"id":"Units_3-4-q161","source":"Units_3-4","sourceNumber":"161","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"A railroad car collides with and couples with an identical railroad car that is initially at rest. After the collision, the kinetic energy of the system","choices":[{"label":"A","text":"is one third as much as before."},{"label":"B","text":"is half as much as before."},{"label":"C","text":"is the same as before."},{"label":"D","text":"is one fourth as much as before."}],"images":[],"answer":"B"},{"id":"Units_3-4-q162","source":"Units_3-4","sourceNumber":"162","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"A rubber ball bounces off a wall with an initial speed v and reverses its direction so its speed is v right after the bounce. As a result of this bounce, which of the following quantities of the ball are constant? (There could be more than one correct choice.)","choices":[{"label":"A","text":"both the momentum and the kinetic energy of the ball"},{"label":"B","text":"the momentum of the ball"},{"label":"C","text":"the kinetic energy of the ball"},{"label":"D","text":"None of the above quantities are constant."}],"images":[],"answer":"C"},{"id":"Units_3-4-q163","source":"Units_3-4","sourceNumber":"163","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"On a horizontal frictionless air table, a puck runs into a massless horizontal spring that is fastened to the table at one end. The puck compresses the spring by 15 cm as it comes to rest. During the compression process, which quantities are constant?","choices":[{"label":"A","text":"only the kinetic energy of the puck"},{"label":"B","text":"only the momentum of the puck"},{"label":"C","text":"only the mechanical energy (kinetic plus potential) of the puck-spring system"},{"label":"D","text":"the momentum and the mechanical energy of the puck-spring system"},{"label":"E","text":"both the momentum and the kinetic energy of the puck"}],"images":[],"answer":"C"},{"id":"Units_3-4-q164","source":"Units_3-4","sourceNumber":"164","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"Two objects of different mass have equal, non-zero kinetic energies. Which object has the greater magnitude momentum?","choices":[{"label":"A","text":"the object of greater mass"},{"label":"B","text":"the object of lesser mass"},{"label":"C","text":"They both have the same magnitude momentum."}],"images":[],"answer":"A"},{"id":"Units_3-4-q165","source":"Units_3-4","sourceNumber":"165","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"Two objects of different masses have momentum values of equal, non-zero magnitude. Which object has more kinetic energy?","choices":[{"label":"A","text":"the object of greater mass"},{"label":"B","text":"the object of lesser mass"},{"label":"C","text":"They both have the same kinetic energy."}],"images":[],"answer":"B"},{"id":"Units_3-4-q166","source":"Units_3-4","sourceNumber":"166","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"If you want to double the kinetic energy of a gas molecule, by what factor must you increase its momentum?","choices":[{"label":"A","text":"4"},{"label":"B","text":"C) 2"},{"label":"D","text":"2"},{"label":"E","text":"16"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"D"},{"id":"Units_3-4-q167","source":"Units_3-4","sourceNumber":"167","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"If you want to double the momentum of a gas molecule, by what factor must you increase its kinetic energy?","choices":[{"label":"A","text":"4"},{"label":"B","text":"16"},{"label":"C","text":"D) 2"},{"label":"E","text":"2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_3-4-q168","source":"Units_3-4","sourceNumber":"168","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"A firecracker explodes in midair and suddenly breaks up into many fragments. Which of the following statements are true regarding conditions immediately before and immediately after the explosion: I. The total momentum of the fragments is equal to the original momentum of the firecracker. II. The total kinetic energy of the fragments is equal to the original kinetic energy of the firecracker.","choices":[{"label":"A","text":"Statement II only"},{"label":"B","text":"Statement I only"},{"label":"C","text":"Both Statement I and Statement II"},{"label":"D","text":"Neither statement is true."}],"images":[],"answer":"B"},{"id":"Units_3-4-q169","source":"Units_3-4","sourceNumber":"169","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"How do the escape speeds for two rockets, the first with a mass of 2 kg and the second with a mass of 20 kg, compare?","choices":[{"label":"A","text":"The escape speed for the rocket of lesser mass is the same as that for the rocket of greater mass."},{"label":"B","text":"The escape speed for the rocket of lesser mass is smaller than that for the rocket of greater mass."},{"label":"C","text":"The escape speed for the rocket of lesser mass is greater than that for the rocket of greater mass."}],"images":[],"answer":"A"},{"id":"Units_3-4-q170","source":"Units_3-4","sourceNumber":"170","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"Planet A has twice the mass of Planet B. From this information, what can we conclude about the escape speed for Planet A compared to that of Planet B?","choices":[{"label":"A","text":"The escape speed for Planet A must be four times as great as the escape speed from Planet B."},{"label":"B","text":"The escape speed for Planet A must be twice as great as the escape speed from Planet B."},{"label":"C","text":"The escape speed for Planet A is greater than the escape speed from Planet B, but we cannot say how much greater."},{"label":"D","text":"The escape speed for Planet A is the same as the escape speed from Planet B."},{"label":"E","text":"We cannot conclude anything about the escape speed for Planet A without knowing the radii of the two planets."}],"images":[],"answer":"E"},{"id":"Units_3-4-q171","source":"Units_3-4","sourceNumber":"171","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A \"gravity force car\" is powered by the force exerted by Earth on an object of mass 1.0 kg. The object is tied to a rope that is turning the axle of the rear wheels, as shown in the image above. The mass of the car (excluding the hanging object) is also 1.0 kg. As the car accelerates, the object descends a distance of 1.0 m. The rear axle diameter is chosen so that the speed of the object tied to the rope is always negligible compared to the speed of the car as a whole. Assuming that the pulley and wheels are light, and ignoring air resistance and friction in the pulley and wheels, derive an expression for the final speed of the car.","choices":[{"label":"A","text":"19.6 m/s"},{"label":"B","text":"4.9 m/s"},{"label":"C","text":"9.8 m/s"},{"label":"D","text":"4.4 m/s"},{"label":"E","text":"3.1 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"500","height":"276"}],"answer":"E"},{"id":"Units_3-4-q173","source":"Units_3-4","sourceNumber":"173","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A ball of mass m with speed v strikes the floor at an angle with the normal, as shown above. It then rebounds with the same speed and at the same angle. The magnitude of the ball's change in kinetic energy is","choices":[{"label":"A","text":"m (2 vcos0 ) 2"},{"label":"B","text":"mv 2 cos0"},{"label":"C","text":"zero"},{"label":"D","text":"2 mv 2 cos0"},{"label":"E","text":"m ( vcos0 ) 2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"(1/2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"(1/2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"(1/2)","width":null,"height":null}],"answer":"A"},{"id":"Units_3-4-q174","source":"Units_3-4","sourceNumber":"174","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A spring of spring constant k is hanging vertically, at rest. A block is then hung from the spring and allowed to come to rest, stretching the spring by an amount ∆ L . How much work would an external agent (represented by the hand in the diagram) need to do in order to pull down on the block and stretch the spring by an additional amount 2∆ L , as shown in the picture above?","choices":[{"label":"A","text":"4 k (Δ L ) 2"},{"label":"B","text":"2 k (Δ L ) 2"},{"label":"C","text":"k (Δ L ) 2"},{"label":"D","text":"k (Δ L ) 2"},{"label":"E","text":"3 k (Δ L ) 2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"(1/2)","width":null,"height":null}],"answer":"D"},{"id":"Units_3-4-q175","source":"Units_3-4","sourceNumber":"175","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A block on a smooth horizontal surface is placed in contact with a massless spring described by Hooke's law, shown above. The block is moved to the left so that the spring is compressed a distance x from equilibrium and then released from rest. The block has kinetic energy K 1 when it separates from the spring. When the spring is compressed a distance 2 x and the block is released from rest, the kinetic energy of the block when it separates from the spring is","choices":[{"label":"A","text":"K 1 /2"},{"label":"B","text":"4 K 1"},{"label":"C","text":"2 K 1"},{"label":"D","text":"K 1"},{"label":"E","text":"K 1"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"235","height":"112"},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"D"},{"id":"Units_3-4-q176","source":"Units_3-4","sourceNumber":"176","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A block on a smooth horizontal surface is placed in contact with a massless spring described by Hooke's law, as shown above. The block is moved to the left so that the spring is compressed a distance x from equilibrium and then released from rest. The block has speed v 1 when it separates from the spring. When the spring is compressed a distance 2 x and the block is released from rest, the speed of the block when it separates from the spring is","choices":[{"label":"A","text":"2 v 1"},{"label":"B","text":"v 1 /2"},{"label":"C","text":"v 1"},{"label":"D","text":"v 1"},{"label":"E","text":"4 v 1"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"B"},{"id":"Units_3-4-q178","source":"Units_3-4","sourceNumber":"178","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"How much work would a child do while pulling a 12-kg wagon a distance of 4.3 m with a 22 N force?","choices":[{"label":"A","text":"67 J"},{"label":"B","text":"52 J"},{"label":"C","text":"109 J"},{"label":"D","text":"95 J"}],"images":[],"answer":"D"},{"id":"Units_3-4-q179","source":"Units_3-4","sourceNumber":"179","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A child does 350 J of work while pulling a box from the ground up to his tree house at a steady speed with a light rope. The tree house is 4.0 m above the ground. What is the mass of the box?","choices":[{"label":"A","text":"6.7 kg"},{"label":"B","text":"8.9 kg"},{"label":"C","text":"5.3 kg"},{"label":"D","text":"8.0 kg"}],"images":[],"answer":"B"},{"id":"Units_3-4-q180","source":"Units_3-4","sourceNumber":"180","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"You carry a 7.00-kg bag of groceries 1.20 m above the ground at constant speed across a room 2.70 m wide. How much work do you do on the bag in the process?","choices":[{"label":"A","text":"157 J"},{"label":"B","text":"0.00 J"},{"label":"C","text":"185 J"},{"label":"D","text":"82.3 J"}],"images":[],"answer":"B"},{"id":"Units_3-4-q181","source":"Units_3-4","sourceNumber":"181","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"It requires 0.30 kJ of work to fully drive a stake into the ground. If the average resistive force exerted on the stake by the ground is 828 N, how long is the stake?","choices":[{"label":"A","text":"0.31 m"},{"label":"B","text":"0.36 m"},{"label":"C","text":"0.41 m"},{"label":"D","text":"0.23 m"}],"images":[],"answer":"B"},{"id":"Units_3-4-q182","source":"Units_3-4","sourceNumber":"182","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A crane lifts a 425-kg steel beam vertically upward a distance of 95 m. How much work does the crane do on the beam if the beam accelerates upward at 1.8 m/s 2 ? Neglect frictional forces.","choices":[{"label":"A","text":"4.0 × 10 5 J"},{"label":"B","text":"2.7 × 10 5 J"},{"label":"C","text":"4.7 × 10 5 J"},{"label":"D","text":"3.2 × 10 5 J"}],"images":[],"answer":"C"},{"id":"Units_3-4-q183","source":"Units_3-4","sourceNumber":"183","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A traveler pulls on a suitcase strap at an angle 36° above the horizontal. If 555 J of work are done by the strap while moving the suitcase a horizontal distance of 15 m, what is the tension in the strap?","choices":[{"label":"A","text":"46 N"},{"label":"B","text":"52 N"},{"label":"C","text":"37 N"},{"label":"D","text":"56 N"}],"images":[],"answer":"A"},{"id":"Units_3-4-q185","source":"Units_3-4","sourceNumber":"185","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Matthew pulls his little sister Sarah along the horizontal ground in a wagon. He exerts a force on the wagon of 60.0 N at an angle of 37.0° above the horizontal. If he pulls her a distance of 12.0 m, how much work does Matthew do?","choices":[{"label":"A","text":"720 J"},{"label":"B","text":"575 J"},{"label":"C","text":"185 J"},{"label":"D","text":"433 J"}],"images":[],"answer":"B"},{"id":"Units_3-4-q187","source":"Units_3-4","sourceNumber":"187","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A stone with a mass of 1.0 kg is tied to one end of a light string. The other end of the string is fixed on a perfectly smooth horizontal tabletop, so that the stone keeps moving in a circle with a constant speed of 4.0 m/s. The radius of the path is 0.60 m. How much work does the tension in the string do on the stone as it makes one-half of a complete circle?","choices":[{"label":"A","text":"40 J"},{"label":"B","text":"80 J"},{"label":"C","text":"3.8 J"},{"label":"D","text":"0 J"},{"label":"E","text":"100 J"}],"images":[],"answer":"D"},{"id":"Units_3-4-q189","source":"Units_3-4","sourceNumber":"189","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"An object hits a wall and bounces back with half of its original speed. What is the ratio of the final kinetic energy to the initial kinetic energy of the object?","choices":[{"label":"A","text":"1/2"},{"label":"B","text":"1/8"},{"label":"C","text":"1/4"},{"label":"D","text":"1/16"}],"images":[],"answer":"C"},{"id":"Units_3-4-q190","source":"Units_3-4","sourceNumber":"190","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 1000-kg car is moving at 15 km/h. If a 2000-kg truck has 23 times the kinetic energy of the car, how fast is the truck moving?","choices":[{"label":"A","text":"41 km/h"},{"label":"B","text":"72 km/h"},{"label":"C","text":"61 km/h"},{"label":"D","text":"51 km/h"}],"images":[],"answer":"A"},{"id":"Units_3-4-q191","source":"Units_3-4","sourceNumber":"191","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"What is the minimum energy needed to change the speed of a 1600-kg sport utility vehicle from 15.0 m/s to 40.0 m/s?","choices":[{"label":"A","text":"20.0 kJ"},{"label":"B","text":"0.960 MJ"},{"label":"C","text":"1.10 MJ"},{"label":"D","text":"10.0 kJ"},{"label":"E","text":"40.0 kJ"}],"images":[],"answer":"C"},{"id":"Units_3-4-q193","source":"Units_3-4","sourceNumber":"193","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"When a car of mass 1167 kg accelerates from 10.0 m/s to some final speed, 4.00 × 10 5 J of work is done. Find this final speed.","choices":[{"label":"A","text":"22.4 m/s"},{"label":"B","text":"30.8 m/s"},{"label":"C","text":"28.0 m/s"},{"label":"D","text":"25.2 m/s"}],"images":[],"answer":"C"},{"id":"Units_3-4-q194","source":"Units_3-4","sourceNumber":"194","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 10.0-kg dog is running with a speed of 5.00 m/s. What is the minimum magnitude of the work required to stop the dog in 2.40 s?","choices":[{"label":"A","text":"75.0 J"},{"label":"B","text":"100 J"},{"label":"C","text":"50.0 J"},{"label":"D","text":"125 J"}],"images":[],"answer":"D"},{"id":"Units_3-4-q195","source":"Units_3-4","sourceNumber":"195","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"How large a net force is required to accelerate a 1600-kg SUV from rest to a speed of 25 m/s in a distance of 200 m?","choices":[{"label":"A","text":"1600 N"},{"label":"B","text":"200 N"},{"label":"C","text":"0 N"},{"label":"D","text":"400 N"},{"label":"E","text":"2500 N"}],"images":[],"answer":"E"},{"id":"Units_3-4-q196","source":"Units_3-4","sourceNumber":"196","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 100-N force has a horizontal component of 80 N and a vertical component of 60 N. The force is applied to a cart on a level frictionless floor. The cart starts from rest and moves 2.0 m horizontally along the floor due to this force. What is the cart's final kinetic energy?","choices":[{"label":"A","text":"120 J"},{"label":"B","text":"zero"},{"label":"C","text":"160 J"},{"label":"D","text":"200 J"}],"images":[],"answer":"C"},{"id":"Units_3-4-q197","source":"Units_3-4","sourceNumber":"197","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 1000-kg car experiences a net force of 9500 N while slowing down from 30 m/s to 15.9 m/s. How far does it travel while slowing down?","choices":[{"label":"A","text":"41 m"},{"label":"B","text":"34 m"},{"label":"C","text":"37 m"},{"label":"D","text":"31 m"}],"images":[],"answer":"B"},{"id":"Units_3-4-q198","source":"Units_3-4","sourceNumber":"198","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A stone initially moving at 8.0 m/s on a level surface comes to rest due to friction after it travels 11 m. What is the coefficient of kinetic friction between the stone and the surface?","choices":[{"label":"A","text":"0.80"},{"label":"B","text":"0.25"},{"label":"C","text":"0.30"},{"label":"D","text":"0.43"},{"label":"E","text":"0.13"}],"images":[],"answer":"C"},{"id":"Units_3-4-q199","source":"Units_3-4","sourceNumber":"199","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A sled having a certain initial speed on a horizontal surface comes to rest after traveling 10 m. If the coefficient of kinetic friction between the object and the surface is 0.20, what was the initial speed of the object?","choices":[{"label":"A","text":"7.2 m/s"},{"label":"B","text":"6.3 m/s"},{"label":"C","text":"9.8 m/s"},{"label":"D","text":"8.9 m/s"},{"label":"E","text":"3.6 m/s"}],"images":[],"answer":"B"},{"id":"Units_3-4-q200","source":"Units_3-4","sourceNumber":"200","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"On an alien planet, an object moving at 4.0 m/s on the horizontal ground comes to rest after traveling a distance of 10 m. If the coefficient of kinetic friction between the object and the surface is 0.20, what is the value of g on that planet?","choices":[{"label":"A","text":"10 m/s 2"},{"label":"B","text":"12 m/s 2"},{"label":"C","text":"6.0 m/s 2"},{"label":"D","text":"8.0 m/s 2"},{"label":"E","text":"4.0 m/s 2"}],"images":[],"answer":"E"},{"id":"Units_3-4-q201","source":"Units_3-4","sourceNumber":"201","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A driver, traveling at 22 m/s, brakes her 2000 kg truck to stop for a red light. How much internal energy is produced?","choices":[{"label":"A","text":"9.7 × 10 5 J"},{"label":"B","text":"4.4 × 10 4 J"},{"label":"C","text":"2.2 × 10 4 J"},{"label":"D","text":"4.8 × 10 5 J"}],"images":[],"answer":"D"},{"id":"Units_3-4-q202","source":"Units_3-4","sourceNumber":"202","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"The kinetic friction force that a horizontal surface exerts on a 60.0-kg object is 50.0 N. If the initial speed of the object is 25.0 m/s, what distance will it slide before coming to a stop?","choices":[{"label":"A","text":"15.0 m"},{"label":"B","text":"750 m"},{"label":"C","text":"375 m"},{"label":"D","text":"30.0 m"}],"images":[],"answer":"C"},{"id":"Units_3-4-q203","source":"Units_3-4","sourceNumber":"203","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A stone is moving on a rough level surface. It has 24 J of kinetic energy, and the friction force on it is a constant 0.50 N. What is the maximum distance it can slide?","choices":[{"label":"A","text":"12 m"},{"label":"B","text":"2.0 m"},{"label":"C","text":"24 m"},{"label":"D","text":"48 m"}],"images":[],"answer":"D"},{"id":"Units_3-4-q204","source":"Units_3-4","sourceNumber":"204","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"In a ballistics test, a 28-g bullet pierces a sand bag that is 30 cm thick. If the initial bullet velocity was 55 m/s and it emerged from the sandbag moving at 18 m/s, what was the magnitude of the friction force (assuming it to be constant) that the bullet experienced while it traveled through the bag?","choices":[{"label":"A","text":"13 N"},{"label":"B","text":"38 N"},{"label":"C","text":"130 N"},{"label":"D","text":"1.3 N"}],"images":[],"answer":"C"},{"id":"Units_3-4-q205","source":"Units_3-4","sourceNumber":"205","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A certain car traveling at 34.0 mi/h skids to a stop in 29.0 meters from the point where the brakes were applied. In approximately what distance would the car have stopped had it been going 105.4 mi/h?","choices":[{"label":"A","text":"90.0 m"},{"label":"B","text":"158 m"},{"label":"C","text":"279 m"},{"label":"D","text":"29.0 m"},{"label":"E","text":"51.0 m"}],"images":[],"answer":"C"},{"id":"Units_3-4-q207","source":"Units_3-4","sourceNumber":"207","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"You do 116 J of work while pulling your sister back on a frictionless swing, whose chains are 5.10 m long, until the swing makes an angle of 32.0° with the vertical. What is your sister's mass?","choices":[{"label":"A","text":"19.0 kg"},{"label":"B","text":"15.3 kg"},{"label":"C","text":"13.0 kg"},{"label":"D","text":"17.6 kg"}],"images":[],"answer":"B"},{"id":"Units_3-4-q208","source":"Units_3-4","sourceNumber":"208","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A tennis ball bounces on the floor three times, and each time it loses 23.0% of its mechanical energy to internal energy. How high does it go on the third bounce, if we released it 4.0 m from the floor?","choices":[{"label":"A","text":"180 mm"},{"label":"B","text":"18 cm"},{"label":"C","text":"240 cm"},{"label":"D","text":"180 cm"}],"images":[],"answer":"D"},{"id":"Units_3-4-q209","source":"Units_3-4","sourceNumber":"209","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"An object of mass 10-kg, hung by a spring described by Hooke's law, causes the spring to stretch 2.0 cm. What is the spring constant (force constant) for this spring?","choices":[{"label":"A","text":"20 N/m"},{"label":"B","text":"500 N/m"},{"label":"C","text":"49 N/m"},{"label":"D","text":"4900 N/m"},{"label":"E","text":"0.20 N/m"}],"images":[],"answer":"D"},{"id":"Units_3-4-q210","source":"Units_3-4","sourceNumber":"210","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A spring described by Hooke's law has a spring constant (force constant) of 2500 N/m. is stretched 4.0 cm. How much work is required to stretch the spring by 4.0 cm?","choices":[{"label":"A","text":"3.0 J"},{"label":"B","text":"1.0 J"},{"label":"C","text":"4.0 J"},{"label":"D","text":"2.0 J"},{"label":"E","text":"0 J"}],"images":[],"answer":"D"},{"id":"Units_3-4-q212","source":"Units_3-4","sourceNumber":"212","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"If 4.0 J of work are performed in stretching a spring described by Hooke's law with a spring constant (force constant) of 2500 N/m, by what distance is the spring stretched?","choices":[{"label":"A","text":"0.3 cm"},{"label":"B","text":"3.2 m"},{"label":"C","text":"5.7 m"},{"label":"D","text":"5.7 cm"},{"label":"E","text":"3.2 cm"}],"images":[],"answer":"D"},{"id":"Units_3-4-q213","source":"Units_3-4","sourceNumber":"213","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"If the work done to stretch a spring described by Hooke's law by 4.0 cm is 6.0 J, what is the spring constant (force constant) of this spring?","choices":[{"label":"A","text":"3500 N/m"},{"label":"B","text":"7500 N/m"},{"label":"C","text":"6000 N/m"},{"label":"D","text":"300 N/m"},{"label":"E","text":"3000 N/m"}],"images":[],"answer":"B"},{"id":"Units_3-4-q214","source":"Units_3-4","sourceNumber":"214","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A spring described by Hooke's law has a spring constant (force constant) of 60 N/m. How much energy does it store when it is stretched by 1.0 cm?","choices":[{"label":"A","text":"0.30 J"},{"label":"B","text":"600 J"},{"label":"C","text":"60 J"},{"label":"D","text":"0.0030 J"}],"images":[],"answer":"D"},{"id":"Units_3-4-q215","source":"Units_3-4","sourceNumber":"215","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"How much work is required to stretch a spring described by Hooke's law with spring constant (force constant) 40 N/m from x = 0.20 m to x = 0.25 m if the unstretched position is at x = 0.00 m?","choices":[{"label":"A","text":"0.80 J"},{"label":"B","text":"0.050 J"},{"label":"C","text":"1.3 J"},{"label":"D","text":"0.45 J"}],"images":[],"answer":"D"},{"id":"Units_3-4-q216","source":"Units_3-4","sourceNumber":"216","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A spring described by Hooke's law with a force constant (spring constant) of 15 N/m is initially compressed by 3.0 cm from its uncompressed position. How much work is required to compress the spring an additional 4.0 cm?","choices":[{"label":"A","text":"0.030 J"},{"label":"B","text":"0.024 J"},{"label":"C","text":"0.0068 J"},{"label":"D","text":"0.012 J"}],"images":[],"answer":"A"},{"id":"Units_3-4-q217","source":"Units_3-4","sourceNumber":"217","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"It takes 87 J of work to stretch a spring described by Hooke's law from 1.4 m to 2.9 m from equilibrium. What is the value of the spring constant (force constant) of this spring?","choices":[{"label":"A","text":"52 N/m"},{"label":"B","text":"39 N/m"},{"label":"C","text":"27 N/m"},{"label":"D","text":"77 N/m"}],"images":[],"answer":"C"},{"id":"Units_3-4-q218","source":"Units_3-4","sourceNumber":"218","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A spring described by Hooke's law with a spring constant (force constant) of 22 N/m is stretched from equilibrium to 2.9 m. How much work is done in the process?","choices":[{"label":"A","text":"120 J"},{"label":"B","text":"93 J"},{"label":"C","text":"190 J"},{"label":"D","text":"47 J"}],"images":[],"answer":"B"},{"id":"Units_3-4-q219","source":"Units_3-4","sourceNumber":"219","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A rock falls from a vertical cliff that is 4.0 m tall and experiences no significant air resistance as it falls. At what speed will the gravitational potential energy of the rock-Earth system (relative to the base of the cliff) be equal to the rock's kinetic energy?","choices":[{"label":"A","text":"8.9 m/s"},{"label":"B","text":"3.1 m/s"},{"label":"C","text":"6.3 m/s"},{"label":"D","text":"4.4 m/s"},{"label":"E","text":"13 m/s"}],"images":[],"answer":"C"},{"id":"Units_3-4-q220","source":"Units_3-4","sourceNumber":"220","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A block slides down a frictionless inclined ramp and experiences no significant air resistance. If the ramp angle is 17.0° above the horizontal and the length of the surface of the ramp is 20.0 m, find the speed of the block as it reaches the bottom of the ramp, assuming it started sliding from rest at the top.","choices":[{"label":"A","text":"114 m/s"},{"label":"B","text":"7.57 m/s"},{"label":"C","text":"19.6 m/s"},{"label":"D","text":"10.7 m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q221","source":"Units_3-4","sourceNumber":"221","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A prankster drops a water balloon from the top of a building. If the balloon is traveling at 29.1 m/s when it strikes a window ledge that is 1.5 m above the ground, how tall is the building? Neglect air resistance.","choices":[{"label":"A","text":"45 m"},{"label":"B","text":"46 m"},{"label":"C","text":"47 m"},{"label":"D","text":"43 m"}],"images":[],"answer":"A"},{"id":"Units_3-4-q222","source":"Units_3-4","sourceNumber":"222","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A spring-loaded dart gun is used to shoot a dart straight up into the air, and the dart reaches a maximum height of 24 meters. The same dart is shot up a second time from the same gun, but this time the spring is compressed only half as far (compared to the first shot). How far up does the dart go this time (neglect all friction and assume Hooke's law describes the spring)?","choices":[{"label":"A","text":"48 m"},{"label":"B","text":"3.0 m"},{"label":"C","text":"6.0 m"},{"label":"D","text":"12 m"}],"images":[],"answer":"C"},{"id":"Units_3-4-q223","source":"Units_3-4","sourceNumber":"223","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A bead is moving with a speed of 20 m/s at position A on the track shown in the figure. This track is friction-free, and there is no appreciable air resistance. What is the speed of the bead at point C?","choices":[{"label":"A","text":"34 m/s"},{"label":"B","text":"20 m/s"},{"label":"C","text":"0 m/s"},{"label":"D","text":"69 m/s"},{"label":"E","text":"We cannot solve this problem without knowing the mass of the bead."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"328","height":"139"}],"answer":"A"},{"id":"Units_3-4-q225","source":"Units_3-4","sourceNumber":"225","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"The figure shows a famous roller coaster ride. You can ignore friction. If the roller coaster leaves point Q from rest, what is its speed at the top of the 25-m hill (point S)?","choices":[{"label":"A","text":"22 m/s"},{"label":"B","text":"120 m/s"},{"label":"C","text":"44 m/s"},{"label":"D","text":"62 m/s"},{"label":"E","text":"10 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"281","height":"128"}],"answer":"A"},{"id":"Units_3-4-q226","source":"Units_3-4","sourceNumber":"226","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"What is the minimum energy needed to lift a 1.0-kg rocket to a height of 200 km and to give it a speed of 8.0 km/s at that height? (Neglect air resistance and the small decrease in g over that distance.)","choices":[{"label":"A","text":"34 MJ"},{"label":"B","text":"34 J"},{"label":"C","text":"34 GJ"},{"label":"D","text":"34 kJ"},{"label":"E","text":"34 TJ"}],"images":[],"answer":"A"},{"id":"Units_3-4-q227","source":"Units_3-4","sourceNumber":"227","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Assuming negligible friction, find the spring constant (force constant) needed for the spring in a \"B-B gun\" to fire a 10-g pellet to a height of 100 m if the spring is initially compressed by 0.10 m?","choices":[{"label":"A","text":"200 N/m"},{"label":"B","text":"20 N/m"},{"label":"C","text":"0.0020 N/m"},{"label":"D","text":"2000 N/m"},{"label":"E","text":"200000 N/m"}],"images":[],"answer":"D"},{"id":"Units_3-4-q228","source":"Units_3-4","sourceNumber":"228","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"If a spring-operated gun can shoot a pellet to a maximum height of 100 m on Earth, how high could the pellet rise if fired on the Moon, where g = 1.6 m/s 2 ?","choices":[{"label":"A","text":"160 m"},{"label":"B","text":"100 m"},{"label":"C","text":"3.6 km"},{"label":"D","text":"17 m"},{"label":"E","text":"610 m"}],"images":[],"answer":"E"},{"id":"Units_3-4-q229","source":"Units_3-4","sourceNumber":"229","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 60-kg skier pushes off the top of a frictionless hill with an initial speed of 4.0 m/s. How fast will she be moving after dropping 10 m in elevation? Air resistance is negligible.","choices":[{"label":"A","text":"0.20 km/s"},{"label":"B","text":"49 m/s"},{"label":"C","text":"15 m/s"},{"label":"D","text":"0.15 km/s"},{"label":"E","text":"10 m/s"}],"images":[],"answer":"C"},{"id":"Units_3-4-q230","source":"Units_3-4","sourceNumber":"230","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"In the figure, a ball hangs by a very light string with its top end fixed. What is the minimum speed of the ball at the bottom of its swing (point","choices":[{"label":"B","text":"in order for it to reach point A, which is 1.0 m above the bottom of the swing?"},{"label":"A","text":"4.4 m/s"},{"label":"B","text":"2.2 m/s"},{"label":"C","text":"4.9 m/s"},{"label":"D","text":"3.1 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"209","height":"158"}],"answer":"A"},{"id":"Units_3-4-q231","source":"Units_3-4","sourceNumber":"231","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 1500-kg car moving at 25 m/s hits an initially uncompressed horizontal spring described by Hooke's law with spring constant (force constant) of 2.0 × 10 6 N/m. What is the maximum distance the spring compresses?","choices":[{"label":"A","text":"0.51 m"},{"label":"B","text":"0.17 m"},{"label":"C","text":"0.34 m"},{"label":"D","text":"0.68 m"}],"images":[],"answer":"D"},{"id":"Units_3-4-q232","source":"Units_3-4","sourceNumber":"232","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A small but dense 2.0-kg stone is attached to one end of a very light rod that is 1.2 m long. The other end of the rod is attached to a frictionless pivot. The rod is raised until it is vertical, with the stone above the pivot. The rod is released and the stone moves in a vertical circle with no air resistance. What is the tension in the rod as the stone moves through the bottom of the circle?","choices":[{"label":"A","text":"20 N"},{"label":"B","text":"59 N"},{"label":"C","text":"39 N"},{"label":"D","text":"78 N"},{"label":"E","text":"98 N"}],"images":[],"answer":"E"},{"id":"Units_3-4-q233","source":"Units_3-4","sourceNumber":"233","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"In a museum exhibit of a simple pendulum, a very small but dense 6.0-kg ball swings at the bottom end of a very light 2.5-m wire, with the top end of the wire fixed. The ball is released from rest when the pendulum wire makes a 65° angle with the vertical, and it swings in a circular arc with no appreciable friction or air resistance. What is the tension in the wire just as the ball swings through its lowest position?","choices":[{"label":"A","text":"0 N"},{"label":"B","text":"130 N"},{"label":"C","text":"59 N"},{"label":"D","text":"11 N"},{"label":"E","text":"68 N"}],"images":[],"answer":"B"},{"id":"Units_3-4-q234","source":"Units_3-4","sourceNumber":"234","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A roller coaster car starts from rest at a height h at the left side of a loop-the-loop, as shown in the figure. It is not attached to the track in any way, and there is no friction from the track or from air resistance. If the radius of the loop is R = 6.0 m, what is the minimum height h for which the roller coaster car will not fall off the track at the top of the loop?","choices":[{"label":"A","text":"8.5 m"},{"label":"B","text":"18 m"},{"label":"C","text":"15 m"},{"label":"D","text":"21 m"},{"label":"E","text":"12 m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"286","height":"152"}],"answer":"C"},{"id":"Units_3-4-q235","source":"Units_3-4","sourceNumber":"235","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A puck is released from rest at a height h at the left side of a loop-the-loop, as shown in the figure. There is no appreciable friction from the track on which the puck slides or from air resistance. If the radius of the loop is R , what is the minimum height h for which the puck will not fall off the track at the top of the loop?","choices":[{"label":"A","text":"2.5 R"},{"label":"B","text":"2.0 R"},{"label":"C","text":"3.0 R"},{"label":"D","text":"3.5 R"},{"label":"E","text":"R"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"286","height":"152"},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_3-4-q236","source":"Units_3-4","sourceNumber":"236","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A small 1.4-N stone slides down a frictionless bowl, starting from rest at the rim. The bowl itself is a hemisphere of radius 75 cm. Just as the stone reaches the bottom of the bowl, how hard is the bowl pushing on it?","choices":[{"label":"A","text":"2.8 N"},{"label":"B","text":"1.4 N"},{"label":"C","text":"4.2 N"},{"label":"D","text":"0.70 N"},{"label":"E","text":"5.6 N"}],"images":[],"answer":"C"},{"id":"Units_3-4-q237","source":"Units_3-4","sourceNumber":"237","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 30-N box is dropped from a height of 10 m and strikes the ground with a speed of 13 m/s. What was the average force the air exerted on the box as it fell?","choices":[{"label":"A","text":"7.2 N"},{"label":"B","text":"2.9 N"},{"label":"C","text":"4.1 N"},{"label":"D","text":"1.2 N"},{"label":"E","text":"0.13 kN"}],"images":[],"answer":"C"},{"id":"Units_3-4-q238","source":"Units_3-4","sourceNumber":"238","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Model a 60-kg skier as a point mass. She starts from rest from the top of a 50-m high slope. If the work done by friction is -6.0 kJ, what is the speed of the skier on reaching the bottom of the slope?","choices":[{"label":"A","text":"24 m/s"},{"label":"B","text":"31 m/s"},{"label":"C","text":"17 m/s"},{"label":"D","text":"28 m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q240","source":"Units_3-4","sourceNumber":"240","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"An object with a mass of 10 kg is initially at rest at the top of a frictionless inclined plane that rises at 30° above the horizontal. At the top, the object is initially 8.0 m from the bottom of the incline, as shown in the figure. After the object is released from this position, it eventually stops at a distance d from the bottom of the inclined plane along a horizontal surface, as shown. The coefficient of kinetic friction between the horizontal surface and the object is 0.20, and air resistance is negligible. Find the distance d .","choices":[{"label":"A","text":"10 m"},{"label":"B","text":"15 m"},{"label":"C","text":"25 m"},{"label":"D","text":"20 m"},{"label":"E","text":"5.0 m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"349","height":"160"}],"answer":"D"},{"id":"Units_3-4-q241","source":"Units_3-4","sourceNumber":"241","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"On a planet where g = 10.0 m/s 2 and air resistance is negligible, a sled is at rest on a rough inclined hill rising at 30° and 8.0 m long as shown in the figure. The object is allowed to move and it stops on a rough horizontal surface, at a distance of 4.0 m from the bottom of the hill. The coefficient of kinetic friction on the hill is 0.40. What is the coefficient of kinetic friction between the horizontal surface and the sled?","choices":[{"label":"A","text":"0.60"},{"label":"B","text":"0.10"},{"label":"C","text":"0.20"},{"label":"D","text":"0.31"},{"label":"E","text":"0.40"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"349","height":"158"}],"answer":"D"},{"id":"Units_3-4-q242","source":"Units_3-4","sourceNumber":"242","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A 0.12-kg block is held in place against a spring by a 35-N horizontal external force. The external force is removed, and the block is projected with a velocity v 1 = 1.2 m/s when it separates from the spring, as shown in the figure. The block descends a ramp and has a velocity v 2 = 1.4 m/s at the bottom of the ramp. The track is frictionless between points A and B. The block enters a rough section at B, extending to E. The coefficient of kinetic friction between the block and the rough surface is 0.26. The block moves on to D, where it stops. By how many centimeters was the spring initially compressed?","choices":[{"label":"A","text":"0.49 cm"},{"label":"B","text":"0.99 cm"},{"label":"C","text":"0.67 cm"},{"label":"D","text":"0.26 cm"},{"label":"E","text":"0.18 cm"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"586","height":"162"}],"answer":"A"},{"id":"Units_3-4-q243","source":"Units_3-4","sourceNumber":"243","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"As shown in the figure, a 1.45-kg block is held in place against the spring by a 21-N horizontal external force. The external force is removed, and the block is projected with a velocity v 1 = 1.2 m/s as it separates from the spring. The block descends a ramp and has a velocity v 2 = 2.1 m/s at the bottom. The track is frictionless between points A and B. The block enters a rough section at B, extending to E. The coefficient of kinetic friction between the block and the rough surface is 0.29. The velocity of the block is v 3 = 1.4 m/s at C. The block moves on to D, where it stops. Model the block as a point mass. How much work is done by friction on the block between points B and C?","choices":[{"label":"A","text":"- 7.0 J"},{"label":"B","text":"- 14 J"},{"label":"C","text":"- 6.4 J"},{"label":"D","text":"- 1.8 J"},{"label":"E","text":"- 3.6 J"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"586","height":"162"}],"answer":"E"},{"id":"Units_3-4-q244","source":"Units_3-4","sourceNumber":"244","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A 0.46-kg block is held in place against the spring by a 30-N horizontal external force. The external force is removed, and the block is projected with a velocity v 1 = 1.2 m/s upon separation from the spring, as shown in the figure. The block descends a ramp and has a velocity v 2 = 1.5 m/s at the bottom. The track is frictionless between points A and B. The block enters a rough section at point B, extending to E. The coefficient of kinetic friction between the block and the rough surface is 0.38. The velocity of the block is v 3 = 1.4 m/s at point C. The block moves on to D, where it stops. What distance does the block travel between points B and D?","choices":[{"label":"A","text":"0.30 m"},{"label":"B","text":"0.039 m"},{"label":"C","text":"0.60 m"},{"label":"D","text":"0.26 m"},{"label":"E","text":"0.40 m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"586","height":"162"}],"answer":"A"},{"id":"Units_3-4-q249","source":"Units_3-4","sourceNumber":"249","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A child pulls on a wagon in the direction it is moving, with a force of 7.5 N. If the wagon moves a total of 42 m in 3.1 min, what is the average power delivered by the child?","choices":[{"label":"A","text":"21 W"},{"label":"B","text":"22 W"},{"label":"C","text":"26 W"},{"label":"D","text":"17 W"}],"images":[],"answer":"D"},{"id":"Units_3-4-q251","source":"Units_3-4","sourceNumber":"251","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 1500-kg car accelerates from rest to 25 m/s in 7.0 s. What is the average power delivered by the engine to the car's motion? (1 hp = 746 W)","choices":[{"label":"A","text":"300 hp"},{"label":"B","text":"180 hp"},{"label":"C","text":"90 hp"},{"label":"D","text":"600 hp"}],"images":[],"answer":"C"},{"id":"Units_3-4-q253","source":"Units_3-4","sourceNumber":"253","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A 1321-kg car climbs a 5.0° slope at a constant speed of 80.0 km/h. Assuming that air resistance may be neglected, at what rate (in kW) must the engine deliver energy to the drive wheels of the car?","choices":[{"label":"A","text":"25 kW"},{"label":"B","text":"38 kW"},{"label":"C","text":"48 kW"},{"label":"D","text":"290 kW"}],"images":[],"answer":"A"},{"id":"Units_3-4-q255","source":"Units_3-4","sourceNumber":"255","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"What is the net power needed to change the speed of a 1600-kg sport utility vehicle from 15.0 m/s to 40.0 m/s in 4.00 seconds?","choices":[{"label":"A","text":"275 kW"},{"label":"B","text":"100 kW"},{"label":"C","text":"14.0 kW"},{"label":"D","text":"140 kW"},{"label":"E","text":"10.0 kW"}],"images":[],"answer":"A"},{"id":"Units_3-4-q257","source":"Units_3-4","sourceNumber":"257","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A sand mover at a quarry lifts 2000 kg of sand per minute a vertical distance of 12 m. The sand is initially at rest and is discharged at the top of the sand mover with speed 5.0 m/s into a loading chute. What minimum power must be supplied to this machine?","choices":[{"label":"A","text":"1.1 kW"},{"label":"B","text":"4.3 kW"},{"label":"C","text":"520 W"},{"label":"D","text":"6.7 kW"},{"label":"E","text":"3.9 kW"}],"images":[],"answer":"B"},{"id":"Units_3-4-q259","source":"Units_3-4","sourceNumber":"259","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 2.0-kg block moving at 5.0 m/s suddenly collides head-on with a 3.0-kg block at rest. If the collision is totally inelastic , what is the speed of the blocks just after the collision?","choices":[{"label":"A","text":"10 m/s"},{"label":"B","text":"2.0 m/s"},{"label":"C","text":"2.5 m/s"},{"label":"D","text":"0 m/s, since the collision is inelastic"}],"images":[],"answer":"B"},{"id":"Units_3-4-q260","source":"Units_3-4","sourceNumber":"260","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 320-g air track glider traveling at 1.25 m/s suddenly collides elastically with a stationary 270-g glider. What is the speed of the 270-g glider just after the collision?","choices":[{"label":"A","text":"1.14 m/s"},{"label":"B","text":"0.678 m/s"},{"label":"C","text":"1.36 m/s"},{"label":"D","text":"0.106 m/s"},{"label":"E","text":"2.72 m/s"}],"images":[],"answer":"C"},{"id":"Units_3-4-q261","source":"Units_3-4","sourceNumber":"261","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 320-g air track glider traveling at 1.25 m/s suddenly collides elastically with a stationary 270-g glider. What is the speed of the 320-g glider just after the collision?","choices":[{"label":"A","text":"0.21 m/s"},{"label":"B","text":"0.68 m/s"},{"label":"C","text":"1.4 m/s"},{"label":"D","text":"0.11 m/s"},{"label":"E","text":"1.1 m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q262","source":"Units_3-4","sourceNumber":"262","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 550-g ball traveling at 8.0 m/s undergoes a sudden head-on elastic collision with a 250-g ball traveling toward it also at 8.0 m/s. What is the speed of the 250-g ball just after the collision?","choices":[{"label":"A","text":"8.0 m/s"},{"label":"B","text":"14 m/s"},{"label":"C","text":"0 m/s"},{"label":"D","text":"15 m/s"},{"label":"E","text":"4.0 m/s"}],"images":[],"answer":"B"},{"id":"Units_3-4-q263","source":"Units_3-4","sourceNumber":"263","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A proton of mass m is at rest when it is suddenly struck head-on by an alpha particle of mass 4 m moving at speed v . If the collision is elastic, what speed will the alpha particle have after the collision?","choices":[{"label":"A","text":"zero"},{"label":"B","text":"5 v /3"},{"label":"C","text":"3 v /5"},{"label":"D","text":"2 v /3"}],"images":[],"answer":"C"},{"id":"Units_3-4-q264","source":"Units_3-4","sourceNumber":"264","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 50-g ball moving at 10 m/s in the + x direction suddenly collides head-on with a stationary ball of mass 100 g. If the collision is elastic, what is the velocity of each ball immediately after the collision?","choices":[{"label":"A","text":"+ 6.7 m/s, -3.3 m/s"},{"label":"B","text":"+ 3.3 m/s, -6.7 m/s"},{"label":"C","text":"- 3.3 m/s, +6.7 m/s"},{"label":"D","text":"- 6.7 m/s, +3.3 m/s"}],"images":[],"answer":"B"},{"id":"Units_3-4-q266","source":"Units_3-4","sourceNumber":"266","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 0.140-kg baseball is dropped from rest from a height of 2.20 m above the ground and experiences negligible air resistance as it falls. It rebounds to a height of 1.60 m. What change in the ball's momentum occurs as it rebounds from the ground?","choices":[{"label":"A","text":"0.117 kg ∙ m/s downward"},{"label":"B","text":"1.70 kg ∙ m/s upward"},{"label":"C","text":"0.117 kg ∙ m/s upward"},{"label":"D","text":"0.350 kg ∙ m/s downward"},{"label":"E","text":"0.350 kg ∙ m/s upward"}],"images":[],"answer":"B"},{"id":"Units_3-4-q268","source":"Units_3-4","sourceNumber":"268","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"In a police ballistics test, a 2.00-g bullet hits and becomes embedded in a 5.00-kg wood block which is hanging, originally stationary from a 1.20-m long string. This causes the block to swing through an arc of 3.50°. What was the speed of the bullet just before it hit the block?","choices":[{"label":"A","text":"16.7 m/s"},{"label":"B","text":"25.3 m/s"},{"label":"C","text":"262 m/s"},{"label":"D","text":"524 m/s"},{"label":"E","text":"789 m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q270","source":"Units_3-4","sourceNumber":"270","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"As shown in the figure, a bullet of mass 0.010 kg moving horizontally suddenly strikes a block of wood of mass 1.5 kg that is suspended as a pendulum. The bullet lodges in the wood, and together they swing upward a vertical distance of 0.40 m. The length of the string is 2.0 m. What was the speed of the bullet just before it struck the wooden block?","choices":[{"label":"A","text":"67 m/s"},{"label":"B","text":"650 m/s"},{"label":"C","text":"420 m/s"},{"label":"D","text":"370 m/s"},{"label":"E","text":"250 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"226","height":"212"}],"answer":"C"},{"id":"Units_3-4-q271","source":"Units_3-4","sourceNumber":"271","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"An 8.0-g bullet is suddenly shot into a 4.0-kg block that is at rest on a frictionless horizontal surface, as shown in the figure. The bullet remains lodged in the block. The block then runs into a spring bumper and compresses it by 3.7 cm. The force constant (spring constant) of the spring is 2500 N/m. What was the initial speed v of the bullet?","choices":[{"label":"A","text":"460 m/s"},{"label":"B","text":"500 m/s"},{"label":"C","text":"440 m/s"},{"label":"D","text":"480 m/s"},{"label":"E","text":"520 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"217","height":"83"}],"answer":"A"},{"id":"Units_3-4-q272","source":"Units_3-4","sourceNumber":"272","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"An 8.0-g bullet is suddenly shot into a 4.0-kg block, at rest on a frictionless horizontal surface, as shown in the figure. The bullet remains lodged in the block. The block then moves into a spring bumper and compresses it by 8.9 cm. The force constant (spring constant) of the spring is 1400 N/m. What is the magnitude of the impulse on the block (including the bullet inside) due to the spring during the entire time interval while the block compresses the spring?","choices":[{"label":"A","text":"10 N ∙ s"},{"label":"B","text":"6.7 N ∙ s"},{"label":"C","text":"8.3 N ∙ s"},{"label":"D","text":"13 N ∙ s"},{"label":"E","text":"12 N ∙ s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"217","height":"83"}],"answer":"D"},{"id":"Units_3-4-q274","source":"Units_3-4","sourceNumber":"274","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"In a certain nuclear reactor, neutrons suddenly collide with deuterons, which have twice the mass of neutrons. In a head-on elastic collision with a stationary deuteron, what fraction of the initial kinetic energy of a neutron is transferred to the deuteron?","choices":[{"label":"A","text":"5/6"},{"label":"B","text":"8/9"},{"label":"C","text":"1/2"},{"label":"D","text":"1/3"},{"label":"E","text":"3/4"}],"images":[],"answer":"B"},{"id":"Units_3-4-q275","source":"Units_3-4","sourceNumber":"275","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"In a certain nuclear reactor, neutrons suddenly collide with carbon nuclei, which have 12 times the mass of neutrons. In a head-on elastic collision with a stationary carbon nucleus, what fraction of its initial speed does the neutron have after the collision?","choices":[{"label":"A","text":"5/6"},{"label":"B","text":"11/13"},{"label":"C","text":"11/12"},{"label":"D","text":"10/13"},{"label":"E","text":"1/12"}],"images":[],"answer":"B"},{"id":"Units_3-4-q277","source":"Units_3-4","sourceNumber":"277","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two simple pendulums of equal length l = 0.45 m consist of cords, each with the top end fixed at the same point and in turn supporting bobs that are small solid steel spheres. The first bob is drawn back to make a 35° angle with the vertical, while the other one is left hanging at rest. If the first bob has a mass of 0.25 kg and the second has a mass of 0.54 kg, how high will the second bob rise above its initial position after it is struck elastically by the first bob, following the first bob's release?","choices":[{"label":"A","text":"3.3 cm"},{"label":"B","text":"3.9 cm"},{"label":"C","text":"2.7 cm"},{"label":"D","text":"4.4 cm"}],"images":[],"answer":"A"},{"id":"Units_3-4-q280","source":"Units_3-4","sourceNumber":"280","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Far from Earth and all other objects, three objects are located as follows: a 3.0-kg object is at the origin, a 4.5-kg object at (0.0 m, 4.0 m) and a 2.5-kg object at (3.0 m, 0.0 m). What is the gravitational potential energy of this system of objects? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"- 3.2 × 10 -10 J"},{"label":"B","text":"- 3.9 × 10 -10 J"},{"label":"C","text":"- 3.8 × 10 -10 J"},{"label":"D","text":"- 3.5 × 10 -10 J"},{"label":"E","text":"- 5.4 × 10 -10 J"}],"images":[],"answer":"A"},{"id":"Units_3-4-q281","source":"Units_3-4","sourceNumber":"281","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Far from Earth and all other objects, three objects are located as follows: a 3.5-kg object is at the origin, a 4.2-kg object at (0.0 m, 7.0 m), and a 6.5-kg object at (24.0 m, 0.0 m). What is the gravitational potential energy of this system of objects? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"- 3.9 × 10 -10 J"},{"label":"B","text":"- 1.4 × 10 -10 J"},{"label":"C","text":"- 3.2 × 10 -10 J"},{"label":"D","text":"- 2.0 × 10 -10 J"},{"label":"E","text":"- 2.8 × 10 -10 J"}],"images":[],"answer":"A"},{"id":"Units_3-4-q282","source":"Units_3-4","sourceNumber":"282","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A projectile is shot straight up from the surface of Earth by means of a very powerful cannon and experiences no appreciable air resistance. If the projectile reaches a height of 35,000 m above Earth's surface, what was the speed of the projectile when it left the cannon? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 , the radius of Earth is 6.38 × 10 6 m, and M earth = 5.97 ∙ 10 24 kg)","choices":[{"label":"A","text":"906 m/s"},{"label":"B","text":"710 m/s"},{"label":"C","text":"505 m/s"},{"label":"D","text":"825 m/s"},{"label":"E","text":"355 m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q283","source":"Units_3-4","sourceNumber":"283","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A certain spherical asteroid has a mass of is 4.65 × 10 17 kg and a radius of 39,600 m. If a 150-kg object is dropped from rest at an altitude of 12,400 m above the surface of this asteroid, with what speed will it hit the surface? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"18.2 m/s"},{"label":"B","text":"22.7 m/s"},{"label":"C","text":"26.2 m/s"},{"label":"D","text":"19.3 m/s"},{"label":"E","text":"13.8 m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q284","source":"Units_3-4","sourceNumber":"284","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"In 1994, fragments of Comet P/Shoemaker-Levy 9 collided with Jupiter. Model these fragments as coming from very far away with no initial speed, and neglect the effect of the Sun. What was their speed when they neared Jupiter's cloud tops, at a distance of 71.4 × 10 6 m from its center? Jupiter has a mass of 1.90 × 10 27 kg, and G = 6.67 × 10 -11 N ∙ m 2 /kg 2 .","choices":[{"label":"A","text":"42,100 m/s"},{"label":"B","text":"35,500 m/s"},{"label":"C","text":"10,400 m/s"},{"label":"D","text":"59,600 m/s"},{"label":"E","text":"11,200 m/s"}],"images":[],"answer":"D"},{"id":"Units_3-4-q285","source":"Units_3-4","sourceNumber":"285","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"The mass of Earth is 9.31 times the mass of Mars, and the radius of Earth is 1.88 times the radius of Mars. The escape speed for Mars is what percent of the escape speed for Earth?","choices":[{"label":"A","text":"22.5%"},{"label":"B","text":"66.2%"},{"label":"C","text":"222%"},{"label":"D","text":"44.9%"},{"label":"E","text":"20.2%"}],"images":[],"answer":"D"},{"id":"Units_3-4-q286","source":"Units_3-4","sourceNumber":"286","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Planet X-39 has a mass equal to 1/3 that of Earth and a radius equal to 1/3 that of Earth. If v is the escape speed for Earth, what is the escape speed for X-39?","choices":[{"label":"A","text":"3 v"},{"label":"B","text":"v"},{"label":"C","text":"6 v"},{"label":"D","text":"v /9"},{"label":"E","text":"9 v"}],"images":[],"answer":"B"},{"id":"Units_3-4-q287","source":"Units_3-4","sourceNumber":"287","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Planet W-70 has a radius of 2.48 × 10 7 m and an escape velocity of 23,300 m/s. What is the mass of W-70? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"3.03 × 10 26 kg"},{"label":"B","text":"4.04 × 10 26 kg"},{"label":"C","text":"1.01 × 10 26 kg"},{"label":"D","text":"2.02 × 10 26 kg"},{"label":"E","text":"2.50 × 10 33 kg"}],"images":[],"answer":"C"},{"id":"Units_3-4-q288","source":"Units_3-4","sourceNumber":"288","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"The value of g at the surface of spherical Asteroid X is 0.00600 m/s 2 , and the escape speed is 9.95 m/s. What is the radius of this asteroid? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"8250 m"},{"label":"B","text":"16,000 m"},{"label":"C","text":"400 m"},{"label":"D","text":"1600 m"},{"label":"E","text":"800 m"}],"images":[],"answer":"A"},{"id":"Units_3-4-q289","source":"Units_3-4","sourceNumber":"289","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"The value of g at the surface of the spherical Asteroid X is 0.0060 m/s 2 and the escape velocity is 10.1 m/s. What is the mass of this asteroid? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"3.5 × 10 12 kg"},{"label":"B","text":"6.7 × 10 13 kg"},{"label":"C","text":"4.9 × 10 14 kg"},{"label":"D","text":"6.5 × 10 15 kg"},{"label":"E","text":"2.3 × 10 16 kg"}],"images":[],"answer":"E"},{"id":"Units_3-4-q291","source":"Units_3-4","sourceNumber":"291","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"To what radius would the Sun have to be compressed in order for it to become a black hole? The mass of the Sun is 1.99 × 10 30 kg, G = 6.67 × 10 -11 N ∙ m 2 /kg 2 , and c = 3.00 × 10 8 m/s.","choices":[{"label":"A","text":"2.66 × 10 6 m"},{"label":"B","text":"6.96 × 10 8 m"},{"label":"C","text":"2950 m"},{"label":"D","text":"3.72 × 10 4 m"},{"label":"E","text":"1470 m"}],"images":[],"answer":"C"},{"id":"Units_3-4-q292","source":"Units_3-4","sourceNumber":"292","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"What mass would have to be compressed to a radius of 1.0 × 10 -15 m (the order of magnitude of the radius of an atomic nucleus) in order for it to become a black hole? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 , c = 3.0 × 10 8 m/s)","choices":[{"label":"A","text":"4.1 × 10 -8 kg"},{"label":"B","text":"8.3 × 10 15 kg"},{"label":"C","text":"1.1 × 10 -6 kg"},{"label":"D","text":"6.7 × 10 11 kg"},{"label":"E","text":"2.2 × 10 3 kg"}],"images":[],"answer":"E"},{"id":"Units_5-6-q2","source":"Units_5-6","sourceNumber":"2","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A space station, depicted above, rotates so that people in the outer ring, at a radius 2 r from the center, experience a radial acceleration of constant magnitude g . What will be the magnitude of the radial acceleration experienced by people in the inner ring, at radius r from the center?","choices":[{"label":"A","text":"4 g"},{"label":"B","text":"g /4"},{"label":"C","text":"g /2"},{"label":"D","text":"2 g"},{"label":"E","text":"g"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"214","height":"199"}],"answer":"E"},{"id":"Units_5-6-q3","source":"Units_5-6","sourceNumber":"3","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The circle shown above represents the path followed by an object moving at constant speed. At four different positions on the circle, the object's motion is described using velocity and acceleration arrows. At which location are the descriptions correct?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"269","height":"248"}],"answer":"D"},{"id":"Units_5-6-q4","source":"Units_5-6","sourceNumber":"4","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Car A drives at speed v around a circular section of an unbanked road with a radius of curvature r . Car B drives at speed 2 v around a different circular section of unbanked road with a radius of curvature 2 r . If the frictional force required to keep Car A on the road without skidding is F , then the frictional force required to keep Car B on the road without skidding is","choices":[{"label":"A","text":"F /2"},{"label":"B","text":"F /4"},{"label":"C","text":"4 F"},{"label":"D","text":"2 F"},{"label":"E","text":"F"}],"images":[],"answer":"E"},{"id":"Units_5-6-q5","source":"Units_5-6","sourceNumber":"5","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"If a satellite moves with constant speed in a perfectly circular orbit around Earth, what is the direction of the acceleration of the satellite?","choices":[{"label":"A","text":"in the direction opposite the satellite's velocity"},{"label":"B","text":"the acceleration is zero because the speed is constant."},{"label":"C","text":"in the direction of the satellite's velocity"},{"label":"D","text":"toward Earth"},{"label":"E","text":"away from Earth"}],"images":[],"answer":"D"},{"id":"Units_5-6-q6","source":"Units_5-6","sourceNumber":"6","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"An object moves in a circular path at a constant speed. Compare the direction of the object's velocity and acceleration vectors.","choices":[{"label":"A","text":"The vectors are perpendicular to each other."},{"label":"B","text":"The vectors point in opposite directions."},{"label":"C","text":"The acceleration is zero but the velocity is constant."},{"label":"D","text":"Both vectors point in the same direction."}],"images":[],"answer":"A"},{"id":"Units_5-6-q7","source":"Units_5-6","sourceNumber":"7","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"The Moon is accelerating toward Earth, so it is gradually getting closer to Earth.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False: It is not gradually approaching."},{"label":"C","text":"False: The Moon is not accelerating toward Earth."}],"images":[],"answer":"B"},{"id":"Units_5-6-q8","source":"Units_5-6","sourceNumber":"8","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"You are making a circular turn in your car on a horizontal road when you come to a big patch of ice, causing the force of friction between the tires and the road to become zero. While the car is on the ice, it","choices":[{"label":"A","text":"moves along a curved path that is neither straight nor circular."},{"label":"B","text":"continues to follow a circular path, but with a radius larger than the original radius."},{"label":"C","text":"moves along a straight-line path in its original direction."},{"label":"D","text":"moves along a straight-line path toward the center of the circle."},{"label":"E","text":"moves along a straight-line path away from the center of the circle."}],"images":[],"answer":"C"},{"id":"Units_5-6-q9","source":"Units_5-6","sourceNumber":"9","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"When a car goes around a circular curve on a horizontal road at constant speed, what force causes it to follow the circular path?","choices":[{"label":"A","text":"the friction force exerted by the road"},{"label":"B","text":"the normal force exerted by the road"},{"label":"C","text":"the gravitational force exerted by the road"},{"label":"D","text":"No force causes the car to do this because the car is traveling at constant speed and therefore has no acceleration."}],"images":[],"answer":"A"},{"id":"Units_5-6-q10","source":"Units_5-6","sourceNumber":"10","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A car goes around a circular curve on a horizontal road at constant speed. What is the direction of the friction force on the car, exerted by the road?","choices":[{"label":"A","text":"perpendicular to the curve, outward"},{"label":"B","text":"tangent to the curve opposite to the direction of the car's motion"},{"label":"C","text":"tangent to the curve in the forward direction"},{"label":"D","text":"perpendicular to the curve, inward"},{"label":"E","text":"There is no friction on the car because its speed is constant."}],"images":[],"answer":"D"},{"id":"Units_5-6-q11","source":"Units_5-6","sourceNumber":"11","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"When an object moves in uniform circular motion, the direction of its acceleration is","choices":[{"label":"A","text":"is directed toward the center of its circular path."},{"label":"B","text":"in the same direction as its velocity vector."},{"label":"C","text":"depends on the speed of the object."},{"label":"D","text":"is directed away from the center of its circular path."},{"label":"E","text":"in the opposite direction of its velocity vector."}],"images":[],"answer":"A"},{"id":"Units_5-6-q12","source":"Units_5-6","sourceNumber":"12","topic":"Unit 8: Fluids","difficulty":"Easy","question":"If you swing a bucket of water fast enough in a vertical circle, at the highest point the water does not spill out. This happens because an outward force balances the gravitational force exerted on the water.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_5-6-q13","source":"Units_5-6","sourceNumber":"13","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Two small spheres, A and B, attract each other gravitationally with a force of magnitude F . If we now double both masses and the separation of the spheres, what will now be the magnitude of the attractive force on each one?","choices":[{"label":"A","text":"F /4"},{"label":"B","text":"8 F"},{"label":"C","text":"F"},{"label":"D","text":"4 F"},{"label":"E","text":"16 F"}],"images":[],"answer":"C"},{"id":"Units_5-6-q15","source":"Units_5-6","sourceNumber":"15","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Which of the force diagrams accurately represents the forces exerted on the car at Point B?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"52","height":"97"},{"src":"data:image/jpeg;base64,","alt":"","width":"55","height":"139"},{"src":"data:image/jpeg;base64,","alt":"","width":"61","height":"139"},{"src":"data:image/jpeg;base64,","alt":"","width":"61","height":"177"}],"answer":"C"},{"id":"Units_5-6-q16","source":"Units_5-6","sourceNumber":"16","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Which of the force diagrams accurately represents the forces exerted on the car at Point C?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"61","height":"177"},{"src":"data:image/jpeg;base64,","alt":"","width":"61","height":"139"},{"src":"data:image/jpeg;base64,","alt":"","width":"55","height":"139"},{"src":"data:image/jpeg;base64,","alt":"","width":"52","height":"97"}],"answer":"A"},{"id":"Units_5-6-q17","source":"Units_5-6","sourceNumber":"17","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A ball moves at a constant speed in a vertical circle when the string breaks at the position shown. Which choice best describes the path of the ball after the string has been cut?","choices":[{"label":"A","text":"P"},{"label":"B","text":"R"},{"label":"C","text":"S"},{"label":"D","text":"Q"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"418","height":"263"}],"answer":"C"},{"id":"Units_5-6-q18","source":"Units_5-6","sourceNumber":"18","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A roller coaster car is on a track that forms a vertical loop. If the car is to just maintain contact with the track at the top of the loop, what is the minimum value for its radial acceleration at the top of the loop?","choices":[{"label":"A","text":"g downward"},{"label":"B","text":"g upward"},{"label":"C","text":"0.5 g downward"},{"label":"D","text":"2 g upward"}],"images":[],"answer":"A"},{"id":"Units_5-6-q19","source":"Units_5-6","sourceNumber":"19","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A coin is on a flat turntable, which is spinning at a constant rate of rotation. A top view of the coin/turntable is shown above. The coin does not slip with respect to the turntable. Which of the following vectors shows the direction of the friction force exerted on the coin at the position shown?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"143","height":"127"},{"src":"data:image/jpeg;base64,","alt":"","width":"48","height":"40"},{"src":"data:image/jpeg;base64,","alt":"","width":"53","height":"33"},{"src":"data:image/jpeg;base64,","alt":"","width":"34","height":"53"},{"src":"data:image/jpeg;base64,","alt":"","width":"51","height":"36"},{"src":"data:image/jpeg;base64,","alt":"","width":"49","height":"41"}],"answer":"A"},{"id":"Units_5-6-q21","source":"Units_5-6","sourceNumber":"21","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A car travels at constant speed along a banked, circular racetrack, shown above. The car is coasting around a turn, with negligible friction. Which of the following statements correctly relates the magnitude of the gravitational and normal forces exerted on the car?","choices":[{"label":"A","text":"N < mg"},{"label":"B","text":"N = mg"},{"label":"C","text":"N > mg"},{"label":"D","text":"Cannot be determined."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"376","height":"168"}],"answer":"C"},{"id":"Units_5-6-q23","source":"Units_5-6","sourceNumber":"23","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Two identical cars are moving with equal speeds on a wet road toward a turn, as shown in the figure above. Car A is on the left, and Car B is on the right. Which car is more likely to slide off the road during the turn and why, assuming their speeds remain unchanged?","choices":[{"label":"A","text":"Both cars are equally likely to slide off the road, because their speeds are equal."},{"label":"B","text":"Both cars are equally likely to slide off the road, because their masses are equal."},{"label":"C","text":"Car A, because the distance it needs to travel the turn is smaller."},{"label":"D","text":"Car A, because it moves through the turn with a smaller radius."},{"label":"E","text":"Car B, because it is closer to the outer side of the turn."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"168","height":"298"}],"answer":"D"},{"id":"Units_5-6-q25","source":"Units_5-6","sourceNumber":"25","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"In which scenario do the two objects have the same magnitude radial acceleration?","choices":[{"label":"A","text":"a"},{"label":"B","text":"b"},{"label":"C","text":"c"},{"label":"D","text":"d"}],"images":[],"answer":"C"},{"id":"Units_5-6-q26","source":"Units_5-6","sourceNumber":"26","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"In which scenario is the radial acceleration of object Q twice that of object P ?","choices":[{"label":"A","text":"a"},{"label":"B","text":"b"},{"label":"C","text":"c"},{"label":"D","text":"d"}],"images":[],"answer":"D"},{"id":"Units_5-6-q27","source":"Units_5-6","sourceNumber":"27","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Two small objects, with masses m and M , are originally a distance r apart, and the magnitude of the gravitational force on each one is F . The masses are changed to 2 m and 2 M , and the distance is changed to 4 r . What is the magnitude of the new gravitational force?","choices":[{"label":"A","text":"F /16"},{"label":"B","text":"4 F"},{"label":"C","text":"16 F"},{"label":"D","text":"F /4"},{"label":"E","text":"F /2"}],"images":[],"answer":"A"},{"id":"Units_5-6-q28","source":"Units_5-6","sourceNumber":"28","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Two small objects, with masses m and M , are originally a distance r apart, and the gravitational force on each one has magnitude F . The second object has its mass changed to 2 M , and the distance is changed to r /4. What is the magnitude of the new gravitational force?","choices":[{"label":"A","text":"16 F"},{"label":"B","text":"2 F"},{"label":"C","text":"F /32"},{"label":"D","text":"32 F"},{"label":"E","text":"F /16"}],"images":[],"answer":"B"},{"id":"Units_5-6-q29","source":"Units_5-6","sourceNumber":"29","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"If you stood on a planet having a mass four times Earth's mass, and a radius two times Earth's radius, the gravitational force exerted on you would be","choices":[{"label":"A","text":"the same as it is on Earth."},{"label":"B","text":"four times more than it is on Earth."},{"label":"C","text":"two times less than it is on Earth."},{"label":"D","text":"two times more than it is on Earth."}],"images":[],"answer":"A"},{"id":"Units_5-6-q30","source":"Units_5-6","sourceNumber":"30","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"A piece of space debris is released from rest at a location that is two Earth radii from the center of Earth. The gravitational force exerted on this debris is","choices":[{"label":"A","text":"one-third of its value on the surface of Earth."},{"label":"B","text":"the same as it is on the surface of Earth."},{"label":"C","text":"one-half of its value on the surface of Earth."},{"label":"D","text":"zero."},{"label":"E","text":"one-quarter of its value on the surface of Earth."}],"images":[],"answer":"E"},{"id":"Units_5-6-q31","source":"Units_5-6","sourceNumber":"31","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A satellite orbits Mars at a distance above its surface equal to 3 times the radius of Mars. If g m is the freefall acceleration at the surface of Mars, what is the freefall acceleration at the location of the satellite?","choices":[{"label":"A","text":"g m /9"},{"label":"B","text":"g m /16"},{"label":"C","text":"g m /3"},{"label":"D","text":"g m"},{"label":"E","text":"0"}],"images":[],"answer":"C"},{"id":"Units_5-6-q32","source":"Units_5-6","sourceNumber":"32","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A hypothetical planet has a mass of one-half that of Earth and a radius of twice that of Earth. What is the freefall acceleration on the planet in terms of g , the freefall acceleration at the surface of Earth?","choices":[{"label":"A","text":"g /2"},{"label":"B","text":"g /4"},{"label":"C","text":"g /16"},{"label":"D","text":"g /8"},{"label":"E","text":"g"}],"images":[],"answer":"E"},{"id":"Units_5-6-q33","source":"Units_5-6","sourceNumber":"33","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"The freefall acceleration on Planet A is one-sixth of what it is on Planet B, and the radius of the Planet A is one-fourth that of Planet B. The mass of Planet A is what fraction of the mass of Planet B?","choices":[{"label":"A","text":"1/6"},{"label":"B","text":"1/12"},{"label":"C","text":"1/24"},{"label":"D","text":"1/16"},{"label":"E","text":"1/96"}],"images":[],"answer":"E"},{"id":"Units_5-6-q34","source":"Units_5-6","sourceNumber":"34","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Two planets have the same freefall acceleration at the surface, but planet B has twice the radius of planet A. If planet A has mass m , what is the mass of planet B?","choices":[{"label":"A","text":"m"},{"label":"B","text":"4 m"},{"label":"C","text":"m /4"},{"label":"D","text":"m"},{"label":"E","text":"m /"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_5-6-q35","source":"Units_5-6","sourceNumber":"35","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Two planets have the same freefall acceleration at the surface, but planet B has twice the mass of planet A. If planet A has radius r , what is the radius of planet B?","choices":[{"label":"A","text":"r"},{"label":"B","text":"r /"},{"label":"C","text":"4 r"},{"label":"D","text":"2 r"},{"label":"E","text":"r"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_5-6-q36","source":"Units_5-6","sourceNumber":"36","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Planet A has twice the mass of Planet B. From this information, what can we conclude about the freefall acceleration at the surface of Planet A compared to that at the surface of Planet B?","choices":[{"label":"A","text":"The freefall acceleration on Planet A must be twice as great as the freefall acceleration on Planet B."},{"label":"B","text":"The freefall acceleration on Planet A is greater than the freefall acceleration on Planet B, but we cannot say how much greater."},{"label":"C","text":"The freefall acceleration on Planet A is the same as the freefall acceleration on Planet B."},{"label":"D","text":"The freefall acceleration on Planet A must be four times as great as the freefall acceleration on Planet B."},{"label":"E","text":"We cannot conclude anything about the freefall acceleration on Planet A without knowing the radii of the two planets."}],"images":[],"answer":"E"},{"id":"Units_5-6-q37","source":"Units_5-6","sourceNumber":"37","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"The reason an astronaut feels \"weightless\" while in a space station orbiting Earth is that","choices":[{"label":"A","text":"the astronaut is in freefall."},{"label":"B","text":"the gravitational force exerted on the astronaut is almost zero."},{"label":"C","text":"the astronaut's acceleration is zero."},{"label":"D","text":"this is a psychological effect associated with rapid motion."},{"label":"E","text":"the astronaut is at a point in space where the gravitational force exerted by the Moon and Earth cancel."}],"images":[],"answer":"A"},{"id":"Units_5-6-q38","source":"Units_5-6","sourceNumber":"38","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A satellite orbits the Earth at a distance r 1 from Earth's center, and completes an orbit in period T . A second satellite is about to be launched into orbit, and engineers need the second satellite to complete an orbit in period 2 T . How must r 2 , the distance of the second satellite from Earth's center, compare to r 1 ?","choices":[{"label":"A","text":"2 r 1 < r 2"},{"label":"B","text":"r 2 = r 1"},{"label":"C","text":"r 1 < r 2 < 2 r 1"},{"label":"D","text":"0 < r 2 < r 1"},{"label":"E","text":"The ratio of the satellites' masses must be known."}],"images":[],"answer":"D"},{"id":"Units_5-6-q39","source":"Units_5-6","sourceNumber":"39","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"What would happen to the force exerted by the Sun on Earth if the Sun expanded and became twice its present size while retaining the same mass?","choices":[{"label":"A","text":"The force would double."},{"label":"B","text":"The force would be one-fourth of the present force."},{"label":"C","text":"The force would stay the same."},{"label":"D","text":"The force would be half the present force."},{"label":"E","text":"The force would quadruple."}],"images":[],"answer":"C"},{"id":"Units_5-6-q40","source":"Units_5-6","sourceNumber":"40","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"The magnitude of the free-fall acceleration on the surface of a particular planet is 2 g . The planet's mass is half the mass of Earth. What is the planet's radius in terms of the radius R E of Earth?","choices":[{"label":"A","text":"R E /4"},{"label":"B","text":"2 R E"},{"label":"C","text":"R E /2"},{"label":"D","text":"R E /2"}],"images":[],"answer":"A"},{"id":"Units_5-6-q41","source":"Units_5-6","sourceNumber":"41","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"What observational data might Newton have used to determine that gravitational force is inversely proportional to the distance squared between the centers of the objects?","choices":[{"label":"A","text":"The data of the acceleration of falling apples."},{"label":"B","text":"The data describing the Moon's orbit (period and radius) and the motion of falling apples."},{"label":"C","text":"The difference between the length of a day during winter and summer."},{"label":"D","text":"The data on moonrise and moonset times."},{"label":"E","text":"The data on the position and speed of comets."}],"images":[],"answer":"B"},{"id":"Units_5-6-q43","source":"Units_5-6","sourceNumber":"43","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"If Earth had twice its present mass but it orbited at the same distance from the Sun as it does now, its orbital period would be","choices":[{"label":"A","text":"2 years."},{"label":"B","text":"4 years."},{"label":"C","text":"1 year."},{"label":"D","text":"6 months."},{"label":"E","text":"3 years."}],"images":[],"answer":"C"},{"id":"Units_5-6-q44","source":"Units_5-6","sourceNumber":"44","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"Satellite A has twice the mass of satellite B, and moves at the same orbital distance from Earth as satellite B. Compare the speeds of the two satellites.","choices":[{"label":"A","text":"The speed of B is equal to the speed of A."},{"label":"B","text":"The speed of B is one-fourth the speed of A."},{"label":"C","text":"The speed of B is twice the speed of A."},{"label":"D","text":"The speed of B is four times the speed of A."},{"label":"E","text":"The speed of B is one-half the speed of A."}],"images":[],"answer":"A"},{"id":"Units_5-6-q45","source":"Units_5-6","sourceNumber":"45","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Suppose our Sun had 4 times its present mass but Earth was still in a circular orbit at the same distance as it is presently. What would be the duration of the year on Earth under those conditions?","choices":[{"label":"A","text":"1/4 as long as the present year"},{"label":"B","text":"four times as long as the present year"},{"label":"C","text":"1/2 as long as the present year"},{"label":"D","text":"the same as the present year"},{"label":"E","text":"twice as long as the present year"}],"images":[],"answer":"C"},{"id":"Units_5-6-q46","source":"Units_5-6","sourceNumber":"46","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"Halley's Comet is in a highly elliptical orbit around the Sun. Therefore the orbital speed of Halley's Comet, while traveling around the Sun,","choices":[{"label":"A","text":"is constant."},{"label":"B","text":"is zero at two points in the orbit."},{"label":"C","text":"increases as it nears the Sun."},{"label":"D","text":"decreases as it nears the Sun."}],"images":[],"answer":"C"},{"id":"Units_5-6-q47","source":"Units_5-6","sourceNumber":"47","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Let the orbital radius of a planet be R and let the orbital period of the planet be T . What quantity is constant for all planets orbiting the Sun, assuming circular orbits?","choices":[{"label":"A","text":"T/R"},{"label":"B","text":"T 2 / R 3"},{"label":"C","text":"T 2 / R"},{"label":"D","text":"T/R 2"},{"label":"E","text":"T 3 / R 2"}],"images":[],"answer":"D"},{"id":"Units_5-6-q52","source":"Units_5-6","sourceNumber":"52","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"An object moves with a constant speed of 30 m/s on a circular track of radius 150 m. What is the magnitude of the acceleration of the object?","choices":[{"label":"A","text":"6.0 m/s 2"},{"label":"B","text":"0 m/s 2"},{"label":"C","text":"0.17 m/s 2"},{"label":"D","text":"5.0 m/s 2"}],"images":[],"answer":"B"},{"id":"Units_5-6-q53","source":"Units_5-6","sourceNumber":"53","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"A point on a wheel of radius 40 cm that is rotating at a constant 5.0 revolutions per second is located 0.20 m from the axis of rotation. What is the radial acceleration of that point?","choices":[{"label":"A","text":"0.050 m/s 2"},{"label":"B","text":"0.00 m/s 2"},{"label":"C","text":"200 m/s 2"},{"label":"D","text":"48 m/s 2"},{"label":"E","text":"1.4 m/s 2"}],"images":[],"answer":"D"},{"id":"Units_5-6-q54","source":"Units_5-6","sourceNumber":"54","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"You are driving at 30.0 m/s on a freeway curve of radius 750.0 m What is the magnitude of your radial acceleration?","choices":[{"label":"A","text":"0.833 m/s 2"},{"label":"B","text":"20.8 m/s 2"},{"label":"C","text":"36.0 m/s 2"},{"label":"D","text":"1.20 m/s 2"}],"images":[],"answer":"D"},{"id":"Units_5-6-q56","source":"Units_5-6","sourceNumber":"56","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A racecar traveling at a constant speed of 50 m/s drives around a circular track that is 500 m in diameter. What is the magnitude of the radial acceleration of the car?","choices":[{"label":"A","text":"2.2 m/s 2"},{"label":"B","text":"0.63 m/s 2"},{"label":"C","text":"0 m/s 2"},{"label":"D","text":"10 m/s 2"},{"label":"E","text":"1.0 m/s 2"}],"images":[],"answer":"B"},{"id":"Units_5-6-q57","source":"Units_5-6","sourceNumber":"57","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A jet plane flying at 600 m/s experiences an acceleration of 4.0 g when pulling out of the circular section of a dive. What is the radius of curvature of this section of the dive?","choices":[{"label":"A","text":"0.64 km"},{"label":"B","text":"5.8 km"},{"label":"C","text":"1.2 km"},{"label":"D","text":"7.0 km"},{"label":"E","text":"9.2 km"}],"images":[],"answer":"E"},{"id":"Units_5-6-q58","source":"Units_5-6","sourceNumber":"58","topic":"Unit 8: Fluids","difficulty":"Hard","question":"In a popular carnival ride called The Centrifuge , shown above, riders stand against the inside wall of a large cylinder, which starts spinning. The radius of the circle traveled by the riders is 5.0 m. The coefficient of static friction between a person's shirt and the wall of the ride is 0.8. At what speed must the riders be moving to not slip downward when the floor lowers?","choices":[{"label":"A","text":"7.8 m/s"},{"label":"B","text":"61.3 m/s"},{"label":"C","text":"39.2 m/s"},{"label":"D","text":"6.3 m/s"},{"label":"E","text":"The mass of the rider must be known."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"188","height":"199"}],"answer":"A"},{"id":"Units_5-6-q59","source":"Units_5-6","sourceNumber":"59","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"In the diagram shown above, the roller coaster cart moves without friction through a circular loop of radius 5 m. At the instant shown, the cart is traveling with speed 10 m/s. Which of the diagrams correctly shows the forces exerted on the cart at that instant?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"214","height":"209"},{"src":"data:image/jpeg;base64,","alt":"","width":"19","height":"84"},{"src":"data:image/jpeg;base64,","alt":"","width":"20","height":"141"},{"src":"data:image/jpeg;base64,","alt":"","width":"24","height":"66"},{"src":"data:image/jpeg;base64,","alt":"","width":"18","height":"106"},{"src":"data:image/jpeg;base64,","alt":"","width":"23","height":"66"}],"answer":"A"},{"id":"Units_5-6-q60","source":"Units_5-6","sourceNumber":"60","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"The conical pendulum shown above swings in a circle of radius 0.60 m and speed 1.4 m/s. What angle does the string make with the vertical?","choices":[{"label":"A","text":"34"},{"label":"B","text":"26"},{"label":"C","text":"18"},{"label":"D","text":"5.0"},{"label":"E","text":"The mass of the pendulum must be known."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"210","height":"179"}],"answer":"C"},{"id":"Units_5-6-q62","source":"Units_5-6","sourceNumber":"62","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A particularly scary roller coaster contains a loop-the-loop in which the car and rider are completely upside down. If the radius of the loop is 13.2 m, what minimum speed must the car have at the top of the loop so that the rider does not fall out while upside down at the top? Assume the rider is not strapped to the car.","choices":[{"label":"A","text":"10.1 m/s"},{"label":"B","text":"14.9 m/s"},{"label":"C","text":"12.5 m/s"},{"label":"D","text":"11.4 m/s"}],"images":[],"answer":"D"},{"id":"Units_5-6-q63","source":"Units_5-6","sourceNumber":"63","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 1000-kg car is moving at 30 m/s around a horizontal unbanked curve with a diameter of 0.20 km. What is the magnitude of the friction force required to keep the car from sliding?","choices":[{"label":"A","text":"9800 N"},{"label":"B","text":"300 N"},{"label":"C","text":"900 N"},{"label":"D","text":"3000 N"},{"label":"E","text":"9000 N"}],"images":[],"answer":"E"},{"id":"Units_5-6-q64","source":"Units_5-6","sourceNumber":"64","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"The curved section of a horizontal highway is a circular unbanked arc of radius 740 m. If the coefficient of static friction between this roadway and typical tires is 0.40, what would be the maximum safe driving speed for this horizontal curved section of highway?","choices":[{"label":"A","text":"54 m/s"},{"label":"B","text":"52 m/s"},{"label":"C","text":"48 m/s"},{"label":"D","text":"46 m/s"},{"label":"E","text":"50 m/s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q65","source":"Units_5-6","sourceNumber":"65","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 0.50-kg toy is attached to the end of a 1.0-m very light string. The toy is whirled in a horizontal circular path on a frictionless tabletop. The maximum tension that the string can withstand without breaking is 350 N. What is the maximum speed the toy can have without breaking the string?","choices":[{"label":"A","text":"13 m/s"},{"label":"B","text":"26 m/s"},{"label":"C","text":"700 m/s"},{"label":"D","text":"19 m/s"}],"images":[],"answer":"B"},{"id":"Units_5-6-q66","source":"Units_5-6","sourceNumber":"66","topic":"Unit 8: Fluids","difficulty":"Medium","question":"One way that future space stations may create artificial gravity is by rotating the station. Consider a cylindrical space station 380 m in diameter that is rotating about its longitudinal axis. Astronauts walk on the inside curved surface of the space station. What time interval is required for each rotation of the cylinder if it is to provide Earth-like conditions for the astronauts?","choices":[{"label":"A","text":"4.4 s"},{"label":"B","text":"6.2 s"},{"label":"C","text":"28 s"},{"label":"D","text":"39 s"}],"images":[],"answer":"C"},{"id":"Units_5-6-q68","source":"Units_5-6","sourceNumber":"68","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 2.0-kg ball is moving with a constant speed of 5.0 m/s in a horizontal circle whose diameter is 1.0 m. What is the magnitude of the net force exerted on the ball?","choices":[{"label":"A","text":"100 N"},{"label":"B","text":"20 N"},{"label":"C","text":"40 N"},{"label":"D","text":"0 N"},{"label":"E","text":"50 N"}],"images":[],"answer":"A"},{"id":"Units_5-6-q69","source":"Units_5-6","sourceNumber":"69","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 1000-kg car is gradually speeding up as it goes around a horizontal unbanked curve with a radius of 100 m. The coefficient of static friction between the tires and the road is 0.35. At what speed will the car begin to skid? The forward component of acceleration of the car is much less than the radial acceleration.","choices":[{"label":"A","text":"24 m/s"},{"label":"B","text":"35 m/s"},{"label":"C","text":"34 m/s"},{"label":"D","text":"19 m/s"},{"label":"E","text":"9.3 m/s"}],"images":[],"answer":"D"},{"id":"Units_5-6-q70","source":"Units_5-6","sourceNumber":"70","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A car moving at a steady 10 m/s on a level highway encounters a bump that has a circular profile with a radius of 30 m. The car maintains its speed over the bump. What is the normal force exerted by the seat of the car on a 60.0-kg passenger when the car is at the top of the bump?","choices":[{"label":"A","text":"390 N"},{"label":"B","text":"790 N"},{"label":"C","text":"490 N"},{"label":"D","text":"590 N"},{"label":"E","text":"200 N"}],"images":[],"answer":"A"},{"id":"Units_5-6-q71","source":"Units_5-6","sourceNumber":"71","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A car moving at a steady 10 m/s on a level highway encounters a depression or dip that has a circular profile with a radius of 30 m. The car maintains its speed as it drives through the depression. What is the normal force exerted by the seat of the car on a 60.0-kg passenger when the car is at the bottom of the depression?","choices":[{"label":"A","text":"590 N"},{"label":"B","text":"490 N"},{"label":"C","text":"790 N"},{"label":"D","text":"200 N"},{"label":"E","text":"390 N"}],"images":[],"answer":"C"},{"id":"Units_5-6-q72","source":"Units_5-6","sourceNumber":"72","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Pulling out of a dive, the pilot of an airplane guides his plane into a vertical circle with a radius of 600 m. At the bottom of the dive, the speed of the airplane is 150 m/s. What is the force exerted by the bottom of the seat on the 70-kg pilot at that instant?","choices":[{"label":"A","text":"690 N down"},{"label":"B","text":"3300 N up"},{"label":"C","text":"490 N down"},{"label":"D","text":"1400 N forward"},{"label":"E","text":"2600 N up"}],"images":[],"answer":"B"},{"id":"Units_5-6-q73","source":"Units_5-6","sourceNumber":"73","topic":"Unit 8: Fluids","difficulty":"Medium","question":"In a carnival ride, passengers stand with their backs against the wall of a cylinder. The cylinder is set into rotation and the floor is lowered away from the passengers, but they remain stuck against the wall of the cylinder. For a cylinder with a 2.0-m radius, what is the minimum speed that the passengers can have so they do not fall if the coefficient of static friction between the passengers and the wall is 0.25?","choices":[{"label":"A","text":"4.9 m/s"},{"label":"B","text":"2.3 m/s"},{"label":"C","text":"8.9 m/s"},{"label":"D","text":"3.0 m/s"},{"label":"E","text":"It depends on the mass of the passengers."}],"images":[],"answer":"C"},{"id":"Units_5-6-q74","source":"Units_5-6","sourceNumber":"74","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 20-g bead is attached to a light 120-cm-long string as shown in the figure. This bead moves in a horizontal circle with a constant speed of 1.5 m/s. What is the tension in the string if the angle α is measured to be 24.6°?","choices":[{"label":"A","text":"0.20 N"},{"label":"B","text":"0.041 N"},{"label":"C","text":"0.089 N"},{"label":"D","text":"0.46 N"},{"label":"E","text":"0.22 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"104","height":"150"}],"answer":"E"},{"id":"Units_5-6-q75","source":"Units_5-6","sourceNumber":"75","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A 20-g bead moves at constant speed in a horizontal circle, attached to a light 120 cm-long string as shown in the figure. If the angle α is measured to be 18°, what is the speed of the bead?","choices":[{"label":"A","text":"0.55 m/s"},{"label":"B","text":"2.0 m/s"},{"label":"C","text":"1.3 m/s"},{"label":"D","text":"1.1 m/s"},{"label":"E","text":"3.8 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"104","height":"150"}],"answer":"D"},{"id":"Units_5-6-q77","source":"Units_5-6","sourceNumber":"77","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A car traveling at a steady 20 m/s rounds an 80-m radius horizontal unbanked curve with the tires on the verge of slipping. What is the maximum speed with which this car can round a second unbanked curve of radius 320 m if the coefficient of static friction between the car's tires and the road surface is the same in both cases?","choices":[{"label":"A","text":"40 m/s"},{"label":"B","text":"80 m/s"},{"label":"C","text":"160 m/s"},{"label":"D","text":"30 m/s"},{"label":"E","text":"70 m/s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q78","source":"Units_5-6","sourceNumber":"78","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 600-kg car is going around a banked curve with a radius of 110 m at a steady speed of 24.5 m/s. What is the appropriate banking angle so that the car stays on its path without the assistance of friction?","choices":[{"label":"A","text":"33.8°"},{"label":"B","text":"29.1°"},{"label":"C","text":"60.9°"},{"label":"D","text":"56.2°"},{"label":"E","text":"13.5°"}],"images":[],"answer":"B"},{"id":"Units_5-6-q79","source":"Units_5-6","sourceNumber":"79","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"The curved section of a speedway is a circular arc having a radius of 190 m. This curve is properly banked for racecars moving at 34 m/s. At what angle with the horizontal is the curved part of the speedway banked?","choices":[{"label":"A","text":"32°"},{"label":"B","text":"26°"},{"label":"C","text":"30°"},{"label":"D","text":"34°"},{"label":"E","text":"28°"}],"images":[],"answer":"A"},{"id":"Units_5-6-q81","source":"Units_5-6","sourceNumber":"81","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Two horizontal curves on a bobsled run are banked at the same angle, but one has twice the radius of the other. The safe speed (for which no friction is needed to stay on the run) for the smaller radius curve is v . What is the safe speed on the larger-radius curve?","choices":[{"label":"A","text":"2 v"},{"label":"B","text":"v"},{"label":"C","text":"v /"},{"label":"D","text":"v /2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"B"},{"id":"Units_5-6-q82","source":"Units_5-6","sourceNumber":"82","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"What is the proper banking angle for an Olympic bobsled to negotiate a 100-m radius turn at 35 m/s without skidding away from the centerline of the curving track?","choices":[{"label":"A","text":"41°"},{"label":"B","text":"51°"},{"label":"C","text":"31°"},{"label":"D","text":"61°"}],"images":[],"answer":"B"},{"id":"Units_5-6-q83","source":"Units_5-6","sourceNumber":"83","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A highway curve of radius 100 m, banked at an angle of 45°, may be negotiated without friction at a speed of","choices":[{"label":"A","text":"31 m/s"},{"label":"B","text":"44 m/s"},{"label":"C","text":"67 m/s"},{"label":"D","text":"22 m/s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q84","source":"Units_5-6","sourceNumber":"84","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A highway curve of radius 80 m is banked at 45°. Suppose that an ice storm hits, and the curve is effectively frictionless. What is the speed with which to take the curve without tending to slide either up or down the surface of the road?","choices":[{"label":"A","text":"9.4 m/s"},{"label":"B","text":"28 m/s"},{"label":"C","text":"The curve cannot be taken safely at any speed."},{"label":"D","text":"780 m/s"}],"images":[],"answer":"B"},{"id":"Units_5-6-q85","source":"Units_5-6","sourceNumber":"85","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"What is the gravitational force exerted on a 59-kg person by another 59-kg person standing 2.0 m away? We can model each person as a small sphere. ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"1.2 × 10 -7 N toward the second person"},{"label":"B","text":"2.0 × 10 -9 N toward the second person"},{"label":"C","text":"5.8 × 10 -8 N toward the second person"},{"label":"D","text":"8.5 × 10 3 N toward the second person"},{"label":"E","text":"9.8 × 10 -10 N toward the second person"}],"images":[],"answer":"C"},{"id":"Units_5-6-q88","source":"Units_5-6","sourceNumber":"88","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"As a 70-kg person stands at the seashore gazing at the tides (which are primarily caused by the Moon), how strong is the gravitational force on that person due to the Moon? The mass of the Moon is 7.35 × 10 22 kg, the distance to the Moon is 3.82 × 10 8 m, and G = 6.67 × 10 -11 N ∙ m 2 /kg 2 .","choices":[{"label":"A","text":"0.0024 N"},{"label":"B","text":"0.00024 N"},{"label":"C","text":"0.024 N"},{"label":"D","text":"0.24 N"}],"images":[],"answer":"A"},{"id":"Units_5-6-q90","source":"Units_5-6","sourceNumber":"90","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"When a spacecraft is launched from Earth toward the Sun, at what distance from Earth will the gravitational forces due to the Sun and Earth be equal in magnitude to each other? Earth's mass is 5.97 × 10 24 kg, the Sun's mass is 1.99 × 10 30 kg, and the Earth-Sun distance is 1.5 × 10 11 m.","choices":[{"label":"A","text":"2.6 × 10 8 m"},{"label":"B","text":"2.6 × 10 10 m"},{"label":"C","text":"1.3 × 10 8 m"},{"label":"D","text":"1.3 × 10 10 m"}],"images":[],"answer":"B"},{"id":"Units_5-6-q91","source":"Units_5-6","sourceNumber":"91","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"​ Mass Radius Orbital radius Orbital period Moon A 4.0 × 10 20 kg unknown 2.0 × 10 8 m 4.0 × 10 6 s Moon B 1.5 × 10 20 kg 2.0 × 10 5 m 3.0 × 10 8 m unknown Mithra is an unknown planet that has two moons, A and B, in circular orbits around it, lying in the same plane. The table summarizes the hypothetical data about these moons. What is the magnitude of the maximum gravitational force that Moon A exerts on Moon B? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"1.6 × 10 13 N"},{"label":"B","text":"4.0 × 10 14 N"},{"label":"C","text":"1.0 × 10 14 N"},{"label":"D","text":"4.4 × 10 13 N"},{"label":"E","text":"2.0 × 10 14 N"}],"images":[],"answer":"D"},{"id":"Units_5-6-q92","source":"Units_5-6","sourceNumber":"92","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"At their closest approach, Venus and Earth are 4.20 × 10 10 m apart. The mass of Venus is 4.87 × 10 24 kg, the mass of Earth is 5.97 × 10 24 kg, and G = 6.67 × 10 -11 N ∙ m 2 /kg 2 . What is the magnitude of the gravitational force exerted by Venus on Earth at that point?","choices":[{"label":"A","text":"1.72 × 10 19 N"},{"label":"B","text":"1.10 × 10 18 N"},{"label":"C","text":"6.30 × 10 20 N"},{"label":"D","text":"4.62 × 10 28 N"},{"label":"E","text":"5.43 × 10 26 N"}],"images":[],"answer":"B"},{"id":"Units_5-6-q93","source":"Units_5-6","sourceNumber":"93","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A spaceship with a mass of 2.8 × 10 6 kg is traveling toward two spherical asteroids, each with a mass of 5.0 × 10 16 kg, that are 40 km apart center-to-center. Its path is perpendicular to the line joining the asteroids and is aimed at the midpoint of that line. What is the net gravitational force exerted by the asteroids on the spaceship when the spaceship is 30 km away from that midpoint? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"18,000 N"},{"label":"B","text":"16,000 N"},{"label":"C","text":"8000 N"},{"label":"D","text":"12,000 N"},{"label":"E","text":"6200 N"}],"images":[],"answer":"D"},{"id":"Units_5-6-q94","source":"Units_5-6","sourceNumber":"94","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Three identical 50-kg spheres are held at the corners of an equilateral triangle, 30 cm on each side. If one of the spheres is released, what is the magnitude of its initial acceleration if the only forces exerted on it are the gravitational forces due to the other two masses? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"1.9 × 10 -8 m/s 2"},{"label":"B","text":"4.2 × 10 -8 m/s 2"},{"label":"C","text":"6.4 × 10 -8 m/s 2"},{"label":"D","text":"3.7 × 10 -8 m/s 2"},{"label":"E","text":"2.5 × 10 -8 m/s 2"}],"images":[],"answer":"C"},{"id":"Units_5-6-q95","source":"Units_5-6","sourceNumber":"95","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"What is the distance from the center of the Moon to the point between Earth and the Moon where the gravitational forces exerted by Earth and the Moon are equal? The mass of Earth is 5.97 × 10 24 kg, the mass of the Moon is 7.35 × 10 22 kg, the center-to-center distance between Earth and the Moon is 3.84 × 10 8 m, and G = 6.67 × 10 -11 N ∙ m 2 /kg 2 .","choices":[{"label":"A","text":"4.69 × 10 6 m"},{"label":"B","text":"3.45 × 10 8 m"},{"label":"C","text":"3.84 × 10 7 m"},{"label":"D","text":"4.69 × 10 7 m"},{"label":"E","text":"3.83 × 10 6 m"}],"images":[],"answer":"B"},{"id":"Units_5-6-q96","source":"Units_5-6","sourceNumber":"96","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"From what height above the surface of Earth should an object be dropped to initially experience an acceleration of 0.54 g ? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 , M earth = 5.97 × 10 24 kg, R earth = 6.38 × 10 6 m)","choices":[{"label":"A","text":"2300 km"},{"label":"B","text":"5400 km"},{"label":"C","text":"1700 km"},{"label":"D","text":"2900 km"}],"images":[],"answer":"A"},{"id":"Units_5-6-q97","source":"Units_5-6","sourceNumber":"97","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"At a certain point above Earth's surface, the freefall acceleration is equal to 7.8 m/s 2 . What is the altitude of this point above Earth's surface? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 , M earth = 5.97 × 10 24 kg, R earth = 6.38 × 10 6 m)","choices":[{"label":"A","text":"770 km"},{"label":"B","text":"1500 km"},{"label":"C","text":"970 km"},{"label":"D","text":"2400 km"},{"label":"E","text":"2000 km"}],"images":[],"answer":"A"},{"id":"Units_5-6-q98","source":"Units_5-6","sourceNumber":"98","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"In another solar system, a planet has an airless moon Zygo that is 4.0 × 10 5 m in diameter. Experiments reveal that a freely falling object at the surface of Zygo accelerates at 0.20 m/s 2 . What is the mass of Zygo? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"1.2 × 10 20 kg"},{"label":"B","text":"4.8 × 10 20 kg"},{"label":"C","text":"2.4 × 10 20 kg"},{"label":"D","text":"4.8 × 10 19 kg"},{"label":"E","text":"2.4 × 10 19 kg"}],"images":[],"answer":"D"},{"id":"Units_5-6-q99","source":"Units_5-6","sourceNumber":"99","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"​ Mass Radius Orbital radius Orbital period Moon A 4.0 × 10 20 kg unknown 2.0 × 10 8 m 4.0 × 10 6 s Moon B 1.5 × 10 20 kg 2.0 × 10 5 m 3.0 × 10 8 m unknown Mithra is an unknown planet that has two airless moons, A and B, in circular orbits around it. The table summarizes the hypothetical data about these moons. If you dropped an object at the surface of Moon B, at what rate would it accelerate? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"0.20 m/s 2"},{"label":"B","text":"0.10 m/s 2"},{"label":"C","text":"0.25 m/s 2"},{"label":"D","text":"0.30 m/s 2"},{"label":"E","text":"0.15 m/s 2"}],"images":[],"answer":"C"},{"id":"Units_5-6-q100","source":"Units_5-6","sourceNumber":"100","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Planet Z-34 has a mass equal to one-third that of Earth and a radius equal to one-third that of Earth. With g representing the freefall acceleration at the surface of Earth, the freefall acceleration at the surface of Z-34 is","choices":[{"label":"A","text":"9 g"},{"label":"B","text":"3 g"},{"label":"C","text":"g /9"},{"label":"D","text":"g /3"},{"label":"E","text":"6 g"}],"images":[],"answer":"D"},{"id":"Units_5-6-q101","source":"Units_5-6","sourceNumber":"101","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"What would be the gravitational force exerted on a 59.1-kg astronaut on a planet twice as massive as Earth and having twice Earth's radius?","choices":[{"label":"A","text":"118 N toward the center of the planet"},{"label":"B","text":"1160 N toward the center of the planet"},{"label":"C","text":"290 N toward the center of the planet"},{"label":"D","text":"1200 N toward the center of the planet"},{"label":"E","text":"580 N toward the center of the planet"}],"images":[],"answer":"C"},{"id":"Units_5-6-q102","source":"Units_5-6","sourceNumber":"102","topic":"Unit 8: Fluids","difficulty":"Medium","question":"What would be the gravitational force exerted on a 59.1-kg astronaut on a planet with the same density as Earth and having twice Earth's radius?","choices":[{"label":"A","text":"2320 N"},{"label":"B","text":"290 N"},{"label":"C","text":"1160 N"},{"label":"D","text":"4630 N"},{"label":"E","text":"579 N"}],"images":[],"answer":"C"},{"id":"Units_5-6-q103","source":"Units_5-6","sourceNumber":"103","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An astronaut goes out for a \"space-walk\" at a distance above the Earth surface equal to the radius of Earth. What is her freefall acceleration at that location?","choices":[{"label":"A","text":"g /"},{"label":"B","text":"zero"},{"label":"C","text":"g"},{"label":"D","text":"g /2"},{"label":"E","text":"g /4"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"C"},{"id":"Units_5-6-q104","source":"Units_5-6","sourceNumber":"104","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The radius of Earth is R . At what distance above Earth's surface will the freefall acceleration be 4.9 m/s 2 ?","choices":[{"label":"A","text":"0.25 R"},{"label":"B","text":"0.41 R"},{"label":"C","text":"1.00 R"},{"label":"D","text":"0.50 R"},{"label":"E","text":"1.41 R"}],"images":[],"answer":"B"},{"id":"Units_5-6-q105","source":"Units_5-6","sourceNumber":"105","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"The mass of Pluto is 1.31 × 10 22 kg and its radius is 1.15 × 10 6 m. What is the acceleration of a freely falling object at the surface of Pluto if it has no atmosphere? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"9.81 m/s 2"},{"label":"B","text":"0.661 m/s 2"},{"label":"C","text":"0.140 m/s 2"},{"label":"D","text":"1.62 m/s 2"},{"label":"E","text":"3.72 m/s 2"}],"images":[],"answer":"B"},{"id":"Units_5-6-q106","source":"Units_5-6","sourceNumber":"106","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"An astronaut drops a marble on the surface of the airless Planet Z-49 and observes that it takes 1.02 s for the marble to fall 2.00 m starting from rest. She also knows that the radius of Z-49 is 3.39 × 10 6 m. From this information, what will she determine for the mass of Z-49? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"4.62 × 10 23 kg."},{"label":"B","text":"9.95 × 10 23 kg."},{"label":"C","text":"6.62 × 10 23 kg."},{"label":"D","text":"8.09 × 10 23 kg."},{"label":"E","text":"3.31 × 10 23 kg."}],"images":[],"answer":"C"},{"id":"Units_5-6-q107","source":"Units_5-6","sourceNumber":"107","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"At a distance of 14,000 km from the center of Planet Z-99, the freefall acceleration s 32 m/s 2 . What is the freefall acceleration at a point 28,000 km from the center of this planet?","choices":[{"label":"A","text":"16 m/s 2"},{"label":"B","text":"8.0 m/s 2"},{"label":"C","text":"2.0 m/s 2"},{"label":"D","text":"4.0 m/s 2"},{"label":"E","text":"128 m/s 2"}],"images":[],"answer":"B"},{"id":"Units_5-6-q108","source":"Units_5-6","sourceNumber":"108","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"The gravitational force exerted on an object is 432 N on the surface of Earth. Earth has radius R . If the object is raised to a height of 3 R above the Earth's surface , what is the gravitational force exerted on it?","choices":[{"label":"A","text":"144 N"},{"label":"B","text":"27.0 N"},{"label":"C","text":"108 N"},{"label":"D","text":"305 N"},{"label":"E","text":"48.0 N"}],"images":[],"answer":"B"},{"id":"Units_5-6-q109","source":"Units_5-6","sourceNumber":"109","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"By how much does the gravitational force exerted on a 100-kg person decrease when he goes from sea level to mountain top at an altitude of 5000 m? The mean radius of Earth is 6.38 × 10 6 m.","choices":[{"label":"A","text":"3.6 N"},{"label":"B","text":"0.60 N"},{"label":"C","text":"9.8 N"},{"label":"D","text":"2.6 N"},{"label":"E","text":"1.5 N"}],"images":[],"answer":"E"},{"id":"Units_5-6-q110","source":"Units_5-6","sourceNumber":"110","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Earth has radius R . A satellite of mass 100 kg is in orbit at an altitude of 3 R above the Earth's surface. What is the gravitational force exerted on the satellite at the altitude of its orbit?","choices":[{"label":"A","text":"16,000 N toward the center of Earth"},{"label":"B","text":"61 N toward the center of Earth"},{"label":"C","text":"9000 N toward the center of Earth"},{"label":"D","text":"110 N toward the center of Earth"}],"images":[],"answer":"B"},{"id":"Units_5-6-q111","source":"Units_5-6","sourceNumber":"111","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A spherically symmetric planet has four times Earth's mass and twice its radius. If the gravitational force exerted on a jar of peanut butter is 12 N on the surface of Earth, how much would it be on the surface of this planet?","choices":[{"label":"A","text":"6.0 N"},{"label":"B","text":"12 N"},{"label":"C","text":"24 N"},{"label":"D","text":"3.0 N"},{"label":"E","text":"36 N"}],"images":[],"answer":"B"},{"id":"Units_5-6-q114","source":"Units_5-6","sourceNumber":"114","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Suppose NASA wants a satellite to revolve around Earth 5 times a day. What should be the radius of its orbit if we neglect the presence of the Moon? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 , M earth = 5.97 × 10 24 kg)","choices":[{"label":"A","text":"7.22 × 10 7 m"},{"label":"B","text":"0.69 × 10 7 m"},{"label":"C","text":"1.44 × 10 7 m"},{"label":"D","text":"2.11 × 10 7 m"}],"images":[],"answer":"B"},{"id":"Units_5-6-q115","source":"Units_5-6","sourceNumber":"115","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"The captain of a spaceship orbiting planet X discovers that to remain in orbit at 410 km from the planet's center, she needs to maintain a speed of 68 m/s. What is the mass of planet X? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"2.8 × 10 16 kg"},{"label":"B","text":"4.2 × 10 17 kg"},{"label":"C","text":"2.8 × 10 19 kg"},{"label":"D","text":"4.2 × 10 14 kg"}],"images":[],"answer":"D"},{"id":"Units_5-6-q116","source":"Units_5-6","sourceNumber":"116","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Find the orbital speed of an ice cube in the rings of Saturn. The mass of Saturn is 5.68 × 10 26 kg, and use an orbital radius of 1.00 × 10 5 km. ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"19.5 km/s"},{"label":"B","text":"13.8 km/s"},{"label":"C","text":"27.5 km/s"},{"label":"D","text":"9.40 km/s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q117","source":"Units_5-6","sourceNumber":"117","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"You are the science officer on a visit to a distant solar system. Prior to landing on a planet you measure its diameter to be 1.8 × 10 7 m. You have previously determined that the planet orbits 2.9 × 10 11 m from its star with a period of 402 Earth days. Once on the surface you find that the freefall acceleration is 19.5 m/s 2 . What are the masses of (a) the planet and (b) the star? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"(a) 4.3 kg × 10 25 kg, (b) 1.2 kg × 10 31 kg"},{"label":"B","text":"(a) 4.3 kg × 10 25 kg, (b) 7.1 kg × 10 30 kg"},{"label":"C","text":"(a) 2.4 kg × 10 25 kg, (b) 7.1 kg × 10 30 kg"},{"label":"D","text":"(a) 2.4 kg × 10 25 kg, (b) 1.2 kg × 10 31 kg"}],"images":[],"answer":"D"},{"id":"Units_5-6-q118","source":"Units_5-6","sourceNumber":"118","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A satellite that is in a circular orbit 230 km above the surface of the planet Zeeman-474 has an orbital period of 89 min. The radius of Zeeman-474 is 6.38 × 10 6 m. What is the mass of this planet? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"6.0 × 10 24 kg"},{"label":"B","text":"6.5 × 10 24 kg"},{"label":"C","text":"5.5 × 10 24 kg"},{"label":"D","text":"5.0 × 10 24 kg"}],"images":[],"answer":"B"},{"id":"Units_5-6-q119","source":"Units_5-6","sourceNumber":"119","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"Asteroid Ida was photographed by the Galileo spacecraft in 1993, and the photograph revealed that the asteroid has a small moon, which has been named Dactyl. From the dimensions of Ida and its general features, one can estimate the mass of Ida to be 4.5 × 10 16 kg, and the distance between Dactyl and Ida is approximately 90 km. If it has a circular orbit, what would be the orbital speed of Dactyl? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"5.8 m/s"},{"label":"B","text":"11 m/s"},{"label":"C","text":"30 m/s"},{"label":"D","text":"2.9 m/s"},{"label":"E","text":"2.3 m/s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q120","source":"Units_5-6","sourceNumber":"120","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"In another solar system, a planet has a moon that is 4.0 × 10 5 m in diameter. Measurements reveal that this moon takes 3.0 × 10 5 s to make each orbit of diameter 1.8 × 10 8 m. What is the mass of the planet? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"3.4 × 10 24 kg"},{"label":"B","text":"4.8 × 10 24 kg"},{"label":"C","text":"1.7 × 10 24 kg"},{"label":"D","text":"1.2 × 10 24 kg"},{"label":"E","text":"2.4 × 10 24 kg"}],"images":[],"answer":"B"},{"id":"Units_5-6-q121","source":"Units_5-6","sourceNumber":"121","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"​ Mass Radius Orbital radius Orbital period Moon A 4.0 × 10 20 kg unknown 2.0 × 10 8 m 4.0 × 10 6 s Moon B 1.5 × 10 20 kg 2.0 × 10 5 m 3.0 × 10 8 m unknown Mithra is an unknown planet that has two moons, A and B, in circular orbits around it. The table summarizes the hypothetical data about these moons. What is the mass of Mithra? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"3.0 × 10 23 kg"},{"label":"B","text":"1.5 × 10 24 kg"},{"label":"C","text":"1.5 × 10 23 kg"},{"label":"D","text":"1.8 × 10 22 kg"},{"label":"E","text":"3.0 × 10 22 kg"}],"images":[],"answer":"C"},{"id":"Units_5-6-q124","source":"Units_5-6","sourceNumber":"124","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A satellite having orbital speed V orbits a planet of mass M . If the planet had half as much mass, the orbital speed of the satellite at the same distance from the center would be","choices":[{"label":"A","text":"V /2"},{"label":"B","text":"2 V"},{"label":"C","text":"V"},{"label":"D","text":"V /"},{"label":"E","text":"V"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"C"},{"id":"Units_5-6-q125","source":"Units_5-6","sourceNumber":"125","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A satellite of mass M takes time interval T to orbit a planet. If the satellite had twice as much mass, the time interval for it to orbit the planet at the same altitude would be","choices":[{"label":"A","text":"4 T"},{"label":"B","text":"T"},{"label":"C","text":"2 T"},{"label":"D","text":"T /2"},{"label":"E","text":"T /4"}],"images":[],"answer":"B"},{"id":"Units_5-6-q127","source":"Units_5-6","sourceNumber":"127","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Europa, a moon of Jupiter, has an orbital diameter of 1.34 × 10 9 m and a period of 3.55 days. What is the mass of Jupiter? ( G = 6.67 × 10 -11 N ∙ m 2 /kg 2 )","choices":[{"label":"A","text":"3.08 × 10 27 kg"},{"label":"B","text":"1.89 × 10 27 kg"},{"label":"C","text":"1.65 × 10 27 kg"},{"label":"D","text":"1.07 × 10 27 kg"},{"label":"E","text":"1.53 × 10 27 kg"}],"images":[],"answer":"A"},{"id":"Units_5-6-q129","source":"Units_5-6","sourceNumber":"129","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"The average distance from Earth to the Sun is defined as one astronomical unit (AU). If an asteroid orbits the Sun in 1/3 of a year in a circular orbit, the asteroid's distance from the Sun is closest to","choices":[{"label":"A","text":"5.2 AU."},{"label":"B","text":"0.33 AU."},{"label":"C","text":"0.19 AU."},{"label":"D","text":"2.1 AU."},{"label":"E","text":"0.48 AU."}],"images":[],"answer":"E"},{"id":"Units_5-6-q130","source":"Units_5-6","sourceNumber":"130","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"If Earth were twice as far from the Sun as it presently is, but still had a circular orbit, what time interval (in terms of the present year) would be required for it to make one orbit around the Sun?","choices":[{"label":"A","text":"2.0 years"},{"label":"B","text":"5.7 years"},{"label":"C","text":"4.0 years"},{"label":"D","text":"16 years"},{"label":"E","text":"2.8 years"}],"images":[],"answer":"E"},{"id":"Units_5-6-q131","source":"Units_5-6","sourceNumber":"131","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"If NASA wants to put a satellite in a circular orbit around the Sun so it will make 2.0 orbits per year, at what distance (in astronomical units, AU) from the Sun should that satellite orbit? Earth's orbit is 1.0 AU from the Sun.","choices":[{"label":"A","text":"2.0 AU"},{"label":"B","text":"0.50 AU"},{"label":"C","text":"0.63 AU"},{"label":"D","text":"0.71 AU"},{"label":"E","text":"7.6 AU"}],"images":[],"answer":"C"},{"id":"Units_5-6-q132","source":"Units_5-6","sourceNumber":"132","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"Two moons orbit one planet in circular orbits. Moon A has orbital radius R , and moon B has orbital radius 4 R . Moon A takes 20 days to complete one orbit. In what time interval does moon B complete an orbit?","choices":[{"label":"A","text":"160 days"},{"label":"B","text":"80 days"},{"label":"C","text":"5 days"},{"label":"D","text":"20 days"},{"label":"E","text":"320 days"}],"images":[],"answer":"A"},{"id":"Units_5-6-q133","source":"Units_5-6","sourceNumber":"133","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"The planet Jupiter is 7.78 × 10 11 m from the Sun. In what time interval does Jupiter orbit once around the Sun, given that the distance from Earth to the Sun is 1.50 × 10 11 m?","choices":[{"label":"A","text":"11.8 years"},{"label":"B","text":"5.19 years"},{"label":"C","text":"5.91 years"},{"label":"D","text":"2.37 years"},{"label":"E","text":"27.4 years"}],"images":[],"answer":"A"},{"id":"Units_5-6-q134","source":"Units_5-6","sourceNumber":"134","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"It takes the planet Jupiter 12 years to orbit the Sun once in a nearly circular orbit. Assuming that Jupiter's orbit is truly circular, find the distance from Jupiter to the Sun, given that the distance from Earth to the Sun is 1.5 × 10 11 m .","choices":[{"label":"A","text":"5.2 × 10 11 m"},{"label":"B","text":"7.9 × 10 11 m"},{"label":"C","text":"3.2 × 10 12 m"},{"label":"D","text":"3.9 × 10 11 m"},{"label":"E","text":"9.7 × 10 11 m"}],"images":[],"answer":"E"},{"id":"Units_5-6-q138","source":"Units_5-6","sourceNumber":"138","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"An empty cylindrical glass is shown in the image above. Where is the center of mass of the glass?","choices":[{"label":"A","text":"Along its central axis, closer to the bottom than the top."},{"label":"B","text":"Along its central axis, at the bottom."},{"label":"C","text":"Along its central axis, closer to the top than the bottom."},{"label":"D","text":"Along its central axis, equidistant from the top and bottom."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"104","height":"138"}],"answer":"A"},{"id":"Units_5-6-q140","source":"Units_5-6","sourceNumber":"140","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"Two objects, of masses m and 2 m , are hanging from opposite ends of a uniform horizontal beam. The beam is being supported by a string at its center, and the objects are balanced. Which of the following must be true?","choices":[{"label":"A","text":"The object of mass 2 m is twice the distance from the center of the beam."},{"label":"B","text":"The mass of the beam must be known."},{"label":"C","text":"The object of mass m is twice the distance from the center of the beam."},{"label":"D","text":"The objects are hanging at the same distance from the center of the beam."}],"images":[],"answer":"C"},{"id":"Units_5-6-q141","source":"Units_5-6","sourceNumber":"141","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"Which of the following wrenches will have the greatest torque exerted on it about the axis where it grips the hexagonal bolt?","choices":[{"label":"A","text":"Wrench A"},{"label":"B","text":"Wrench B"},{"label":"C","text":"Wrench C"},{"label":"D","text":"Wrench D"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"595","height":"116"}],"answer":"D"},{"id":"Units_5-6-q142","source":"Units_5-6","sourceNumber":"142","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Two objects, of masses 6 and 8 kg, are hung from the ends of a stick that is 70 cm long and has marks every l0 cm, as shown above. If the mass of the stick is negligible, at which of the points indicated should a cord be attached if the stick is to remain horizontal when suspended from the cord?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"},{"label":"E","text":"E"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"324","height":"129"}],"answer":"D"},{"id":"Units_5-6-q144","source":"Units_5-6","sourceNumber":"144","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Suppose scale 3 is moved to the right until l 3 is doubled, and then F 3 is adjusted so that F 1 is the same as before. Which of the following is true?","choices":[{"label":"A","text":"The new value of F 3 will be half its original value."},{"label":"B","text":"The new value of F 3 will be double its original value."},{"label":"C","text":"The new value of F 3 will be more, but not double its original value."},{"label":"D","text":"The new value of F 3 will be less, but not half its original value."}],"images":[],"answer":"A"},{"id":"Units_5-6-q146","source":"Units_5-6","sourceNumber":"146","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Which of the following is true about F 1 and F 2 , the forces exerted by the piers at points 1 and 2 on the board?","choices":[{"label":"A","text":"F 1 or F 2 may be more than one combination of pushing upward or pulling downward, depending on the mass of the man and the length of the board."},{"label":"B","text":"Both F 1 and F 2 are pushing upward."},{"label":"C","text":"F 1 is pushing upward, and F 2 is pulling downward."},{"label":"D","text":"F 1 is pulling downward, and F 2 is pushing upward."}],"images":[],"answer":"D"},{"id":"Units_5-6-q148","source":"Units_5-6","sourceNumber":"148","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A hammock is tied with ropes between two trees. When a person lies in it, what happens to the horizontal component of the tension in each rope?","choices":[{"label":"A","text":"It remains constant, because both the magnitude and direction of the tension forces change, keeping the horizontal component the same."},{"label":"B","text":"It increases, because the magnitude of the tension in each rope must increase to make its vertical component increase."},{"label":"C","text":"It decreases, because more tension is directed in the vertical direction, and less in the horizontal direction."},{"label":"D","text":"It remains constant, because the person only pushes on the hammock in the vertical direction."},{"label":"E","text":"It increases, because the person exerts a horizontal force on each of the trees."}],"images":[],"answer":"B"},{"id":"Units_5-6-q152","source":"Units_5-6","sourceNumber":"152","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"Four identical spheres are attached to massless rods and hung on a nail through a pivot point, as shown above. Removing which sphere or spheres will keep the apparatus in rotational equilibrium?","choices":[{"label":"A","text":"Removing spheres B and D"},{"label":"B","text":"Removing sphere C alone"},{"label":"C","text":"Removing spheres A and D"},{"label":"D","text":"Removing sphere A alone"},{"label":"E","text":"Removing sphere B alone"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"339","height":"301"}],"answer":"C"},{"id":"Units_5-6-q154","source":"Units_5-6","sourceNumber":"154","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"Four identical spheres are attached to massless rods and hung on a nail through a pivot point, as shown above. Removing which sphere or spheres will keep the apparatus in rotational equilibrium? Select all that apply.","choices":[{"label":"A","text":"Removing spheres B and C"},{"label":"B","text":"Removing sphere A"},{"label":"C","text":"Removing sphere B"},{"label":"D","text":"Removing spheres D and C"},{"label":"E","text":"Removing sphere C"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"361","height":"367"}],"answer":"E, B"},{"id":"Units_5-6-q155","source":"Units_5-6","sourceNumber":"155","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Easy","question":"Two forces produce equal torques on a door about the door hinge. The first force is exerted at the midpoint of the door; the second force is exerted at the doorknob. Both forces are exerted perpendicular to the door. Which force has a greater magnitude?","choices":[{"label":"A","text":"The second force (at the doorknob)."},{"label":"B","text":"The first force (at the midpoint)."},{"label":"C","text":"The two forces are equal."}],"images":[],"answer":"B"},{"id":"Units_5-6-q156","source":"Units_5-6","sourceNumber":"156","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"Two equal-magnitude forces are exerted to a door at the doorknob. The first force is exerted perpendicular to the door, and the second force is exerted at 30° to the plane of the door. Which force exerts the greater torque about the door hinge?","choices":[{"label":"A","text":"The second force (exerted at an angle)."},{"label":"B","text":"Both forces exert equal non-zero torques."},{"label":"C","text":"The first force (exerted perpendicular to the door)."},{"label":"D","text":"Both forces exert zero torque."}],"images":[],"answer":"C"},{"id":"Units_5-6-q157","source":"Units_5-6","sourceNumber":"157","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"As shown in the figure, a given force is exerted to a rod in several different ways. In which case is the torque about the pivot P due to this force the greatest?","choices":[{"label":"A","text":"1"},{"label":"B","text":"2"},{"label":"C","text":"3"},{"label":"D","text":"4"},{"label":"E","text":"5"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"487","height":"149"}],"answer":"A"},{"id":"Units_5-6-q158","source":"Units_5-6","sourceNumber":"158","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"Five forces act on a rod that is free to pivot at point P, as shown in the figure. Which of these forces is producing a counter-clockwise torque about point P? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Force A"},{"label":"B","text":"Force B"},{"label":"C","text":"Force C"},{"label":"D","text":"Force D"},{"label":"E","text":"Force E"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"286","height":"104"}],"answer":"C"},{"id":"Units_5-6-q159","source":"Units_5-6","sourceNumber":"159","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Easy","question":"If the sum of the external forces on an object is zero, then the sum of the external torques on it must also be zero.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_5-6-q160","source":"Units_5-6","sourceNumber":"160","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Easy","question":"If the sum of the external torques on an object is zero, then the sum of the external forces on it must also be zero.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_5-6-q161","source":"Units_5-6","sourceNumber":"161","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Easy","question":"If the sum of both the external torques and the external forces on an object is zero, then the object must be at rest.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"B"},{"id":"Units_5-6-q162","source":"Units_5-6","sourceNumber":"162","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Easy","question":"If an object remains at rest, then both the sum of the external torques and the sum of the external forces on the object must be zero.","choices":[{"label":"A","text":"True"},{"label":"B","text":"False"}],"images":[],"answer":"A"},{"id":"Units_5-6-q163","source":"Units_5-6","sourceNumber":"163","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"When a car is weighed, it is driven slowly on a horizontal floor over a scale that records a reading as the front wheels together go over the scale, and then records a second reading as the rear wheels together go over the scale. The gravitational force exerted on the car is equal to","choices":[{"label":"A","text":"the sum of the two readings."},{"label":"B","text":"the difference of the two readings."},{"label":"C","text":"the average of the two readings."},{"label":"D","text":"the first reading."},{"label":"E","text":"the second reading."}],"images":[],"answer":"A"},{"id":"Units_5-6-q164","source":"Units_5-6","sourceNumber":"164","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A croquet mallet balances when suspended from its center of mass, as shown in the left part of the figure. If you cut the mallet into two pieces at its center of mass, as shown in the right part of the figure, how do the masses of the two pieces compare?","choices":[{"label":"A","text":"The piece with the head of the mallet has the greater mass."},{"label":"B","text":"The masses are equal."},{"label":"C","text":"The piece with the head of the mallet has the smaller mass."},{"label":"D","text":"It is impossible to tell."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"456","height":"115"}],"answer":"A"},{"id":"Units_5-6-q165","source":"Units_5-6","sourceNumber":"165","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"The board above remains at rest, with its center of mass marked by the dot at its midpoint. What is the mass of the board?","choices":[{"label":"A","text":"2.6 kg"},{"label":"B","text":"2.3 kg"},{"label":"C","text":"1.25 kg"},{"label":"D","text":"1.8 kg"},{"label":"E","text":"Not enough information"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"533","height":"148"}],"answer":"B"},{"id":"Units_5-6-q166","source":"Units_5-6","sourceNumber":"166","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"You are building a toy mobile, copying the design shown above. The numbers in the figure indicate the relative lengths of the rods on each side of their supporting cords. Object A has amass of 1.0 kg. What should be the mass of object B?","choices":[{"label":"A","text":"1.3 kg"},{"label":"B","text":"1.0 kg"},{"label":"C","text":"2.0 kg"},{"label":"D","text":"0.5 kg"},{"label":"E","text":"0.75 kg"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"268","height":"270"}],"answer":"A"},{"id":"Units_5-6-q167","source":"Units_5-6","sourceNumber":"167","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A fulcrum is placed 1.0 m from the right-hand end of a 3.0-m long wooden uniform plank of mass 40 kg. An object of mass m is placed at the extreme right-hand end to make the plank balance. What must be the mass of the object in order to balance the plank?","choices":[{"label":"A","text":"80 kg"},{"label":"B","text":"40 kg"},{"label":"C","text":"5 kg"},{"label":"D","text":"20 kg"},{"label":"E","text":"10 kg"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"297","height":"112"}],"answer":"D"},{"id":"Units_5-6-q168","source":"Units_5-6","sourceNumber":"168","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 50-g uniform meter stick is to be suspended by a single string. A 100-g block hangs from the left-hand edge of the meter stick. Where should the string be attached so that the meter stick is in equilibrium?","choices":[{"label":"A","text":"33 cm from the leftmost end"},{"label":"B","text":"30 cm from the leftmost end"},{"label":"C","text":"50 cm from the leftmost end"},{"label":"D","text":"17 cm from the leftmost end"},{"label":"E","text":"At the leftmost end"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"300","height":"128"}],"answer":"D"},{"id":"Units_5-6-q170","source":"Units_5-6","sourceNumber":"170","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"How far from the left end of the board is the person sitting?","choices":[{"label":"A","text":"2.00 m"},{"label":"B","text":"0.400 m"},{"label":"C","text":"2.50 m"},{"label":"D","text":"3.00 m"},{"label":"E","text":"1.50 m"}],"images":[],"answer":"E"},{"id":"Units_5-6-q172","source":"Units_5-6","sourceNumber":"172","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"As shown in the figure, a 60-cm length of stiff uniform wire, of mass 60 g, is bent into a right triangle. What are the x and y coordinates of the center of mass of this triangle?","choices":[{"label":"A","text":"(9.0 cm, 4.0 cm)"},{"label":"B","text":"(10 cm, 3.0 cm)"},{"label":"C","text":"(10 cm, 5.0 cm)"},{"label":"D","text":"(8.0 cm, 3.0 cm)"},{"label":"E","text":"(8.0 cm, 5.0 cm)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"243","height":"138"}],"answer":"B"},{"id":"Units_5-6-q173","source":"Units_5-6","sourceNumber":"173","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 60.0-kg man stands at one end of a 20.0-kg uniform 10.0-m long board. How far from the man is the center of mass of the man-board system?","choices":[{"label":"A","text":"7.50 m"},{"label":"B","text":"9.00 m"},{"label":"C","text":"1.25 m"},{"label":"D","text":"2.50 m"},{"label":"E","text":"5.00 m"}],"images":[],"answer":"C"},{"id":"Units_5-6-q174","source":"Units_5-6","sourceNumber":"174","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 2.0-m rope is lying on a table. You pick up one end and start raising it vertically. How high above the table is the center of mass of the rope when half of the rope has lifted off the table?","choices":[{"label":"A","text":"0.50 m"},{"label":"B","text":"1.0 m"},{"label":"C","text":"1.5 m"},{"label":"D","text":"0.25 m"},{"label":"E","text":"0.75 m"}],"images":[],"answer":"D"},{"id":"Units_5-6-q175","source":"Units_5-6","sourceNumber":"175","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Three point-like objects are located in the x - y plane as follows: a mass of 6 kg is at (0 m, 0 m), a mass of 4 kg is at (3 m, 0 m), and a mass of 2 kg is at (0 m, 3 m). Where is the center of mass of the system?","choices":[{"label":"A","text":"(2 m, 1 m)"},{"label":"B","text":"(1 m, 0.5 m)"},{"label":"C","text":"(1 m, 2 m)"},{"label":"D","text":"(1 m, 1 m)"},{"label":"E","text":"(0.5 m, 1 m)"}],"images":[],"answer":"B"},{"id":"Units_5-6-q177","source":"Units_5-6","sourceNumber":"177","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 30-kg child stands at one end of a floating 20-kg canoe that is 5.0 m long and initially at rest in the water. The child then slowly walks to the other end of the canoe. How far does the canoe move in the water, assuming water friction is negligible?","choices":[{"label":"A","text":"5.0 m"},{"label":"B","text":"4.0 m"},{"label":"C","text":"2.0 m"},{"label":"D","text":"3.0 m"},{"label":"E","text":"1.0 m"}],"images":[],"answer":"D"},{"id":"Units_5-6-q179","source":"Units_5-6","sourceNumber":"179","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Three small objects are positioned as follows: 2.0 kg at (0.0 m, 0.0 m), 2.0 kg at (2.0 m, 0.0 m), and 4.0 kg at (2.0 m, 1.0 m). Determine the coordinates of the center of mass of this system.","choices":[{"label":"A","text":"(1.5 m, 0.50 m)"},{"label":"B","text":"(2.5 m, 1.5 m)"},{"label":"C","text":"(0.50 m, 1.5 m)"},{"label":"D","text":"(2.5 m, 0.50 m)"}],"images":[],"answer":"A"},{"id":"Units_5-6-q180","source":"Units_5-6","sourceNumber":"180","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Three point-like objects with masses of 1.0 kg, 2.0 kg, and 3.0 kg, are located at (0.0 m, 0.0 m), (1.0 m, 1.0 m), and (2.0 m, -2.0 m), respectively. What is the location of the center of mass of this system?","choices":[{"label":"A","text":"(-1.3 m, 0.67 m)"},{"label":"B","text":"(-1.3 m, -0.67 m)"},{"label":"C","text":"(1.3 m, -0.67 m)"},{"label":"D","text":"(1.3 m, 0.67 m)"}],"images":[],"answer":"C"},{"id":"Units_5-6-q181","source":"Units_5-6","sourceNumber":"181","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 3.0-kg object is located at (0.0 m, 8.0 m), and a 1.0-kg object is located at (12 m, 0.0 m). You want to add a 4.0-kg object so that the center of mass of the three-object system will be at the origin. What should be the coordinates of the 4.0-kg object?","choices":[{"label":"A","text":"(-6.0 m, -3.0 m)"},{"label":"B","text":"(-3.0 m, -6.0 m)"},{"label":"C","text":"(-12 m, -8.0 m)"},{"label":"D","text":"(3.0 m, 6.0 m)"}],"images":[],"answer":"B"},{"id":"Units_5-6-q183","source":"Units_5-6","sourceNumber":"183","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"The lug nuts on a car wheel require tightening to a torque of 90 N ∙ m. If a 30-cm long wrench is used, what is the magnitude of the minimum force required using the wrench?","choices":[{"label":"A","text":"30 N"},{"label":"B","text":"300 N"},{"label":"C","text":"15 N"},{"label":"D","text":"150 N"}],"images":[],"answer":"B"},{"id":"Units_5-6-q184","source":"Units_5-6","sourceNumber":"184","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A man in a gym is holding an 8.0-kg dumbbell at arm's length, a distance of 0.55 m from his shoulder joint. What is the torque about his shoulder joint due to the gravitational force on the dumbbell if his arm is horizontal?","choices":[{"label":"A","text":"4.4 N ∙ m"},{"label":"B","text":"0 N ∙ m"},{"label":"C","text":"43 N ∙ m"},{"label":"D","text":"0.24 N ∙ m"},{"label":"E","text":"15 N ∙ m"}],"images":[],"answer":"C"},{"id":"Units_5-6-q185","source":"Units_5-6","sourceNumber":"185","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A man in a gym is holding an 8.0-kg kettlebell at arm's length, a distance of 0.55 m from his shoulder joint. What is the torque about his shoulder joint due to the gravitational force on the kettlebell if his arm is held at 30° below the horizontal?","choices":[{"label":"A","text":"4.4 N ∙ m"},{"label":"B","text":"37 N ∙ m"},{"label":"C","text":"2.2 N ∙ m"},{"label":"D","text":"22 N ∙ m"},{"label":"E","text":"13 N ∙ m"}],"images":[],"answer":"B"},{"id":"Units_5-6-q186","source":"Units_5-6","sourceNumber":"186","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A force of 17 N is exerted to the end of a 0.63-m long torque wrench at an angle 45° from a line joining the pivot point to the handle. What is the magnitude of the torque about the pivot point produced by this force?","choices":[{"label":"A","text":"7.6 N ∙ m"},{"label":"B","text":"9.7 N ∙ m"},{"label":"C","text":"10.7 N ∙ m"},{"label":"D","text":"12.0 N ∙ m"}],"images":[],"answer":"A"},{"id":"Units_5-6-q187","source":"Units_5-6","sourceNumber":"187","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A 95-N force exerted at the end of a 0.32-m long torque wrench produces a torque of 15 N ∙ m. What is the angle (less than 90°) between the wrench handle and the direction of the exerted force?","choices":[{"label":"A","text":"36°"},{"label":"B","text":"30°"},{"label":"C","text":"24°"},{"label":"D","text":"42°"}],"images":[],"answer":"B"},{"id":"Units_5-6-q188","source":"Units_5-6","sourceNumber":"188","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"The figure shows a person's foot. In that figure, the Achilles tendon exerts a force of magnitude F = 720 N. What is the magnitude of the torque that this force produces about the ankle joint?","choices":[{"label":"A","text":"36 N ∙ m"},{"label":"B","text":"26 N ∙ m"},{"label":"C","text":"12 N ∙ m"},{"label":"D","text":"21 N ∙ m"},{"label":"E","text":"16 N ∙ m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"211","height":"307"}],"answer":"E"},{"id":"Units_5-6-q189","source":"Units_5-6","sourceNumber":"189","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 15-kg child is sitting on a playground teeter-totter, 1.5 m from the pivot. What is the magnitude of the minimum vertical force, exerted 0.30 m on the other side of the pivot, that is needed to lift the child off the ground?","choices":[{"label":"A","text":"23 N"},{"label":"B","text":"66 N"},{"label":"C","text":"740 N"},{"label":"D","text":"44 N"},{"label":"E","text":"75 N"}],"images":[],"answer":"C"},{"id":"Units_5-6-q190","source":"Units_5-6","sourceNumber":"190","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 15-kg child is sitting on a playground teeter-totter, 1.5 m from the pivot. What is the minimum distance, on the other side of the pivot, such that a 220-N vertical force will lift the child off the ground?","choices":[{"label":"A","text":"1.0 m"},{"label":"B","text":"9.8 m"},{"label":"C","text":"1.5 m"},{"label":"D","text":"0.10 m"},{"label":"E","text":"2.4 m"}],"images":[],"answer":"A"},{"id":"Units_5-6-q193","source":"Units_5-6","sourceNumber":"193","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"An irregularly shaped object that is 10 m long is placed with each end on a scale. If the scale on the right reads 96 N while the scale on the left reads 71 N, how far from the left end is the center of mass of this object?","choices":[{"label":"A","text":"4.3 m"},{"label":"B","text":"14 m"},{"label":"C","text":"7.4 m"},{"label":"D","text":"5.7 m"}],"images":[],"answer":"D"},{"id":"Units_5-6-q194","source":"Units_5-6","sourceNumber":"194","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A uniform 122-kg piece of medical apparatus that is 3.5 m long is suspended horizontally by two vertical wires at its ends. A small but dense 56-kg object is placed on the apparatus 2.0 m from one end, as shown in the figure. What are the tensions, A and B , in the two wires?","choices":[{"label":"A","text":"A = 910 N, B = 840 N"},{"label":"B","text":"A = 880 N, B = 880 N"},{"label":"C","text":"A = 9000 N, B = 8200 N"},{"label":"D","text":"A = 8200 N, B = 9000 N"},{"label":"E","text":"A = 840 N, B = 910 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"282","height":"127"}],"answer":"A"},{"id":"Units_5-6-q195","source":"Units_5-6","sourceNumber":"195","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A meter stick balances at the 50.0-cm mark. If an object of mass 50.0 g is hung from the tick at the 90.0-cm mark, the stick balances when a single upward force is exerted on it at the 61.3-cm mark. What is the mass of the meter stick?","choices":[{"label":"A","text":"32.6 g"},{"label":"B","text":"73.4 g"},{"label":"C","text":"89.7 g"},{"label":"D","text":"127 g"},{"label":"E","text":"178 g"}],"images":[],"answer":"D"},{"id":"Units_5-6-q198","source":"Units_5-6","sourceNumber":"198","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A child is trying to stack two uniform bricks, each 24 cm long, so they will protrude as far as possible over the edge of a table without tipping over, as shown in the figure. What is the maximum possible overhang distance d ?","choices":[{"label":"A","text":"14 cm"},{"label":"B","text":"18 cm"},{"label":"C","text":"12 cm"},{"label":"D","text":"16 cm"},{"label":"E","text":"10 cm"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"205","height":"225"}],"answer":"B"},{"id":"Units_5-6-q199","source":"Units_5-6","sourceNumber":"199","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"To determine the location of the center of mass of a car, the car is driven over a scale on a horizontal floor. When the front wheels are both on the scale, the reading of the scale is 5800 N, and when the rear wheels are both on the scale, the scale reads 6500 N. The distance between the front and rear wheels is measured to be 3.20 m. How far behind the front wheels is the center of mass located?","choices":[{"label":"A","text":"1.50 m"},{"label":"B","text":"0.845 m"},{"label":"C","text":"1.59 m"},{"label":"D","text":"1.69 m"},{"label":"E","text":"1.72 m"}],"images":[],"answer":"D"},{"id":"Units_5-6-q200","source":"Units_5-6","sourceNumber":"200","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 120-kg refrigerator that is 2.0 m tall and 85 cm wide has its center of mass at its geometrical center. You are attempting to slide it along the floor by pushing horizontally on the side of the refrigerator. The coefficient of static friction between the floor and the refrigerator is 0.30. Depending on where you push, the refrigerator may start to tip over before it starts to slide along the floor. What is the highest distance above the floor that you can push the refrigerator so that it will not tip before it begins to slide?","choices":[{"label":"A","text":"0.71 m"},{"label":"B","text":"1.0 m"},{"label":"C","text":"1.6 m"},{"label":"D","text":"1.4 m"},{"label":"E","text":"1.2 m"}],"images":[],"answer":"D"},{"id":"Units_5-6-q201","source":"Units_5-6","sourceNumber":"201","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"A uniform rod weighs 40 N and is 1.0 m long. It is hinged to a wall at the left end, and held in a horizontal position at the right end by a vertical string of negligible mass, as shown in the figure. What is the magnitude of the torque due to the string about a horizontal axis that passes through the hinge and is perpendicular to the rod? The hinge is very small with negligible friction.","choices":[{"label":"A","text":"10 N ∙ m"},{"label":"B","text":"5.0 N ∙ m"},{"label":"C","text":"30 N ∙ m"},{"label":"D","text":"20 N ∙ m"},{"label":"E","text":"40 N ∙ m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"206","height":"127"}],"answer":"D"},{"id":"Units_5-6-q207","source":"Units_5-6","sourceNumber":"207","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"An athlete holds a 7.5-kg shot put in his hand with his lower arm horizontal, as shown in the figure. His lower arm has a mass of 2.8 kg and its center of mass is 12 cm from the elbow-joint pivot. How much force must the extensor muscle (which is M in the figure) in the upper arm exert on the lower arm?","choices":[{"label":"A","text":"500 N"},{"label":"B","text":"100 N"},{"label":"C","text":"1000 N"},{"label":"D","text":"1500 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"right ray(F)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"","width":"343","height":"201"}],"answer":"C"},{"id":"Units_5-6-q208","source":"Units_5-6","sourceNumber":"208","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A beam used to unload beer barrels from wagons at a tavern in a town's historic district has a mass of 20 kg and is 3.0 m long. It is uniform, so its center of mass is at the center of the beam. It is supported horizontally by a small loose bolt attached to the wall at one end and by a wire at the other end, as shown in the figure. What is the tension in the wire?","choices":[{"label":"A","text":"200 N"},{"label":"B","text":"120 N"},{"label":"C","text":"230 N"},{"label":"D","text":"460 N"},{"label":"E","text":"300 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"395","height":"282"}],"answer":"C"},{"id":"Units_5-6-q209","source":"Units_5-6","sourceNumber":"209","topic":"Unit 4: Linear Momentum","difficulty":"Hard","question":"A beam used to load beer barrels onto wagons at a brewery in a town's historic district has a mass of 20 kg and is 3.0 m long. It is uniform, so its center of mass is at the center of the beam. It is supported horizontally by a small loose bolt attached to the wall at one end and by a wire at the other end, as shown in the figure. What is the magnitude of the net force that the bolt exerts on the beam?","choices":[{"label":"A","text":"230 N"},{"label":"B","text":"200 N"},{"label":"C","text":"300 N"},{"label":"D","text":"120 N"},{"label":"E","text":"460 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"395","height":"282"}],"answer":"A"},{"id":"Units_5-6-q210","source":"Units_5-6","sourceNumber":"210","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 40-kg uniform ladder that is 5.0 m long is placed against a smooth wall at a height of h = 4.0 m, as shown in the figure. The base of the ladder rests on a rough horizontal surface whose coefficient of static friction with the ladder is 0.70. An 80-kg bucket is suspended from the top rung of the ladder, just at the wall. What is the magnitude of the force that the ladder exerts on the wall?","choices":[{"label":"A","text":"740 N"},{"label":"B","text":"1300 N"},{"label":"C","text":"900 N"},{"label":"D","text":"1100 N"},{"label":"E","text":"980 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"176","height":"301"}],"answer":"A"},{"id":"Units_5-6-q212","source":"Units_5-6","sourceNumber":"212","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"In the figure, a uniform ladder of weight 200 N and length 10 m leans against a perfectly smooth wall. A firefighter of weight 600 N climbs a distance x up the ladder. The coefficient of static friction between the ladder and the floor is 0.50. What is the maximum value of x for which the ladder will not slip?","choices":[{"label":"A","text":"6.0 m"},{"label":"B","text":"3.9 m"},{"label":"C","text":"6.3 m"},{"label":"D","text":"8.4 m"},{"label":"E","text":"5.0 m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"262","height":"285"}],"answer":"C"},{"id":"Units_5-6-q213","source":"Units_5-6","sourceNumber":"213","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A 3.00-m-long ladder, weighing 200 N, leans against a smooth vertical wall with its base on a horizontal rough floor, a distance of 1.00 m away from the wall. The ladder is not completely uniform, so its center of mass is 1.20 m from its base. What force of friction must the floor exert on the base of the ladder to prevent the ladder from sliding down?","choices":[{"label":"A","text":"150 N"},{"label":"B","text":"102 N"},{"label":"C","text":"130 N"},{"label":"D","text":"28.3 N"},{"label":"E","text":"93.3 N"}],"images":[],"answer":"D"},{"id":"Units_5-6-q214","source":"Units_5-6","sourceNumber":"214","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 5.00-m-long uniform ladder, weighing 200 N, rests against a smooth vertical wall with its base on a horizontal rough floor, a distance of 1.20 m away from the wall. The coefficient of static friction between the ladder and the floor is 0.200. How far up the ladder, measured along the ladder, can a 600-N person climb before the ladder begins to slip?","choices":[{"label":"A","text":"1.05 m"},{"label":"B","text":"3.95 m"},{"label":"C","text":"1.50 m"},{"label":"D","text":"1.26 m"},{"label":"E","text":"4.56 m"}],"images":[],"answer":"E"},{"id":"Units_5-6-q215","source":"Units_5-6","sourceNumber":"215","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A stepladder consists of two halves that are hinged at the top and connected by a tie rod which keeps the two halves from spreading apart. In this particular instance, the two halves are 2.5 m long, and the tie rod is connected to the center of each half and is 70 cm long. Earth exerts an 800-N gravitational force on a person who stands 3/5 of the way up the stepladder, as shown in the figure. The ladder is light enough that we can neglect the gravitational force on it, and it rests on an extremely smooth floor. What is the tension in the tie rod? ( Note : To solve this problem, it is helpful to imagine cutting the ladder in half vertically and consider the forces and torques acting on each half of the ladder.)","choices":[{"label":"A","text":"560 N"},{"label":"B","text":"140 N"},{"label":"C","text":"240 N"},{"label":"D","text":"280 N"},{"label":"E","text":"360 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"388","height":"314"}],"answer":"B"},{"id":"Units_5-6-q216","source":"Units_5-6","sourceNumber":"216","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A 320-g ball and a 400-g ball are attached to the two ends of a string that goes over a pulley with a radius of 8.7 cm. Because of friction in its axle, the pulley does not begin to rotate. What is the magnitude of the frictional torque at the axle of the pulley if the system remains at rest when the balls are released?","choices":[{"label":"A","text":"0.063 N ∙ m"},{"label":"B","text":"0.00070 N ∙ m"},{"label":"C","text":"0.079 N ∙ m"},{"label":"D","text":"0.068 N ∙ m"},{"label":"E","text":"0.61 N ∙ m"}],"images":[],"answer":"D"},{"id":"Units_5-6-q219","source":"Units_5-6","sourceNumber":"219","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"Two points, A and B, are on a disk that rotates about an axis. Point A is closer to the axis than point B. Which of the following is not true?","choices":[{"label":"A","text":"Point B has the greater speed."},{"label":"B","text":"Point B has the greater rotational speed."},{"label":"C","text":"Points A and B have the same rotational acceleration."},{"label":"D","text":"Point A has the lesser tangential acceleration."},{"label":"E","text":"Point A has the lesser centripetal acceleration."}],"images":[],"answer":"B"},{"id":"Units_5-6-q220","source":"Units_5-6","sourceNumber":"220","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A ball is suspended by a lightweight string, as shown in the figure above. The ball is displaced to position 1 and released. The four labeled positions are evenly spaced along the arc of the ball's motion. At which of the positions shown does the pendulum have the greatest magnitude of rotational acceleration with respect to the pivot point?","choices":[{"label":"A","text":"1"},{"label":"B","text":"2"},{"label":"C","text":"3"},{"label":"D","text":"4"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"211","height":"218"}],"answer":"A"},{"id":"Units_5-6-q221","source":"Units_5-6","sourceNumber":"221","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"A wheel is rotating at a constant rotational acceleration. Which of the following must be true?","choices":[{"label":"A","text":"The speed of a point at the rim of the wheel is constant."},{"label":"B","text":"The tangential acceleration vector of a point at the rim of the wheel is constant."},{"label":"C","text":"The net force exerted on the wheel is constant."},{"label":"D","text":"The magnitude of the rotational velocity is constant."},{"label":"E","text":"The net torque exerted on the wheel is constant."}],"images":[],"answer":"E"},{"id":"Units_5-6-q222","source":"Units_5-6","sourceNumber":"222","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A block is hanging from the end of a horizontal bar which pivots about an axis through its center and is initially stationary. The bar is released and begins rotating. As the bar rotates from horizontal to vertical, the magnitude of the rotational acceleration of the bar","choices":[{"label":"A","text":"decreases, then increase"},{"label":"B","text":"increases, then decreases"},{"label":"C","text":"increases"},{"label":"D","text":"remains the same"},{"label":"E","text":"decreases"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"203","height":"166"}],"answer":"E"},{"id":"Units_5-6-q223","source":"Units_5-6","sourceNumber":"223","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A thin metal hoop, a thick wooden hoop, and a solid plastic disk have the same mass and outer diameter , as shown above. A string is wrapped around the outside of each one, and is pulled with a constant force F. Rank the resulting rotational acceleration of the three objects, from least to greatest.","choices":[{"label":"A","text":"α A = α B = α C"},{"label":"B","text":"α A = α B < α C"},{"label":"C","text":"α C < α B < α A"},{"label":"D","text":"α A < α B < α C"},{"label":"E","text":"α A < α C < α B"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"337","height":"91"}],"answer":"D"},{"id":"Units_5-6-q224","source":"Units_5-6","sourceNumber":"224","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"An iron hoop and a wooden disk of equal mass and radius are rolling without slipping on flat ground with equal speed, as shown above. The hoop rolls without slipping up an incline elevated at an angle θ 1 above the horizontal, and reaches a vertical height h 1 above its initial height before coming to a stop. The disk rolls without slipping up an incline elevated at an angle θ 2 above the horizontal, and reaches a vertical height h 2 above its initial height before stopping. How do h 1 and h 2 compare?","choices":[{"label":"A","text":"h 1 > h 2"},{"label":"B","text":"h 1 = h 2"},{"label":"C","text":"h 1 < h 2"},{"label":"D","text":"It depends on θ 1 and θ 2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"600","height":"120"}],"answer":"A"},{"id":"Units_5-6-q226","source":"Units_5-6","sourceNumber":"226","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Which one of the following statements about their rotational accelerations is true?","choices":[{"label":"A","text":"The rotational acceleration is greater for the copper disk."},{"label":"B","text":"The rotational acceleration is greater for the plastic disk."},{"label":"C","text":"The rotational accelerations of both systems are equal."},{"label":"D","text":"There is no rotational acceleration for either system."},{"label":"E","text":"Which system has a greater rotational acceleration depends on the actual numerical values of their masses."}],"images":[],"answer":"B"},{"id":"Units_5-6-q227","source":"Units_5-6","sourceNumber":"227","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A spinning rubber ball strikes a wooden floor, as shown in the image above. After bouncing, it is spinning in the opposite direction. Which of the following accounts for the change in direction of the ball's rotation?","choices":[{"label":"A","text":"A combination of the torques produced by the friction force and normal force exerted by the floor."},{"label":"B","text":"The torque produced by the normal force exerted by the floor."},{"label":"C","text":"A combination of the torques produced by the friction force and normal force exerted by the floor, and the torque produced by the gravitational force exerted by Earth."},{"label":"D","text":"The torque produced by the gravitational force exerted by Earth."},{"label":"E","text":"The torque produced by the friction force exerted by the floor."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"302","height":"330"}],"answer":"E"},{"id":"Units_5-6-q228","source":"Units_5-6","sourceNumber":"228","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"Identical blocks are attached to identical platforms in both orientations shown above. The platforms have the ability to rotate about the central axis shown. Which of the following statements comparing the two orientations is correct?","choices":[{"label":"A","text":"The apparatus will have a greater rotational inertia with respect to the central axis in orientation II than in orientation I."},{"label":"B","text":"The apparatus will have the same rotational inertia with respect to the central axis in both orientations."},{"label":"C","text":"The apparatus will have a greater rotational inertia with respect to the central axis in orientation I than in orientation II."},{"label":"D","text":"There is not enough information to compare the rotational inertia of each orientation."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"576","height":"153"}],"answer":"D"},{"id":"Units_5-6-q229","source":"Units_5-6","sourceNumber":"229","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"Two identical cups can be attached to each other in either orientation shown above. Which of the following statements comparing the two orientations is correct?","choices":[{"label":"A","text":"The cups will have the same rotational inertia around the x- axis in both orientations."},{"label":"B","text":"The cups will have a greater rotational inertia around the x- axis in orientation II than in orientation I."},{"label":"C","text":"The cups will have a greater rotational inertia around the x- axis in orientation I than in orientation II."},{"label":"D","text":"There is not enough information to compare the rotational inertia of each orientation."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"401","height":"94"}],"answer":"A"},{"id":"Units_5-6-q231","source":"Units_5-6","sourceNumber":"231","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"Which of the following correctly compares the initial and final total rotational kinetic energy of the two-disk system?","choices":[{"label":"A","text":"The total initial rotational kinetic energy of the two-disk system is equal to the total final rotational kinetic energy."},{"label":"B","text":"The total initial rotational kinetic energy of the two-disk system is greater than the total final rotational kinetic energy."},{"label":"C","text":"The total initial rotational kinetic energy of the two-disk system is less than the total final rotational kinetic energy."},{"label":"D","text":"The relationship depends on the coefficient of friction between the disks."}],"images":[],"answer":"B"},{"id":"Units_5-6-q232","source":"Units_5-6","sourceNumber":"232","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"When a rigid object rotates about a fixed axis, what is true about all points on the object? (There could be more than one correct choice.)","choices":[{"label":"A","text":"They all have the same tangential acceleration."},{"label":"B","text":"They all have the same rotational acceleration."},{"label":"C","text":"They all have the same rotational speed."},{"label":"D","text":"They all have the same radial acceleration."},{"label":"E","text":"They all have the same tangential speed."}],"images":[],"answer":"B, C"},{"id":"Units_5-6-q233","source":"Units_5-6","sourceNumber":"233","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Easy","question":"Two children, Ahmed and Jacques, ride on a merry-go-round. Ahmed is at a greater distance from the axis of rotation than Jacques. Which of the following are true statements? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Jacques and Ahmed have the same tangential speed."},{"label":"B","text":"Jacques has a greater rotational speed than Ahmed."},{"label":"C","text":"Jacques has a smaller rotational speed than Ahmed."},{"label":"D","text":"Jacques and Ahmed have the same rotational speed."},{"label":"E","text":"Ahmed has a greater tangential speed than Jacques."}],"images":[],"answer":"D, E"},{"id":"Units_5-6-q234","source":"Units_5-6","sourceNumber":"234","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"The figure shows scale drawings of four objects, each of the same mass and uniform thickness, with the mass distributed uniformly. Which one has the greatest rotational inertia when rotated about an axis perpendicular to the plane of the drawing at point P?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"},{"label":"E","text":"The rotational inertia is the same for all of these objects."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"469","height":"142"}],"answer":"B"},{"id":"Units_5-6-q235","source":"Units_5-6","sourceNumber":"235","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"Consider a uniform hoop of radius R and mass M rolling without slipping. Which is larger, its translational kinetic energy or its rotational kinetic energy?","choices":[{"label":"A","text":"Rotational kinetic energy."},{"label":"B","text":"Translational kinetic energy."},{"label":"C","text":"Both are equal."},{"label":"D","text":"You need to know the speed of the hoop to tell."}],"images":[],"answer":"C"},{"id":"Units_5-6-q236","source":"Units_5-6","sourceNumber":"236","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Easy","question":"Consider a solid uniform sphere of radius R and mass M rolling without slipping. Which form of its kinetic energy is larger, translational or rotational?","choices":[{"label":"A","text":"Translational kinetic energy."},{"label":"B","text":"Rotational kinetic energy."},{"label":"C","text":"Both are equal."},{"label":"D","text":"You need to know the speed of the sphere to tell."}],"images":[],"answer":"A"},{"id":"Units_5-6-q237","source":"Units_5-6","sourceNumber":"237","topic":"Unit 8: Fluids","difficulty":"Easy","question":"A solid sphere and a solid cylinder, both uniform and of the same mass and radius, roll without slipping at the same translational velocity. The total mechanical energy of the solid sphere is","choices":[{"label":"A","text":"less than the total kinetic energy of the cylinder."},{"label":"B","text":"more than the total kinetic energy of the cylinder."},{"label":"C","text":"equal to the total kinetic energy of the cylinder."}],"images":[],"answer":"A"},{"id":"Units_5-6-q238","source":"Units_5-6","sourceNumber":"238","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A disk and a hoop of the same mass and radius are released at the same moment at the top of an inclined plane, and both roll without slipping. If both are uniform, which one reaches the bottom of the incline first?","choices":[{"label":"A","text":"The hoop"},{"label":"B","text":"The disk"},{"label":"C","text":"Both reach the bottom at the same moment."}],"images":[],"answer":"B"},{"id":"Units_5-6-q239","source":"Units_5-6","sourceNumber":"239","topic":"Unit 8: Fluids","difficulty":"Easy","question":"A solid sphere, solid cylinder, and a hollow pipe all have equal masses and radii. If the three of them are released simultaneously at the top of an inclined plane and roll without slipping, which one will reach the bottom first?","choices":[{"label":"A","text":"Sphere"},{"label":"B","text":"Cylinder"},{"label":"C","text":"Pipe"},{"label":"D","text":"The pipe and cylinder arrive together before the sphere."},{"label":"E","text":"They all reach the bottom at the same moment."}],"images":[],"answer":"A"},{"id":"Units_5-6-q240","source":"Units_5-6","sourceNumber":"240","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A disk, a hoop, and a solid sphere are released from rest simultaneously at the top of an inclined plane. They are all uniform and roll without slipping. In what order do they reach the bottom?","choices":[{"label":"A","text":"hoop, sphere, disk"},{"label":"B","text":"sphere, hoop, disk"},{"label":"C","text":"hoop, disk, sphere"},{"label":"D","text":"disk, hoop, sphere"},{"label":"E","text":"sphere, disk, hoop"}],"images":[],"answer":"E"},{"id":"Units_5-6-q241","source":"Units_5-6","sourceNumber":"241","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A small uniform disk and a small uniform sphere are released simultaneously at the top of a high inclined plane, and they roll down without slipping. Which one will reach the bottom first?","choices":[{"label":"A","text":"The one of greatest mass"},{"label":"B","text":"The one of smallest diameter"},{"label":"C","text":"The disk"},{"label":"D","text":"The sphere"},{"label":"E","text":"They will reach the bottom at the same moment."}],"images":[],"answer":"D"},{"id":"Units_5-6-q242","source":"Units_5-6","sourceNumber":"242","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"Suppose a uniform solid sphere of mass M and radius R rolls without slipping down an inclined plane starting from rest. The linear velocity of the sphere at the bottom of the incline depends on","choices":[{"label":"A","text":"the mass of the sphere."},{"label":"B","text":"the radius of the sphere."},{"label":"C","text":"both the mass and the radius of the sphere."},{"label":"D","text":"neither the mass nor the radius of the sphere."}],"images":[],"answer":"D"},{"id":"Units_5-6-q243","source":"Units_5-6","sourceNumber":"243","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"Suppose a solid uniform sphere of mass M and radius R rolls without slipping down an inclined plane starting from rest. The rotational velocity of the sphere at the bottom of the incline depends on","choices":[{"label":"A","text":"the mass of the sphere."},{"label":"B","text":"the radius of the sphere."},{"label":"C","text":"both the mass and the radius of the sphere."},{"label":"D","text":"neither the mass nor the radius of the sphere."}],"images":[],"answer":"B"},{"id":"Units_5-6-q244","source":"Units_5-6","sourceNumber":"244","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Two uniform solid balls, one of radius R and mass M , the other of radius 2 R and mass 8 M , roll down a high incline. They start together from rest at the top of the incline. Which one will reach the bottom of the incline first?","choices":[{"label":"A","text":"The large sphere arrives first."},{"label":"B","text":"Both reach the bottom at the same moment."},{"label":"C","text":"The small sphere arrives first."}],"images":[],"answer":"B"},{"id":"Units_5-6-q245","source":"Units_5-6","sourceNumber":"245","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"In the figure, cords have been wound onto two reels, which each carry a rod of length 2 r attached across a diameter of the reel. The rotating systems differ only in that the two identical movable beads are attached at a distance r from the axis of rotation (left), or a distance r /2 from the axis of rotation (right). If you release the hanging blocks simultaneously from rest,","choices":[{"label":"A","text":"the block at the left lands first."},{"label":"B","text":"the block at the right lands first."},{"label":"C","text":"both blocks land at the same moment."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"264","height":"181"}],"answer":"B"},{"id":"Units_5-6-q246","source":"Units_5-6","sourceNumber":"246","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Easy","question":"A person sits on a freely spinning lab stool that has no friction in its axle. When this person extends her arms,","choices":[{"label":"A","text":"her rotational inertia decreases and her rotational speed increases."},{"label":"B","text":"her rotational inertia increases and her rotational speed decreases."},{"label":"C","text":"her rotational inertia increases and her rotational speed increases."},{"label":"D","text":"her rotational inertia decreases and her rotational speed decreases."},{"label":"E","text":"her rotational inertia increases and her rotational speed remains the same."}],"images":[],"answer":"B"},{"id":"Units_5-6-q247","source":"Units_5-6","sourceNumber":"247","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Easy","question":"A merry-go-round spins freely when Diego moves quickly to the center along a radius of the merry-go-round. As he does this, it is true to say that","choices":[{"label":"A","text":"the rotational inertia of the system increases and the rotational speed decreases."},{"label":"B","text":"the rotational inertia of the system decreases and the rotational speed decreases."},{"label":"C","text":"the rotational inertia of the system decreases and the rotational speed increases."},{"label":"D","text":"the rotational inertia of the system decreases and the rotational speed remains the same."},{"label":"E","text":"the rotational inertia of the system increases and the rotational speed increases."}],"images":[],"answer":"C"},{"id":"Units_5-6-q248","source":"Units_5-6","sourceNumber":"248","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"If the answer to your calculation has units of kg ∙ m 2 /s, what type of quantity could it be? (There could be more than one correct choice).","choices":[{"label":"A","text":"Torque"},{"label":"B","text":"Linear momentum"},{"label":"C","text":"Force"},{"label":"D","text":"Work"},{"label":"E","text":"Rotational momentum"}],"images":[],"answer":"E"},{"id":"Units_5-6-q249","source":"Units_5-6","sourceNumber":"249","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"Balanced throughout on her toes, a ballet dancer is spinning in the middle of a horizontal frictionless stage. Which of the following things could she change by moving parts of her body? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The elevation of her center of mass"},{"label":"B","text":"The horizontal component of her linear momentum"},{"label":"C","text":"Her rotational kinetic energy"},{"label":"D","text":"Her total kinetic energy"},{"label":"E","text":"Her translational kinetic energy"}],"images":[],"answer":"A, B, D, E"},{"id":"Units_5-6-q250","source":"Units_5-6","sourceNumber":"250","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"A spinning ice skater on extremely smooth ice is able to control the rate at which she rotates by pulling in her arms. Which of the following statements are true about the skater during this process? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Her kinetic energy remains constant."},{"label":"B","text":"Her rotational momentum remains constant."},{"label":"C","text":"Her rotational inertia remains constant."},{"label":"D","text":"She is subject to a constant non-zero torque."}],"images":[],"answer":"B"},{"id":"Units_5-6-q251","source":"Units_5-6","sourceNumber":"251","topic":"Unit 4: Linear Momentum","difficulty":"Easy","question":"When is the rotational momentum of a system constant?","choices":[{"label":"A","text":"Only when no net external force acts on the system."},{"label":"B","text":"Only when its total kinetic energy is constant."},{"label":"C","text":"Only when no net external torque acts on the system."},{"label":"D","text":"Only when the linear momentum and the energy are constant."},{"label":"E","text":"Only when the rotational inertia is constant."}],"images":[],"answer":"C"},{"id":"Units_5-6-q252","source":"Units_5-6","sourceNumber":"252","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"As you are leaving a building, the door opens outward. If the hinges on the door are on your right, what is the direction of the rotational velocity vector of the door as you open it?","choices":[{"label":"A","text":"Forwards"},{"label":"B","text":"Up"},{"label":"C","text":"Down"},{"label":"D","text":"To your right"},{"label":"E","text":"To your left"}],"images":[],"answer":"C"},{"id":"Units_5-6-q253","source":"Units_5-6","sourceNumber":"253","topic":"Unit 1: Kinematics","difficulty":"Easy","question":"When you ride a bicycle, in what direction is the rotational velocity vector of the wheels?","choices":[{"label":"A","text":"To your left"},{"label":"B","text":"To your right"},{"label":"C","text":"Backwards"},{"label":"D","text":"Forwards"},{"label":"E","text":"Up"}],"images":[],"answer":"A"},{"id":"Units_5-6-q254","source":"Units_5-6","sourceNumber":"254","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Starting from rest, a disk rotates with constant rotational acceleration. If it takes 10 rev to reach a rotational velocity ω, then how many additional revolutions are required to reach a rotational velocity 2ω?","choices":[{"label":"A","text":"20 rev"},{"label":"B","text":"50 rev"},{"label":"C","text":"40 rev"},{"label":"D","text":"10 rev"},{"label":"E","text":"30 rev"}],"images":[],"answer":"E"},{"id":"Units_5-6-q255","source":"Units_5-6","sourceNumber":"255","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"Two points, A and B, are on a disk that rotates about an axis. Point A is three times as far from the axis as point B. If the speed of point B is v , what is the speed of point A?","choices":[{"label":"A","text":"v"},{"label":"B","text":"v /3"},{"label":"C","text":"3 v"},{"label":"D","text":"9 v"},{"label":"E","text":"v"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (3)","width":null,"height":null}],"answer":"A"},{"id":"Units_5-6-q256","source":"Units_5-6","sourceNumber":"256","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Two cylinders rotating counterclockwise around a frictionless axle, as shown, are brought together.They stick and rotate in unison.What is their rotational speed after they stick together?","choices":[{"label":"A","text":"ω"},{"label":"B","text":"ω /2"},{"label":"C","text":"3 ω /2"},{"label":"D","text":"4 ω /3"},{"label":"E","text":"5 ω /3"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"286","height":"175"}],"answer":"A"},{"id":"Units_5-6-q257","source":"Units_5-6","sourceNumber":"257","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A small wheel and a large wheel are connected by a belt, which does not slip on the wheels. The small wheel is turned at a constant rotational velocity ω s . How does the magnitude of the rotational velocity of the large wheel ω L compare to that of the small wheel?","choices":[{"label":"A","text":"ω s > ω L"},{"label":"B","text":"ω s < ω L"},{"label":"C","text":"ω s = ω L"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"252","height":"111"}],"answer":"A"},{"id":"Units_5-6-q258","source":"Units_5-6","sourceNumber":"258","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"Three identical objects, each of mass M , are fastened to a massless rod of length L as shown in the diagram. The rotational inertia about one end of the rod of this array is:","choices":[{"label":"A","text":"3 ML 2 /2"},{"label":"B","text":"ML 2"},{"label":"C","text":"ML 2 /2"},{"label":"D","text":"5 ML 2 /4"},{"label":"E","text":"3 ML 2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"276","height":"162"}],"answer":"B"},{"id":"Units_5-6-q259","source":"Units_5-6","sourceNumber":"259","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"A solid sphere of mass m is fastened to another sphere of mass 2 m by a thin rod with a length of 3 x . The spheres have negligible size, and the rod has negligible mass. What is the rotational inertia of the system of spheres as the rod is rotated about the point located at position x , as shown?","choices":[{"label":"A","text":"3 mx 2"},{"label":"B","text":"4 mx 2"},{"label":"C","text":"9 mx 2"},{"label":"D","text":"5 mx 2"},{"label":"E","text":"10 mx 2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"376","height":"136"}],"answer":"E"},{"id":"Units_5-6-q260","source":"Units_5-6","sourceNumber":"260","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"Two disks are cut from the same cardboard of negligible mass. The radius of disk B is twice the radius of the disk A. The disks can rotate around axes with negligible friction. Two battery-powered fans with significant mass are attached to the disks, as shown above. When switched on, the fans exert equal forces on the disks. Which of the following correctly compares the rotational accelerations of the disks after the fans are switched on?","choices":[{"label":"A","text":"α A = 4 α B"},{"label":"B","text":"α B = 2 α A"},{"label":"C","text":"α A = α B"},{"label":"D","text":"α A = 2 α B"},{"label":"E","text":"α B = 4 α A"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"576","height":"185"}],"answer":"A"},{"id":"Units_5-6-q261","source":"Units_5-6","sourceNumber":"261","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"What is the rotational speed, in rad/s, of a flywheel turning at 813.0 revolutions/minute?","choices":[{"label":"A","text":"85.14 rad/s"},{"label":"B","text":"63.84 rad/s"},{"label":"C","text":"95.33 rad/s"},{"label":"D","text":"13.53 rad/s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q262","source":"Units_5-6","sourceNumber":"262","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A turntable is rotating at a constant rotational speed of 33 revolutions/minute. Through how many degrees does the turntable rotate in 0.32 s?","choices":[{"label":"A","text":"35°"},{"label":"B","text":"74°"},{"label":"C","text":"63°"},{"label":"D","text":"46°"}],"images":[],"answer":"C"},{"id":"Units_5-6-q264","source":"Units_5-6","sourceNumber":"264","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A chicken is running in a circular path with a rotational speed of 1.52 rad/s. In what time interval does the chicken to complete one revolution?","choices":[{"label":"A","text":"8.26 s"},{"label":"B","text":"4.13 s"},{"label":"C","text":"2.07 s"},{"label":"D","text":"4.77 s"},{"label":"E","text":"118 s"}],"images":[],"answer":"B"},{"id":"Units_5-6-q265","source":"Units_5-6","sourceNumber":"265","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"When a fan is turned off, its rotational speed decreases from 10 rad/s to 6.3 rad/s in 5.0 s. What is the magnitude of the average rotational acceleration of the fan?","choices":[{"label":"A","text":"11 rad/s 2"},{"label":"B","text":"0.86 rad/s 2"},{"label":"C","text":"1.2 rad/s 2"},{"label":"D","text":"0.37 rad/s 2"},{"label":"E","text":"0.74 rad/s 2"}],"images":[],"answer":"B"},{"id":"Units_5-6-q270","source":"Units_5-6","sourceNumber":"270","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A child is riding a merry-go-round that is turning at 7.18 rev/min. If the child is standing 4.65 m from the center of the merry-go-round, how fast is the child moving?","choices":[{"label":"A","text":"1.75 m/s"},{"label":"B","text":"1.80 m/s"},{"label":"C","text":"3.50 m/s"},{"label":"D","text":"0.556 m/s"},{"label":"E","text":"5.64 m/s"}],"images":[],"answer":"C"},{"id":"Units_5-6-q271","source":"Units_5-6","sourceNumber":"271","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A string is wound tightly around a fixed pulley having a radius of 5.0 cm. As the string is pulled, the pulley rotates without any slipping of the string. What is the rotational speed of the pulley when the string is moving at 5.0 m/s?","choices":[{"label":"A","text":"50 rad/s"},{"label":"B","text":"25 rad/s"},{"label":"C","text":"10 rad/s"},{"label":"D","text":"20 rad/s"},{"label":"E","text":"100 rad/s"}],"images":[],"answer":"E"},{"id":"Units_5-6-q272","source":"Units_5-6","sourceNumber":"272","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A scooter has wheels with a diameter of 120 mm. What is the rotational speed of the wheels when the scooter is moving forward at 6.00 m/s?","choices":[{"label":"A","text":"7.54 rad/s"},{"label":"B","text":"5.24 rad/s"},{"label":"C","text":"100 rad/s"},{"label":"D","text":"4.99 rad/s"},{"label":"E","text":"10.47 rad/s"}],"images":[],"answer":"C"},{"id":"Units_5-6-q273","source":"Units_5-6","sourceNumber":"273","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A bicycle has wheels that are 60 cm in diameter. What is the rotational speed of these wheels when it is moving at 4.0 m/s?","choices":[{"label":"A","text":"4.8 rad/s"},{"label":"B","text":"13 rad/s"},{"label":"C","text":"0.36 rad/s"},{"label":"D","text":"7.6 rad/s"},{"label":"E","text":"1.2 rad/s"}],"images":[],"answer":"B"},{"id":"Units_5-6-q275","source":"Units_5-6","sourceNumber":"275","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Hard","question":"A rolling wheel of diameter of 68 cm slows down uniformly from 8.4 m/s to rest over a distance of 115 m. What is the magnitude of its rotational acceleration if there was no slipping?","choices":[{"label":"A","text":"1.8 rad/s 2"},{"label":"B","text":"0.90 rad/s 2"},{"label":"C","text":"11 rad/s 2"},{"label":"D","text":"5.7 rad/s 2"}],"images":[],"answer":"A"},{"id":"Units_5-6-q276","source":"Units_5-6","sourceNumber":"276","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A child is riding a merry-go-round that has an instantaneous rotational speed of 1.25 rad/s and a rotational acceleration of 0.745 rad/s 2 . The child is standing 4.65 m from the center of the merry-go-round. What is the magnitude of the radial acceleration of the child?","choices":[{"label":"A","text":"3.46 m/s 2"},{"label":"B","text":"4.10 m/s 2"},{"label":"C","text":"7.27 m/s 2"},{"label":"D","text":"2.58 m/s 2"},{"label":"E","text":"8.05 m/s 2"}],"images":[],"answer":"A"},{"id":"Units_5-6-q281","source":"Units_5-6","sourceNumber":"281","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"In what time interval does a rotating object speed up from 15.0 rad/s to 33.3 rad/s if it has a uniform rotational acceleration of 3.45 rad/s 2 ?","choices":[{"label":"A","text":"5.30 s"},{"label":"B","text":"9.57 s"},{"label":"C","text":"10.6 s"},{"label":"D","text":"63.1 s"},{"label":"E","text":"4.35 s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q282","source":"Units_5-6","sourceNumber":"282","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Easy","question":"A wheel accelerates from rest to 59 rad/s at a uniform rate of 58 rad/s 2 . Through what angle (in radians) did the wheel turn while accelerating?","choices":[{"label":"A","text":"30 rad"},{"label":"B","text":"38 rad"},{"label":"C","text":"24 rad"},{"label":"D","text":"60 rad"}],"images":[],"answer":"A"},{"id":"Units_5-6-q283","source":"Units_5-6","sourceNumber":"283","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A machinist turns on the power to a grinding wheel at the instant t = 0 s. The wheel accelerates uniformly from rest for 10 s and reaches the operating rotational speed of 38 rad/s. The wheel is run at that rotational speed for 30 s and then power is shut off. The wheel slows down uniformly with rotational acceleration of magnitude 2.1 rad/s 2 until the wheel stops. In this situation, what is the rotational acceleration of the wheel between t = 0 s and t = 10 s?","choices":[{"label":"A","text":"6.1 rrad/s 2"},{"label":"B","text":"6.8 rad/s 2"},{"label":"C","text":"4.6 rad/s 2"},{"label":"D","text":"5.3 rad/s 2"},{"label":"E","text":"3.8 rad/s 2"}],"images":[],"answer":"D"},{"id":"Units_5-6-q284","source":"Units_5-6","sourceNumber":"284","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A machinist turns on the power on to a grinding wheel at the instant t = 0 s. The wheel accelerates uniformly from rest for 10 s and reaches the operating rotational speed of 58 rad/s. The wheel is run at that rotational velocity for 30 s, and then power is shut off. The wheel slows down uniformly with rotational acceleration of magnitude 1.4 rad/s 2 until the wheel stops. What is the total number of revolutions made by the wheel in this situation?","choices":[{"label":"A","text":"280 rev"},{"label":"B","text":"510 rev"},{"label":"C","text":"750 rev"},{"label":"D","text":"470 rev"},{"label":"E","text":"320 rev"}],"images":[],"answer":"B"},{"id":"Units_5-6-q285","source":"Units_5-6","sourceNumber":"285","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A machinist turns on the power on to a grinding wheel at the instant t = 0 s. The wheel accelerates uniformly from rest for 10 s and reaches the operating rotational speed of 96 rad/s. The wheel is run at that rotational velocity for 40 s and then power is shut off. The wheel slows down uniformly with rotational acceleration of magnitude 1.5 rad/s 2 until the wheel stops. After what time interval after the power is shut off does the wheel come to rest?","choices":[{"label":"A","text":"68 s"},{"label":"B","text":"70 s"},{"label":"C","text":"66 s"},{"label":"D","text":"64 s"},{"label":"E","text":"62 s"}],"images":[],"answer":"D"},{"id":"Units_5-6-q287","source":"Units_5-6","sourceNumber":"287","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An old vinyl record that is originally rotating at 33.3 rad/s is given a uniform rotational acceleration of 2.15 rad/s 2 . Through what angle has the record turned when its rotational speed reaches 72.0 rad/s?","choices":[{"label":"A","text":"316 rad"},{"label":"B","text":"83.2 rad"},{"label":"C","text":"697 rad"},{"label":"D","text":"66.8 rad"},{"label":"E","text":"948 rad"}],"images":[],"answer":"E"},{"id":"Units_5-6-q288","source":"Units_5-6","sourceNumber":"288","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A wheel rotates through an angle of 13.8 rad as it slows down uniformly from 22.0 rad/s to 13.5 rad/s. What is the magnitude of the rotational acceleration of the wheel?","choices":[{"label":"A","text":"22.5 rad/s 2"},{"label":"B","text":"5.45 rad/s 2"},{"label":"C","text":"0.616 rad/s 2"},{"label":"D","text":"10.9 rad/s 2"},{"label":"E","text":"111 rad/s 2"}],"images":[],"answer":"C"},{"id":"Units_5-6-q289","source":"Units_5-6","sourceNumber":"289","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A pulley has an initial rotational speed of 12.5 rad/s and a constant rotational acceleration of 3.41 rad/s 2 . Through what angle does the pulley turn in 5.26 s?","choices":[{"label":"A","text":"42.6 rad"},{"label":"B","text":"113 rad"},{"label":"C","text":"160 rad"},{"label":"D","text":"22.6 rad"},{"label":"E","text":"19.3 rad"}],"images":[],"answer":"B"},{"id":"Units_5-6-q290","source":"Units_5-6","sourceNumber":"290","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"An old 78 rev/min vinyl record rotates through an angle of 320° as it slows down uniformly from 78.0 rev/min to 22.8 rev/min . What is the magnitude of the rotational acceleration of the record?","choices":[{"label":"A","text":"2.34 rad/s 2"},{"label":"B","text":"6.50 rad/s 2"},{"label":"C","text":"5.46 rad/s 2"},{"label":"D","text":"10.9 rad/s 2"},{"label":"E","text":"8.35 rad/s 2"}],"images":[],"answer":"D"},{"id":"Units_5-6-q292","source":"Units_5-6","sourceNumber":"292","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A Ferris wheel rotating at 20 rad/s slows down with a constant rotational acceleration of magnitude 5.0 rad/s 2 . How many revolutions does it make while slowing down as it comes to rest?","choices":[{"label":"A","text":"6.4 rev"},{"label":"B","text":"40 rev"},{"label":"C","text":"20 rev"},{"label":"D","text":"3.2 rev"}],"images":[],"answer":"A"},{"id":"Units_5-6-q295","source":"Units_5-6","sourceNumber":"295","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A triatomic molecule is oriented as follows along the x- axis: mass m is at the origin, mass 2 m is at x = a , and mass 3 m is at x = 2 a . What is the rotational inertia of this molecule about the y- axis?","choices":[{"label":"A","text":"2 ma 2"},{"label":"B","text":"12 ma 2"},{"label":"C","text":"14 ma 2"},{"label":"D","text":"3 ma 2"}],"images":[],"answer":"D"},{"id":"Units_5-6-q296","source":"Units_5-6","sourceNumber":"296","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"Two uniform solid spheres have the same mass, but one has twice the radius of the other. The ratio of the larger sphere's rotational inertia about a central axis to that of the smaller sphere is","choices":[{"label":"A","text":"8/5."},{"label":"B","text":"2."},{"label":"C","text":"4."},{"label":"D","text":"1/2."},{"label":"E","text":"4/5."}],"images":[],"answer":"C"},{"id":"Units_5-6-q300","source":"Units_5-6","sourceNumber":"300","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A potter's wheel has the shape of a solid uniform disk of mass 7.0 kg and radius 0.65 m. It spins about an axis perpendicular to the disk at its center. A small 2.1-kg lump of very dense clay is dropped onto the wheel at a distance 0.41 m from the axis. What is the rotational inertia of the system about the axis of spin?","choices":[{"label":"A","text":"0.40 kg ∙ m 2"},{"label":"B","text":"2.5 kg ∙ m 2"},{"label":"C","text":"1.8 kg ∙ m 2"},{"label":"D","text":"1.5 kg ∙ m 2"}],"images":[],"answer":"C"},{"id":"Units_5-6-q301","source":"Units_5-6","sourceNumber":"301","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A uniform solid cylinder with a radius of 10 cm and a mass of 3.0 kg is rotating about its axis with a rotational speed of 33.4 rev/min. What is its kinetic energy?","choices":[{"label":"A","text":"0.092 J"},{"label":"B","text":"0.96 J"},{"label":"C","text":"0.18 J"},{"label":"D","text":"17 J"},{"label":"E","text":"1.1 J"}],"images":[],"answer":"A"},{"id":"Units_5-6-q302","source":"Units_5-6","sourceNumber":"302","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"What is the kinetic energy of a 120-cm thin uniform rod with a mass of 450 g that is rotating, about an axis perpendicular to the rod and through its center, at 3.60 rad/s?","choices":[{"label":"A","text":"2.10 J"},{"label":"B","text":"0.350 J"},{"label":"C","text":"0.960 J"},{"label":"D","text":"0.700 J"},{"label":"E","text":"4.20 J"}],"images":[],"answer":"B"},{"id":"Units_5-6-q303","source":"Units_5-6","sourceNumber":"303","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"To drive a typical car at 40 mi/h on a level road for one hour requires about 3.2 × 10 7 J of energy. Suppose we tried to store this much energy in a spinning, solid, uniform, cylindrical disk as a flywheel. A large flywheel cannot be spun too fast or it will fracture. If we used a flywheel of diameter 1.2 m and mass 400 kg, what rotational speed would be required to store 3.2 × 10 7 J?","choices":[{"label":"A","text":"3600 rad/s"},{"label":"B","text":"530 rad/s"},{"label":"C","text":"940 rad/s"},{"label":"D","text":"5500 rad/s"},{"label":"E","text":"1800 rad/s"}],"images":[],"answer":"C"},{"id":"Units_5-6-q308","source":"Units_5-6","sourceNumber":"308","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"While spinning down from 500 rev/min to rest, a flywheel does 3.9 kJ of work. This flywheel is in the shape of a solid uniform disk of radius 1.2 m. What is the mass of this flywheel?","choices":[{"label":"A","text":"4.6 kg"},{"label":"B","text":"4.0 kg"},{"label":"C","text":"3.4 kg"},{"label":"D","text":"5.2 kg"}],"images":[],"answer":"B"},{"id":"Units_5-6-q309","source":"Units_5-6","sourceNumber":"309","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A solid uniform sphere of mass 120 kg and radius 1.7 m starts from rest and rolls without slipping down an inclined plane of vertical height 5.3 m. What is the rotational speed of the sphere at the bottom of the inclined plane?","choices":[{"label":"A","text":"5.1 rad/s"},{"label":"B","text":"9.7 rad/s"},{"label":"C","text":"6.1 rad/s"},{"label":"D","text":"8.7 rad/s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q310","source":"Units_5-6","sourceNumber":"310","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"A solid uniform disk of diameter 3.20 m and mass 42 kg rolls without slipping to the bottom of a hill, starting from rest. If the rotational speed of the disk is 4.27 rad/s at the bottom, how high did it start on the hill?","choices":[{"label":"A","text":"2.68 m"},{"label":"B","text":"4.28 m"},{"label":"C","text":"3.14 m"},{"label":"D","text":"3.57 m"}],"images":[],"answer":"D"},{"id":"Units_5-6-q311","source":"Units_5-6","sourceNumber":"311","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A wheel having a rotational inertia of 5.00 kg ∙ m 2 starts from rest and accelerates under a constant torque of 3.00 N ∙ m for 8.00 s. What is the wheel's rotational kinetic energy at the end of 8.00 s?","choices":[{"label":"A","text":"64.0 J"},{"label":"B","text":"57.6 J"},{"label":"C","text":"122 J"},{"label":"D","text":"78.8 J"}],"images":[],"answer":"B"},{"id":"Units_5-6-q312","source":"Units_5-6","sourceNumber":"312","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"As shown in the figure, two blocks are connected by a light string that passes over a frictionless pulley having a rotational inertia of 0.0040 kg ∙ m 2 and diameter 10 cm. The coefficient of kinetic friction between the table top and the upper block is 0.30. The blocks are released from rest, and the string does not slip on the pulley. How fast is the upper block moving when the lower one has fallen 0.60 m?","choices":[{"label":"A","text":"2.0 m/s"},{"label":"B","text":"5.4 m/s"},{"label":"C","text":"3.2 m/s"},{"label":"D","text":"1.2 m/s"},{"label":"E","text":"1.4 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"278","height":"192"}],"answer":"E"},{"id":"Units_5-6-q313","source":"Units_5-6","sourceNumber":"313","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A solid uniform ball with a mass of 125 g is rolling without slipping along the horizontal surface of a table with a speed of 4.5 m/s when it rolls off the edge and falls toward the floor, 1.1 m below. What is the rotational kinetic energy of the ball just before it hits the floor?","choices":[{"label":"A","text":"0.73 J"},{"label":"B","text":"2.6 J"},{"label":"C","text":"0.51 J"},{"label":"D","text":"1.1 J"},{"label":"E","text":"This question cannot be answered without knowing the radius of the ball."}],"images":[],"answer":"C"},{"id":"Units_5-6-q314","source":"Units_5-6","sourceNumber":"314","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A string is wrapped tightly around a fixed reel that has a rotational inertia of 0.0352 kg ∙ m 2 and a radius of 12.5 cm. An object of mass 423 g is attached to the free end of the string. With the string vertical and taut, the object is gently released so it can descend under the influence of gravity. As the object descends, the string unwinds and causes the reel to rotate without friction at its axle. What is the speed of the object after it has fallen 1.25 m?","choices":[{"label":"A","text":"1.97 m/s"},{"label":"B","text":"3.94 m/s"},{"label":"C","text":"2.28 m/s"},{"label":"D","text":"4.95 m/s"},{"label":"E","text":"2.00 m/s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q315","source":"Units_5-6","sourceNumber":"315","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A string is wrapped tightly around a fixed frictionless reel that has a rotational inertia of 0.0352 kg ∙ m 2 and a radius of 12.5 cm. The string is pulled off the pulley with a constant tension force of 5.00 N, causing the reel to rotate. What is the speed of the string after it has unwound 1.25 m?","choices":[{"label":"A","text":"4.95 m/s"},{"label":"B","text":"3.18 m/s"},{"label":"C","text":"2.36 m/s"},{"label":"D","text":"1.18 m/s"},{"label":"E","text":"2.09 m/s"}],"images":[],"answer":"C"},{"id":"Units_5-6-q316","source":"Units_5-6","sourceNumber":"316","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"An Atwood machine consists of a block with mass 3.5 kg connected by a light string to a larger block with mass 6.0 kg over a frictionless pulley with a rotational inertia of 0.0352 kg ∙ m 2 and a radius of 12.5 cm. If the system is released from rest, what is the speed of the blocks after they have moved through 1.25 m if the string does not slip on the pulley?","choices":[{"label":"A","text":"5.0 m/s"},{"label":"B","text":"2.3 m/s"},{"label":"C","text":"4.0 m/s"},{"label":"D","text":"2.0 m/s"},{"label":"E","text":"6.0 m/s"}],"images":[],"answer":"B"},{"id":"Units_5-6-q318","source":"Units_5-6","sourceNumber":"318","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A pencil that is 15.7 cm long is released from a vertical position with the eraser end resting on a table. The eraser does not slip or leave the table as the pencil tips over. Treat the pencil like a uniform rod. What is the rotational speed of the pencil just before it hits the table?","choices":[{"label":"A","text":"13.7 rad/s"},{"label":"B","text":"3.70 rad/s"},{"label":"C","text":"27.4 rad/s"},{"label":"D","text":"7.23 rad/s"},{"label":"E","text":"16.8 rad/s"}],"images":[],"answer":"C"},{"id":"Units_5-6-q319","source":"Units_5-6","sourceNumber":"319","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A uniform solid disk is released from rest and rolls without slipping down an inclined plane that makes an angle of 25° with the horizontal. What is the forward speed of the disk after it has rolled 3.0 m, measured along the plane?","choices":[{"label":"A","text":"6.3 m/s"},{"label":"B","text":"2.0 m/s"},{"label":"C","text":"3.5 m/s"},{"label":"D","text":"5.7 m/s"},{"label":"E","text":"4.1 m/s"}],"images":[],"answer":"E"},{"id":"Units_5-6-q320","source":"Units_5-6","sourceNumber":"320","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A solid uniform disk is rolling without slipping along a horizontal surface with a speed of 4.5 m/s when it starts up a ramp that makes an angle of 25° with the horizontal. What is the speed of the disk after it has rolled 3.0 m up, as measured along the surface of the ramp?","choices":[{"label":"A","text":"1.9 m/s"},{"label":"B","text":"2.1 m/s"},{"label":"C","text":"4.0 m/s"},{"label":"D","text":"6.8 m/s"},{"label":"E","text":"8.0 m/s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q321","source":"Units_5-6","sourceNumber":"321","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A solid uniform sphere is rolling without slipping along a horizontal surface with a speed of 5.5 m/s when it starts up a ramp that makes an angle of 25° with the horizontal. What is the speed of the sphere after it has rolled 3.0 m up as measured along the surface of the ramp?","choices":[{"label":"A","text":"2.2 m/s"},{"label":"B","text":"3.5 m/s"},{"label":"C","text":"4.0 m/s"},{"label":"D","text":"1.9 m/s"},{"label":"E","text":"8.0 m/s"}],"images":[],"answer":"B"},{"id":"Units_5-6-q322","source":"Units_5-6","sourceNumber":"322","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A hoop is rolling without slipping along a horizontal surface with a forward speed of 5.50 m/s when it starts up a ramp that makes an angle of 25.0° with the horizontal. What is the speed of the hoop after it has rolled 3.00 m up as measured along the surface of the ramp?","choices":[{"label":"A","text":"3.79 m/s"},{"label":"B","text":"1.91 m/s"},{"label":"C","text":"2.06 m/s"},{"label":"D","text":"4.22 m/s"},{"label":"E","text":"8.02 m/s"}],"images":[],"answer":"D"},{"id":"Units_5-6-q323","source":"Units_5-6","sourceNumber":"323","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A hoop with a mass of 2.75 kg is rolling without slipping along a horizontal surface with a speed of 4.5 m/s when it starts down a ramp that makes an angle of 25° below the horizontal. What is the forward speed of the hoop after it has rolled 3.0 m down as measured along the surface of the ramp?","choices":[{"label":"A","text":"5.2 m/s"},{"label":"B","text":"8.0 m/s"},{"label":"C","text":"6.3 m/s"},{"label":"D","text":"5.7 m/s"},{"label":"E","text":"4.9 m/s"}],"images":[],"answer":"D"},{"id":"Units_5-6-q324","source":"Units_5-6","sourceNumber":"324","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A hoop with a mass of 2.75 kg is rolling without slipping along a horizontal surface with a speed of 4.5 m/s when it starts down a ramp that makes an angle of 25° below the horizontal. What is the rotational kinetic energy of the hoop after it has rolled 3.0 m down as measured along the surface of the ramp?","choices":[{"label":"A","text":"34 J"},{"label":"B","text":"45 J"},{"label":"C","text":"22 J"},{"label":"D","text":"62 J"},{"label":"E","text":"This question cannot be answered without knowing the radius of the hoop."}],"images":[],"answer":"B"},{"id":"Units_5-6-q329","source":"Units_5-6","sourceNumber":"329","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A solid uniform cylinder is rolling without slipping. What fraction of its kinetic energy is rotational?","choices":[{"label":"A","text":"1/4"},{"label":"B","text":"1/3"},{"label":"C","text":"3/4"},{"label":"D","text":"1/2"},{"label":"E","text":"2/3"}],"images":[],"answer":"B"},{"id":"Units_5-6-q331","source":"Units_5-6","sourceNumber":"331","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"The drive chain in a bicycle is applying a net torque of 0.850 N ∙ m to the back wheel of the bicycle. You can treat the wheel as a thin uniform hoop (or ring) with a mass of 0.750 kg and a radius of 33.0 cm. What is the rotational acceleration of the wheel?","choices":[{"label":"A","text":"5.20 rad/s 2"},{"label":"B","text":"1.06 rad/s 2"},{"label":"C","text":"3.43 rad/s 2"},{"label":"D","text":"10.4 rad/s 2"},{"label":"E","text":"20.8 rad/s 2"}],"images":[],"answer":"E"},{"id":"Units_5-6-q332","source":"Units_5-6","sourceNumber":"332","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A mechanic is examining the wheel of a bicycle, preparing to adjust the brake. With the bicycle off the ground, he manually rotates the wheel until it reaches a rotational speed of 12.0 rad/s and then allows it to coast to a stop. If the wheel has a rotational inertia of 0.100 kg ∙ m 2 , and the wheel slows uniformly to a stop in 160 s, what is the magnitude of the retarding torque?","choices":[{"label":"A","text":"1.33 N ∙ m"},{"label":"B","text":"0.00750 N ∙ m"},{"label":"C","text":"0.0787 N ∙ m"},{"label":"D","text":"1.67 N ∙ m"},{"label":"E","text":"1.00 N ∙ m"}],"images":[],"answer":"B"},{"id":"Units_5-6-q333","source":"Units_5-6","sourceNumber":"333","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"A force of 16.88 N is applied tangentially to a wheel of radius 0.340 m and causes a rotational acceleration of 1.20 rad/s 2 . What is the rotational inertia of the wheel?","choices":[{"label":"A","text":"4.78 kg ∙ m 2"},{"label":"B","text":"7.17 kg ∙ m 2"},{"label":"C","text":"3.59 kg ∙ m 2"},{"label":"D","text":"5.98 kg ∙ m 2"}],"images":[],"answer":"A"},{"id":"Units_5-6-q334","source":"Units_5-6","sourceNumber":"334","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A torque of 12 N ∙ m is applied to a solid, uniform disk of radius 0.50 m. If the disk's rotation accelerates at 1.6 rad/s 2 , what is the mass of the disk?","choices":[{"label":"A","text":"15 kg"},{"label":"B","text":"30 kg"},{"label":"C","text":"60 kg"},{"label":"D","text":"45 kg"}],"images":[],"answer":"C"},{"id":"Units_5-6-q335","source":"Units_5-6","sourceNumber":"335","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A particular motor can provide a maximum torque of 110 N ∙ m. Assuming that all of this torque is used to accelerate a solid, uniform, cylindrical flywheel of mass 10.0 kg and radius 3.00 m, in what time interval will the flywheel accelerate from rest to 8.13 rad/s?","choices":[{"label":"A","text":"2.83 s"},{"label":"B","text":"3.33 s"},{"label":"C","text":"4.36 s"},{"label":"D","text":"4.03 s"}],"images":[],"answer":"B"},{"id":"Units_5-6-q336","source":"Units_5-6","sourceNumber":"336","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"The drum shown in the figure has a radius of 0.40 m and a rotational inertia of 2.3 kg ∙ m 2 about an axis perpendicular to it through its center. The frictional torque at the drum axle is 3.0 N ∙ m. A 14-m length of rope is wound around the rim. The drum is initially at rest. A constant force is applied to the free end of the rope until the rope is completely unwound and slips off. At that instant, the rotational speed of the drum is 23 rad/s. The drum then slows down at a constant rate and comes to a halt. In this situation, what was the magnitude of the constant force applied to the rope?","choices":[{"label":"A","text":"40 N"},{"label":"B","text":"29 N"},{"label":"C","text":"18 N"},{"label":"D","text":"51 N"},{"label":"E","text":"7.5 N"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"241","height":"115"}],"answer":"D"},{"id":"Units_5-6-q338","source":"Units_5-6","sourceNumber":"338","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A uniform solid cylinder of mass 10 kg can rotate about a frictionless axle through its center O, as shown in the cross-sectional view in the figure. A rope wrapped around the outer radius R 1 = 1.0 m exerts a force of magnitude F 1 = 5.0 N to the right. A second rope wrapped around another low-mass section of radius R 2 = 0.50 m exerts a force of magnitude F 2 = 6.0 N downward. What is the rotational acceleration of the cylinder?","choices":[{"label":"A","text":"0.40 rad/s 2 clockwise"},{"label":"B","text":"0.60 rad/s 2 clockwise"},{"label":"C","text":"1.0 rad/s 2 clockwise"},{"label":"D","text":"0.80 rad/s 2 clockwise"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"188","height":"180"}],"answer":"B"},{"id":"Units_5-6-q339","source":"Units_5-6","sourceNumber":"339","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A uniform solid cylinder of mass 10 kg can rotate about a frictionless axle through its center O, as shown in the cross-sectional view in the figure. A rope wrapped around the outer radius R 1 = 1.0 m exerts a force of magnitude F 1 = 5.0 N to the right. A second rope wrapped around another low-mass section of radius R 2 = 0.50 m exerts a force of magnitude F 2 = 6.0 N downward. How many radians does the cylinder rotate through in the first 5.0 seconds, if it starts from rest?","choices":[{"label":"A","text":"10 rad clockwise"},{"label":"B","text":"13 rad clockwise"},{"label":"C","text":"7.5 rad clockwise"},{"label":"D","text":"5.0 rad clockwise"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"188","height":"180"}],"answer":"D"},{"id":"Units_5-6-q340","source":"Units_5-6","sourceNumber":"340","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"In the figure, cords have been wound onto reels, each of which carries a rod of length 2 r attached across a diameter of the reel. The rotating systems differ only in that the two identical movable beads are fastened a distance r from the axis of rotation (left), or a distance r /2 from the axis of rotation (right). If you release the hanging blocks simultaneously from rest, and call t L the time interval taken by the block on the left and t R the time interval taken by the block on the right to reach the bottom, respectively, then","choices":[{"label":"A","text":"t L = t R ."},{"label":"B","text":"t L > t R ."},{"label":"C","text":"t L < t R ."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"212","height":"149"}],"answer":"B"},{"id":"Units_5-6-q344","source":"Units_5-6","sourceNumber":"344","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"As shown in the figure, a 35.30-kg box is attached to a light string that is wrapped around a cylindrical frictionless spool of radius 10.0 cm and rotational inertia 4.00 kg ∙ m 2 . The spool is suspended from the ceiling, and the box is then released from rest a distance 3.50 m above the floor. After what time interval does the box reach the floor?","choices":[{"label":"A","text":"2.85 s"},{"label":"B","text":"5.89 s"},{"label":"C","text":"0.892 s"},{"label":"D","text":"4.18 s"},{"label":"E","text":"2.97 s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"88","height":"197"}],"answer":"E"},{"id":"Units_5-6-q345","source":"Units_5-6","sourceNumber":"345","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A 385-g tile hangs from one end of a string that goes over a pulley with a rotational inertia of 0.0125 kg ∙ m 2 and a radius of 15.0 cm. A tile of mass 710 g hangs from the other end of the string. When the tiles are released, the larger one accelerates downward while the lighter one accelerates upward. The pulley has no friction in its axle and turns without the string slipping. What is the tension in the string on the side of the 710-g tile?","choices":[{"label":"A","text":"6.87 N"},{"label":"B","text":"5.59 N"},{"label":"C","text":"4.41 N"},{"label":"D","text":"9.77 N"},{"label":"E","text":"3.68 N"}],"images":[],"answer":"B"},{"id":"Units_5-6-q348","source":"Units_5-6","sourceNumber":"348","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A proton of mass 1.67 × 10 -27 kg moves in a circle of diameter 1.6 m with a rotational speed of 2.0 × 10 6 rad/s. What is the rotational momentum of the proton?","choices":[{"label":"A","text":"3.2 × 10 -21 kg ∙ m 2 /s"},{"label":"B","text":"1.3 × 10 -21 kg ∙ m 2 /s"},{"label":"C","text":"2.1 × 10 -21 kg ∙ m 2 /s"},{"label":"D","text":"1.8 × 10 -21 kg ∙ m 2 /s"}],"images":[],"answer":"C"},{"id":"Units_5-6-q349","source":"Units_5-6","sourceNumber":"349","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"Three solid, uniform, cylindrical flywheels, each of mass 65.0 kg and radius 1.47 m, rotate independently around a common axis through their centers. Two of the flywheels rotate in one direction at 8.94 rad/s, but the other one rotates in the opposite direction at 3.42 rad/s. Calculate the magnitude of the net rotational momentum of the system.","choices":[{"label":"A","text":"1500 kg ∙ m 2 /s"},{"label":"B","text":"940 kg ∙ m 2 /s"},{"label":"C","text":"975 kg ∙ m 2 /s"},{"label":"D","text":"1020 kg ∙ m 2 /s"}],"images":[],"answer":"D"},{"id":"Units_5-6-q350","source":"Units_5-6","sourceNumber":"350","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A uniform, solid, cylindrical flywheel of radius 1.4 m and mass 15 kg rotates at 2.7 rad/s. What is the magnitude of the flywheel's rotational momentum?","choices":[{"label":"A","text":"60 kg ∙ m 2 /s"},{"label":"B","text":"20 kg ∙ m 2 /s"},{"label":"C","text":"40 kg ∙ m 2 /s"},{"label":"D","text":"80 kg ∙ m 2 /s"}],"images":[],"answer":"C"},{"id":"Units_5-6-q351","source":"Units_5-6","sourceNumber":"351","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A uniform 135-g meter stick rotates about an axis perpendicular to the stick passing through its center with a rotational speed of 3.50 rad/s. What is the magnitude of the rotational momentum of the stick?","choices":[{"label":"A","text":"0.0394 kg ∙ m 2 /s"},{"label":"B","text":"0.0739 kg ∙ m 2 /s"},{"label":"C","text":"0.0236 kg ∙ m 2 /s"},{"label":"D","text":"0.158 kg ∙ m 2 /s"},{"label":"E","text":"0.473 kg ∙ m 2 /s"}],"images":[],"answer":"A"},{"id":"Units_5-6-q352","source":"Units_5-6","sourceNumber":"352","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A figure skater rotating at 5.00 rad/s with arms extended has a rotational inertia of 2.25 kg ∙ m 2 . If he pulls in his arms so his rotational inertia decreases to 1.80 kg ∙ m 2 , what will be his new rotational speed?","choices":[{"label":"A","text":"4.60 rad/s"},{"label":"B","text":"2.25 rad/s"},{"label":"C","text":"0.81 rad/s"},{"label":"D","text":"6.25 rad/s"}],"images":[],"answer":"D"},{"id":"Units_5-6-q353","source":"Units_5-6","sourceNumber":"353","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"A solid wood door, 90.0 cm wide by 2.00 m tall has a mass of 35.0 kg. It is open and at rest. A small 500-g ball is thrown perpendicular to the door with a speed of 20.0 m/s and hits the door 60.0 cm from the hinged side. The ball rebounds with a speed of 16.0 m/s along the same line. What is the rotational speed of the door just after the collision with the ball?","choices":[{"label":"A","text":"0.127 rad/s"},{"label":"B","text":"2.28 rad/s"},{"label":"C","text":"1.14 rad/s"},{"label":"D","text":"4.57 rad/s"},{"label":"E","text":"0.925 rad/s"}],"images":[],"answer":"C"},{"id":"Units_5-6-q354","source":"Units_5-6","sourceNumber":"354","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A light-weight potter's wheel, having a rotational inertia of 24 kg ∙ m 2 , is spinning freely at 40.0 rev/min . The potter drops a small but dense lump of clay onto the wheel, where it sticks at a distance of 1.2 m from the rotational axis. If the subsequent rotational speed of the wheel and clay is 32 rev/min , what is the mass of the clay?","choices":[{"label":"A","text":"2.8 kg"},{"label":"B","text":"4.6 kg"},{"label":"C","text":"3.7 kg"},{"label":"D","text":"4.2 kg"}],"images":[],"answer":"D"},{"id":"Units_5-6-q355","source":"Units_5-6","sourceNumber":"355","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A 40.0-kg child running at 3.00 m/s suddenly jumps onto a stationary playground merry-go-round at a distance of 1.50 m from the axis of rotation of the merry-go-round. The child is traveling tangentially to the edge of the merry-go-round just before jumping on. The disk's rotational inertia about its axis of rotation is 600 kg ∙ m 2 and there is very little friction at its rotation axis. What is the rotational speed of the merry-go-round just after the child has jumped onto it?","choices":[{"label":"A","text":"3.14 rev/s"},{"label":"B","text":"6.28 rev/s"},{"label":"C","text":"2.00 rad/s"},{"label":"D","text":"0.788 rad/s"},{"label":"E","text":"0.261 rad/s"}],"images":[],"answer":"E"},{"id":"Units_5-6-q356","source":"Units_5-6","sourceNumber":"356","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A 5.0-m radius playground merry-go-round with a rotational inertia of 2000 kg ∙ m 2 is rotating freely with a rotational speed of 1.0 rad/s. Two people, each of mass 60 kg, are standing just beyond the edge of the merry-go-round and suddenly step onto the edge with negligible speed relative to the ground. What is the rotational speed of the merry-go-round right after the two people have stepped on?","choices":[{"label":"A","text":"0.80 rad/s"},{"label":"B","text":"0.60 rad/s"},{"label":"C","text":"0.67 rad/s"},{"label":"D","text":"0.20 rad/s"},{"label":"E","text":"0.40 rad/s"}],"images":[],"answer":"E"},{"id":"Units_5-6-q358","source":"Units_5-6","sourceNumber":"358","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Hard","question":"Initially, a small 2.0-kg rock is whirling at the end of a very thin string in a circular path of radius 0.75 m on a horizontal frictionless surface, as shown in the figure. The initial tangential speed of the rock was 5.0 m/s. The string has been slowly winding around a thin vertical rod, and a few seconds later the length of the string has shortened to 0.25 m. What is the instantaneous speed of the rock at the moment the string reaches a length of 0.25 m?","choices":[{"label":"A","text":"9.3 m/s"},{"label":"B","text":"3.9 m/s"},{"label":"C","text":"75 m/s"},{"label":"D","text":"225 m/s"},{"label":"E","text":"15 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"232","height":"127"}],"answer":"E"},{"id":"Units_5-6-q360","source":"Units_5-6","sourceNumber":"360","topic":"Unit 1: Kinematics","difficulty":"Hard","question":"A puck moves on a horizontal air table. It is attached to a string that passes through a small hole in the center of the table. As the puck rotates about the hole, the string is pulled downward very slowly and shortens the radius of rotation, so the puck gradually spirals in toward the center. By what factor will the puck's rotational speed have changed when the string's length has decreased to one-half of its original length?","choices":[{"label":"A","text":"2"},{"label":"B","text":"C) 4"},{"label":"D","text":"1"},{"label":"E","text":"1/2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"B"},{"id":"Units_7-8-q5","source":"Units_7-8","sourceNumber":"5","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Which of the following are true about the springs in each scenario at the moment of maximum compression?","choices":[{"label":"A","text":"The lengths of the springs in both scenarios are equal at maximum compression."},{"label":"B","text":"The length of the spring in scenario 1 is shorter than the length of the spring in scenario 2 at maximum compression."},{"label":"C","text":"The masses of the carts and spring constant of the spring must be known to make any conclusion about the lengths of the springs at maximum compression."},{"label":"D","text":"The length of the spring in scenario 2 is shorter than the length of the spring in scenario 1 at maximum compression."}],"images":[],"answer":"B"},{"id":"Units_7-8-q6","source":"Units_7-8","sourceNumber":"6","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"If we double the frequency of a system undergoing simple harmonic motion, which of the following statements about that system is true?","choices":[{"label":"A","text":"The amplitude is doubled."},{"label":"B","text":"The period is doubled."},{"label":"C","text":"The amplitude is reduced to one-half of what it was."},{"label":"D","text":"The period is reduced to one-half of what it was."}],"images":[],"answer":"D"},{"id":"Units_7-8-q7","source":"Units_7-8","sourceNumber":"7","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A simple harmonic oscillator oscillates with frequency f when its amplitude is A . If the amplitude is now doubled to 2 A , what is the new frequency?","choices":[{"label":"A","text":"f /4"},{"label":"B","text":"f"},{"label":"C","text":"f /2"},{"label":"D","text":"4 f"},{"label":"E","text":"2 f"}],"images":[],"answer":"B"},{"id":"Units_7-8-q10","source":"Units_7-8","sourceNumber":"10","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"The figure shows a graph of the position x as a function of time t for a system undergoing simple harmonic motion. Which one of the following graphs represents the acceleration of this system as a function of time?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"234","height":"140"},{"src":"data:image/jpeg;base64,","alt":"","width":"233","height":"140"},{"src":"data:image/jpeg;base64,","alt":"","width":"232","height":"138"},{"src":"data:image/jpeg;base64,","alt":"","width":"233","height":"139"},{"src":"data:image/jpeg;base64,","alt":"","width":"233","height":"139"}],"answer":"A"},{"id":"Units_7-8-q11","source":"Units_7-8","sourceNumber":"11","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"In simple harmonic motion, when is the speed the greatest? (There could be more than one correct choice.)","choices":[{"label":"A","text":"when the potential energy is a maximum"},{"label":"B","text":"when the potential energy is zero"},{"label":"C","text":"when the magnitude of the acceleration is a maximum"},{"label":"D","text":"when the displacement is a maximum"},{"label":"E","text":"when the magnitude of the acceleration is a minimum"}],"images":[],"answer":"B, E"},{"id":"Units_7-8-q12","source":"Units_7-8","sourceNumber":"12","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"In simple harmonic motion, when is the magnitude of the acceleration the greatest? (There could be more than one correct choice.)","choices":[{"label":"A","text":"when the kinetic energy is a minimum"},{"label":"B","text":"when the speed is a maximum"},{"label":"C","text":"when the displacement from equilibrium is zero"},{"label":"D","text":"when the magnitude of the displacement from equilibrium is a maximum"},{"label":"E","text":"when the potential energy is a maximum"}],"images":[],"answer":"D, E, B"},{"id":"Units_7-8-q13","source":"Units_7-8","sourceNumber":"13","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"The total mechanical energy of a simple harmonic oscillating system is","choices":[{"label":"A","text":"zero as it passes the equilibrium point."},{"label":"B","text":"zero when it reaches the maximum displacement from equilibrium."},{"label":"C","text":"a non-zero constant."},{"label":"D","text":"a maximum when it passes through the equilibrium point."},{"label":"E","text":"a minimum when it passes through the equilibrium point."}],"images":[],"answer":"C"},{"id":"Units_7-8-q14","source":"Units_7-8","sourceNumber":"14","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"An object attached to a spring described by Hooke's law undergoes simple harmonic motion after the object is released from rest. If you want to double the total energy of the object-spring-Earth system, you could","choices":[{"label":"A","text":"double both the amplitude and the spring constant."},{"label":"B","text":"double the spring constant of the spring."},{"label":"C","text":"double the amplitude of vibration."},{"label":"D","text":"double both the mass and amplitude of vibration."},{"label":"E","text":"double the mass of the object."}],"images":[],"answer":"B"},{"id":"Units_7-8-q15","source":"Units_7-8","sourceNumber":"15","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"An object that hangs from the ceiling of a stationary elevator by a spring described by Hooke's law oscillates with a period T . If the elevator accelerates upward with acceleration 2 g , what will be the period of oscillation of the object?","choices":[{"label":"A","text":"4 T"},{"label":"B","text":"T"},{"label":"C","text":"2 T"},{"label":"D","text":"T /2"},{"label":"E","text":"T /46"}],"images":[],"answer":"B"},{"id":"Units_7-8-q16","source":"Units_7-8","sourceNumber":"16","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A block attached to a spring undergoes SHM. When the block passes through the equilibrium position, which of the following statements about it are true? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The block's acceleration is zero."},{"label":"B","text":"The elastic potential energy of the spring is zero."},{"label":"C","text":"The total mechanical energy of the block-spring system is zero."},{"label":"D","text":"The block's kinetic energy is a maximum."},{"label":"E","text":"The block's speed is zero."}],"images":[],"answer":"D, B, A"},{"id":"Units_7-8-q17","source":"Units_7-8","sourceNumber":"17","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A block on a spring undergoes SHM. When the block is at its maximum distance from the equilibrium position, which of the following statements about it is true? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Its elastic potential energy is zero."},{"label":"B","text":"Its acceleration is zero."},{"label":"C","text":"Its kinetic energy is a maximum."},{"label":"D","text":"Its speed is zero."},{"label":"E","text":"Its total mechanical energy is zero."}],"images":[],"answer":"D"},{"id":"Units_7-8-q18","source":"Units_7-8","sourceNumber":"18","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"An object is attached to a vertical spring and bobs up and down between points A and B. Where is the object located when its kinetic energy is a minimum?","choices":[{"label":"A","text":"one-fourth of the way between A and B"},{"label":"B","text":"midway between A and B"},{"label":"C","text":"one-third of the way between A and B"},{"label":"D","text":"at either A or B"},{"label":"E","text":"at none of the above points"}],"images":[],"answer":"D"},{"id":"Units_7-8-q19","source":"Units_7-8","sourceNumber":"19","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"An object is attached to a vertical spring and bobs up and down between points A and B. Where is the object located when its kinetic energy is a maximum?","choices":[{"label":"A","text":"at either A or B"},{"label":"B","text":"one-fourth of the way between A and B"},{"label":"C","text":"one-third of the way between A and B"},{"label":"D","text":"midway between A and B"},{"label":"E","text":"at none of the above points"}],"images":[],"answer":"D"},{"id":"Units_7-8-q20","source":"Units_7-8","sourceNumber":"20","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"Two simple pendulums, A and B, are each 3.0 m long, and the period of pendulum A is T . Pendulum A is twice as heavy as pendulum B. What is the period of pendulum B?","choices":[{"label":"A","text":"T /2"},{"label":"B","text":"T"},{"label":"C","text":"T /"},{"label":"D","text":"T"},{"label":"E","text":"2 T"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"B"},{"id":"Units_7-8-q21","source":"Units_7-8","sourceNumber":"21","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A ball swinging at the end of a massless string, as shown in the figure, undergoes simple harmonic motion. At what point (or points) is the magnitude of the tangential acceleration of the ball the greatest?","choices":[{"label":"A","text":"A and B"},{"label":"B","text":"A and D"},{"label":"C","text":"B"},{"label":"D","text":"C"},{"label":"E","text":"A and C"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"191","height":"158"}],"answer":"B"},{"id":"Units_7-8-q22","source":"Units_7-8","sourceNumber":"22","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A ball swinging at the end of a massless string, as shown in the figure, undergoes simple harmonic motion. At what point (or points) is the magnitude of the radial acceleration of the ball the greatest?","choices":[{"label":"A","text":"A and C"},{"label":"B","text":"A and D"},{"label":"C","text":"C"},{"label":"D","text":"A and B"},{"label":"E","text":"B"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"191","height":"158"}],"answer":"C"},{"id":"Units_7-8-q23","source":"Units_7-8","sourceNumber":"23","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"Grandfather clocks are designed so they can be adjusted by moving the bob at the bottom of the pendulum up or down on the rod to which it is clamped. Suppose you have a grandfather clock at home that runs slow. Which of the following adjustments of the bob would make it more accurate? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Raise the bob."},{"label":"B","text":"Increase the amplitude of swing by a small amount."},{"label":"C","text":"Decrease the mass of the bob."},{"label":"D","text":"Lower the bob."},{"label":"E","text":"Increase the mass of the bob."}],"images":[],"answer":"A"},{"id":"Units_7-8-q24","source":"Units_7-8","sourceNumber":"24","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"Grandfather clocks are designed so they can be adjusted by moving the bob at the bottom of the pendulum up or down on the rod to which it is clamped. Suppose you have a grandfather clock at home that runs fast. Which of the following adjustments of the bob would make it more accurate? (There could be more than one correct choice.)","choices":[{"label":"A","text":"Raise the bob."},{"label":"B","text":"Decrease the mass of the bob."},{"label":"C","text":"Increase the mass of the bob."},{"label":"D","text":"Lower the bob."}],"images":[],"answer":"D"},{"id":"Units_7-8-q25","source":"Units_7-8","sourceNumber":"25","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A pendulum of length L is suspended from the ceiling of an elevator. When the elevator is remaining at rest the period of the pendulum is T . How does the period of the pendulum change when the elevator moves upward with constant acceleration?","choices":[{"label":"A","text":"The period increases."},{"label":"B","text":"The period becomes zero."},{"label":"C","text":"The period increases if the upward acceleration is more than g /2 but decreases if the upward acceleration is less than g /2."},{"label":"D","text":"The period decreases."},{"label":"E","text":"The period does not change."}],"images":[],"answer":"D"},{"id":"Units_7-8-q26","source":"Units_7-8","sourceNumber":"26","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A pendulum of length L is suspended from the ceiling of an elevator. When the elevator is remaining at rest the period of the pendulum is T . How does the period of the pendulum change when the elevator moves downward with constant acceleration?","choices":[{"label":"A","text":"The period becomes zero."},{"label":"B","text":"The period increases if the downward acceleration is more than g /2 but decreases if the downward acceleration is less than g /2."},{"label":"C","text":"The period increases."},{"label":"D","text":"The period does not change."},{"label":"E","text":"The period decreases."}],"images":[],"answer":"C"},{"id":"Units_7-8-q27","source":"Units_7-8","sourceNumber":"27","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A pendulum of length L is suspended from the ceiling of an elevator. When the elevator is remaining at rest the period of the pendulum is T . How does the period of the pendulum change when the elevator moves upward with constant velocity?","choices":[{"label":"A","text":"The period increases if the upward acceleration is more than g /2 but decreases if the upward acceleration is less than g /2."},{"label":"B","text":"The period becomes zero."},{"label":"C","text":"The period decreases."},{"label":"D","text":"The period increases."},{"label":"E","text":"The period does not change."}],"images":[],"answer":"E"},{"id":"Units_7-8-q28","source":"Units_7-8","sourceNumber":"28","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"A pendulum of length L is suspended from the ceiling of an elevator. When the elevator is remaining at rest the period of the pendulum is T . How would the period of the pendulum change if the supporting cable were to break, putting the elevator into freefall?","choices":[{"label":"A","text":"The period does not change."},{"label":"B","text":"The period becomes infinite because the pendulum would not swing."},{"label":"C","text":"The period becomes zero."},{"label":"D","text":"The period decreases slightly."},{"label":"E","text":"The period increases slightly."}],"images":[],"answer":"B"},{"id":"Units_7-8-q29","source":"Units_7-8","sourceNumber":"29","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A simple pendulum and a block oscillating on a spring described by Hooke's law both have period T in an elevator remaining at rest. If the elevator now accelerates downward uniformly at 2 m/s 2 , what is true about the periods of these two systems?","choices":[{"label":"A","text":"Both periods would remain the same."},{"label":"B","text":"The period of the pendulum would decrease but the period of the spring would stay the same."},{"label":"C","text":"Both periods would decrease."},{"label":"D","text":"Both periods would increase."},{"label":"E","text":"The period of the pendulum would increase but the period of the spring would stay the same."}],"images":[],"answer":"E"},{"id":"Units_7-8-q30","source":"Units_7-8","sourceNumber":"30","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A simple pendulum and a block oscillating on a spring described by Hooke's law both have period T in an elevator at rest. If the elevator now moves downward at a uniform 2 m/s, what is true about the periods of these two systems?","choices":[{"label":"A","text":"The period of the pendulum would increase but the period of the spring would stay the same."},{"label":"B","text":"Both periods would decrease."},{"label":"C","text":"The period of the pendulum would decrease but the period of the spring would stay the same."},{"label":"D","text":"Both periods would increase."},{"label":"E","text":"Both periods would remain the same."}],"images":[],"answer":"E"},{"id":"Units_7-8-q31","source":"Units_7-8","sourceNumber":"31","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 300-gram object hangs from a spring with spring constant 15 N/m. The top of the spring is moved up and down at constant small amplitude, at frequency 0.40 Hz. The object vibrates in steady state with amplitude 8.0 cm. Will this amplitude decrease, increase, or stay constant if the outside agent changes frequency to 0.90 Hz?","choices":[{"label":"A","text":"It will remain the same"},{"label":"B","text":"It will decrease"},{"label":"C","text":"It will increase"},{"label":"D","text":"Not enough information to determine"}],"images":[],"answer":"C"},{"id":"Units_7-8-q32","source":"Units_7-8","sourceNumber":"32","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 300-gram object hangs from a spring with spring constant 15 N/m. The top of the spring is made to oscillate at constant small amplitude, at frequency 1.20 Hz, and the object vibrates in steady state with amplitude 13.0 cm. Will this amplitude decrease, increase, or stay constant if the outside agent changes frequency to 1.90 Hz?","choices":[{"label":"A","text":"It will increase"},{"label":"B","text":"It will remain the same"},{"label":"C","text":"It will decrease"},{"label":"D","text":"Not enough information to determine"}],"images":[],"answer":"C"},{"id":"Units_7-8-q33","source":"Units_7-8","sourceNumber":"33","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A leaky faucet drips 40 times in 30.0 s. What is the frequency of the dripping?","choices":[{"label":"A","text":"1.6 Hz"},{"label":"B","text":"1.3 Hz"},{"label":"C","text":"0.75 Hz"},{"label":"D","text":"0.63 Hz"}],"images":[],"answer":"B"},{"id":"Units_7-8-q35","source":"Units_7-8","sourceNumber":"35","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"The quartz crystal in a digital watch vibrates at a frequency of 32.8 kHz. What is its period of oscillation?","choices":[{"label":"A","text":"0.191 ms"},{"label":"B","text":"9.71 µ s"},{"label":"C","text":"15.3 µs"},{"label":"D","text":"30.5 µ s"},{"label":"E","text":"95.8 µs"}],"images":[],"answer":"A"},{"id":"Units_7-8-q36","source":"Units_7-8","sourceNumber":"36","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"If your heart is beating at 76.0 beats per minute, what is the frequency of your heart's oscillations in hertz?","choices":[{"label":"A","text":"1450 Hz"},{"label":"B","text":"2.54 Hz"},{"label":"C","text":"1.27 Hz"},{"label":"D","text":"3.98 Hz"},{"label":"E","text":"4560 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q37","source":"Units_7-8","sourceNumber":"37","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"An object hanging from a spring moves in simple harmonic motion with amplitude A and period T . In terms of A , what distance does the object travel in time interval T ?","choices":[{"label":"A","text":"A /2"},{"label":"B","text":"A"},{"label":"C","text":"2 A"},{"label":"D","text":"8 A"},{"label":"E","text":"4 A"}],"images":[],"answer":"B"},{"id":"Units_7-8-q38","source":"Units_7-8","sourceNumber":"38","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"An object hanging from a spring moves in simple harmonic motion with amplitude A and period T . What distance does the object travel in time interval 1.5 T ?","choices":[{"label":"A","text":"7.5 A"},{"label":"B","text":"9 A"},{"label":"C","text":"1.5 A"},{"label":"D","text":"6 A"},{"label":"E","text":"3 A"}],"images":[],"answer":"A"},{"id":"Units_7-8-q39","source":"Units_7-8","sourceNumber":"39","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"An object hanging from a spring oscillates in simple harmonic motion with amplitude A and period T . In terms of T , in what time interval does the object travel a total distance of 2 A ?","choices":[{"label":"A","text":"4 T"},{"label":"B","text":"T"},{"label":"C","text":"2 T"},{"label":"D","text":"T /4"},{"label":"E","text":"T /2"}],"images":[],"answer":"B"},{"id":"Units_7-8-q40","source":"Units_7-8","sourceNumber":"40","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A block is suspended by a spring with force constant k . When set into oscillation on Earth, it has a period T . Its period on Mars, whose mass is about 1/9 and radius 1/2 that of Earth, is most nearly:","choices":[{"label":"A","text":"3 T"},{"label":"B","text":"T"},{"label":"C","text":"T /3"},{"label":"D","text":"(2/3) T"},{"label":"E","text":"(3/2) T"}],"images":[],"answer":"B"},{"id":"Units_7-8-q41","source":"Units_7-8","sourceNumber":"41","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A child is sitting in a seat, hanging from an elastic cable as shown above. The vertical position as a function of time is shown by the graph. The combined mass of the child and seat is 24 kg. What is the spring constant of the elastic cable?","choices":[{"label":"A","text":"480 N/m"},{"label":"B","text":"120 N/m"},{"label":"C","text":"60 N/m"},{"label":"D","text":"240 N/m"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"480","height":"284"}],"answer":"D"},{"id":"Units_7-8-q44","source":"Units_7-8","sourceNumber":"44","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"If the frequency of a system undergoing simple harmonic motion doubles, by what factor does the maximum value of acceleration change?","choices":[{"label":"A","text":"B) 4"},{"label":"C","text":"2"},{"label":"D","text":"2/π"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_7-8-q49","source":"Units_7-8","sourceNumber":"49","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"The position of an air-track cart that is oscillating on a spring is given by the equation x = (12.4 cm) cos[(6.35 s -1 ) t ]. At what value of t after t = 0.00 s is the cart first located at x = 8.47 cm?","choices":[{"label":"A","text":"0.128 s"},{"label":"B","text":"7.75 s"},{"label":"C","text":"7.39 s"},{"label":"D","text":"4.34 s"},{"label":"E","text":"0.108 s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q50","source":"Units_7-8","sourceNumber":"50","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"An air-track cart is attached to a spring and completes one oscillation every 5.67 s in simple harmonic motion. At the instant t = 0.00 s the cart is released at the position x = +0.250 m. What is the position of the cart when t = 29.6 s?","choices":[{"label":"A","text":"x = 0.342 m"},{"label":"B","text":"x = 0.218 m"},{"label":"C","text":"x = -0.218 m"},{"label":"D","text":"x = 0.210 m"},{"label":"E","text":"x = 0.0461 m"}],"images":[],"answer":"E"},{"id":"Units_7-8-q51","source":"Units_7-8","sourceNumber":"51","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"An object is oscillating on a spring with a period of 4.60 s. At the instant t = 0.00 s the object has zero speed and is at x = 8.30 cm. What is the acceleration of the object at t = 2.50 s?","choices":[{"label":"A","text":"0.00 cm/s 2"},{"label":"B","text":"11.5 cm/s 2"},{"label":"C","text":"1.33 cm/s 2"},{"label":"D","text":"14.9 cm/s 2"},{"label":"E","text":"0.784 cm/s 2"}],"images":[],"answer":"D"},{"id":"Units_7-8-q52","source":"Units_7-8","sourceNumber":"52","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A package is oscillating on a spring scale with a period of 4.60 s. At the instant t = 0.00 s the package has zero speed and is at x = 8.30 cm. At what instant after t = 0.00 s will the package first be at x = 4.15 cm?","choices":[{"label":"A","text":"1.15 s"},{"label":"B","text":"0.767 s"},{"label":"C","text":"1.30 s"},{"label":"D","text":"1.53 s"},{"label":"E","text":"0.575 s"}],"images":[],"answer":"B"},{"id":"Units_7-8-q57","source":"Units_7-8","sourceNumber":"57","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"An object undergoing simple harmonic motion has a maximum displacement from equilibrium of 6.2 m at t = 0.00 s. If the frequency of oscillation is 0.255 Hz, what is the object's displacement from equilibrium when t = 3.5 s?","choices":[{"label":"A","text":"3.1 m"},{"label":"B","text":"5.6 m"},{"label":"C","text":"4.8 m"},{"label":"D","text":"3.7 m"}],"images":[],"answer":"C"},{"id":"Units_7-8-q58","source":"Units_7-8","sourceNumber":"58","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"If the frequency of the motion of a simple harmonic oscillator is doubled, by what factor does the maximum speed of the oscillator change?","choices":[{"label":"A","text":"4"},{"label":"B","text":"1/4"},{"label":"C","text":"1/2"},{"label":"D","text":"It does not change."},{"label":"E","text":"2"}],"images":[],"answer":"E"},{"id":"Units_7-8-q59","source":"Units_7-8","sourceNumber":"59","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"If the amplitude of the motion of a simple harmonic oscillator is doubled, by what factor does the maximum speed of the oscillator change?","choices":[{"label":"A","text":"It does not change."},{"label":"B","text":"1/4"},{"label":"C","text":"2"},{"label":"D","text":"4"},{"label":"E","text":"1/2"}],"images":[],"answer":"C"},{"id":"Units_7-8-q61","source":"Units_7-8","sourceNumber":"61","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 0.25 kg harmonic oscillator has a total mechanical energy of 4.1 J. If the oscillation amplitude is 20.0 cm, what is the oscillation frequency?","choices":[{"label":"A","text":"3.2 Hz"},{"label":"B","text":"1.4 Hz"},{"label":"C","text":"2.3 Hz"},{"label":"D","text":"4.6 Hz"}],"images":[],"answer":"D"},{"id":"Units_7-8-q62","source":"Units_7-8","sourceNumber":"62","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 0.250-kg stone is attached to a massless spring described by Hooke's law and undergoes simple harmonic oscillations with a period of 0.640 s. What is the spring constant of the spring?","choices":[{"label":"A","text":"24.1 N/m"},{"label":"B","text":"12.1 N/m"},{"label":"C","text":"2.45 N/m"},{"label":"D","text":"0.102 N/m"},{"label":"E","text":"0.610 N/m"}],"images":[],"answer":"A"},{"id":"Units_7-8-q63","source":"Units_7-8","sourceNumber":"63","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 0.150-kg air track cart is attached to a massless spring described by Hooke's law with a spring constant of 3.58 N/m, and undergoes simple harmonic oscillations. What is the period of the oscillations?","choices":[{"label":"A","text":"1.29 s"},{"label":"B","text":"1.14 s"},{"label":"C","text":"0.527 s"},{"label":"D","text":"0.263 s"},{"label":"E","text":"2.57 s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q64","source":"Units_7-8","sourceNumber":"64","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"In a supermarket, you place a 22.3-N (around 5 lb) bag of oranges on a scale, and the scale starts to oscillate at 2.7 Hz. What is the spring constant of the spring in the scale?","choices":[{"label":"A","text":"600 N/m"},{"label":"B","text":"820 N/m"},{"label":"C","text":"330 N/m"},{"label":"D","text":"650 N/m"},{"label":"E","text":"410 N/m"}],"images":[],"answer":"D"},{"id":"Units_7-8-q65","source":"Units_7-8","sourceNumber":"65","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"When a 0.350-kg package is attached to a vertical spring and lowered slowly, the spring stretches 12.0 cm. The package is now displaced from its equilibrium position and undergoes simple harmonic oscillations when released. What is the period of the oscillations?","choices":[{"label":"A","text":"1.44 s"},{"label":"B","text":"0.483 s"},{"label":"C","text":"0.695 s"},{"label":"D","text":"0.286 s"},{"label":"E","text":"0.0769 s"}],"images":[],"answer":"C"},{"id":"Units_7-8-q68","source":"Units_7-8","sourceNumber":"68","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 3.42-kg stone hanging vertically from a massless spring described by Hooke's law undergoes simple harmonic motion at a location where g = 9.80 m/s 2 . If the spring constant of the spring is 12 N/m, find the period of oscillation of this system on a planet where g = 1.60 m/s 2 .","choices":[{"label":"A","text":"3.35 s"},{"label":"B","text":"5.70 s"},{"label":"C","text":"2.51 s"},{"label":"D","text":"4.36 s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q69","source":"Units_7-8","sourceNumber":"69","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 51.8-kg bungee jumper jumps off a bridge and undergoes simple harmonic motion. If the period of oscillation is 11.2 s, what is the spring constant of the bungee cord?","choices":[{"label":"A","text":"26.1 N/m"},{"label":"B","text":"16.3 N/m"},{"label":"C","text":"19.6 N/m"}],"images":[],"answer":"B"},{"id":"Units_7-8-q70","source":"Units_7-8","sourceNumber":"70","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A 4.8-kg block attached to a massless spring described by Hooke's law undergoes simple harmonic motion on a frictionless horizontal surface. At the instant t = 0.00 s, the block has a displacement from equilibrium of -0.90 m, a velocity of -0.80 m/s, and an acceleration of +2.9 m/s 2 . The spring constant of the spring is closest to","choices":[{"label":"A","text":"12 N/m."},{"label":"B","text":"14 N/m."},{"label":"C","text":"11 N/m."},{"label":"D","text":"13 N/m."},{"label":"E","text":"15 N/m."}],"images":[],"answer":"E"},{"id":"Units_7-8-q71","source":"Units_7-8","sourceNumber":"71","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"An object of mass m = 8.0 kg is attached to a massless spring described by Hooke's law and allowed to hang in Earth's gravitational field. The spring stretches 2.2 cm as the object reaches its equilibrium position. If it were now allowed to oscillate on this spring, what would be its frequency?","choices":[{"label":"A","text":"0.28 × 10 -3 Hz"},{"label":"B","text":"1.6 Hz"},{"label":"C","text":"0.52 Hz"},{"label":"D","text":"3.4 Hz"}],"images":[],"answer":"D"},{"id":"Units_7-8-q72","source":"Units_7-8","sourceNumber":"72","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A block attached to a massless spring described by Hooke's law with spring constant 15 N/m undergoes simple harmonic motion on a frictionless horizontal surface. At the instant t = 0 s, the block has a displacement from equilibrium of -0.90 m, a velocity of -0.80 m/s, and an acceleration of +2.9 m/s 2 . The mass of the block is closest to","choices":[{"label":"A","text":"2.6 kg"},{"label":"B","text":"4.7 kg"},{"label":"C","text":"2.3 kg"},{"label":"D","text":"9.4 kg"}],"images":[],"answer":"B"},{"id":"Units_7-8-q73","source":"Units_7-8","sourceNumber":"73","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 0.39-kg block on a horizontal frictionless surface is attached to a massless spring described by Hooke's law with spring constant 570 N/m. The block is pulled from its equilibrium position at x = 0.000 m to a displacement from equilibrium x = +0.080 m and is released from rest. The block then undergoes simple harmonic motion along the horizontal x -axis. When the position of the block is x = 0.057 m, its kinetic energy is closest to","choices":[{"label":"A","text":"0.95 J."},{"label":"B","text":"0.84 J."},{"label":"C","text":"0.90 J."},{"label":"D","text":"1.1 J."},{"label":"E","text":"1.0 J."}],"images":[],"answer":"C"},{"id":"Units_7-8-q74","source":"Units_7-8","sourceNumber":"74","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A 0.16-kg block on a horizontal frictionless surface is attached to a massless spring described by Hooke's law with spring constant 360 N/m. The block is pulled from its equilibrium position at x = 0.000 m to a position x = +0.080 m and is released from rest. The block then undergoes simple harmonic motion along the horizontal x -axis. When the position is x = -0.037 m, what is the acceleration of the block?","choices":[{"label":"A","text":"370 m/s 2"},{"label":"B","text":"270 m/s 2"},{"label":"C","text":"64 m/s 2"},{"label":"D","text":"83 m/s 2"},{"label":"E","text":"43 m/s 2"}],"images":[],"answer":"D"},{"id":"Units_7-8-q75","source":"Units_7-8","sourceNumber":"75","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 3.7-kg block on a horizontal frictionless surface is attached to a massless spring described by Hooke's law with spring constant 450 N/m. The block is pulled from its equilibrium position at x = 0.000 m to a position x = +0.080 m and is released from rest. The block then undergoes simple harmonic motion along the horizontal x -axis. The maximum elastic potential energy of the system is closest to","choices":[{"label":"A","text":"1.6 J."},{"label":"B","text":"1.7 J."},{"label":"C","text":"1.4 J."},{"label":"D","text":"1.8 J."},{"label":"E","text":"1.3 J."}],"images":[],"answer":"C"},{"id":"Units_7-8-q78","source":"Units_7-8","sourceNumber":"78","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A ball is attached to a massless spring described by Hooke's law, and oscillates with a period T . If the mass of the ball is doubled, what is the new period?","choices":[{"label":"A","text":"T"},{"label":"B","text":"2 T"},{"label":"C","text":"T"},{"label":"D","text":"T/"},{"label":"E","text":"T /2"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_7-8-q80","source":"Units_7-8","sourceNumber":"80","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"How much mass should be attached to a massless vertical spring described by Hooke's law with spring constant 39.5 N/m, so that it will oscillate at 1.00 Hz?","choices":[{"label":"A","text":"2.00 kg"},{"label":"B","text":"1.56 kg"},{"label":"C","text":"6.29 kg"},{"label":"D","text":"39.5 kg"},{"label":"E","text":"1.00 kg"}],"images":[],"answer":"E"},{"id":"Units_7-8-q83","source":"Units_7-8","sourceNumber":"83","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 0.150-kg cart that is attached to a massless spring described by Hooke's law with spring constant 3.58 N/m undergoes simple harmonic oscillations with an amplitude of 7.50 cm. What is the total mechanical energy of the system?","choices":[{"label":"A","text":"0 J"},{"label":"B","text":"0.0101 J"},{"label":"C","text":"0.0201 J"},{"label":"D","text":"0.269 J"},{"label":"E","text":"0.134 J"}],"images":[],"answer":"B"},{"id":"Units_7-8-q85","source":"Units_7-8","sourceNumber":"85","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 0.50-kg object is attached to a massless spring described by Hooke's law with spring constant 20 N/m on a horizontal, frictionless surface. The object oscillates in simple harmonic motion and has a speed of 1.5 m/s at the equilibrium position. At what distance from the equilibrium position are the kinetic energy and potential energy of the system the same?","choices":[{"label":"A","text":"0.029 m"},{"label":"B","text":"0.12 m"},{"label":"C","text":"0.017 m"},{"label":"D","text":"0.17 m"}],"images":[],"answer":"D"},{"id":"Units_7-8-q86","source":"Units_7-8","sourceNumber":"86","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 1.53-kg piece of iron is hung on a vertical massless spring described by Hooke's law. When displaced slightly, the iron moves up and down in simple harmonic oscillation with a frequency of 1.95 Hz and an amplitude of 7.50 cm. If we choose the total potential energy (elastic plus gravitational) to be zero at the equilibrium position of the hanging iron, what is the total mechanical energy of the system?","choices":[{"label":"A","text":"0.844 J"},{"label":"B","text":"0.955 J"},{"label":"C","text":"0.633 J"},{"label":"D","text":"0.000 J"},{"label":"E","text":"0.646 J"}],"images":[],"answer":"E"},{"id":"Units_7-8-q88","source":"Units_7-8","sourceNumber":"88","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A ball vibrates back and forth from the free end of a massless spring described by Hooke's law with spring constant 20 N/m. If the amplitude of this motion is 0.30 m, what is the kinetic energy of the ball when it is 0.30 m from its equilibrium position?","choices":[{"label":"A","text":"0.00 J"},{"label":"B","text":"0.45 J"},{"label":"C","text":"1.4 J"},{"label":"D","text":"0.90 J"},{"label":"E","text":"0.22 J"}],"images":[],"answer":"A"},{"id":"Units_7-8-q89","source":"Units_7-8","sourceNumber":"89","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"What is the length of a simple pendulum with a period of 2.0 s?","choices":[{"label":"A","text":"20 m"},{"label":"B","text":"0.99 m"},{"label":"C","text":"0.87 m"},{"label":"D","text":"1.6 m"},{"label":"E","text":"1.2 m"}],"images":[],"answer":"B"},{"id":"Units_7-8-q90","source":"Units_7-8","sourceNumber":"90","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 34-kg child on an 18-kg swing seat swings back and forth through small angles. If the length of the very light supporting cables for the swing is 4.9 m, what is the time interval for each complete back-and-forth swing? Assume that the child and the swing seat are very small compared to the length of the cables.","choices":[{"label":"A","text":"5.7 s"},{"label":"B","text":"4.8 s"},{"label":"C","text":"4.4 s"},{"label":"D","text":"5.3 s"}],"images":[],"answer":"C"},{"id":"Units_7-8-q91","source":"Units_7-8","sourceNumber":"91","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"The period of a simple pendulum that is 1.00 m long on another planet is 1.66 s. What is the freefall acceleration on this planet if the mass of the pendulum bob is 1.5 kg?","choices":[{"label":"A","text":"14.3 m/s 2"},{"label":"B","text":"13.3 m/s 2"},{"label":"C","text":"17.2 m/s 2"},{"label":"D","text":"15.7 m/s 2"}],"images":[],"answer":"B"},{"id":"Units_7-8-q92","source":"Units_7-8","sourceNumber":"92","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"On the Moon, the freefall acceleration is g /6. If a pendulum has a period T on Earth, what will its period be on the Moon?","choices":[{"label":"A","text":"T/"},{"label":"B","text":"T /6"},{"label":"C","text":"T/ 3"},{"label":"D","text":"T"},{"label":"E","text":"6 T"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (6)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (6)","width":null,"height":null}],"answer":"D"},{"id":"Units_7-8-q93","source":"Units_7-8","sourceNumber":"93","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A simple pendulum has a period T on Earth. If it were used on Planet X, where the freefall acceleration is 3 times what it is on Earth, what would its period be?","choices":[{"label":"A","text":"T"},{"label":"B","text":"3 T"},{"label":"C","text":"T"},{"label":"D","text":"T/3"},{"label":"E","text":"T/"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (3)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (3)","width":null,"height":null}],"answer":"E"},{"id":"Units_7-8-q94","source":"Units_7-8","sourceNumber":"94","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A simple pendulum having a bob of mass M has a period T . If you double M but change nothing else, what would be the new period?","choices":[{"label":"A","text":"T/"},{"label":"B","text":"T /2"},{"label":"C","text":"2 T"},{"label":"D","text":"T"},{"label":"E","text":"T"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"D"},{"id":"Units_7-8-q95","source":"Units_7-8","sourceNumber":"95","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"If both the mass of a simple pendulum and its length are doubled, the period will","choices":[{"label":"A","text":"be unchanged."},{"label":"B","text":"decrease as it is multiplied by a factor of 1/ ."},{"label":"C","text":"increase by a factor of 2."},{"label":"D","text":"increase by a factor of ."},{"label":"E","text":"increase by a factor of 4."}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"C"},{"id":"Units_7-8-q96","source":"Units_7-8","sourceNumber":"96","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A simple pendulum takes 2.00 s to make one compete swing. If we now triple the length, what time interval is required for one complete swing?","choices":[{"label":"A","text":"1.15 s"},{"label":"B","text":"6.00 s"},{"label":"C","text":"2.00 s"},{"label":"D","text":"0.667 s"},{"label":"E","text":"3.46 s"}],"images":[],"answer":"E"},{"id":"Units_7-8-q100","source":"Units_7-8","sourceNumber":"100","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"An astronaut has landed on Planet N-40 and conducts an experiment to determine the freefall acceleration on that planet. She uses a simple pendulum that is 0.640 m long and measures that 10 complete oscillations require 26.0 s. What is the freefall acceleration on Planet N-40?","choices":[{"label":"A","text":"4.85 m/s 2"},{"label":"B","text":"1.66 m/s 2"},{"label":"C","text":"9.81 m/s 2"},{"label":"D","text":"3.74 m/s 2"},{"label":"E","text":"2.39 m/s 2"}],"images":[],"answer":"D"},{"id":"Units_7-8-q101","source":"Units_7-8","sourceNumber":"101","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"An astronaut has landed on an asteroid and conducts an experiment to determine the freefall acceleration on that asteroid. He uses a simple pendulum that has a period of oscillation of 2.00 s on Earth and finds that on the asteroid the period is 11.3 s. What is the freefall acceleration at the surface of that asteroid?","choices":[{"label":"A","text":"5.51 m/s 2"},{"label":"B","text":"0.0544 m/s 2"},{"label":"C","text":"1.66 m/s 2"},{"label":"D","text":"1.74 m/s 2"},{"label":"E","text":"0.307 m/s 2"}],"images":[],"answer":"A"},{"id":"Units_7-8-q102","source":"Units_7-8","sourceNumber":"102","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"In 1851, Jean Bernard Leon Foucault demonstrated the rotation of Earth using a pendulum 11.0 m long, which was set up in the Paris Observatory. What time interval was required for Foucault's pendulum to make one complete swing back to its starting point? Note that g = 9.81 m/s 2 at the observatory.","choices":[{"label":"A","text":"5.63 s"},{"label":"B","text":"2.58 s"},{"label":"C","text":"2.12 s"},{"label":"D","text":"6.65 s"},{"label":"E","text":"1.79 s"}],"images":[],"answer":"D"},{"id":"Units_7-8-q103","source":"Units_7-8","sourceNumber":"103","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A pendulum that was originally erected by Jean Bernard Leon Foucault at the Pantheon in Paris for the Paris Exhibition in 1851 was restored in 1995. It has a 28.0-kg sphere suspended from a 67.0-m light cable. What time interval is required for the bob of this pendulum to move from the position of maximum displacement down to the equilibrium point? In Paris, g = 9.81 m/s 2 .","choices":[{"label":"A","text":"4.11 s"},{"label":"B","text":"42.9 s"},{"label":"C","text":"2.58 s"},{"label":"D","text":"21.5 s"},{"label":"E","text":"32.2 s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q111","source":"Units_7-8","sourceNumber":"111","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"The diagram below represents a transverse wave traveling to the right through a medium. Point A represents a particle of the medium. In which direction will particle A move in the next instant?","choices":[{"label":"A","text":"up"},{"label":"B","text":"right"},{"label":"C","text":"no motion"},{"label":"D","text":"down"},{"label":"E","text":"left"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"296","height":"120"}],"answer":"D"},{"id":"Units_7-8-q114","source":"Units_7-8","sourceNumber":"114","topic":"Unit 3: Work, Energy, and Power","difficulty":"Easy","question":"What does a wave transfer through a medium?","choices":[{"label":"A","text":"neither energy nor matter"},{"label":"B","text":"energy and matter"},{"label":"C","text":"energy only"},{"label":"D","text":"matter only"},{"label":"E","text":"depends on the type of wave"}],"images":[],"answer":"C"},{"id":"Units_7-8-q116","source":"Units_7-8","sourceNumber":"116","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A stationary source emits sound waves of frequency f and wavelength λ that travel through the air with speed v . If the frequency of the source is changed to 2 f , what will be the wavelength and speed of the new wave? λ ν","choices":[{"label":"A","text":"λ ν/ 2"},{"label":"B","text":"λ/2 ν"},{"label":"C","text":"λ/2 2 ν"},{"label":"D","text":"2λ ν"},{"label":"E","text":"λ 2 ν"}],"images":[],"answer":"B"},{"id":"Units_7-8-q118","source":"Units_7-8","sourceNumber":"118","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"A source of sound waves produces a constant frequency f . If no other sound sources were nearby, what would you have to do in order to hear a steadily increasing frequency?","choices":[{"label":"A","text":"Move away from the source at constant speed"},{"label":"B","text":"Accelerate away from the source"},{"label":"C","text":"Move toward the source at constant speed"},{"label":"D","text":"Accelerate toward the source"},{"label":"E","text":"None of the above will work"}],"images":[],"answer":"D"},{"id":"Units_7-8-q119","source":"Units_7-8","sourceNumber":"119","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A person is standing at a train station, and two identical trains are passing each other 100 m down the tracks. Train A is moving away from him at 20 m/s, and train B is moving toward him at 20 m/s. As the trains pass each other, they emit identical pulses of sound from their horns. At the instant that the pulses are sounded, the trains' horns are both precisely 100 m away from him. What will the person hear?","choices":[{"label":"A","text":"Pulse B will reach him first, and have a higher pitch than A."},{"label":"B","text":"The pulses reach him at the same instant of time, but B has a higher pitch."},{"label":"C","text":"The pulses reach him at the same instant of time, but A has a higher pitch."},{"label":"D","text":"Pulse A will reach him first, and have a higher pitch than B."},{"label":"E","text":"Pulse A will reach him first, and have a lower pitch than B."}],"images":[],"answer":"B"},{"id":"Units_7-8-q120","source":"Units_7-8","sourceNumber":"120","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"Some students stretch a long rope down a hallway. The students tie a knot in the rope, and send a pulse down the rope, with the shape shown. During the time interval required for the pulse to travel down the rope, the students measure that the knot travels a total path length of 60 cm. Using this information, what can they determine about the pulse? Select all that apply.","choices":[{"label":"A","text":"The amplitude of the pulse is 15 cm."},{"label":"B","text":"The wavelength of the pulse is 30 cm."},{"label":"C","text":"The wavelength of the pulse is 60 cm."},{"label":"D","text":"The wavelength of the pulse is 15 cm."},{"label":"E","text":"The amplitude of the pulse is 60 cm."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"447","height":"59"}],"answer":"A"},{"id":"Units_7-8-q122","source":"Units_7-8","sourceNumber":"122","topic":"Unit 8: Fluids","difficulty":"Hard","question":"The frequency f 2 and amplitude A 2 are both increased to significantly higher values, and the student again uses the microphone equidistant from the two speakers to make a pressure-vs-time graph. Which of the following could be a graph that the student might now observe on the screen?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"193","height":"132"},{"src":"data:image/jpeg;base64,","alt":"","width":"192","height":"133"},{"src":"data:image/jpeg;base64,","alt":"","width":"193","height":"133"},{"src":"data:image/jpeg;base64,","alt":"","width":"193","height":"131"}],"answer":"C"},{"id":"Units_7-8-q124","source":"Units_7-8","sourceNumber":"124","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A student holds vibrating tuning fork of frequency 440 Hz above an air column with one end open and one end closed, having length L , and producing resonance. If the tuning fork is replaced with a vibrating tuning fork of frequency 880 Hz, what will the student observe?","choices":[{"label":"A","text":"The student will not hear another resonance."},{"label":"B","text":"The student will hear another resonance with frequency 440 Hz."},{"label":"C","text":"It depends on the length L of the air column."},{"label":"D","text":"The student will hear another resonance of frequency 880 Hz."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"128","height":"210"}],"answer":"A"},{"id":"Units_7-8-q125","source":"Units_7-8","sourceNumber":"125","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"An earthquake wave is traveling from west to east through rock. If the particles of the rock are vibrating in a east-west direction, the wave must be classified as","choices":[{"label":"A","text":"Neither transverse nor longitudinal"},{"label":"B","text":"A tsunami"},{"label":"C","text":"Longitudinal"},{"label":"D","text":"Transverse"}],"images":[],"answer":"C"},{"id":"Units_7-8-q126","source":"Units_7-8","sourceNumber":"126","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Two waves are in superposition as shown in the graph. Which point on the graph results in the largest positive displacement while the waves are in superposition as shown?","choices":[{"label":"A","text":"Point A"},{"label":"B","text":"Point B"},{"label":"C","text":"Point C"},{"label":"D","text":"Point D"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"445","height":"276"}],"answer":"A"},{"id":"Units_7-8-q127","source":"Units_7-8","sourceNumber":"127","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two pulses are sent down a rope, as shown above. Which of the following could show the rope at a later instant in time, when the two pulses fully overlap?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"462","height":"135"},{"src":"data:image/jpeg;base64,","alt":"","width":"168","height":"88"},{"src":"data:image/jpeg;base64,","alt":"","width":"174","height":"53"},{"src":"data:image/jpeg;base64,","alt":"","width":"177","height":"61"},{"src":"data:image/jpeg;base64,","alt":"","width":"173","height":"92"}],"answer":"A"},{"id":"Units_7-8-q129","source":"Units_7-8","sourceNumber":"129","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"The wavelength of this wave is equal to the distance between which two points?","choices":[{"label":"A","text":"A and B"},{"label":"B","text":"A and C"},{"label":"C","text":"B and E"},{"label":"D","text":"B and C"}],"images":[],"answer":"B"},{"id":"Units_7-8-q130","source":"Units_7-8","sourceNumber":"130","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"On a highway where cars are traveling at 60 km/h, a car slams on its brakes. Seeing the brake lights, the driver of the car behind it then slams on its brakes. One by one, car after car behind them slam on their brakes, until eventually the cars several miles back along the highway are slamming on their brakes as well. What type of wave is this, and why?","choices":[{"label":"A","text":"This is not a wave, since the cars are not directly transferring energy to one another."},{"label":"B","text":"An electromagnetic wave, because the drivers stop when they see the brake lights."},{"label":"C","text":"A longitudinal wave, because the cars are oscillating parallel to the direction of energy transfer."},{"label":"D","text":"A transverse wave, because the cars are oscillating perpendicular to the direction of energy transfer."}],"images":[],"answer":"A"},{"id":"Units_7-8-q131","source":"Units_7-8","sourceNumber":"131","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"What is the wavelength of the wave shown in the figure?","choices":[{"label":"A","text":"2 m"},{"label":"B","text":"4 m"},{"label":"C","text":"1 m"},{"label":"D","text":"8 m"},{"label":"E","text":"It cannot be determined from the given information."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"266","height":"222"}],"answer":"E"},{"id":"Units_7-8-q132","source":"Units_7-8","sourceNumber":"132","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A string of mass m is pulled with some tension, and the speed of a wave in the string is v . What will be the speed of a wave in the string if the mass of the string is increased to 2 m but with no change in the length or tension?","choices":[{"label":"A","text":"v /2"},{"label":"B","text":"v /"},{"label":"C","text":"4 v"},{"label":"D","text":"2 v"},{"label":"E","text":"v"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"E"},{"id":"Units_7-8-q133","source":"Units_7-8","sourceNumber":"133","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A string of length L is pulled with some tension, and the speed of a wave in the string is v . What will be the speed of a wave in the string if the length is increased to 2 L but with no change in the mass or tension?","choices":[{"label":"A","text":"4 v"},{"label":"B","text":"v /"},{"label":"C","text":"v /2"},{"label":"D","text":"2 v"},{"label":"E","text":"v"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"E"},{"id":"Units_7-8-q134","source":"Units_7-8","sourceNumber":"134","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"When a certain string is pulled with some tension T , the speed of a wave in the string is v . What will be the speed of a wave in the string if the tension is increased to 2 T without changing the mass or length of the string?","choices":[{"label":"A","text":"2 v"},{"label":"B","text":"v"},{"label":"C","text":"v /2"},{"label":"D","text":"4 v"},{"label":"E","text":"v /"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"B"},{"id":"Units_7-8-q135","source":"Units_7-8","sourceNumber":"135","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Four waves are described by the following equations, where distances are measured in meters and times in seconds. I. y = 0.12 cos(3 x - 21 t ) II. y = 0.15 sin(6 x + 42 t ) III. y = 0.13 cos(6 x + 21 t ) IV. y = −0.23 sin(3 x − 42 t ) Which of these waves have the same speed?","choices":[{"label":"A","text":"III and IV"},{"label":"B","text":"I and II"},{"label":"C","text":"I and III"},{"label":"D","text":"II and III"},{"label":"E","text":"II and IV"}],"images":[],"answer":"B"},{"id":"Units_7-8-q136","source":"Units_7-8","sourceNumber":"136","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Four waves are described by the following equations, where distances are measured in meters and times in seconds. I. y = 0.12 cos(3 x - 21 t ) II. y = 0.15 sin(6 x + 42 t ) III. y = 0.13 cos(6 x + 21 t ) IV. y = -0.23 sin(3 x − 42 t ) Which of these waves have the same period?","choices":[{"label":"A","text":"I and II, and also III and IV"},{"label":"B","text":"All of them have the same period."},{"label":"C","text":"I and IV, and also II and III"},{"label":"D","text":"They all have different periods."},{"label":"E","text":"I and III, and also II and IV"}],"images":[],"answer":"E"},{"id":"Units_7-8-q137","source":"Units_7-8","sourceNumber":"137","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"The intensity of the waves spreading into three-dimensional space from a point source at a distance d from the source is I . What is the intensity at a distance 2 d from the source?","choices":[{"label":"A","text":"I /"},{"label":"B","text":"I /4"},{"label":"C","text":"4 I"},{"label":"D","text":"I /2"},{"label":"E","text":"2 I"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_7-8-q138","source":"Units_7-8","sourceNumber":"138","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"The intensity of the waves spreading into three-dimensional space from a point source at a distance d from the source is I . At what distance from the sources is the intensity equal to 2 I ?","choices":[{"label":"A","text":"d /"},{"label":"B","text":"d /2"},{"label":"C","text":"d /8"},{"label":"D","text":"d /4"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"A"},{"id":"Units_7-8-q139","source":"Units_7-8","sourceNumber":"139","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"Why does the intensity of waves propagating into three-dimensional space from a small source decrease with the square of the distance from the source?","choices":[{"label":"A","text":"The frequency of the waves decreases as they get farther from the source."},{"label":"B","text":"The waves spread out as they travel."},{"label":"C","text":"The medium through which the waves travel absorbs the energy of the waves."},{"label":"D","text":"The waves run out of energy as they travel."},{"label":"E","text":"The waves slow down as they travel away from the source."}],"images":[],"answer":"B"},{"id":"Units_7-8-q140","source":"Units_7-8","sourceNumber":"140","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"When a guitar is tuned to adjust it pitch, what is it that is changed?","choices":[{"label":"A","text":"The amplitude of the fundamental."},{"label":"B","text":"The wavelength of the fundamental."},{"label":"C","text":"The frequency of the fundamental."}],"images":[],"answer":"C"},{"id":"Units_7-8-q141","source":"Units_7-8","sourceNumber":"141","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"If a guitar string has a fundamental frequency of 500 Hz, which one of the following frequencies can set the string into resonant vibration?","choices":[{"label":"A","text":"1500 Hz"},{"label":"B","text":"1750 Hz"},{"label":"C","text":"750 Hz"},{"label":"D","text":"250 Hz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q142","source":"Units_7-8","sourceNumber":"142","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A stretched string is observed to produce a standing wave with four antinodes, when vibrated at a frequency of 480 Hz. What frequency will produce a standing wave with five antinodes?","choices":[{"label":"A","text":"600 Hz"},{"label":"B","text":"120 Hz"},{"label":"C","text":"360 Hz"},{"label":"D","text":"240 Hz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q143","source":"Units_7-8","sourceNumber":"143","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"If a string fixed at both ends resonates in its fundamental mode with a frequency of 150 Hz, at which of the following frequencies will it not resonate? (There could be more than one correct choice.)","choices":[{"label":"A","text":"300 Hz"},{"label":"B","text":"450 Hz"},{"label":"C","text":"75 Hz"},{"label":"D","text":"500 Hz"},{"label":"E","text":"600 Hz"}],"images":[],"answer":"D, C"},{"id":"Units_7-8-q144","source":"Units_7-8","sourceNumber":"144","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"A string fixed at both ends is vibrating in one of its harmonics. If we now increase only the frequency at which the string is vibrating, which of the following characteristics do we also increase? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The wavelength of the traveling waves on the string"},{"label":"B","text":"The period of the traveling waves on the string"},{"label":"C","text":"The speed of the traveling waves on the string"},{"label":"D","text":"The amplitude of the traveling waves on the string"},{"label":"E","text":"None of the above"}],"images":[],"answer":"E"},{"id":"Units_7-8-q145","source":"Units_7-8","sourceNumber":"145","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"Sound A has a high pitch and sound B has a low pitch. Which of the following statements about these two sounds are correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The period of A is shorter than the period of B."},{"label":"B","text":"The frequency of A is greater than the frequency of B."},{"label":"C","text":"The amplitude of A is larger than the amplitude of B."},{"label":"D","text":"The wavelength of A is longer than the wavelength of B."},{"label":"E","text":"Sound A travels faster than sound B through air."}],"images":[],"answer":"B, A"},{"id":"Units_7-8-q146","source":"Units_7-8","sourceNumber":"146","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"You double your distance from a sound source that is radiating equally in all directions. What happens to the intensity of the sound?","choices":[{"label":"A","text":"It reduces to one-fourth its original value."},{"label":"B","text":"It reduces to one-sixteenth its original value."},{"label":"C","text":"It reduces to one-half its original value."},{"label":"D","text":"None of the above"}],"images":[],"answer":"A"},{"id":"Units_7-8-q147","source":"Units_7-8","sourceNumber":"147","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"Suppose that a sound source is emitting waves uniformly in all directions. If you move to a point twice as far away from the source, the frequency of the sound will be","choices":[{"label":"A","text":"half as great"},{"label":"B","text":"unchanged"},{"label":"C","text":"twice as great"},{"label":"D","text":"one-fourth as great"}],"images":[],"answer":"B"},{"id":"Units_7-8-q148","source":"Units_7-8","sourceNumber":"148","topic":"Unit 8: Fluids","difficulty":"Easy","question":"An organ pipe of length L that is open at one end resonates in its third harmonic with a wavelength of 2 L /3. Is the other end of the pipe closed or open?","choices":[{"label":"A","text":"closed"},{"label":"B","text":"open"},{"label":"C","text":"We cannot tell from the information provided."}],"images":[],"answer":"B"},{"id":"Units_7-8-q149","source":"Units_7-8","sourceNumber":"149","topic":"Unit 8: Fluids","difficulty":"Easy","question":"In a resonating pipe that is open at both ends, there","choices":[{"label":"A","text":"is an air displacement node at one end and an air displacement antinode at the other end."},{"label":"B","text":"are air displacement nodes at each end."},{"label":"C","text":"are air displacement antinodes at each end."},{"label":"D","text":"None of the above choices are correct."}],"images":[],"answer":"C"},{"id":"Units_7-8-q150","source":"Units_7-8","sourceNumber":"150","topic":"Unit 8: Fluids","difficulty":"Easy","question":"In a resonating pipe that is open at one end and closed at the other end, there","choices":[{"label":"A","text":"are air displacement antinodes at each end."},{"label":"B","text":"are air displacement nodes at each end."},{"label":"C","text":"is an air displacement node at the closed end and an air displacement antinode at the open end."},{"label":"D","text":"is an air displacement node at the open end and an air displacement antinode at the closed end."}],"images":[],"answer":"C"},{"id":"Units_7-8-q151","source":"Units_7-8","sourceNumber":"151","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The lowest tone to resonate a pipe of length L that is open at both ends is 200 Hz. Which one of the following frequencies will not cause the same pipe to resonate?","choices":[{"label":"A","text":"900 Hz"},{"label":"B","text":"600 Hz"},{"label":"C","text":"400 Hz"},{"label":"D","text":"800 Hz"},{"label":"E","text":"200 Hz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q152","source":"Units_7-8","sourceNumber":"152","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The lowest tone to resonate a pipe of length L that is closed at one end but open at the other end is 200 Hz. Which one of the following frequencies will not cause that pipe to resonate?","choices":[{"label":"A","text":"400 Hz"},{"label":"B","text":"1400 Hz"},{"label":"C","text":"600 Hz"},{"label":"D","text":"1000 Hz"},{"label":"E","text":"200 Hz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q153","source":"Units_7-8","sourceNumber":"153","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"Consider the standing wave on a guitar string and the sound wave generated by the string as a result of this vibration. What do these two waves have in common? (There may be more than one correct choice.)","choices":[{"label":"A","text":"They have the same amplitude."},{"label":"B","text":"They have the same period."},{"label":"C","text":"They have the same frequency."},{"label":"D","text":"They have the same wavelength."},{"label":"E","text":"They have the same speed."}],"images":[],"answer":"C, B"},{"id":"Units_7-8-q154","source":"Units_7-8","sourceNumber":"154","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Consider a pipe of length L that is open at both ends. What are the wavelengths of the three lowest-pitch tones produced by this pipe?","choices":[{"label":"A","text":"2 L , L , L /2"},{"label":"B","text":"4 L , 4 L /3, 4 L /5"},{"label":"C","text":"2 L , L , 2 L /3"},{"label":"D","text":"4 L , 2 L , L"}],"images":[],"answer":"C"},{"id":"Units_7-8-q155","source":"Units_7-8","sourceNumber":"155","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A pipe of length L that is open at both ends is resonating at its fundamental frequency. Which statement about the sound is correct?","choices":[{"label":"A","text":"The wavelength is L and there is an air displacement antinode at the pipe's midpoint."},{"label":"B","text":"The wavelength is 2 L and there is an air displacement antinode at the pipe's midpoint."},{"label":"C","text":"The wavelength is L and there is an air displacement node at the pipe's midpoint."},{"label":"D","text":"The wavelength is 2 L and there is an air displacement node at the pipe's midpoint."}],"images":[],"answer":"C"},{"id":"Units_7-8-q156","source":"Units_7-8","sourceNumber":"156","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Consider a pipe of length L that is open at one end and closed at the other end. What are the wavelengths of the three lowest-pitch tones produced by resonance in this pipe?","choices":[{"label":"A","text":"2 L , L , L /2"},{"label":"B","text":"2 L , L , 2 L /3"},{"label":"C","text":"4 L , 2 L , L"},{"label":"D","text":"4 L , 4 L /3, 4 L /5"}],"images":[],"answer":"A"},{"id":"Units_7-8-q157","source":"Units_7-8","sourceNumber":"157","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A pipe of length L that is closed at one end and open at the other end is resonating at its fundamental frequency. Which statement about the sound is correct?","choices":[{"label":"A","text":"The wavelength is 4 L and there is an air displacement node at the pipe's open end."},{"label":"B","text":"The wavelength is L and there is an air displacement antinode at the pipe's open end."},{"label":"C","text":"The wavelength is L and there is an air displacement node at the pipe's open end."},{"label":"D","text":"The wavelength is 4 L and there is an air displacement antinode at the pipe's open end."}],"images":[],"answer":"B"},{"id":"Units_7-8-q158","source":"Units_7-8","sourceNumber":"158","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two tuning forks have frequencies of 220 and 302 Hz. What is the beat frequency if both are sounding simultaneously?","choices":[{"label":"A","text":"481 Hz"},{"label":"B","text":"55 Hz"},{"label":"C","text":"962 Hz"},{"label":"D","text":"41 Hz"},{"label":"E","text":"82 Hz"}],"images":[],"answer":"E"},{"id":"Units_7-8-q159","source":"Units_7-8","sourceNumber":"159","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two strings both vibrate at precisely 819 Hz. The tension in one of them is then increased slightly. As a result, six beats per second are heard when both strings vibrate. What is the new frequency of the string that was tightened?","choices":[{"label":"A","text":"813 Hz"},{"label":"B","text":"822 Hz"},{"label":"C","text":"816 Hz"},{"label":"D","text":"825 Hz"}],"images":[],"answer":"D"},{"id":"Units_7-8-q160","source":"Units_7-8","sourceNumber":"160","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"Two pure tones are sounded together and a particular beat frequency is heard. What happens to the beat frequency if the frequency of one of the tones is increased?","choices":[{"label":"A","text":"It decreases"},{"label":"B","text":"It increases"},{"label":"C","text":"It does not change"},{"label":"D","text":"It could either increase or decrease"}],"images":[],"answer":"D"},{"id":"Units_7-8-q161","source":"Units_7-8","sourceNumber":"161","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A music tuner uses a 554-Hz C# tuning fork to tune the frequency of a musical instrument. If the tuner hears a beat frequency of 2 Hz, what is the frequency of the instrument?","choices":[{"label":"A","text":"It could be either 553 Hz or 555 Hz"},{"label":"B","text":"It is neither be 556 Hz nor 552 Hz"},{"label":"C","text":"It could be either 556 Hz or 552 Hz"},{"label":"D","text":"It must be 552 Hz"},{"label":"E","text":"It must be 556 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q162","source":"Units_7-8","sourceNumber":"162","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A person stands between two speakers driven by the same source. Each speaker produces a tone with a frequency of 200 Hz on a day when the speed of sound is 330 m/s. The person is 1.65 m from one speaker and 4.95 m from the other. What type of interference does the person perceive?","choices":[{"label":"A","text":"constructive"},{"label":"B","text":"destructive"},{"label":"C","text":"both constructive and destructive"},{"label":"D","text":"neither constructive nor destructive"}],"images":[],"answer":"A"},{"id":"Units_7-8-q163","source":"Units_7-8","sourceNumber":"163","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A transverse wave is traveling on a string. The graph above shows position as a function of time for a point on the string. If the frequency of the wave is doubled, what is the new maximum speed of the point?","choices":[{"label":"A","text":"4.8 m/s"},{"label":"B","text":"0 m/s"},{"label":"C","text":"15 m/s"},{"label":"D","text":"9.6 m/s"},{"label":"E","text":"2.4 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"447","height":"239"}],"answer":"C"},{"id":"Units_7-8-q165","source":"Units_7-8","sourceNumber":"165","topic":"Unit 8: Fluids","difficulty":"Medium","question":"What is the speed of the passing water waves?","choices":[{"label":"A","text":"0.4 m/s"},{"label":"B","text":"0.8 m/s"},{"label":"C","text":"0.1 m/s"},{"label":"D","text":"0.2 m/s"},{"label":"E","text":"2 m/s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q166","source":"Units_7-8","sourceNumber":"166","topic":"Unit 6: Energy and Momentum of Rotating Systems","difficulty":"Medium","question":"A fisherman fishing from a pier observes that a continuous train of waves rolling in causes the float on his line to bob up and down, taking 2.4 s to move from its highest point to its lowest point. He also estimates that the distance between adjacent wave crests is 48 m. What is the speed of the waves going past the pier?","choices":[{"label":"A","text":"10 m/s"},{"label":"B","text":"120 m/s"},{"label":"C","text":"5.0 m/s"},{"label":"D","text":"20 m/s"},{"label":"E","text":"1.0 m/s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q167","source":"Units_7-8","sourceNumber":"167","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A tsunami, an ocean wave generated by an earthquake, propagates along the open ocean at 700 km/h and has a wavelength of 750 km. What is the frequency of the waves in such a tsunami?","choices":[{"label":"A","text":"6.8 Hz"},{"label":"B","text":"1.1 Hz"},{"label":"C","text":"0.93 Hz"},{"label":"D","text":"0.00026 Hz"},{"label":"E","text":"0.15 Hz"}],"images":[],"answer":"D"},{"id":"Units_7-8-q168","source":"Units_7-8","sourceNumber":"168","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"What is the frequency of a wave of wavelength 2.5 m that is traveling at 1400 m/s?","choices":[{"label":"A","text":"560 Hz"},{"label":"B","text":"1.78 kHz"},{"label":"C","text":"178 Hz"},{"label":"D","text":"5.6 kHz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q169","source":"Units_7-8","sourceNumber":"169","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"If a wave has a speed of 362 m/s and a period of 4.17 ms, what is its wavelength?","choices":[{"label":"A","text":"86,800 m"},{"label":"B","text":"0.0115 m"},{"label":"C","text":"1510 m"},{"label":"D","text":"86.8 m"},{"label":"E","text":"1.51 m"}],"images":[],"answer":"E"},{"id":"Units_7-8-q171","source":"Units_7-8","sourceNumber":"171","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"The speed of sound in steel is 5000 m/s. What is the wavelength of a sound wave of frequency 660 Hz in steel?","choices":[{"label":"A","text":"0.829 m"},{"label":"B","text":"7.58 m"},{"label":"C","text":"1.21 m"},{"label":"D","text":"0.132 m"},{"label":"E","text":"2.41 m"}],"images":[],"answer":"B"},{"id":"Units_7-8-q172","source":"Units_7-8","sourceNumber":"172","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Crests of an ocean wave pass a pier every 10.0 s. If the waves are moving at 5.6 m/s, what is the wavelength of the ocean waves?","choices":[{"label":"A","text":"64 m"},{"label":"B","text":"56 m"},{"label":"C","text":"28 m"},{"label":"D","text":"48 m"}],"images":[],"answer":"B"},{"id":"Units_7-8-q173","source":"Units_7-8","sourceNumber":"173","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Transverse waves travel at 43.2 m/s in a string that is pulled to a tension of 60.5 N . If the string is 15.9 m long, what is its mass?","choices":[{"label":"A","text":"0.216 kg"},{"label":"B","text":"0.366 kg"},{"label":"C","text":"0.597 kg"},{"label":"D","text":"0.515 kg"}],"images":[],"answer":"D"},{"id":"Units_7-8-q174","source":"Units_7-8","sourceNumber":"174","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A piano wire of linear mass density 0.0050 kg/m is pulled to a tension of 1350 N. What is the speed at which waves will travel along this wire?","choices":[{"label":"A","text":"1040 m/s"},{"label":"B","text":"130 m/s"},{"label":"C","text":"260 m/s"},{"label":"D","text":"2700 m/s"},{"label":"E","text":"520 m/s"}],"images":[],"answer":"E"},{"id":"Units_7-8-q176","source":"Units_7-8","sourceNumber":"176","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The density of aluminum is 2700 kg/m 3 . If transverse waves travel at 38 m/s in an aluminum wire of diameter 4.6 mm, what is the tension in the wire?","choices":[{"label":"A","text":"52 N"},{"label":"B","text":"65 N"},{"label":"C","text":"39 N"},{"label":"D","text":"78 N"}],"images":[],"answer":"B"},{"id":"Units_7-8-q178","source":"Units_7-8","sourceNumber":"178","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 2.31-kg rope is stretched between supports that are 10.4 m apart, and is pulled to a tension of 49.2 N. If one end of the rope is slightly tweaked, in what time interval will the resulting disturbance reach the other end?","choices":[{"label":"A","text":"0.615 s"},{"label":"B","text":"0.664 s"},{"label":"C","text":"0.720 s"},{"label":"D","text":"0.699 s"}],"images":[],"answer":"D"},{"id":"Units_7-8-q179","source":"Units_7-8","sourceNumber":"179","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 1.1-kg uniform bar of metal is 0.40 m long and has a diameter of 2.0 cm. When someone strikes one end of this bar, a 1.5 MHz sound wave travels along the length of the bar and reaches the other end in 0.12 ms. What is the wavelength of the sound wave in the metal?","choices":[{"label":"A","text":"3.8 mm"},{"label":"B","text":"3.4 mm"},{"label":"C","text":"3.0 mm"},{"label":"D","text":"2.6 mm"},{"label":"E","text":"2.2 mm"}],"images":[],"answer":"E"},{"id":"Units_7-8-q180","source":"Units_7-8","sourceNumber":"180","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 10-gram wire that is 6.0 m long is pulled with some tension. When a transverse wave of frequency 280 Hz travels along the wire, its wavelength is 0.60 m, and its amplitude is 8.4 mm. In what time interval does a crest of the transverse wave travel the length of the wire?","choices":[{"label":"A","text":"49 ms"},{"label":"B","text":"36 ms"},{"label":"C","text":"44 ms"},{"label":"D","text":"31 ms"},{"label":"E","text":"40 ms"}],"images":[],"answer":"B"},{"id":"Units_7-8-q181","source":"Units_7-8","sourceNumber":"181","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 90-gram wire that is 1.0 m long is pulled with some tension. When a transverse wave of frequency 890 Hz travels down the wire, its wavelength is 0.10 m and its amplitude is 6.5 mm. What is the tension in the wire?","choices":[{"label":"A","text":"710 N"},{"label":"B","text":"1000 N"},{"label":"C","text":"930 N"},{"label":"D","text":"1100 N"},{"label":"E","text":"820 N"}],"images":[],"answer":"A"},{"id":"Units_7-8-q182","source":"Units_7-8","sourceNumber":"182","topic":"Unit 8: Fluids","difficulty":"Medium","question":"An earthquake generates three kinds of waves: surface waves (L-waves), which are the slowest and weakest, shear (S) waves, which are transverse waves and carry most of the energy, and pressure (P) waves, which are longitudinal waves and are the fastest. The speed of P waves is approximately 7 km/s, and that of S waves is about 4 km/s. People do not generally feel the P waves, but animals seem to be sensitive to them. If a person reports that her dog started barking 20 s \"before the earthquake,\" then approximately how far away was the origin (epicenter) of the earthquake?","choices":[{"label":"A","text":"100 km"},{"label":"B","text":"500 km"},{"label":"C","text":"200 km"},{"label":"D","text":"400 km"},{"label":"E","text":"300 km"}],"images":[],"answer":"C"},{"id":"Units_7-8-q183","source":"Units_7-8","sourceNumber":"183","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 15-m rope is pulled taut with a tension of 140 N. It takes 0.545 s for the crest of a wave to propagate along the rope. What is the mass of the rope?","choices":[{"label":"A","text":"5.1 kg"},{"label":"B","text":"1.7 kg"},{"label":"C","text":"3.2 kg"},{"label":"D","text":"2.8 kg"},{"label":"E","text":"2.1 kg"}],"images":[],"answer":"D"},{"id":"Units_7-8-q184","source":"Units_7-8","sourceNumber":"184","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"Two steel wires are stretched with the same tension. The first wire has a diameter of 0.610 mm and the second wire has a diameter of 0.910 mm. If the speed of waves traveling along the first wire is 54.0 m/s, what is the speed of waves traveling along the second wire?","choices":[{"label":"A","text":"81.0 m/s"},{"label":"B","text":"24.9 m/s"},{"label":"C","text":"27.2 m/s"},{"label":"D","text":"100 m/s"},{"label":"E","text":"36.2 m/s"}],"images":[],"answer":"E"},{"id":"Units_7-8-q185","source":"Units_7-8","sourceNumber":"185","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"A crane lifts a 2500-kg beam at a steady rate of 15 cm/s using a steel cable, whose mass per unit length is 0.65 kg/m. What is the speed at which waves would propagate along this cable?","choices":[{"label":"A","text":"230 m/s"},{"label":"B","text":"1200 m/s"},{"label":"C","text":"580 m/s"},{"label":"D","text":"190 m/s"},{"label":"E","text":"1900 m/s"}],"images":[],"answer":"D"},{"id":"Units_7-8-q186","source":"Units_7-8","sourceNumber":"186","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A wire that is 1.0 m long with a mass of 90 g is under a tension of 710 N. When a transverse wave travels on the wire, its wavelength is 0.10 m and its amplitude is 6.5 mm. What is the frequency of this wave?","choices":[{"label":"A","text":"890 Hz"},{"label":"B","text":"1000 Hz"},{"label":"C","text":"1500 Hz"},{"label":"D","text":"1200 Hz"},{"label":"E","text":"920 Hz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q187","source":"Units_7-8","sourceNumber":"187","topic":"Unit 8: Fluids","difficulty":"Medium","question":"What is the speed of a wave on a brass wire with a radius of 0.500 mm stretched with a tension of 125 N? The density of brass is 8.60 × 10 3 kg/m 3 .","choices":[{"label":"A","text":"68.8 m/s"},{"label":"B","text":"136 m/s"},{"label":"C","text":"0.121 m/s"},{"label":"D","text":"100 m/s"},{"label":"E","text":"500 m/s"}],"images":[],"answer":"B"},{"id":"Units_7-8-q190","source":"Units_7-8","sourceNumber":"190","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Find the speed of an ocean wave whose displacement is given by the equation y = 3.7 cos(2.2 x − 5.6 t ) where x and y are in meters and t is in seconds.","choices":[{"label":"A","text":"4.5 m/s"},{"label":"B","text":"1.9 m/s"},{"label":"C","text":"3.5 m/s"},{"label":"D","text":"2.5 m/s"}],"images":[],"answer":"D"},{"id":"Units_7-8-q191","source":"Units_7-8","sourceNumber":"191","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"What are the wavelength (in meters) and frequency (in hertz) of a wave whose displacement is given by the equation y = 0.5 sin(0.20 x + 120 t ), where x and y are in meters and t is in seconds?","choices":[{"label":"A","text":"5.0 m, 10 Hz"},{"label":"B","text":"10 m, 0.50 Hz"},{"label":"C","text":"31 m, 19 Hz"},{"label":"D","text":"0.20 m, 120 Hz"},{"label":"E","text":"19 m, 120 Hz"}],"images":[{"src":"data:image/jpeg;base64,","alt":"square root of (2π)","width":null,"height":null}],"answer":"C"},{"id":"Units_7-8-q192","source":"Units_7-8","sourceNumber":"192","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"Light from a laser forms a 1.31-mm diameter spot on a wall. If the light intensity in the spot is 1.58 × 10 4 W/m 2 , what is the power output of the laser? Assume that all the light emitted by the laser hits the spot.","choices":[{"label":"A","text":"17.9 mW"},{"label":"B","text":"13.2 mW"},{"label":"C","text":"24.7 mW"},{"label":"D","text":"21.3 mW"}],"images":[],"answer":"D"},{"id":"Units_7-8-q193","source":"Units_7-8","sourceNumber":"193","topic":"Unit 7: Oscillations","difficulty":"Easy","question":"Calculate the light intensity 1.45 m from a light bulb that radiates 100 W equally in all directions.","choices":[{"label":"A","text":"47.6 W/m 2"},{"label":"B","text":"3.78 W/m 2"},{"label":"C","text":"4.36 W/m 2"},{"label":"D","text":"54.7 W/m 2"}],"images":[],"answer":"B"},{"id":"Units_7-8-q194","source":"Units_7-8","sourceNumber":"194","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"The average intensity of sunlight incident on Earth is measured to be about 1.4 kW/m 2 . What is the power of sunlight emitted by the Sun? (Earth-Sun distance = 1.5 × 10 8 km, Earth radius = 6.4 × 10 3 km)","choices":[{"label":"A","text":"3.2 × 10 22 W"},{"label":"B","text":"7.2 × 10 14 W"},{"label":"C","text":"7.6 × 10 8 W"},{"label":"D","text":"4.0 × 10 26 W"}],"images":[],"answer":"C"},{"id":"Units_7-8-q197","source":"Units_7-8","sourceNumber":"197","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A string is pulled taut, and vibrated at frequency 25 Hz, then 50 Hz, then 100 Hz, and finally 200 Hz. Standing waves are observed on the string at three out of these four frequencies. Which of the frequencies does not produce a standing wave in the string?","choices":[{"label":"A","text":"50 Hz"},{"label":"B","text":"100 Hz"},{"label":"C","text":"25 Hz"},{"label":"D","text":"200 Hz"},{"label":"E","text":"Not enough information to determine"}],"images":[],"answer":"C"},{"id":"Units_7-8-q198","source":"Units_7-8","sourceNumber":"198","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A string of linear density 1.5 g/m is under a tension of 20 N. What should be its length if its fundamental resonance frequency is 220 Hz?","choices":[{"label":"A","text":"1.1 m"},{"label":"B","text":"0.26 m"},{"label":"C","text":"1.2 m"},{"label":"D","text":"0.96 m"}],"images":[],"answer":"B"},{"id":"Units_7-8-q199","source":"Units_7-8","sourceNumber":"199","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Find the first three harmonics of a string of linear mass density 2.00 g/m and length 0.600 m when the tension in it is 50.0 N.","choices":[{"label":"A","text":"264 Hz, 528 Hz, 792 Hz"},{"label":"B","text":"66 Hz, 132 Hz, 198 Hz"},{"label":"C","text":"132 Hz, 264 Hz, 395 Hz"},{"label":"D","text":"None of the above"}],"images":[],"answer":"C"},{"id":"Units_7-8-q201","source":"Units_7-8","sourceNumber":"201","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"What is the frequency of the fundamental mode of vibration of a steel piano wire stretched to a tension of 440 N? The wire is 0.600 m long and has a mass of 5.60 g.","choices":[{"label":"A","text":"366 Hz"},{"label":"B","text":"181 Hz"},{"label":"C","text":"517 Hz"},{"label":"D","text":"312 Hz"},{"label":"E","text":"234 Hz"}],"images":[],"answer":"B"},{"id":"Units_7-8-q202","source":"Units_7-8","sourceNumber":"202","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 25-g string is stretched with a tension of 43 N between two fixed points 12 m apart. What is the frequency of the second harmonic?","choices":[{"label":"A","text":"6.0 Hz"},{"label":"B","text":"18 Hz"},{"label":"C","text":"12 Hz"},{"label":"D","text":"24 Hz"},{"label":"E","text":"36 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q203","source":"Units_7-8","sourceNumber":"203","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A 0.588-m string is tightly clamped at both ends. If the lowest standing wave frequency of the string is 326 Hz, how fast do waves travel on this string?","choices":[{"label":"A","text":"475 m/s"},{"label":"B","text":"383 m/s"},{"label":"C","text":"724 m/s"},{"label":"D","text":"582 m/s"}],"images":[],"answer":"B"},{"id":"Units_7-8-q204","source":"Units_7-8","sourceNumber":"204","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A string that is 2.0 m long is fixed at both ends and tightened until the wave speed is 18 m/s. What is the frequency of the standing wave shown in the figure?","choices":[{"label":"A","text":"27 Hz"},{"label":"B","text":"81 Hz"},{"label":"C","text":"54 Hz"},{"label":"D","text":"110 Hz"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"388","height":"95"}],"answer":"A"},{"id":"Units_7-8-q205","source":"Units_7-8","sourceNumber":"205","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A standing wave is oscillating at 950 Hz on a string, as shown in the figure. What is the wave speed?","choices":[{"label":"A","text":"290 m/s"},{"label":"B","text":"380 m/s"},{"label":"C","text":"570 m/s"},{"label":"D","text":"190 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"389","height":"112"}],"answer":"B"},{"id":"Units_7-8-q206","source":"Units_7-8","sourceNumber":"206","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A guitar-like stringed instrument has a string that is 16 cm long. It sounds the musical note A (440 Hz) when played without the length of its vibrating section being shortened by pressing a finger to the fingerboard. By what distance should you shorten it to make the string vibrate at the note C (523 Hz)?","choices":[{"label":"A","text":"1.7 cm"},{"label":"B","text":"3.4 cm"},{"label":"C","text":"2.5 cm"},{"label":"D","text":"4.2 cm"}],"images":[],"answer":"C"},{"id":"Units_7-8-q207","source":"Units_7-8","sourceNumber":"207","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 4.0-g string is 0.36 m long and is under tension. The string vibrates at 500 Hz in its third harmonic. What is the wavelength of the standing wave in the string?","choices":[{"label":"A","text":"0.24 m"},{"label":"B","text":"0.90 m"},{"label":"C","text":"0.72 m"},{"label":"D","text":"0.36 m"},{"label":"E","text":"0.54 m"}],"images":[],"answer":"A"},{"id":"Units_7-8-q208","source":"Units_7-8","sourceNumber":"208","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Medium","question":"A 4.0-g string is 0.39 m long and is under tension. The string vibrates at 600 Hz in its third harmonic. What is the tension in this string?","choices":[{"label":"A","text":"200 N"},{"label":"B","text":"250 N"},{"label":"C","text":"290 N"},{"label":"D","text":"340 N"},{"label":"E","text":"160 N"}],"images":[],"answer":"B"},{"id":"Units_7-8-q209","source":"Units_7-8","sourceNumber":"209","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"One of the harmonics of a string fixed at both ends has a frequency of 52.2 Hz and the next higher harmonic has a frequency of 60.9 Hz. What is the fundamental frequency of the string?","choices":[{"label":"A","text":"8.7 Hz"},{"label":"B","text":"4.35 Hz"},{"label":"C","text":"30.4 Hz"},{"label":"D","text":"17.4 Hz"},{"label":"E","text":"26.1 Hz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q211","source":"Units_7-8","sourceNumber":"211","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"The speed of sound through the ground is about 6.0 km/s, and the speed of sound in air is 343 m/s. A very powerful explosion occurs some distance away and you feel the ground vibrate 60 s before you hear the sound of the explosion. How far away is the explosion?","choices":[{"label":"A","text":"25 km"},{"label":"B","text":"27 km"},{"label":"C","text":"22 km"},{"label":"D","text":"20 km"},{"label":"E","text":"30 km"}],"images":[],"answer":"C"},{"id":"Units_7-8-q212","source":"Units_7-8","sourceNumber":"212","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"Two motors in a factory are running at slightly different rates. One runs at 825.0 rev/min and the other at 786.0 rev/min. You hear the sound intensity increase and then decrease periodically due to wave interference. What is the time interval between successive instances of the sound intensity starting to increase?","choices":[{"label":"A","text":"1.43 s"},{"label":"B","text":"1.66 s"},{"label":"C","text":"1.79 s"},{"label":"D","text":"1.54 s"}],"images":[],"answer":"D"},{"id":"Units_7-8-q214","source":"Units_7-8","sourceNumber":"214","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"What is the intensity of a 70-dB sound? The threshold of human hearing is 1.0 × 10 −12 W/m 2 .","choices":[{"label":"A","text":"10 −6 W/m 2"},{"label":"B","text":"10 −7 W/m 2"},{"label":"C","text":"10 −4 W/m 2"},{"label":"D","text":"10 −5 W/m 2"}],"images":[],"answer":"C"},{"id":"Units_7-8-q215","source":"Units_7-8","sourceNumber":"215","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"What is the ratio of the intensities of two sounds with sound intensity levels of 70 dB and 40 dB?","choices":[{"label":"A","text":"100:1"},{"label":"B","text":"10:1"},{"label":"C","text":"10,000:1"},{"label":"D","text":"1000:1"}],"images":[],"answer":"D"},{"id":"Units_7-8-q216","source":"Units_7-8","sourceNumber":"216","topic":"Unit 5: Torque and Rotational Dynamics","difficulty":"Medium","question":"If the sound intensity level produced by 15 identical engines in a garage is 100 dB, what is the sound intensity level generated by each one of these engines?","choices":[{"label":"A","text":"44 dB"},{"label":"B","text":"67 dB"},{"label":"C","text":"13 dB"},{"label":"D","text":"6.7 dB"},{"label":"E","text":"88 dB"}],"images":[],"answer":"E"},{"id":"Units_7-8-q217","source":"Units_7-8","sourceNumber":"217","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"The intensity at a distance of 6.0 m from a source that is radiating equally in all directions is 6.0 × 10 −10 W/m 2 . What is the power emitted by the source?","choices":[{"label":"A","text":"2.1 × 10 −8 W"},{"label":"B","text":"2.1 × 10 −6 W"},{"label":"C","text":"2.7 × 10 −5 W"},{"label":"D","text":"2.7 × 10 −7 W"}],"images":[],"answer":"D"},{"id":"Units_7-8-q218","source":"Units_7-8","sourceNumber":"218","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"The intensity at a distance of 6.0 m from a source that is radiating equally in all directions is 6.0 × 10 −10 W/m 2 . What is the sound intensity level in dB? The threshold of human hearing is 1.0 × 10 −12 W/m 2 .","choices":[{"label":"A","text":"28 dB"},{"label":"B","text":"18 dB"},{"label":"C","text":"32 dB"},{"label":"D","text":"23 dB"}],"images":[],"answer":"A"},{"id":"Units_7-8-q219","source":"Units_7-8","sourceNumber":"219","topic":"Unit 3: Work, Energy, and Power","difficulty":"Medium","question":"A barking dog delivers about 1.0 mW of power, which is uniformly distributed in all directions. What is the sound intensity level (in decibels) at a distance 5.00 m from the dog? The threshold of human hearing is 1.0 × 10 −12 W/m 2 .","choices":[{"label":"A","text":"65 dB"},{"label":"B","text":"63 dB"},{"label":"C","text":"61 dB"},{"label":"D","text":"68 dB"}],"images":[],"answer":"A"},{"id":"Units_7-8-q220","source":"Units_7-8","sourceNumber":"220","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"The sound intensity level is 65 dB at a distance 5.00 m from a barking dog. What would be a reasonable estimate for the intensity level if two identical dogs very close to each other were barking? You can ignore any interference effects.","choices":[{"label":"A","text":"130 dB"},{"label":"B","text":"65 dB"},{"label":"C","text":"136 dB"},{"label":"D","text":"68 dB"}],"images":[],"answer":"D"},{"id":"Units_7-8-q221","source":"Units_7-8","sourceNumber":"221","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"At a distance of 15.0 m from a sound source, the sound intensity level is 60.0 dB. What is the sound intensity level (in decibels) at a point 2.00 m from the source if the source radiates equally in all directions?","choices":[{"label":"A","text":"57.5 dB"},{"label":"B","text":"77.5 dB"},{"label":"C","text":"75.5 dB"},{"label":"D","text":"55.7 dB"}],"images":[],"answer":"B"},{"id":"Units_7-8-q222","source":"Units_7-8","sourceNumber":"222","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"The sound intensity level 5.0 m from a point source is 95 dB. At what distance will it be 75 dB?","choices":[{"label":"A","text":"25 m"},{"label":"B","text":"75 m"},{"label":"C","text":"225 m"},{"label":"D","text":"50 m"}],"images":[],"answer":"D"},{"id":"Units_7-8-q224","source":"Units_7-8","sourceNumber":"224","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"You double your distance from a sound source that is radiating equally in all directions. What happens to the intensity level of the sound? It drops by","choices":[{"label":"A","text":"3 dB."},{"label":"B","text":"8 dB."},{"label":"C","text":"2 dB."},{"label":"D","text":"6 dB."}],"images":[],"answer":"D"},{"id":"Units_7-8-q225","source":"Units_7-8","sourceNumber":"225","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"By how many decibels does the intensity level of a sound decrease when you triple your distance from its source?","choices":[{"label":"A","text":"9.5 dB"},{"label":"B","text":"12 dB"},{"label":"C","text":"4.8 dB"},{"label":"D","text":"6.0 dB"},{"label":"E","text":"3.0 dB"}],"images":[],"answer":"A"},{"id":"Units_7-8-q226","source":"Units_7-8","sourceNumber":"226","topic":"Unit 3: Work, Energy, and Power","difficulty":"Hard","question":"A certain factory whistle can be heard up to a distance of 2.5 km. Assuming that the acoustic output of the whistle is uniform in all directions, how much acoustic power is emitted by the whistle? The threshold of human hearing is 1.0 × 10 −12 W/m 2 .","choices":[{"label":"A","text":"0.79 mW"},{"label":"B","text":"2.6 mW"},{"label":"C","text":"0.026 mW"},{"label":"D","text":"0.079 mW"},{"label":"E","text":"0.26 mW"}],"images":[],"answer":"D"},{"id":"Units_7-8-q227","source":"Units_7-8","sourceNumber":"227","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"A certain factory whistle can be heard up to a distance of 9.8 km. Assuming that the acoustic output of the whistle is uniform in all directions, at what distance from the factory is the sound intensity level of the whistle sound equal to 25 dB? The threshold of human hearing is 1.0 × 10 −12 W/m 2 .","choices":[{"label":"A","text":"830 m"},{"label":"B","text":"1100 m"},{"label":"C","text":"550 m"},{"label":"D","text":"660 m"},{"label":"E","text":"940 m"}],"images":[],"answer":"C"},{"id":"Units_7-8-q229","source":"Units_7-8","sourceNumber":"229","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two people are talking at a distance of 3.0 m from where you are, and you measure the sound intensity as 1.1 × 10 −7 W/m 2 . Another student is 4.0 m away from the talkers. Calculate a reasonable estimate for the sound intensity that the other student measures.","choices":[{"label":"A","text":"8.3 × 10 −8 W/m 2"},{"label":"B","text":"6.2 × 10 −8 W/m 2"},{"label":"C","text":"1.5 × 10 −7 W/m 2"},{"label":"D","text":"2.5 × 10 −8 W/m 2"},{"label":"E","text":"7.8 × 10 −7 W/m 2"}],"images":[],"answer":"D"},{"id":"Units_7-8-q230","source":"Units_7-8","sourceNumber":"230","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A crying baby emits sound with an intensity of 8.0 × 10 −8 W/m 2 . Calculate a reasonable estimate for the sound intensity level from a set of quintuplets (five babies), all crying simultaneously at the same place. The lowest detectable intensity is 1.0 × 10 −12 W/m 2 .","choices":[{"label":"A","text":"69 dB"},{"label":"B","text":"49 dB"},{"label":"C","text":"56 dB"},{"label":"D","text":"36 dB"},{"label":"E","text":"79 dB"}],"images":[],"answer":"C"},{"id":"Units_7-8-q231","source":"Units_7-8","sourceNumber":"231","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"If the sound intensity level of one trombone is 70 dB, which is a reasonable estimate for the sound intensity level of 76 trombones all playing simultaneously in the same place?","choices":[{"label":"A","text":"89 dB"},{"label":"B","text":"70 dB"},{"label":"C","text":"82 dB"},{"label":"D","text":"76 dB"},{"label":"E","text":"146 dB"}],"images":[],"answer":"A"},{"id":"Units_7-8-q234","source":"Units_7-8","sourceNumber":"234","topic":"Unit 8: Fluids","difficulty":"Medium","question":"An organ pipe open at both ends has a length of 0.80 m. If the speed of sound in air is 340 m/s, what is the frequency of the second harmonic of this pipe?","choices":[{"label":"A","text":"850 Hz"},{"label":"B","text":"638 Hz"},{"label":"C","text":"213 Hz"},{"label":"D","text":"425 Hz"}],"images":[],"answer":"D"},{"id":"Units_7-8-q235","source":"Units_7-8","sourceNumber":"235","topic":"Unit 8: Fluids","difficulty":"Medium","question":"What is the length of a pipe closed on one end and open at the other end that will have a fundamental frequency of 0.060 kHz on a day when the speed of sound is 340 m/s?","choices":[{"label":"A","text":"2.14 m"},{"label":"B","text":"1.24 m"},{"label":"C","text":"1.42 m"},{"label":"D","text":"4.12 m"}],"images":[],"answer":"C"},{"id":"Units_7-8-q236","source":"Units_7-8","sourceNumber":"236","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Consider two pipes of the same length: one pipe is open at both ends and the other pipe is closed on one end but open at the other end. If the fundamental frequency of the totally open pipe is 300 Hz, what is the fundamental frequency of the other pipe?","choices":[{"label":"A","text":"450 Hz"},{"label":"B","text":"150 Hz"},{"label":"C","text":"300 Hz"},{"label":"D","text":"600 Hz"}],"images":[],"answer":"B"},{"id":"Units_7-8-q237","source":"Units_7-8","sourceNumber":"237","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"One of the standing-wave vibration possibilities of a column of air in a tube that is open at one end and closed at the other has a frequency of 448 Hz, and the next higher standing-wave vibration possibility has a frequency of 576 Hz. What is the fundamental frequency of the air column in this tube?","choices":[{"label":"A","text":"88 Hz"},{"label":"B","text":"32 Hz"},{"label":"C","text":"64 Hz"},{"label":"D","text":"128 Hz"},{"label":"E","text":"256 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q238","source":"Units_7-8","sourceNumber":"238","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"One of the harmonics of a column of air in a tube that is open at both ends has a frequency of 512 Hz, and the next higher harmonic has a frequency of 640 Hz. What is the fundamental frequency of the air column in this tube?","choices":[{"label":"A","text":"88 Hz"},{"label":"B","text":"32 Hz"},{"label":"C","text":"256 Hz"},{"label":"D","text":"128 Hz"},{"label":"E","text":"64 Hz"}],"images":[],"answer":"D"},{"id":"Units_7-8-q239","source":"Units_7-8","sourceNumber":"239","topic":"Unit 7: Oscillations","difficulty":"Hard","question":"One of the standing-wave vibration possibilities of a column of air in a tube that is open at one end and closed at the other has a frequency of 448 Hz, and the next higher vibration possibility has a frequency of 576 Hz. How long is the tube? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"1.34 m"},{"label":"B","text":"0.670 m"},{"label":"C","text":"1.00 m"},{"label":"D","text":"2.68 m"},{"label":"E","text":"0.335 m"}],"images":[],"answer":"A"},{"id":"Units_7-8-q240","source":"Units_7-8","sourceNumber":"240","topic":"Unit 2: Force and Translational Dynamics","difficulty":"Hard","question":"A 2.0-g string that is 0.67 m long is pulled with some tension. The string vibrates at 700 Hz in its third harmonic, and this vibration causes a sound wave. What is the wavelength of the sound? The speed of sound in air is 344 m/s.","choices":[{"label":"A","text":"0.45 m"},{"label":"B","text":"0.55 m"},{"label":"C","text":"0.67 m"},{"label":"D","text":"0.49 m"},{"label":"E","text":"0.61 m"}],"images":[],"answer":"D"},{"id":"Units_7-8-q241","source":"Units_7-8","sourceNumber":"241","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A string that is 0.26 m long is vibrating in its n = 6 harmonic. The sound from this string excites the air in a pipe that is 0.88 m long and open at both ends into its third-harmonic resonance. What is the common resonant frequency of the string and the pipe? The speed of sound in air is 345 m/s.","choices":[{"label":"A","text":"760 Hz"},{"label":"B","text":"490 Hz"},{"label":"C","text":"590 Hz"},{"label":"D","text":"390 Hz"},{"label":"E","text":"690 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q243","source":"Units_7-8","sourceNumber":"243","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"The wavelengths of the sounds produced by two horns are 6.0 m and 7.0 m, respectively. What beat frequency is heard when the horns are sounded on a day when the speed of sound is 340 m/s?","choices":[{"label":"A","text":"8 Hz"},{"label":"B","text":"7 Hz"},{"label":"C","text":"5 Hz"},{"label":"D","text":"6 Hz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q244","source":"Units_7-8","sourceNumber":"244","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two taut strings of identical mass per unit length are stretched with the same tension with their ends fixed, but one string is 0.330 cm longer than the other. Waves on these strings propagate at 34.0 m/s. The fundamental frequency of the shorter string is 258 Hz. What is the beat frequency when each string is vibrating at its fundamental frequency?","choices":[{"label":"A","text":"9.00 Hz"},{"label":"B","text":"12.0 Hz"},{"label":"C","text":"11.3 Hz"},{"label":"D","text":"12.3 Hz"},{"label":"E","text":"12.7 Hz"}],"images":[],"answer":"D"},{"id":"Units_7-8-q245","source":"Units_7-8","sourceNumber":"245","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two taut strings of identical mass and length are stretched with their ends fixed, but the tension in one string is 1.10 times greater than in the other. Waves on the string with the lower tension propagate at 35.2 m/s. The fundamental frequency of that string is 258 Hz. What is the beat frequency when each string is vibrating at its fundamental frequency?","choices":[{"label":"A","text":"11.0 Hz"},{"label":"B","text":"13.7 Hz"},{"label":"C","text":"9.00 Hz"},{"label":"D","text":"12.6 Hz"},{"label":"E","text":"17.1 Hz"}],"images":[],"answer":"D"},{"id":"Units_7-8-q246","source":"Units_7-8","sourceNumber":"246","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A policeman in a stationary car measures the speed of approaching cars by means of an ultrasonic device that emits a sound with a frequency of 39.6 kHz. A car is approaching him at a speed of 35.0 m/s. The wave is reflected by the car and interferes with the emitted sound producing beats. What is the frequency of the beats when the speed of sound in air is 343 m/s?","choices":[{"label":"A","text":"4500 Hz"},{"label":"B","text":"5000 Hz"},{"label":"C","text":"9000 Hz"},{"label":"D","text":"8490 Hz"},{"label":"E","text":"4250 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q249","source":"Units_7-8","sourceNumber":"249","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A car approaches you at a constant speed, sounding its horn, and you hear a frequency of 76 Hz. After the car goes by, you hear a frequency of 65 Hz. What is the frequency of the sound emitted by the horn? The speed of sound in the air is 343 m/s.","choices":[{"label":"A","text":"72 Hz"},{"label":"B","text":"73 Hz"},{"label":"C","text":"70 Hz"},{"label":"D","text":"69 Hz"},{"label":"E","text":"68 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q250","source":"Units_7-8","sourceNumber":"250","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"As you stand by the side of the road, a car approaches you at a constant speed, sounding its horn, and you hear a frequency of 76 Hz. After the car goes by, you hear a frequency of 65 Hz. What is the speed of the car? The speed of sound in the air is 343 m/s.","choices":[{"label":"A","text":"28 m/s"},{"label":"B","text":"29 m/s"},{"label":"C","text":"30 m/s"},{"label":"D","text":"26 m/s"},{"label":"E","text":"27 m/s"}],"images":[],"answer":"E"},{"id":"Units_7-8-q251","source":"Units_7-8","sourceNumber":"251","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"You are driving along a highway at 35.0 m/s when you hear the siren of a police car approaching you from behind at constant speed and you perceive the highest frequency of the siren's wail as 1340 Hz. You are relieved that he is in pursuit of a different driver when he continues past you, but now you perceive the highest frequency as 1300 Hz. What is the speed of the police car? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"30 m/s"},{"label":"B","text":"41.7 m/s"},{"label":"C","text":"40.1 m/s"},{"label":"D","text":"38.4 m/s"},{"label":"E","text":"39.2 m/s"}],"images":[],"answer":"C"},{"id":"Units_7-8-q252","source":"Units_7-8","sourceNumber":"252","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"You are driving along a highway at 35.0 m/s when you hear the siren of a police car approaching you from behind at constant speed and you perceive the highest frequency of the siren's wail as 1310 Hz. You are relieved that he is in pursuit of a different driver when he continues past you, but now you perceive the highest frequency as 1240 Hz. What is the highest frequency heard from the siren in the police car? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"1370 Hz"},{"label":"B","text":"1360 Hz"},{"label":"C","text":"1320 Hz"},{"label":"D","text":"1270 Hz"},{"label":"E","text":"1300 Hz"}],"images":[],"answer":"D"},{"id":"Units_7-8-q253","source":"Units_7-8","sourceNumber":"253","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"You are driving along a highway at 25 m/s when you hear the siren of an emergency vehicle traveling at constant speed in the opposite direction on the other side of the highway. When the vehicle is approaching you, you hear the highest frequency of the siren's wail as 2380 Hz, but after it has passed close beside you the highest frequency you hear becomes 1680 Hz. What is the speed of the vehicle? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"41 m/s"},{"label":"B","text":"32 m/s"},{"label":"C","text":"35 m/s"},{"label":"D","text":"50 m/s"},{"label":"E","text":"30 m/s"}],"images":[],"answer":"C"},{"id":"Units_7-8-q254","source":"Units_7-8","sourceNumber":"254","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"You are driving along a highway at 25.0 m/s when you hear the siren of an emergency vehicle traveling at constant speed in the opposite direction on the other side of the highway. When the vehicle is approaching you, you hear the highest frequency of the siren's wail as 2380 Hz, but after it has passed close beside you the highest frequency you hear becomes 1680 Hz. What is the highest frequency at which the siren vibrates? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"1980 Hz"},{"label":"B","text":"1850 Hz"},{"label":"C","text":"2050 Hz"},{"label":"D","text":"2030 Hz"},{"label":"E","text":"1990 Hz"}],"images":[],"answer":"E"},{"id":"Units_7-8-q255","source":"Units_7-8","sourceNumber":"255","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A whistle produces sound of frequency of 1.00 kHz. If a listener moves with a speed of 30 m/s away from the whistle, what frequency does this person hear if the sound speed is 340 m/s?","choices":[{"label":"A","text":"1000 Hz"},{"label":"B","text":"919 Hz"},{"label":"C","text":"912 Hz"},{"label":"D","text":"1090 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q256","source":"Units_7-8","sourceNumber":"256","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A dragon squawks at 800 Hz. It is traveling at 35.0 m/s on a day when the speed of sound in air is 340 m/s. Moving in a straight line, the monster swoops past an observer who is standing just beside its line of flight. What change of frequency does the observer hear?","choices":[{"label":"A","text":"249 Hz"},{"label":"B","text":"0 Hz"},{"label":"C","text":"166 Hz"},{"label":"D","text":"82 HZ"}],"images":[],"answer":"C"},{"id":"Units_7-8-q257","source":"Units_7-8","sourceNumber":"257","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"What frequency does a stationary observer hear when a train approaches her with a speed of 30.0 m/s? The frequency of the train horn is 0.600 kHz and the speed of sound is 340 m/s.","choices":[{"label":"A","text":"600 Hz"},{"label":"B","text":"653 Hz"},{"label":"C","text":"658 Hz"},{"label":"D","text":"551 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q258","source":"Units_7-8","sourceNumber":"258","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"You are moving at 120 km/h toward a stationary train. The train blows its 0.400-kHz whistle. Take the speed of sound to be 340 m/s. What frequency do you hear?","choices":[{"label":"A","text":"439 Hz"},{"label":"B","text":"444 Hz"},{"label":"C","text":"361 Hz"},{"label":"D","text":"364 Hz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q259","source":"Units_7-8","sourceNumber":"259","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A train is traveling away from you at 120 km/h. It blows its whistle, and you hear a tone of 0.400 kHz. Take the speed of sound to be 340 m/s. What frequency would the whistle produce if the train were at rest?","choices":[{"label":"A","text":"361 Hz"},{"label":"B","text":"364 Hz"},{"label":"C","text":"439 Hz"},{"label":"D","text":"444 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q260","source":"Units_7-8","sourceNumber":"260","topic":"Unit 1: Kinematics","difficulty":"Medium","question":"Sonar is used to determine the speed of an object. A 40.0-kHz signal is sent out, and a 42.0-kHz signal is returned. If the speed of sound is 345 m/s, how fast is the object moving?","choices":[{"label":"A","text":"8.4 m/s"},{"label":"B","text":"347 m/s"},{"label":"C","text":"6.9 m/s"},{"label":"D","text":"331 m/s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q261","source":"Units_7-8","sourceNumber":"261","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"A bat emits a sound at a frequency of 39.0 kHz as it approaches a wall. The bat detects beats with a frequency of 827 Hz between the sound it emits and the echo bouncing from the wall. What is the speed of the bat if the speed of sound in air is 343 m/s?","choices":[{"label":"A","text":"3.6 m/s"},{"label":"B","text":"9.0 m/s"},{"label":"C","text":"2.7 m/s"},{"label":"D","text":"3.0 m/s"},{"label":"E","text":"5.4 m/s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q262","source":"Units_7-8","sourceNumber":"262","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two in-phase loudspeakers are some distance apart. They emit sound with a frequency of 536 Hz. A microphone is moved between the speakers along the line joining the two speakers with a constant speed of 1.60 m/s. What beat frequency is observed? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"8.00 Hz"},{"label":"B","text":"5.00 Hz"},{"label":"C","text":"7.00 Hz"},{"label":"D","text":"6.00 Hz"},{"label":"E","text":"9.00 Hz"}],"images":[],"answer":"B"},{"id":"Units_7-8-q263","source":"Units_7-8","sourceNumber":"263","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"At a particular instant, a siren emitting sound of frequency 1000 Hz is approaching a stationary observer at one-half the speed of sound. The observer hears a frequency of","choices":[{"label":"A","text":"1500 Hz"},{"label":"B","text":"500 Hz"},{"label":"C","text":"1000 Hz"},{"label":"D","text":"2000 Hz"},{"label":"E","text":"none of the above"}],"images":[],"answer":"D"},{"id":"Units_7-8-q264","source":"Units_7-8","sourceNumber":"264","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"The sound from the whistle of a truck moving at 17.0 m/s toward a cliff reflects from the cliff and is heard by the driver of the truck. When the truck is parked at the side of the road, the whistle produces sound of frequency 2.267 kHz. As observed by the driver of the truck, what is the change in frequency of the sound from the whistle due to the reflection? The speed of sound is 343 m/s.","choices":[{"label":"A","text":"207 Hz"},{"label":"B","text":"228 Hz"},{"label":"C","text":"236 Hz"},{"label":"D","text":"118 Hz"},{"label":"E","text":"472 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q265","source":"Units_7-8","sourceNumber":"265","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two in-phase speakers are 3.0 m apart. They emit sound with a frequency of 490 Hz. A microphone is placed half-way between the speakers and then moved along the line joining the two speakers until the next point of constructive interference is found. At what distance from the midpoint is that next point? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"0.70 m"},{"label":"B","text":"0.18 m"},{"label":"C","text":"0.50 m"},{"label":"D","text":"0.35 m"},{"label":"E","text":"There is no point in that line where constructive interference occurs."}],"images":[],"answer":"D"},{"id":"Units_7-8-q266","source":"Units_7-8","sourceNumber":"266","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two in-phase loudspeakers are placed along a wall and are separated by a distance of 4.00 m. They emit sound with a frequency of 514 Hz. A person is standing away from the wall, directly in front of one of the loudspeakers. What is the closest distance from the wall the person can stand and hear constructive interference? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"1.6 m"},{"label":"B","text":"1.2 m"},{"label":"C","text":"0.34 m"},{"label":"D","text":"0.73 m"}],"images":[],"answer":"D"},{"id":"Units_7-8-q267","source":"Units_7-8","sourceNumber":"267","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two in-phase loudspeakers are placed along a wall and are separated by a distance of 4.00 m. They emit sound with a frequency of 514 Hz. A person is standing away from the wall, directly in front of one of the loudspeakers. What is the closest distance from the wall the person can stand and hear destructive interference? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"1.6 m"},{"label":"B","text":"0.73 m"},{"label":"C","text":"1.2 m"},{"label":"D","text":"0.34 m"},{"label":"E","text":"0.37 m"}],"images":[],"answer":"D"},{"id":"Units_7-8-q268","source":"Units_7-8","sourceNumber":"268","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two in-phase loudspeakers that emit sound with the same frequency are placed along a wall and are separated by a distance of 5.00 m. A person is standing 12.0 m away from the wall, equidistant from the loudspeakers. When the person moves 1.00 m parallel to the wall, she experiences destructive interference for the first time. What is the frequency of the sound? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"256 Hz"},{"label":"B","text":"211 Hz"},{"label":"C","text":"422 Hz"},{"label":"D","text":"512 Hz"},{"label":"E","text":"674 Hz"}],"images":[],"answer":"C"},{"id":"Units_7-8-q269","source":"Units_7-8","sourceNumber":"269","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two in-phase loudspeakers that emit sound with the same frequency are placed along a wall and are separated by a distance of 8.00 m. A person is standing 12.0 m away from the wall, equidistant from the loudspeakers. When the person moves 3.00 m parallel to the wall, she experiences destructive interference for the second time. What is the frequency of the sound? The speed of sound in air is 343 m/s.","choices":[{"label":"A","text":"452 Hz"},{"label":"B","text":"278 Hz"},{"label":"C","text":"694 Hz"},{"label":"D","text":"422 Hz"},{"label":"E","text":"562 Hz"}],"images":[],"answer":"B"},{"id":"Units_7-8-q270","source":"Units_7-8","sourceNumber":"270","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two loudspeakers placed 6.00 m apart are driven in phase by an audio oscillator having a frequency range from 1908 Hz to 2471 Hz. A point P is located 4.70 m from one loudspeaker and 3.60 m from the other speaker. At what frequency of the oscillator do the sound waves at point P interfere constructively? The speed of sound is 344 m/s.","choices":[{"label":"A","text":"2190 Hz"},{"label":"B","text":"2270 Hz"},{"label":"C","text":"2340 Hz"},{"label":"D","text":"2420 Hz"},{"label":"E","text":"2110 Hz"}],"images":[],"answer":"A"},{"id":"Units_7-8-q271","source":"Units_7-8","sourceNumber":"271","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two loudspeakers placed 6.00 m apart are driven in phase by an audio oscillator having a frequency range from 1595 Hz to 2158 Hz. A point P is located 4.70 m from one loudspeaker and 3.60 m from the other speaker. The speed of sound in the room is 344 m/s. At what frequency (or frequencies) of the oscillator do the sound waves reaching point P interfere destructively? (There could be more than one correct choice.)","choices":[{"label":"A","text":"2100 Hz"},{"label":"B","text":"2030 Hz"},{"label":"C","text":"2130 Hz"},{"label":"D","text":"1720 Hz"},{"label":"E","text":"1630 Hz"}],"images":[],"answer":"B, D"},{"id":"Units_7-8-q272","source":"Units_7-8","sourceNumber":"272","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two speakers are mounted 4.52 m apart on a wall, and emit identical sound waves. You are standing at the opposite wall of the room at a point equally distant from the two speakers. You walk 2.11 m parallel to the wall to a location where you first notice that the sound intensity is essentially zero. If the wall along which you are walking is 10.7 m from the wall with the speakers, what is the wavelength of the sound waves? The walls are cushioned to absorb sound reflections.","choices":[{"label":"A","text":"1.71 m"},{"label":"B","text":"2.91 m"},{"label":"C","text":"2.57 m"},{"label":"D","text":"2.05 m"}],"images":[],"answer":"A"},{"id":"Units_7-8-q273","source":"Units_7-8","sourceNumber":"273","topic":"Unit 7: Oscillations","difficulty":"Medium","question":"Two speakers are placed side-by-side and driven by the same electrical oscillation at a frequency of 0.50 kHz. If the distance from a person to one speaker is 5.0 m and the person detects little or no sound, which of the following is a possible distance from the person to the other speaker? The speed of sound in the room is 340 m/s.","choices":[{"label":"A","text":"8.1 m"},{"label":"B","text":"9.1 m"},{"label":"C","text":"8.4 m"},{"label":"D","text":"7.7 m"}],"images":[],"answer":"A"},{"id":"Units_7-8-q277","source":"Units_7-8","sourceNumber":"277","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Two barrels, A and B, each contain the same volume of water at the same temperature, as shown in the diagram. Which statement best describes the pressures at the bottom of the barrels?","choices":[{"label":"A","text":"P A < P B since the pressure of the water depends upon the amount of atmosphere above the water."},{"label":"B","text":"P A > P B since the pressure of the water depends upon the water's depth."},{"label":"C","text":"P A = P B since the pressure of the water depends upon the volume of water."},{"label":"D","text":"Not enough information given."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"337","height":"144"}],"answer":"B"},{"id":"Units_7-8-q278","source":"Units_7-8","sourceNumber":"278","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A sailboat at rest on a very small calm lake has its anchor hanging a certain distance below the surface of the water, not touching the bottom. A rope of negligible mass and volume suspends the anchor. The surface of the water is a distance h above the bottom of the lake. Suppose the anchor is lifted back into the boat so that the surface of the water is then a distance h ' from the bottom of the lake. How does h ' compare to h ?","choices":[{"label":"A","text":"h ' = h"},{"label":"B","text":"h ' > h"},{"label":"C","text":"h ' < h"},{"label":"D","text":"h' may be greater than, less than or equal to h , depending on the density of the anchor"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"205","height":"198"}],"answer":"B"},{"id":"Units_7-8-q279","source":"Units_7-8","sourceNumber":"279","topic":"Unit 8: Fluids","difficulty":"Medium","question":"You are originally 2 m beneath the surface of a pool. If you dive to a depth of 4 m beneath the surface, the gauge water pressure:","choices":[{"label":"A","text":"increases, but less than doubles."},{"label":"B","text":"quadruples."},{"label":"C","text":"more than quadruples."},{"label":"D","text":"more than doubles, but less than quadruples."},{"label":"E","text":"doubles."}],"images":[],"answer":"E"},{"id":"Units_7-8-q280","source":"Units_7-8","sourceNumber":"280","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Two identical wooden blocks are in identical containers that are holding equal amounts of water. Each of the containers is resting on a platform scale. Block 1 is floating on top of the water, while Block 2 is tethered to the bottom of the container by a string of negligible mass. How does the reading on Scale 1 compare to the reading on Scale 2?","choices":[{"label":"A","text":"The reading on Scale 1 is greater than the reading on Scale 2."},{"label":"B","text":"The reading on Scale 1 may be greater than, less than or equal to the reading on Scale 2, depending on the density of the wooden blocks."},{"label":"C","text":"The reading on Scale 2 is greater than the reading on Scale 1."},{"label":"D","text":"The reading on Scale 1 is equal to the reading on Scale 2."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"443","height":"203"}],"answer":"D"},{"id":"Units_7-8-q281","source":"Units_7-8","sourceNumber":"281","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Three identical blocks of wood are tethered to the bottom of a tank of water by strings, as shown above. The blocks of wood are placed in three different orientations, X , Y , and Z . Which of the following correctly compares the buoyant force exerted on each of the blocks of wood?","choices":[{"label":"A","text":"F BX = F BY = F BZ"},{"label":"B","text":"F BX > F BY > F BZ ,"},{"label":"C","text":"F BX = F BY > F BZ , and"},{"label":"D","text":"F BZ > F BY > F BX ,"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"323","height":"160"}],"answer":"D"},{"id":"Units_7-8-q282","source":"Units_7-8","sourceNumber":"282","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Two identical wooden blocks are in identical containers that are holding equal amounts of water. Each of the containers is resting on a platform scale. Block 1 is floating on top of the water, while Block 2 is pushed down by a person's finger so that its top surface is level with the surface of the water. How does the reading on Scale 2 compare to Scale 1?","choices":[{"label":"A","text":"The reading on Scale 2 may be greater than, less than or equal to the reading on Scale 1, depending on the density of the wooden blocks."},{"label":"B","text":"The reading on Scale 2 is greater than the reading on Scale 1."},{"label":"C","text":"The reading on Scale 2 is less than the reading on Scale 1."},{"label":"D","text":"The reading on Scale 2 is equal to the reading on Scale 1."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"276","height":"263"}],"answer":"B"},{"id":"Units_7-8-q285","source":"Units_7-8","sourceNumber":"285","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A wooden sphere has a volume 0.2 m 3 . A downward force of 100 N is needed in order to hold the sphere completely submerged in water, 1.0 m below the surface. What magnitude of downward force is needed in order to hold the sphere completely submerged in water 2.0 m below the surface? Select all that apply.","choices":[{"label":"A","text":"Less than 100 N, because more water is above the sphere pushing downwards."},{"label":"B","text":"More than 100 N, because the density of water is greater at a greater depth."},{"label":"C","text":"Precisely 100 N, because the volume of the sphere does not change."},{"label":"D","text":"More than 100 N, because the pressure is greater at a greater depth."},{"label":"E","text":"Less than 100 N, because the gravitational force exerted on the sphere decreases."}],"images":[],"answer":"C, E"},{"id":"Units_7-8-q287","source":"Units_7-8","sourceNumber":"287","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Two containers are each filled to the same height with the same fluid of uniform density. When compared to the quantities as they are on the base of container I, what would be the pressure and force on the base of container II? Pressure Force","choices":[{"label":"A","text":"Equal less"},{"label":"B","text":"equal greater"},{"label":"C","text":"greater equal"},{"label":"D","text":"greater less"},{"label":"E","text":"less less"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"242","height":"127"}],"answer":"A"},{"id":"Units_7-8-q288","source":"Units_7-8","sourceNumber":"288","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A metal block is slowly lowered into two separate containers of fluid. The graph above shows the buoyant force that the fluids exert on the block in both cases, as it is completely submerged. Which of the following is true about the two fluids? Select all that apply.","choices":[{"label":"A","text":"The block must have been submerged in fluid 1 during a shorter time interval than fluid 2."},{"label":"B","text":"Fluid 2 must have a greater density than fluid 1."},{"label":"C","text":"Fluid 1 must have a greater density than fluid 2."},{"label":"D","text":"The block must have been submerged in fluid 2 during a shorter time interval than fluid 1."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"356","height":"316"}],"answer":"C"},{"id":"Units_7-8-q289","source":"Units_7-8","sourceNumber":"289","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Salt water is denser than fresh water. Identical ships float in both fresh water and salt water. How does the buoyant force exerted on the ship floating in fresh water compare to the buoyant force exerted on the ship floating in salt water?","choices":[{"label":"A","text":"The buoyant forces on both ships are equal in magnitude, because both ships displace the same amount of water."},{"label":"B","text":"The buoyant forces exerted on both ships are equal in magnitude, because the gravitational forces exerted on both ships are equal."},{"label":"C","text":"The buoyant force exerted on the ship in salt water is greater, because salt water exerts a greater buoyant force for the same amount of water displaced."},{"label":"D","text":"The buoyant force exerted on the ship in fresh water is greater, because the ship sinks deeper beneath the surface of the water."},{"label":"E","text":"The buoyant force exerted on the ship in salt water is greater, because the ship does not sink as deep beneath the surface of the water."}],"images":[],"answer":"B"},{"id":"Units_7-8-q290","source":"Units_7-8","sourceNumber":"290","topic":"Unit 8: Fluids","difficulty":"Medium","question":"As shown in the figure, fluid fills a container having several sections. At which of the indicated points is the pressure greatest?","choices":[{"label":"A","text":"A"},{"label":"B","text":"B"},{"label":"C","text":"C"},{"label":"D","text":"D"},{"label":"E","text":"The pressure is the same at each of the labeled points."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"385","height":"218"}],"answer":"E"},{"id":"Units_7-8-q291","source":"Units_7-8","sourceNumber":"291","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Consider a brick that is totally immersed in water, with the long edge of the brick oriented vertically. The pressure on the brick is","choices":[{"label":"A","text":"greatest on the top of the brick."},{"label":"B","text":"greatest on the sides of the brick."},{"label":"C","text":"the same on all surfaces of the brick."},{"label":"D","text":"greatest on the face with largest area."},{"label":"E","text":"greatest on the bottom of the brick."}],"images":[],"answer":"E"},{"id":"Units_7-8-q292","source":"Units_7-8","sourceNumber":"292","topic":"Unit 8: Fluids","difficulty":"Easy","question":"An air bubble underwater has the same pressure as that of the surrounding water. As the air bubble rises toward the surface (and its temperature remains constant), the volume of the air bubble","choices":[{"label":"A","text":"increases."},{"label":"B","text":"decreases."},{"label":"C","text":"remains constant."},{"label":"D","text":"increases or decreases, depending on the rate it rises."}],"images":[],"answer":"A"},{"id":"Units_7-8-q294","source":"Units_7-8","sourceNumber":"294","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A cubical block of stone is lowered at a steady rate into the ocean by a crane, always keeping the top and bottom faces horizontal. Which one of the following graphs best describes the absolute (total) pressure P on the bottom of this block as a function of time t if the block just enters the water at the instant we define as time t = 0 s?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"167","height":"152"},{"src":"data:image/jpeg;base64,","alt":"","width":"168","height":"152"},{"src":"data:image/jpeg;base64,","alt":"","width":"169","height":"142"},{"src":"data:image/jpeg;base64,","alt":"","width":"166","height":"151"},{"src":"data:image/jpeg;base64,","alt":"","width":"165","height":"154"}],"answer":"A"},{"id":"Units_7-8-q295","source":"Units_7-8","sourceNumber":"295","topic":"Unit 8: Fluids","difficulty":"Easy","question":"If atmospheric pressure increases by an amount Δ P , which of the following statements about the pressure in a lake is true? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The gauge pressure increases by Δ P ."},{"label":"B","text":"The absolute (total) pressure increases by Δ P ."},{"label":"C","text":"The absolute (total) pressure does not change."},{"label":"D","text":"The gauge pressure does not change."},{"label":"E","text":"The absolute (total) pressure increases, but by an amount less than Δ P ."}],"images":[],"answer":"B, D"},{"id":"Units_7-8-q296","source":"Units_7-8","sourceNumber":"296","topic":"Unit 8: Fluids","difficulty":"Easy","question":"A closed cubical chamber resting on the floor contains oil and a piston. If you push down on the piston hard enough to increase the pressure just below the piston by an amount Δ P , which of the following statements is correct? (There could be more than one correct choice.)","choices":[{"label":"A","text":"The pressure everywhere in the oil will increase by Δ P ."},{"label":"B","text":"The pressure at the top of the oil will increase by less than Δ P ."},{"label":"C","text":"The increase in the force exerted by the oil on the top of the chamber will be the same as the increase in the force on the bottom of the chamber."},{"label":"D","text":"The pressure at the bottom of the oil will increase by more than Δ P ."},{"label":"E","text":"The pressure on the sides of the chamber will not increase."}],"images":[],"answer":"A, C"},{"id":"Units_7-8-q297","source":"Units_7-8","sourceNumber":"297","topic":"Unit 8: Fluids","difficulty":"Easy","question":"The water pressure to an apartment is increased by the water company. The water enters the apartment through an entrance valve at the front of the apartment. Where will the increase in the water pressure be greatest when no water is flowing in the system?","choices":[{"label":"A","text":"It will be the same at all faucets."},{"label":"B","text":"At a faucet close to the entrance valve."},{"label":"C","text":"There will be no increase in the pressure at the faucets."},{"label":"D","text":"At a faucet far from the entrance valve."}],"images":[],"answer":"A"},{"id":"Units_7-8-q298","source":"Units_7-8","sourceNumber":"298","topic":"Unit 8: Fluids","difficulty":"Easy","question":"A waiter fills your water glass with ice water (containing many ice cubes) such that the liquid water is perfectly level with the rim of the glass. As the ice melts,","choices":[{"label":"A","text":"the liquid-water level rises, causing water to run down the outside of the glass."},{"label":"B","text":"the liquid-water level remains level with the rim of the glass."},{"label":"C","text":"the liquid-water level decreases."}],"images":[],"answer":"B"},{"id":"Units_7-8-q299","source":"Units_7-8","sourceNumber":"299","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A spherical ball of lead (density 11.3 g/cm 3 ) is placed in a tub of mercury (density 13.6 g/cm 3 ). Which answer best describes the result?","choices":[{"label":"A","text":"The lead ball will float with its top precisely even with the surface of the mercury."},{"label":"B","text":"The lead will sink to the bottom of the mercury."},{"label":"C","text":"The lead ball will float with about 17% of its volume above the surface of the mercury."},{"label":"D","text":"The lead ball will float with about 83% of its volume above the surface of the mercury."}],"images":[],"answer":"C"},{"id":"Units_7-8-q300","source":"Units_7-8","sourceNumber":"300","topic":"Unit 8: Fluids","difficulty":"Easy","question":"A wooden block contains some nails so that its density is precisely equal to that of water. If it is placed in a tank of water and released from rest when it is completely submerged, it will","choices":[{"label":"A","text":"rise to the surface."},{"label":"B","text":"sink to the bottom."},{"label":"C","text":"remain where it is released."}],"images":[],"answer":"C"},{"id":"Units_7-8-q301","source":"Units_7-8","sourceNumber":"301","topic":"Unit 8: Fluids","difficulty":"Easy","question":"A boat loaded with rocks is floating in a swimming pool. If the rocks are thrown into the pool, the water level in the pool, after the rocks have settled to the bottom,","choices":[{"label":"A","text":"falls."},{"label":"B","text":"rises."},{"label":"C","text":"stays the same."}],"images":[],"answer":"A"},{"id":"Units_7-8-q302","source":"Units_7-8","sourceNumber":"302","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Salt water has greater density than fresh water. A boat floats in both fresh water and in salt water. Where is the buoyant force greater on the boat?","choices":[{"label":"A","text":"in fresh water"},{"label":"B","text":"in salt water"},{"label":"C","text":"The buoyant force is the same in both cases."}],"images":[],"answer":"C"},{"id":"Units_7-8-q303","source":"Units_7-8","sourceNumber":"303","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Salt water is denser than fresh water. A ship floats in both fresh water and salt water. Compared to the fresh water, the volume of water displaced in the salt water is","choices":[{"label":"A","text":"less."},{"label":"B","text":"the same."},{"label":"C","text":"more."},{"label":"D","text":"Cannot be determined because we do not know the volume of the ship."}],"images":[],"answer":"A"},{"id":"Units_7-8-q304","source":"Units_7-8","sourceNumber":"304","topic":"Unit 8: Fluids","difficulty":"Easy","question":"A steel ball sinks in water but floats in a pool of mercury, which is much denser than water. Where is the buoyant force exerted on the ball greater?","choices":[{"label":"A","text":"submerged in the water"},{"label":"B","text":"floating on the mercury"},{"label":"C","text":"It is the same in both cases."},{"label":"D","text":"It cannot be determined from the information given."}],"images":[],"answer":"B"},{"id":"Units_7-8-q305","source":"Units_7-8","sourceNumber":"305","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 10-kg piece of aluminum sits at the bottom of a lake, right next to a 10-kg piece of lead, which is much denser than aluminum. Which one has the greater buoyant force exerted on it?","choices":[{"label":"A","text":"the lead"},{"label":"B","text":"Both have the same buoyant force."},{"label":"C","text":"the aluminum"},{"label":"D","text":"It cannot be determined without knowing their volumes."}],"images":[],"answer":"C"},{"id":"Units_7-8-q306","source":"Units_7-8","sourceNumber":"306","topic":"Unit 8: Fluids","difficulty":"Easy","question":"A piece of iron rests on top of a piece of wood floating in a bathtub. If the iron is removed from the wood, and kept out of the water, what happens to the water level in the tub?","choices":[{"label":"A","text":"It goes down."},{"label":"B","text":"It goes up."},{"label":"C","text":"It does not change."},{"label":"D","text":"It is impossible to determine from the information given."}],"images":[],"answer":"A"},{"id":"Units_7-8-q307","source":"Units_7-8","sourceNumber":"307","topic":"Unit 8: Fluids","difficulty":"Easy","question":"A piece of wood is floating in a bathtub. A second piece of wood sits on top of the first piece, and does not touch the water. If the top piece is taken off and placed in the water, what happens to the water level in the tub?","choices":[{"label":"A","text":"It goes down."},{"label":"B","text":"It goes up."},{"label":"C","text":"It does not change."},{"label":"D","text":"It cannot be determined without knowing the volumes of the two pieces of wood."}],"images":[],"answer":"C"},{"id":"Units_7-8-q308","source":"Units_7-8","sourceNumber":"308","topic":"Unit 8: Fluids","difficulty":"Easy","question":"As a rock sinks deeper and deeper into water of constant density, what happens to the buoyant force on it if it started above the surface of the water?","choices":[{"label":"A","text":"The buoyant force remains constant."},{"label":"B","text":"The buoyant force first increases and then remains constant."},{"label":"C","text":"The buoyant force steadily decreases."},{"label":"D","text":"The buoyant force keeps increasing steadily."}],"images":[],"answer":"B"},{"id":"Units_7-8-q309","source":"Units_7-8","sourceNumber":"309","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A cubical block of stone is lowered at a steady rate into the ocean by a crane, always keeping the top and bottom faces horizontal. Which one of the following graphs best describes the buoyant force B on this block as a function of time t if the block just enters the water at the instant we define as time t = 0 s?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"168","height":"144"},{"src":"data:image/jpeg;base64,","alt":"","width":"167","height":"143"},{"src":"data:image/jpeg;base64,","alt":"","width":"166","height":"144"},{"src":"data:image/jpeg;base64,","alt":"","width":"168","height":"144"},{"src":"data:image/jpeg;base64,","alt":"","width":"166","height":"144"}],"answer":"C"},{"id":"Units_7-8-q310","source":"Units_7-8","sourceNumber":"310","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 50-cm 3 block of wood is floating on water, and a 50-cm 3 chunk of iron is totally submerged in the water. Which one has the greater buoyant force exerted on it?","choices":[{"label":"A","text":"Both have the same buoyant force."},{"label":"B","text":"the wood"},{"label":"C","text":"the iron"},{"label":"D","text":"It cannot be determined without knowing their densities."}],"images":[],"answer":"C"},{"id":"Units_7-8-q311","source":"Units_7-8","sourceNumber":"311","topic":"Unit 8: Fluids","difficulty":"Hard","question":"The column of mercury in a closed-tube mercury barometer has a height of 760 mm when the instrument is placed in a room at 1 atmosphere (101,300 Pa) of pressure. If mercury has a density of 13,600 kg/m 3 , how tall would the barometer need to be if the liquid used inside it were honey (density 1400 kg/m 3 )?","choices":[{"label":"A","text":"78 mm,"},{"label":"B","text":"78 m, and"},{"label":"C","text":"7400 m"},{"label":"D","text":"7.4 m,"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"185","height":"270"}],"answer":"D"},{"id":"Units_7-8-q312","source":"Units_7-8","sourceNumber":"312","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A block of wood floating on water has mass 5.00 kg and volume 2.5 × 10 -2 m 3 . What is the magnitude of the force that must be exerted on the block to hold it completely submerged in water? The density of water is 1.00 × 10 3 kg/m 3 .","choices":[{"label":"A","text":"25 N,"},{"label":"B","text":"200 N, and"},{"label":"C","text":"30 N,"},{"label":"D","text":"20 N,"},{"label":"E","text":"250 N"}],"images":[],"answer":"B"},{"id":"Units_7-8-q313","source":"Units_7-8","sourceNumber":"313","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A water tank is filled to a depth of 10 m, and the bottom of the tank is 20 m above ground. A water-filled hose that is 2.0 cm in diameter extends from the bottom of the tank to the ground, but no water is flowing in this hose. The absolute water pressure at ground level in the hose is closest to which of the following values? The density of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"3.9 × 10 5 N/m 2"},{"label":"B","text":"9.2 N/m 2"},{"label":"C","text":"2.0 × 10 4 N/m 2"},{"label":"D","text":"The question cannot be answered because the cross-sectional area of the tank is needed."}],"images":[],"answer":"C"},{"id":"Units_7-8-q314","source":"Units_7-8","sourceNumber":"314","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The Aswan High Dam on the Nile River in Egypt is 111 m high. What is the gauge pressure in the water at the foot of the dam? The density of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"1.11 × 10 2 Pa"},{"label":"B","text":"1.09 × 10 6 Pa"},{"label":"C","text":"1.16 × 10 6 Pa"},{"label":"D","text":"1.11 × 10 5 Pa"},{"label":"E","text":"1.09 × 10 3 Pa"}],"images":[],"answer":"B"},{"id":"Units_7-8-q315","source":"Units_7-8","sourceNumber":"315","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The deepest point of the Pacific Ocean is 11,033 m, in the Mariana Trench. What is the gauge pressure in the water at that point? Take the density of seawater, modeled as incompressible, as 1025 kg/m 3 .","choices":[{"label":"A","text":"5.55 × 10 7 Pa"},{"label":"B","text":"8.88 × 10 7 Pa"},{"label":"C","text":"2.22 × 10 8 Pa"},{"label":"D","text":"1.11 × 10 8 Pa"},{"label":"E","text":"3.33 × 10 8 Pa"}],"images":[],"answer":"E"},{"id":"Units_7-8-q316","source":"Units_7-8","sourceNumber":"316","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The Tonga Trench in the Pacific Ocean is 36,000 feet deep. Assuming that sea water has an average density of 1.04 g/cm 3 , calculate the absolute (total) pressure at the bottom of the trench in atmospheres. (1.00 in = 2.54 cm, 1.00 atm = 1.01 × 10 5 Pa)","choices":[{"label":"A","text":"1.1 × 10 8 atm"},{"label":"B","text":"2.1 atm"},{"label":"C","text":"1.1 × 10 3 atm"},{"label":"D","text":"1.1 × 10 5 atm"},{"label":"E","text":"1.1 × 10 6 atm"}],"images":[],"answer":"E"},{"id":"Units_7-8-q317","source":"Units_7-8","sourceNumber":"317","topic":"Unit 8: Fluids","difficulty":"Medium","question":"What force does the water exert (in addition to that due to atmospheric pressure) on a submarine window of radius 44.0 cm at a depth of 9400 m in sea water? The density of sea water is 1025 kg/m 3 .","choices":[{"label":"A","text":"1.83 × 10 7 N"},{"label":"B","text":"2.87 × 10 11 N"},{"label":"C","text":"5.74 × 10 7 N"},{"label":"D","text":"2.87 × 10 7 N"},{"label":"E","text":"5.74 × 10 11 N"}],"images":[],"answer":"D"},{"id":"Units_7-8-q318","source":"Units_7-8","sourceNumber":"318","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A cubical box 25.0 cm on each side is immersed in a fluid. The pressure at the top surface of the box is 109.40 kPa and the pressure on the bottom surface is 112.00 kPa. What is the density of the fluid?","choices":[{"label":"A","text":"1030 kg/m 3"},{"label":"B","text":"1120 kg/m 3"},{"label":"C","text":"1060 kg/m 3"},{"label":"D","text":"1000 kg/m 3"},{"label":"E","text":"1090 kg/m 3"}],"images":[],"answer":"E"},{"id":"Units_7-8-q319","source":"Units_7-8","sourceNumber":"319","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A circular window 30 cm in diameter in a submarine can withstand a maximum force, exerted by the fluids surrounding it, of 5.20 × 10 5 N without damage. What is the maximum depth in a fresh-water lake to which the submarine, containing air at atmospheric pressure, can go without damaging the window? The density of fresh water is 1000 kg/m 3 .","choices":[{"label":"A","text":"750 m"},{"label":"B","text":"680 m"},{"label":"C","text":"1200 m"},{"label":"D","text":"740 m"}],"images":[],"answer":"A"},{"id":"Units_7-8-q320","source":"Units_7-8","sourceNumber":"320","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A container has a vertical tube, whose inner radius is 24.00 mm, connected to it at its side, as shown in the figure. An unknown liquid reaches level A in the container and level B in the tube—level A being 5.0 cm higher than level B. The liquid supports a 20-cm high column of oil, between levels B and C, whose density is 570 kg/m 3 . The mass of the oil is closest to","choices":[{"label":"A","text":"620 g"},{"label":"B","text":"410 g"},{"label":"C","text":"210 g"},{"label":"D","text":"820 g"},{"label":"E","text":"1000 g"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"259","height":"144"}],"answer":"C"},{"id":"Units_7-8-q321","source":"Units_7-8","sourceNumber":"321","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A container has a vertical tube, whose inner radius is 12.00 mm, connected to it at its side, as shown in the figure. An unknown liquid reaches level A in the container and level B in the tube—level A being 5.0 cm higher than level B. The liquid supports a 20-cm high column of oil, between levels B and C, whose density is 320 kg/m 3 . The gauge pressure at level B is closest to","choices":[{"label":"A","text":"470 Pa"},{"label":"B","text":"940 Pa"},{"label":"C","text":"310 Pa"},{"label":"D","text":"790 Pa"},{"label":"E","text":"630 Pa"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"259","height":"144"}],"answer":"E"},{"id":"Units_7-8-q322","source":"Units_7-8","sourceNumber":"322","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A container has a vertical tube, whose inner radius is 20.00 mm, connected to it at its side, as shown in the figure. An unknown liquid reaches level A in the container and level B in the tube—level A being 5.0 cm higher than level B. The liquid supports a 20-cm high column of oil, between levels B and C, whose density is 900 kg/m 3 . The density of the unknown liquid is closest to","choices":[{"label":"A","text":"3600 kg/m 3"},{"label":"B","text":"3100 kg/m 3"},{"label":"C","text":"3900 kg/m 3"},{"label":"D","text":"3300 kg/m 3"},{"label":"E","text":"2800 kg/m 3"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"259","height":"144"}],"answer":"E"},{"id":"Units_7-8-q325","source":"Units_7-8","sourceNumber":"325","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 1,220-kg car is raised using a hydraulic lift, which consists of a U-tube with arms of unequal areas, filled with oil and capped at both ends with tight-fitting pistons. The wider arm of the U-tube has a radius of 18.0 cm and the narrower arm has a radius of 5.00 cm. The car rests on the piston on the wider arm of the U-tube. The pistons are initially at the same level. What is the initial force that must be applied to the smaller piston in order to start lifting the car? For purposes of this problem, neglect the mass of the pistons.","choices":[{"label":"A","text":"3.33 kN"},{"label":"B","text":"926 N"},{"label":"C","text":"1.20 kN"},{"label":"D","text":"2.90 kN"},{"label":"E","text":"727 N"}],"images":[],"answer":"B"},{"id":"Units_7-8-q326","source":"Units_7-8","sourceNumber":"326","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 12,000-N car is raised using a hydraulic lift, which consists of a U-tube with arms of unequal areas, filled with oil with a density of 800 kg/m 3 and capped at both ends with tight-fitting pistons. The wider arm of the U-tube has a radius of 18.0 cm and the narrower arm has a radius of 5.00 cm. The car rests on the piston on the wider arm of the U-tube. The pistons are initially at the same level. What is the force that must be applied to the smaller piston in order to lift the car after it has been raised 1.20 m? For purposes of this problem, neglect the mass of the pistons.","choices":[{"label":"A","text":"1.96 kN"},{"label":"B","text":"1.88 kN"},{"label":"C","text":"1.20 kN"},{"label":"D","text":"3.67 kN"},{"label":"E","text":"0.954 kN"}],"images":[],"answer":"A"},{"id":"Units_7-8-q327","source":"Units_7-8","sourceNumber":"327","topic":"Unit 8: Fluids","difficulty":"Medium","question":"In a hydraulic garage lift, the small piston has a radius of 5.0 cm and the large piston has a radius of 15 cm. What force must be applied on the small piston in order to lift a 2040 kg car on the large piston? Assume the pistons each have negligible mass.","choices":[{"label":"A","text":"2.9 × 10 3 N"},{"label":"B","text":"6.7 × 10 3 N"},{"label":"C","text":"5.0 × 10 3 N"},{"label":"D","text":"2.2 × 10 3 N"}],"images":[],"answer":"B"},{"id":"Units_7-8-q328","source":"Units_7-8","sourceNumber":"328","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 1327-kg vehicle is to be lifted by a 25-cm diameter hydraulic piston. What force needs to be applied to a 5.0-cm diameter piston to accomplish this? Assume the pistons each have negligible mass.","choices":[{"label":"A","text":"2600 N"},{"label":"B","text":"520 N"},{"label":"C","text":"5200 N"},{"label":"D","text":"260 N"}],"images":[],"answer":"B"},{"id":"Units_7-8-q330","source":"Units_7-8","sourceNumber":"330","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The upward force required to hold a block of metal at rest is 40 N in air and 30 N in water. What is the buoyant force on the block due to the water? The density of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"30 N up"},{"label":"B","text":"10 N up"},{"label":"C","text":"70 N up"},{"label":"D","text":"40 N up"}],"images":[],"answer":"B"},{"id":"Units_7-8-q331","source":"Units_7-8","sourceNumber":"331","topic":"Unit 8: Fluids","difficulty":"Medium","question":"If a ship has a mass of 10 million kilograms, what volume of fresh water must it displace in order to float? The density of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"10 7 m 3"},{"label":"B","text":"10 10 m 3"},{"label":"C","text":"10 4 m 3"},{"label":"D","text":"10 12 m 3"},{"label":"E","text":"10 8 m 3"}],"images":[],"answer":"B"},{"id":"Units_7-8-q332","source":"Units_7-8","sourceNumber":"332","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 4.0-kg cylinder of solid iron is supported by a string while submerged in water. What is the tension in the string? The density of iron is 7860 kg/m 3 and that of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"24 N"},{"label":"B","text":"40 N"},{"label":"C","text":"2.5 N"},{"label":"D","text":"34 N"},{"label":"E","text":"20 N"}],"images":[],"answer":"D"},{"id":"Units_7-8-q333","source":"Units_7-8","sourceNumber":"333","topic":"Unit 8: Fluids","difficulty":"Medium","question":"What buoyant force does a 0.60-kg solid gold crown experience when it is immersed in water? The density of gold is 19.3 × 10 3 kg/m 3 and that of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"3.0 × 10 -4 N up"},{"label":"B","text":"0.30 N up"},{"label":"C","text":"3.0 × 10 -5 N up"},{"label":"D","text":"3.0 × 10 -2 N up"}],"images":[],"answer":"B"},{"id":"Units_7-8-q334","source":"Units_7-8","sourceNumber":"334","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A crane lifts a submerged steel casting of density 7800 kg/m 3 and mass 20,000 kg. What is the tension in the lifting cable (a) when the casting is surrounded by water of density 1000 kg/m 3 , and (b) when it is entirely out of the water?","choices":[{"label":"A","text":"(a) 2.6 × 10 3 N (b) 2.0 × 10 5 N"},{"label":"B","text":"(a) 1.7 × 10 5 N (b) 2.0 × 10 5 N"},{"label":"C","text":"(a) 2.0 × 10 5 N (b) 2.6 × 10 3 N"},{"label":"D","text":"(a) 2.0 × 10 5 N (b) 1.7 × 10 5 N"}],"images":[],"answer":"B"},{"id":"Units_7-8-q335","source":"Units_7-8","sourceNumber":"335","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The upward force required to hold an object at rest is 7.84 N when it is in air and 6.86 N when it is immersed in water of density 1000 kg/m 3 . What is the density of the object?","choices":[{"label":"A","text":"7000 kg/m 3"},{"label":"B","text":"8000 kg/m 3"},{"label":"C","text":"9000 kg/m 3"},{"label":"D","text":"6000 kg/m 3"}],"images":[],"answer":"B"},{"id":"Units_7-8-q336","source":"Units_7-8","sourceNumber":"336","topic":"Unit 8: Fluids","difficulty":"Medium","question":"When a container of water is placed on a laboratory scale, the scale reads 120 g. Now a 20-g piece of copper (of density 8.9 g/cm 3 ) is suspended from a thread and lowered into the water, not touching the bottom of the container. What will the scale now read? The density of water is 1.0 g/cm 3 .","choices":[{"label":"A","text":"140 g"},{"label":"B","text":"122 g"},{"label":"C","text":"138 g"},{"label":"D","text":"120 g"}],"images":[],"answer":"B"},{"id":"Units_7-8-q338","source":"Units_7-8","sourceNumber":"338","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A cylindrical rod of length 12 cm and diameter 2.0 cm will just barely float in water of density 1000 kg/m 3 . What is its mass?","choices":[{"label":"A","text":"300 g"},{"label":"B","text":"38 g"},{"label":"C","text":"150 g"},{"label":"D","text":"75 g"}],"images":[],"answer":"B"},{"id":"Units_7-8-q339","source":"Units_7-8","sourceNumber":"339","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A rectangular box of negligible mass measures 5.0 m long, 1.0 m wide, and 0.50 m high. How many kilograms of mass can be loaded onto the box before it sinks in a lake having water of density 1000 kg/m 3 ?","choices":[{"label":"A","text":"3.5 × 10 3 kg"},{"label":"B","text":"2.5 × 10 3 kg"},{"label":"C","text":"0.50 × 10 3 kg"},{"label":"D","text":"1.5 × 10 3 kg"}],"images":[],"answer":"C"},{"id":"Units_7-8-q340","source":"Units_7-8","sourceNumber":"340","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 1.00-m 3 object floats in water with 20.0% of its volume above the waterline. What is the gravitational force exerted on the object? The density of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"1960 N up"},{"label":"B","text":"9800 N down"},{"label":"C","text":"11,800 N down"},{"label":"D","text":"7840 N down"}],"images":[],"answer":"D"},{"id":"Units_7-8-q341","source":"Units_7-8","sourceNumber":"341","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A solid object floats in water with three-fourths of its volume beneath the surface. What is the object's density? The density of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"750 kg/m 3"},{"label":"B","text":"250 kg/m 3"},{"label":"C","text":"1000 kg/m 3"},{"label":"D","text":"1333 kg/m 3"}],"images":[],"answer":"C"},{"id":"Units_7-8-q342","source":"Units_7-8","sourceNumber":"342","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 20.4-kg object floats with three-fourths of its volume beneath the surface of the water. What is the buoyant force on the object? The density of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"50 N down"},{"label":"B","text":"200 N up"},{"label":"C","text":"267 N up"},{"label":"D","text":"150 N up"},{"label":"E","text":"It cannot be determined because we do not know the volume of the object."}],"images":[],"answer":"B"},{"id":"Units_7-8-q343","source":"Units_7-8","sourceNumber":"343","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A polar bear of mass 200 kg stands on an ice floe that is a uniform 1.0 m thick. What is the minimum area of the floe that will just support the bear in saltwater of density 1030 kg/m 3 ? The density of ice is 980 kg/m 3 .","choices":[{"label":"A","text":"2.0 m 2"},{"label":"B","text":"3.0 m 2"},{"label":"C","text":"1.0 m 2"},{"label":"D","text":"4.0 m 2"}],"images":[],"answer":"C"},{"id":"Units_7-8-q345","source":"Units_7-8","sourceNumber":"345","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A hollow steel ball of diameter 3.0 m just barely floats in water. What is the wall thickness of the ball? ( p Fe = 7.87 g/cm 3 , ρ water = 1.00 g/cm 3 )","choices":[{"label":"A","text":"79 cm"},{"label":"B","text":"6.6 cm"},{"label":"C","text":"131 cm"},{"label":"D","text":"37 cm"}],"images":[],"answer":"B"},{"id":"Units_7-8-q346","source":"Units_7-8","sourceNumber":"346","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 200-kg flat-bottomed boat floats in fresh water, which has a density of 1000 kg/m 3 . If the base of the boat is 1.42 m wide and 4.53 m long, to what depth is the bottom of the boat submerged when it carries three passengers whose total mass is 257 kg?","choices":[{"label":"A","text":"8.52 cm"},{"label":"B","text":"7.53 cm"},{"label":"C","text":"7.95 cm"},{"label":"D","text":"7.10 cm"}],"images":[],"answer":"D"},{"id":"Units_7-8-q347","source":"Units_7-8","sourceNumber":"347","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A 4.7-kg solid sphere, made of metal whose density is 4000 kg/m 3 , hangs by a light cord. When the sphere is immersed in water, what is the tension in the cord? The density of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"35 N"},{"label":"B","text":"46 N"},{"label":"C","text":"40 N"},{"label":"D","text":"52 N"},{"label":"E","text":"58 N"}],"images":[],"answer":"A"},{"id":"Units_7-8-q348","source":"Units_7-8","sourceNumber":"348","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A solid sphere of mass 8.6 kg, made of metal whose density is 3400 kg/m 3 , hangs by a cord. When the sphere is immersed in a liquid of unknown density, the tension in the cord is 38 N. The density of the liquid is closest to which one of the following values?","choices":[{"label":"A","text":"1700 kg/m 3"},{"label":"B","text":"1900 kg/m 3"},{"label":"C","text":"1500 kg/m 3"},{"label":"D","text":"1600 kg/m 3"},{"label":"E","text":"1400 kg/m 3"}],"images":[],"answer":"D"},{"id":"Units_7-8-q349","source":"Units_7-8","sourceNumber":"349","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A barge is 10 m wide and 60 m long and has vertical sides. The bottom of the boat is 1.2 m below the water surface. What is the total gravitational force exerted on the barge and its cargo, if it is floating in fresh water of density 1000 kg/m 3 ?","choices":[{"label":"A","text":"3.5 MN down"},{"label":"B","text":"9.5 MN down"},{"label":"C","text":"6.8 MN down"},{"label":"D","text":"7.1 MN down"},{"label":"E","text":"6.4 MN down"}],"images":[],"answer":"D"},{"id":"Units_7-8-q350","source":"Units_7-8","sourceNumber":"350","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A barge with vertical sides is 10 m wide and 60 m long and is floating in fresh water of density 1000 kg/m 3 . How much deeper into the water does the barge sink when 3.0 × 10 5 kg of coal are loaded on the barge?","choices":[{"label":"A","text":"1.0 m"},{"label":"B","text":"1.5 m"},{"label":"C","text":"75 cm"},{"label":"D","text":"25 cm"},{"label":"E","text":"50 cm"}],"images":[],"answer":"E"},{"id":"Units_7-8-q351","source":"Units_7-8","sourceNumber":"351","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The envelope of a hot air balloon along with its cargo has a mass of 4.0 × 10 5 kg, and it holds 7.0 × 10 5 m 3 of hot air. It is floating at a constant height in air with a density of 1.29 kg/m 3 . What is the density of the hot air in the balloon?","choices":[{"label":"A","text":"0.57 kg/m 3"},{"label":"B","text":"1.4 kg/m 3"},{"label":"C","text":"0.43 kg/m 3"},{"label":"D","text":"0.72 kg/m 3"},{"label":"E","text":"0.86 kg/m 3"}],"images":[],"answer":"A"},{"id":"Units_7-8-q352","source":"Units_7-8","sourceNumber":"352","topic":"Unit 8: Fluids","difficulty":"Medium","question":"The bathyscaphe Trieste consists of a thin-walled but very strong cylindrical hull, 15.2 m long and 3.66 m in diameter, filled with gasoline with a density of 880 kg/m 3 . If it is totally submerged in seawater with a density of 1025 kg/m 3 and neither rising nor sinking, what is the total gravitational force exerted on the hull of the Trieste craft?","choices":[{"label":"A","text":"427 kN down"},{"label":"B","text":"227 kN down"},{"label":"C","text":"327 kN down"},{"label":"D","text":"527 kN down"},{"label":"E","text":"127 kN down"}],"images":[],"answer":"B"},{"id":"Units_7-8-q353","source":"Units_7-8","sourceNumber":"353","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A cylinder, semicircular in cross section, is 10 m long and 5.0 m in radius. It is completely submerged, with its flat bottom side horizontal and 8.0 m below the water surface, as shown in the figure. What is the magnitude of the total force exerted on the curved upper surface of the half-cylinder? Neglect atmospheric pressure.","choices":[{"label":"A","text":"3.5 × 10 6 N down"},{"label":"B","text":"4.0 × 10 6 N down"},{"label":"C","text":"3.0 × 10 6 N down"},{"label":"D","text":"2.5 × 10 6 N down"},{"label":"E","text":"2.0 × 10 6 N down"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"209","height":"162"}],"answer":"B"},{"id":"Units_7-8-q354","source":"Units_7-8","sourceNumber":"354","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A rectangular wooden block measures 10.0 cm × 4.00 cm × 2.00 cm. When the block is placed in water, it floats horizontally, with its bottom face 1.65 cm below the surface. What is the density of the wood? The density of water is 1.00 g/cm 3 .","choices":[{"label":"A","text":"0.825 g/cm 3"},{"label":"B","text":"0.606 g/cm 3"},{"label":"C","text":"1.65 g/cm 3"},{"label":"D","text":"1.21 g/cm 3"},{"label":"E","text":"0.350 g/cm 3"}],"images":[],"answer":"E"},{"id":"Units_7-8-q360","source":"Units_7-8","sourceNumber":"360","topic":"Unit 8: Fluids","difficulty":"Easy","question":"When you blow some air above a paper strip, the paper rises. This happens because","choices":[{"label":"A","text":"the air above the paper moves faster and the pressure is higher."},{"label":"B","text":"the air above the paper moves slower and the pressure is higher."},{"label":"C","text":"the air above the paper moves faster and the pressure is lower."},{"label":"D","text":"the air above the paper moves faster and the pressure remains constant."},{"label":"E","text":"the air above the paper moves slower and the pressure is lower."}],"images":[],"answer":"C"},{"id":"Units_7-8-q361","source":"Units_7-8","sourceNumber":"361","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A straight section of vertical pipe has a constant diameter, and water is flowing upward through it as shown above. How does the fluid pressure at point A compare the pressure at point B?","choices":[{"label":"A","text":"P A < P B"},{"label":"B","text":"P A > P B"},{"label":"C","text":"P A = P B"},{"label":"D","text":"Not enough information to determine."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"99","height":"169"}],"answer":"B"},{"id":"Units_7-8-q362","source":"Units_7-8","sourceNumber":"362","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A straight section of horizontal pipe has a constant diameter, and nonviscous water is flowing through it as shown above. How does the fluid pressure at point A compare the pressure at point B?","choices":[{"label":"A","text":"P A = P B"},{"label":"B","text":"P A > P B"},{"label":"C","text":"P A < P B"},{"label":"D","text":"Not enough information to determine."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"170","height":"101"}],"answer":"A"},{"id":"Units_7-8-q363","source":"Units_7-8","sourceNumber":"363","topic":"Unit 8: Fluids","difficulty":"Hard","question":"In the scenario shown above, water is flowing at a constant flow rate through the horizontal pipe. Two open vertical tubes are attached to the pipe, with valves that are initially shut. When the valves are opened and the water in the tubes is allowed to reach equilibrium, how will the height h 1 of the water column in Tube 1 compare to the height h 2 of the water column in Tube 2?","choices":[{"label":"A","text":"h 1 = h 2 > 0"},{"label":"B","text":"h 1 = h 2 = 0"},{"label":"C","text":"h 2 > h 1"},{"label":"D","text":"h 1 > h 2"},{"label":"E","text":"Not enough information to make a prediction."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"466","height":"128"}],"answer":"A"},{"id":"Units_7-8-q364","source":"Units_7-8","sourceNumber":"364","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Water flows through a pipe. The diameter of the pipe at point B is larger than at point A. Where is the water pressure greatest?","choices":[{"label":"A","text":"at point A"},{"label":"B","text":"at point B"},{"label":"C","text":"It is the same at both A and B."}],"images":[],"answer":"B"},{"id":"Units_7-8-q365","source":"Units_7-8","sourceNumber":"365","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Water flowing through a horizontal pipe goes from a section with a large diameter to a section with a small diameter. Which of the following are true about the water? Select all that apply.","choices":[{"label":"A","text":"Positive work is done because the water in the larger pipe has a higher pressure."},{"label":"B","text":"The density of the water decreases."},{"label":"C","text":"The density of the water increases."},{"label":"D","text":"The speed of the water increases."},{"label":"E","text":"Negative work is done because the water in the smaller pipe has a higher pressure."}],"images":[],"answer":"D, A"},{"id":"Units_7-8-q366","source":"Units_7-8","sourceNumber":"366","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Water is flowing out of plastic can through a small opening at the bottom, as shown above. Which graph shows the correct qualitative dependence of the vertical position of the surface of the water as a function of time?","choices":[{"label":"A","text":"B)"},{"label":"C","text":"D) E)"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"414","height":"283"},{"src":"data:image/jpeg;base64,","alt":"","width":"184","height":"188"},{"src":"data:image/jpeg;base64,","alt":"","width":"188","height":"191"},{"src":"data:image/jpeg;base64,","alt":"","width":"182","height":"191"},{"src":"data:image/jpeg;base64,","alt":"","width":"183","height":"190"},{"src":"data:image/jpeg;base64,","alt":"","width":"187","height":"190"}],"answer":"C"},{"id":"Units_7-8-q367","source":"Units_7-8","sourceNumber":"367","topic":"Unit 4: Linear Momentum","difficulty":"Medium","question":"The continuity equation A 1 v 1 = A 2 v 2 describes the conservation of which of the following quantities?","choices":[{"label":"A","text":"Electric charge,"},{"label":"B","text":"Speed"},{"label":"C","text":"Energy,"},{"label":"D","text":"Momentum,"},{"label":"E","text":"Mass, and"}],"images":[],"answer":"E"},{"id":"Units_7-8-q368","source":"Units_7-8","sourceNumber":"368","topic":"Unit 8: Fluids","difficulty":"Hard","question":"An incompressible nonviscous fluid is flowing steadily through the pipe shown in the figure above at a constant flow rate. Section A has a radius r , section B has a radius r /2, and section C has a radius r . Section B is a vertical height h above section A, and section C is a vertical height h below section A. Which of the following correctly ranks the speed of the fluid in each of the sections?","choices":[{"label":"A","text":"v A < v B < v C"},{"label":"B","text":"v B < v A < v C"},{"label":"C","text":"v B < v A = v C"},{"label":"D","text":"v A = v C < v B"},{"label":"E","text":"It depends if the fluid is flowing left or right."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"458","height":"149"}],"answer":"C"},{"id":"Units_7-8-q369","source":"Units_7-8","sourceNumber":"369","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A pipe of flowing water, shown above, has a nozzle at the end so that the final radius of the pipe is one-third of the initial radius. If the flow speed of the fluid in the widest potion of the tube is v , what is the exit speed of the fluid at the end of the nozzle?","choices":[{"label":"A","text":"v ,"},{"label":"B","text":"9 v"},{"label":"C","text":"3 v , and"},{"label":"D","text":"v /3,"},{"label":"E","text":"v /9,"}],"images":[],"answer":"A"},{"id":"Units_7-8-q370","source":"Units_7-8","sourceNumber":"370","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Two horizontal pipes are of the same length, but pipe B has twice the diameter of pipe A. Water undergoes viscous flow in both pipes, subject to the same pressure difference across the lengths of the pipes. If the flow rate in pipe A is Q = , what is the flow rate in pipe B?","choices":[{"label":"A","text":"2 Q"},{"label":"B","text":"8 Q"},{"label":"C","text":"16 Q"},{"label":"D","text":"Q"},{"label":"E","text":"4 Q"}],"images":[{"src":"data:image/jpeg;base64,","alt":"(ΔV/Δt)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"D"},{"id":"Units_7-8-q371","source":"Units_7-8","sourceNumber":"371","topic":"Unit 8: Fluids","difficulty":"Easy","question":"Water flows without viscosity or turbulence through a horizontal pipe. The diameter of the pipe at point B is larger than at point A. Where is the water pressure greatest?","choices":[{"label":"A","text":"at point A"},{"label":"B","text":"at point B"},{"label":"C","text":"It is the same at both A and B."}],"images":[],"answer":"B"},{"id":"Units_7-8-q372","source":"Units_7-8","sourceNumber":"372","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Two horizontal pipes are of the same length, but pipe B has twice the diameter of pipe A. Water undergoes viscous flow in both pipes, subject to the same pressure difference across the lengths of the pipes. If the flow rate in pipe A is Q = , what is the flow rate in pipe B?","choices":[{"label":"A","text":"16 Q"},{"label":"B","text":"4 Q"},{"label":"C","text":"2 Q"},{"label":"D","text":"8 Q"},{"label":"E","text":"Q"}],"images":[{"src":"data:image/jpeg;base64,","alt":"(ΔV/Δt)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"E"},{"id":"Units_7-8-q373","source":"Units_7-8","sourceNumber":"373","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Two horizontal pipes have the same diameter, but pipe B is twice as long as pipe A. Water undergoes viscous flow in both pipes, subject to the same pressure difference across the lengths of the pipes. If the flow rate in pipe B is Q = , what is the flow rate in pipe A?","choices":[{"label":"A","text":"16 Q"},{"label":"B","text":"2 Q"},{"label":"C","text":"Q"},{"label":"D","text":"8 Q"},{"label":"E","text":"4 Q"}],"images":[{"src":"data:image/jpeg;base64,","alt":"(ΔV/Δt)","width":null,"height":null},{"src":"data:image/jpeg;base64,","alt":"square root of (2)","width":null,"height":null}],"answer":"C"},{"id":"Units_7-8-q374","source":"Units_7-8","sourceNumber":"374","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A fluid flows through a pipe of radius r at a speed v for a time interval t . The volume of fluid that flows past a point in the pipe during this time interval is equal to","choices":[{"label":"A","text":"πr 2 / vt"},{"label":"B","text":"2 πr 2 / t"},{"label":"C","text":"2 πrvt"},{"label":"D","text":"2 πrv / t"},{"label":"E","text":"πr 2 vt"}],"images":[],"answer":"B"},{"id":"Units_7-8-q375","source":"Units_7-8","sourceNumber":"375","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Consider a very small hole in the bottom of a tank that is 17.0 cm in diameter and filled with water to a height of 90.0 cm. Find the speed at which the water exits the tank through the hole. Model the water as a nonviscous incompressible fluid in streamline flow.","choices":[{"label":"A","text":"44.1 m/s"},{"label":"B","text":"17.64 m/s"},{"label":"C","text":"4.20 m/s"},{"label":"D","text":"48.3 m/s"}],"images":[],"answer":"C"},{"id":"Units_7-8-q376","source":"Units_7-8","sourceNumber":"376","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Water flowing through a cylindrical pipe suddenly comes to a section of pipe where the diameter decreases to 86% of its previous value. If the speed of the water in the larger section of the pipe was 32 m/s, what is its speed in this smaller section if the water behaves like an incompressible fluid flowing steadily?","choices":[{"label":"A","text":"28 m/s"},{"label":"B","text":"37 m/s"},{"label":"C","text":"43 m/s"},{"label":"D","text":"24 m/s"}],"images":[],"answer":"C"},{"id":"Units_7-8-q377","source":"Units_7-8","sourceNumber":"377","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A pump uses a piston of 15 cm diameter that moves at 2.0 cm/s as it pushes a fluid through a pipe. What is the speed of the fluid when it enters a portion of the pipe that is 3.0 mm in diameter? Treat the fluid as incompressible and in steady flow.","choices":[{"label":"A","text":"22 cm/s"},{"label":"B","text":"50 m/s"},{"label":"C","text":"50 cm/s"},{"label":"D","text":"6.0 cm/s"}],"images":[],"answer":"B"},{"id":"Units_7-8-q378","source":"Units_7-8","sourceNumber":"378","topic":"Unit 8: Fluids","difficulty":"Medium","question":"An incompressible fluid flows steadily through a pipe that has a change in diameter. The fluid speed at a location where the pipe diameter is 8.0 cm is 1.28 m/s. What is the fluid speed at a location where the diameter has narrowed to 4.0 cm?","choices":[{"label":"A","text":"1.3 m/s"},{"label":"B","text":"2.6 m/s"},{"label":"C","text":"5.1 m/s"},{"label":"D","text":"0.32 m/s"},{"label":"E","text":"0.64 m/s"}],"images":[],"answer":"C"},{"id":"Units_7-8-q379","source":"Units_7-8","sourceNumber":"379","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Fluid flows at 2.0 m/s through a pipe of diameter 3.0 cm. What is the volume flow rate of the fluid?","choices":[{"label":"A","text":"1.4 × 10 -3 m 3 /s"},{"label":"B","text":"5.7 × 10 -3 m 3 /s"},{"label":"C","text":"57 m 3 /s"},{"label":"D","text":"14 m 3 /s"}],"images":[],"answer":"C"},{"id":"Units_7-8-q380","source":"Units_7-8","sourceNumber":"380","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Incompressible fluid flows steadily through a 4.0-cm-diameter pipe at 1.0 m/s. There is a 2.0 cm diameter constriction in the line. What is the speed of the fluid in this constriction?","choices":[{"label":"A","text":"4.0 m/s"},{"label":"B","text":"2.0 m/s"},{"label":"C","text":"0.25 m/s"},{"label":"D","text":"0.50 m/s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q381","source":"Units_7-8","sourceNumber":"381","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Water, which we can treat as incompressible and nonviscous, flows steadily at 12 m/s in a horizontal pipe with a pressure of 3.0 × 10 4 Pa. If the pipe widens to twice its original radius, what is the pressure in the wider section?","choices":[{"label":"A","text":"7.4 × 10 4 Pa"},{"label":"B","text":"4.9 × 10 4 Pa"},{"label":"C","text":"3.0 × 10 4 Pa"},{"label":"D","text":"9.8 × 10 4 Pa"}],"images":[],"answer":"C"},{"id":"Units_7-8-q382","source":"Units_7-8","sourceNumber":"382","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A hole of radius 1.0 mm forms in the bottom of a very large water storage tank that holds water to a depth of 15 m. At what volume rate will incompressible, nonviscous water flow out of the hole?","choices":[{"label":"A","text":"5.4 × 10 -4 m 3 /s"},{"label":"B","text":"5.4 × 10 -7 m 3 /s"},{"label":"C","text":"5.4 × 10 -6 m 3 /s"},{"label":"D","text":"5.4 × 10 -5 m 3 /s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q383","source":"Units_7-8","sourceNumber":"383","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Incompressible, nonviscous water flows steadily through a horizontal pipe of cross-sectional area 10.0 cm 2 at a pressure of 0.250 atm with a volume flow rate of 1.00 × 10 -3 m 3 /s. At a valve, the effective cross-sectional area of the pipe is reduced to 5.00 cm 2 . What is the pressure at the valve?","choices":[{"label":"A","text":"0.200 atm"},{"label":"B","text":"0.112 atm"},{"label":"C","text":"0.157 atm"},{"label":"D","text":"0.235 atm"}],"images":[],"answer":"D"},{"id":"Units_7-8-q384","source":"Units_7-8","sourceNumber":"384","topic":"Unit 8: Fluids","difficulty":"Medium","question":"For a certain patient, the build-up of fatty tissue on the wall of an artery has decreased the arterial radius by 10%. By how much would the pressure provided by the heart have to be increased to maintain a constant volume of blood flow? Model the blood as a viscous incompressible fluid.","choices":[{"label":"A","text":"48%"},{"label":"B","text":"46%"},{"label":"C","text":"54%"},{"label":"D","text":"52%"}],"images":[],"answer":"D"},{"id":"Units_7-8-q386","source":"Units_7-8","sourceNumber":"386","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Incompressible water is flowing steadily in a drainage channel of rectangular cross section. At one point, the width of the channel is 12 m, the depth of water is 6.0 m, and the speed of the flow is 2.5 m/s. At a point downstream, the width has narrowed to 9.0 m, and the depth of water is 8.0 m. What is the speed of the flow at the second point?","choices":[{"label":"A","text":"4.0 m/s"},{"label":"B","text":"2.0 m/s"},{"label":"C","text":"2.5 m/s"},{"label":"D","text":"3.5 m/s"},{"label":"E","text":"3.0 m/s"}],"images":[],"answer":"C"},{"id":"Units_7-8-q387","source":"Units_7-8","sourceNumber":"387","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Water is flowing in a drainage channel of rectangular cross section. The width of the channel is 15 m, the depth of water is 8.0 m, and the speed of the flow is 2.5 m/s. What is the mass flow rate of the water? The density of water is 1000 kg/m 3 .","choices":[{"label":"A","text":"3.0 × 10 5 kg/s"},{"label":"B","text":"2.0 × 10 5 kg/s"},{"label":"C","text":"3.0 × 10 2 kg/s"},{"label":"D","text":"2.0 × 10 3 kg/s"},{"label":"E","text":"3.0 × 10 3 kg/s"}],"images":[],"answer":"D"},{"id":"Units_7-8-q388","source":"Units_7-8","sourceNumber":"388","topic":"Unit 8: Fluids","difficulty":"Medium","question":"In a section of horizontal pipe with a diameter of 3.0 cm, the pressure is 100 kPa and water is flowing with a speed of 1.5 m/s. The pipe narrows to 2.0 cm. What is the pressure in the narrower region? Treat the water as an incompressible nonviscous fluid in steady flow.","choices":[{"label":"A","text":"230 kPa"},{"label":"B","text":"67 kPa"},{"label":"C","text":"48 kPa"},{"label":"D","text":"44 kPa"},{"label":"E","text":"95 kPa"}],"images":[],"answer":"E"},{"id":"Units_7-8-q389","source":"Units_7-8","sourceNumber":"389","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Water flows through a horizontal pipe of cross-sectional area 10.0 cm 2 at a pressure of 0.250 atm with a flow rate is 1.00 L/s. At a valve, the effective cross-sectional area of the pipe is reduced to 5.00 cm 2 . What is the pressure at the valve? The density of water is 1000 kg/m 3 , and treat it as a nonviscous incompressible fluid in steady flow.","choices":[{"label":"A","text":"0.235 atm"},{"label":"B","text":"7700 Pa"},{"label":"C","text":"0.157 atm"},{"label":"D","text":"0.200 atm"},{"label":"E","text":"0.110 atm"}],"images":[],"answer":"A"},{"id":"Units_7-8-q390","source":"Units_7-8","sourceNumber":"390","topic":"Unit 8: Fluids","difficulty":"Medium","question":"An incompressible fluid flows at 12 m/s in a horizontal pipe. If the pipe widens to twice its original radius, what is the flow speed in the wider section?","choices":[{"label":"A","text":"12 m/s"},{"label":"B","text":"4.0 m/s"},{"label":"C","text":"6.0 m/s"},{"label":"D","text":"3.0 m/s"}],"images":[],"answer":"D"},{"id":"Units_7-8-q391","source":"Units_7-8","sourceNumber":"391","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Water flows out of a large reservoir through an open pipe, as shown in the figure. What is the speed of the water as it comes out of the pipe? Model the water as a nonviscous incompressible fluid in streamline flow.","choices":[{"label":"A","text":"16 m/s"},{"label":"B","text":"9.9 m/s"},{"label":"C","text":"13 m/s"},{"label":"D","text":"14 m/s"},{"label":"E","text":"8.9 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"208","height":"171"}],"answer":"C"},{"id":"Units_7-8-q392","source":"Units_7-8","sourceNumber":"392","topic":"Unit 8: Fluids","difficulty":"Hard","question":"Water flows out of a large reservoir through 5.0-cm diameter pipe. The pipe connects to a 3.0-cm diameter pipe that is open to the atmosphere, as shown in the figure. What is the speed of the water in the 5.0-cm pipe? Treat the water as a nonviscous incompressible fluid in streamline flow.","choices":[{"label":"A","text":"3.2 m/s"},{"label":"B","text":"10 m/s"},{"label":"C","text":"3.9 m/s"},{"label":"D","text":"2.3 m/s"},{"label":"E","text":"8.9 m/s"}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"235","height":"148"}],"answer":"A"},{"id":"Units_7-8-q393","source":"Units_7-8","sourceNumber":"393","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A pressurized cylindrical tank, 5.0 m in diameter, contains water that emerges from the pipe at point C with a speed of 13 m/s as shown in the figure. Point A is 10 m above point B and point C is 3.0 m above point B. The area of the pipe at point B is 0.080 m 2 and the pipe narrows to an area of 0.040 m 2 at point C. Assume that the water is a nonviscous incompressible fluid in streamline flow. The density of water is 1000 kg/m 3 The mass flow rate in the pipe is closest to","choices":[{"label":"A","text":"420 kg/s."},{"label":"B","text":"310 kg/s."},{"label":"C","text":"360 kg/s."},{"label":"D","text":"520 kg/s."},{"label":"E","text":"470 kg/s."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"373","height":"175"}],"answer":"D"},{"id":"Units_7-8-q394","source":"Units_7-8","sourceNumber":"394","topic":"Unit 8: Fluids","difficulty":"Hard","question":"A pressurized cylindrical tank, 5.0 m in diameter, contains water that emerges from the pipe at point C with a speed of 84 m/s, as shown in the figure. Point A is 10 m above point B and point C is 3.0 m above point B. The area of the pipe at point B is 0.080 m 2 and the pipe narrows to an area of 0.070 m 2 at point C. Assume that the water is a nonviscous incompressible fluid in streamline flow. The density of water is 1000 kg/m 3 . The rate at which the water level is falling in the tank is closest to","choices":[{"label":"A","text":"340 mm/s."},{"label":"B","text":"250 mm/s."},{"label":"C","text":"210 mm/s."},{"label":"D","text":"300 mm/s."},{"label":"E","text":"160 mm/s."}],"images":[{"src":"data:image/jpeg;base64,","alt":"","width":"373","height":"175"}],"answer":"D"},{"id":"Units_7-8-q395","source":"Units_7-8","sourceNumber":"395","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Glycerin, with a viscosity of 1.5 N ∙ s/m 2 , is flowing with an average speed of 1.2 m/s through a tube that has a radius of 5.0 mm and is 25 cm long. What is the change in pressure throughout the length of this pipe?","choices":[{"label":"A","text":"140 kPa"},{"label":"B","text":"46 kPa"},{"label":"C","text":"130 kPa"},{"label":"D","text":"72 kPa"},{"label":"E","text":"76 kPa"}],"images":[],"answer":"A"},{"id":"Units_7-8-q396","source":"Units_7-8","sourceNumber":"396","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Motor oil, with a viscosity of 0.25 N ∙ s/m 2 , is flowing through a tube that has a radius of 3.0 mm and is 1.0 m long. The change in pressure over the length of the tube is 200 kPa. What is the average speed of the oil?","choices":[{"label":"A","text":"0.90 m/s"},{"label":"B","text":"0.80 m/s"},{"label":"C","text":"1.1 m/s"},{"label":"D","text":"1.2 m/s"},{"label":"E","text":"1.0 m/s"}],"images":[],"answer":"A"},{"id":"Units_7-8-q397","source":"Units_7-8","sourceNumber":"397","topic":"Unit 8: Fluids","difficulty":"Medium","question":"Motor oil, with a viscosity of 0.25 N ∙ s/m 2 , is flowing through a tube that has a radius of 5.0 mm and is 25 cm long. The drop in pressure is 300 kPa. What is the volume of oil flowing through the tube per second?","choices":[{"label":"A","text":"0.025 m 3 /s"},{"label":"B","text":"7.5 m 3 /s"},{"label":"C","text":"0.0012 m 3 /s"},{"label":"D","text":"0.00038 m 3 /s"},{"label":"E","text":"4.7 m 3 /s"}],"images":[],"answer":"D"},{"id":"Units_7-8-q398","source":"Units_7-8","sourceNumber":"398","topic":"Unit 8: Fluids","difficulty":"Medium","question":"A fluid is flowing with an average speed of 1.5 m/s through a tube that has a radius of 2.0 mm and is 18 cm long. The drop in pressure is 967 Pa. What is the viscosity of the fluid?","choices":[{"label":"A","text":"0.028 N ∙ s/m 2"},{"label":"B","text":"0.0056 N ∙ s/m 2"},{"label":"C","text":"0.013 N ∙ s/m 2"},{"label":"D","text":"0.0034 N ∙ s/m 2"},{"label":"E","text":"0.0018 N ∙ s/m 2"}],"images":[],"answer":"E"}];
